(globalThis.TURBOPACK||(globalThis.TURBOPACK=[])).push(["object"==typeof document?document.currentScript:void 0,57249,(e,i,a)=>{i.exports=JSON.parse('[{"module":"Day 1 Module 1","group":"d1m1-lln","question":"An actuary can estimate with surprising accuracy how many of 100,000 insured drivers will become disabled this year, even though she cannot say which ones. Which principle makes this possible?","options":["The law of large numbers","The principle of indemnity","The rule of adhesion","The doctrine of utmost good faith"],"answer":"The law of large numbers","topic":"Law of Large Numbers","explanation":"The law of large numbers says predictions get more accurate as the number of similar exposure units grows. It\'s what lets insurers price premiums reliably — they can\'t predict WHO will suffer a loss, only HOW MANY will."},{"module":"Day 1 Module 1","group":"d1m1-lln","question":"Premiums can be calculated reliably because predictions of loss become more accurate as the number of similar exposure units grows. This concept is called:","options":["The law of large numbers","Adverse selection","Experience rating","The law of averages"],"answer":"The law of large numbers","topic":"Law of Large Numbers","explanation":"The law of large numbers says predictions get more accurate as the number of similar exposure units grows. It\'s what lets insurers price premiums reliably — they can\'t predict WHO will suffer a loss, only HOW MANY will."},{"module":"Day 1 Module 1","group":"d1m1-hazard","question":"A warehouse owner stores oily rags in a pile next to the furnace. The rags are an example of:","options":["A physical hazard","A peril","A moral hazard","A morale hazard"],"answer":"A physical hazard","topic":"Hazards","explanation":"A hazard increases the chance or severity of loss. Physical = tangible conditions (oily rags, ice). Moral = dishonesty (fraud, exaggerated claims). Morale = carelessness because insurance exists (unlocked doors)."},{"module":"Day 1 Module 1","group":"d1m1-hazard","question":"Trent exaggerates the value of the items stolen from his car when he files his claim. Trent\'s dishonesty is an example of:","options":["A moral hazard","A morale hazard","A physical hazard","A peril"],"answer":"A moral hazard","topic":"Hazards","explanation":"A hazard increases the chance or severity of loss. Physical = tangible conditions (oily rags, ice). Moral = dishonesty (fraud, exaggerated claims). Morale = carelessness because insurance exists (unlocked doors)."},{"module":"Day 1 Module 1","group":"d1m1-hazard","question":"Since buying renters insurance, Dana has stopped locking her apartment door, figuring \\"the insurance will cover it.\\" Her new carelessness is an example of:","options":["A morale hazard","A moral hazard","A physical hazard","A speculative risk"],"answer":"A morale hazard","topic":"Hazards","explanation":"A hazard increases the chance or severity of loss. Physical = tangible conditions (oily rags, ice). Moral = dishonesty (fraud, exaggerated claims). Morale = carelessness because insurance exists (unlocked doors)."},{"module":"Day 1 Module 1","group":"d1m1-purespec","question":"Devon bets $500 on a playoff game, where he may win or lose. Priya owns a home that faces only the chance of loss from fire. Which statement is TRUE?","options":["Priya\'s exposure is a pure risk and is insurable; Devon\'s is speculative and is not","Both exposures are insurable pure risks","Devon\'s exposure is insurable because the outcome is measurable","Neither exposure is insurable"],"answer":"Priya\'s exposure is a pure risk and is insurable; Devon\'s is speculative and is not","topic":"Pure vs. Speculative Risk","explanation":"Pure risk has only the chance of loss or no loss — it\'s insurable. Speculative risk includes a chance of GAIN (gambling, investing) — never insurable."},{"module":"Day 1 Module 1","group":"d1m1-purespec","question":"Which statement concerning pure and speculative risk is TRUE?","options":["Only pure risks are insurable","Only speculative risks are insurable","Both pure and speculative risks are insurable","Speculative risks involve no chance of gain"],"answer":"Only pure risks are insurable","topic":"Pure vs. Speculative Risk","explanation":"Pure risk has only the chance of loss or no loss — it\'s insurable. Speculative risk includes a chance of GAIN (gambling, investing) — never insurable."},{"module":"Day 1 Module 1","group":"d1m1-riskdef","question":"As insurers use the term, \\"risk\\" is best defined as:","options":["Uncertainty regarding financial loss","The certainty that a loss will occur","Any dangerous activity","The dollar amount of a claim"],"answer":"Uncertainty regarding financial loss","topic":"Definition of Risk","explanation":"In insurance, risk means uncertainty regarding financial loss — not danger, not the loss amount, just the uncertainty of whether a loss will occur."},{"module":"Day 1 Module 1","group":"d1m1-riskdef","question":"Every exposure an insurer is willing to cover shares one essential element. What is it?","options":["Uncertainty about whether a financial loss will occur","A guaranteed payout amount","Government backing","A chance of profit for the insured"],"answer":"Uncertainty about whether a financial loss will occur","topic":"Definition of Risk","explanation":"In insurance, risk means uncertainty regarding financial loss — not danger, not the loss amount, just the uncertainty of whether a loss will occur."},{"module":"Day 1 Module 1","group":"d1m1-peril","question":"A tornado that levels a barn is an example of:","options":["A peril","A hazard","A risk retention","A speculative risk"],"answer":"A peril","topic":"Peril vs. Hazard","explanation":"A peril is the CAUSE of loss (fire, flood, tornado, death). A hazard is a CONDITION that increases the chance of loss. Conditions of the body (like poor eyesight) are not perils."},{"module":"Day 1 Module 1","group":"d1m1-peril","question":"Which of the following is the CAUSE of a loss, rather than a condition that increases the chance of one?","options":["A flood","Unsalted icy steps","Smoking in bed","Poor building maintenance"],"answer":"A flood","topic":"Peril vs. Hazard","explanation":"A peril is the CAUSE of loss (fire, flood, tornado, death). A hazard is a CONDITION that increases the chance of loss. Conditions of the body (like poor eyesight) are not perils."},{"module":"Day 1 Module 1","group":"d1m1-peril","question":"All of the following are perils EXCEPT:","options":["Nearsightedness","Fire","Windstorm","Theft"],"answer":"Nearsightedness","topic":"Peril vs. Hazard","explanation":"A peril is the CAUSE of loss (fire, flood, tornado, death). A hazard is a CONDITION that increases the chance of loss. Conditions of the body (like poor eyesight) are not perils."},{"module":"Day 1 Module 1","group":"d1m1-methods","question":"Rosa refuses to ever ride a motorcycle because she fears being injured. Rosa is handling risk through:","options":["Avoidance","Reduction","Retention","Transference"],"answer":"Avoidance","topic":"Risk-Handling Methods (ARRT)","explanation":"Four ways to handle risk: Avoid (eliminate the exposure), Reduce (lower likelihood/severity — sprinklers, alarms), Retain (accept it yourself — self-insure), Transfer (shift it to another party — buying insurance)."},{"module":"Day 1 Module 1","group":"d1m1-methods","question":"A restaurant installs a kitchen sprinkler system to limit fire damage. This is risk:","options":["Reduction","Avoidance","Retention","Transference"],"answer":"Reduction","topic":"Risk-Handling Methods (ARRT)","explanation":"Four ways to handle risk: Avoid (eliminate the exposure), Reduce (lower likelihood/severity — sprinklers, alarms), Retain (accept it yourself — self-insure), Transfer (shift it to another party — buying insurance)."},{"module":"Day 1 Module 1","group":"d1m1-methods","question":"A courier company with 300 vans pays collision losses out of its own reserve fund rather than buying coverage. This is risk:","options":["Retention","Reduction","Transference","Avoidance"],"answer":"Retention","topic":"Risk-Handling Methods (ARRT)","explanation":"Four ways to handle risk: Avoid (eliminate the exposure), Reduce (lower likelihood/severity — sprinklers, alarms), Retain (accept it yourself — self-insure), Transfer (shift it to another party — buying insurance)."},{"module":"Day 1 Module 1","group":"d1m1-methods","question":"Marcus buys a homeowners policy, shifting the financial consequences of a fire to an insurer. This is risk:","options":["Transference","Retention","Avoidance","Reduction"],"answer":"Transference","topic":"Risk-Handling Methods (ARRT)","explanation":"Four ways to handle risk: Avoid (eliminate the exposure), Reduce (lower likelihood/severity — sprinklers, alarms), Retain (accept it yourself — self-insure), Transfer (shift it to another party — buying insurance)."},{"module":"Day 1 Module 1","group":"d1m1-elements","question":"Which of the following describe elements of an insurable risk? I - The loss must be due to chance. II - The loss must be definite and measurable. III - The loss must not be catastrophic. IV - There must be a large number of similar exposure units.","options":["I, II, III, and IV","I and II only","II, III, and IV only","I, II, and III only"],"answer":"I, II, III, and IV","topic":"Elements of Insurable Risk","explanation":"An insurable risk must be: due to chance, definite and measurable, statistically predictable, NOT catastrophic, part of a large group of similar exposures, and randomly selected."},{"module":"Day 1 Module 1","group":"d1m1-elements","question":"An insurer declines to write a policy covering losses from a single mega-earthquake striking an entire metro area. Which element of insurable risk is missing?","options":["The loss must not be catastrophic","The loss must be due to chance","The loss must be definite and measurable","There must be a large number of exposure units"],"answer":"The loss must not be catastrophic","topic":"Elements of Insurable Risk","explanation":"An insurable risk must be: due to chance, definite and measurable, statistically predictable, NOT catastrophic, part of a large group of similar exposures, and randomly selected."},{"module":"Day 1 Module 1","group":"d1m1-adverse","question":"A disproportionate share of applicants for a new critical-illness policy turn out to already have troubling symptoms. This tendency is called:","options":["Adverse selection","Moral hazard","The law of large numbers","Subrogation"],"answer":"Adverse selection","topic":"Adverse Selection","explanation":"Adverse selection is the tendency of people in poor health (higher risk) to seek insurance more than low-risk people. Insurers control it through underwriting."},{"module":"Day 1 Module 1","group":"d1m1-adverse","question":"Adverse selection is the tendency of people in ______ to seek insurance to a greater extent than other risks.","options":["Poor health","High income brackets","Rural areas","Low-risk occupations"],"answer":"Poor health","topic":"Adverse Selection","explanation":"Adverse selection is the tendency of people in poor health (higher risk) to seek insurance more than low-risk people. Insurers control it through underwriting."},{"module":"Day 1 Module 1","group":"d1m1-hlv","question":"The concept that measures a person\'s worth by the future earnings they would generate for their family is called:","options":["Human life value","Net worth analysis","Adverse selection","The indemnity principle"],"answer":"Human life value","topic":"Human Life Value","explanation":"Human life value measures a person\'s worth by their future earning potential — the essence of a family\'s economic existence. It\'s the economic root of life and health insurance."},{"module":"Day 1 Module 1","group":"d1m1-hlv","question":"The purpose and function of insurance has its roots in economics and ______.","options":["Human life value","Government mandates","Stock market returns","Actuarial science"],"answer":"Human life value","topic":"Human Life Value","explanation":"Human life value measures a person\'s worth by their future earning potential — the essence of a family\'s economic existence. It\'s the economic root of life and health insurance."},{"module":"Day 1 Module 1","group":"d1m1-hlv","question":"Human life value is, at its core, a measure of an individual\'s or family\'s ______.","options":["Economic existence","Social standing","Physical health","Insurance history"],"answer":"Economic existence","topic":"Human Life Value","explanation":"Human life value measures a person\'s worth by their future earning potential — the essence of a family\'s economic existence. It\'s the economic root of life and health insurance."},{"module":"Day 1 Module 1","group":"d1m1-function","question":"Which statement best describes the core function of insurance?","options":["It minimizes the individual\'s loss by spreading financial risk across a large group","It guarantees that no one ever suffers a financial loss","It generates investment profits for policyholders","It eliminates the underlying causes of loss"],"answer":"It minimizes the individual\'s loss by spreading financial risk across a large group","topic":"Function of Insurance","explanation":"Insurance minimizes individual loss by spreading financial risk across a large group. Life and health insurance specifically address the economic losses of death, sickness, and accidents."},{"module":"Day 1 Module 1","group":"d1m1-function","question":"Life and health insurance developed primarily as a practical answer to the economic losses associated with:","options":["Death, sickness, and accidents","Inflation, taxes, and unemployment","Crime, fraud, and theft","War, famine, and drought"],"answer":"Death, sickness, and accidents","topic":"Function of Insurance","explanation":"Insurance minimizes individual loss by spreading financial risk across a large group. Life and health insurance specifically address the economic losses of death, sickness, and accidents."},{"module":"Day 1 Module 1","group":"d1m1-transfer","question":"People buy insurance mainly because it is one of the most effective ways of:","options":["Transferring risk","Avoiding risk entirely","Increasing personal wealth","Eliminating perils"],"answer":"Transferring risk","topic":"Insurance as Risk Transfer","explanation":"Buying insurance is the classic example of risk TRANSFERENCE — the insurer assumes financial risk in exchange for premium. Of the four ARRT methods, transference is the basis of insurance."},{"module":"Day 1 Module 1","group":"d1m1-transfer","question":"Of the four risk-handling techniques, the one that forms the basis of insurance is:","options":["Transference","Avoidance","Reduction","Retention"],"answer":"Transference","topic":"Insurance as Risk Transfer","explanation":"Buying insurance is the classic example of risk TRANSFERENCE — the insurer assumes financial risk in exchange for premium. Of the four ARRT methods, transference is the basis of insurance."},{"module":"Day 1 Module 1","group":"d1m1-uninsurable","question":"Vince wants a policy that pays him if his cryptocurrency holdings lose value. Why will insurers refuse?","options":["Investment losses are speculative risks, which are uninsurable","The potential loss is too small to measure","Cryptocurrency is regulated federally, not by states","Vince lacks insurable interest in his own assets"],"answer":"Investment losses are speculative risks, which are uninsurable","topic":"Uninsurable Risks","explanation":"Speculative risks (investments, gambling) and catastrophic exposures (region-wide tsunami, war) fail the elements of insurable risk and will be declined."},{"module":"Day 1 Module 1","group":"d1m1-uninsurable","question":"Which exposure would an insurer most likely refuse to cover?","options":["Region-wide destruction from a tsunami","A homeowner\'s risk of kitchen fire","A delivery driver\'s risk of collision","An office worker\'s risk of disability"],"answer":"Region-wide destruction from a tsunami","topic":"Uninsurable Risks","explanation":"Speculative risks (investments, gambling) and catastrophic exposures (region-wide tsunami, war) fail the elements of insurable risk and will be declined."},{"module":"Day 1 Module 2","group":"d1m2-naic","question":"Which statement about the National Association of Insurance Commissioners (NAIC) is NOT correct?","options":["The NAIC has the authority to prosecute and punish criminal violators in the insurance industry","The NAIC is composed of state insurance regulators","The NAIC develops model laws for states to consider adopting","The NAIC works to encourage uniformity among state insurance regulations"],"answer":"The NAIC has the authority to prosecute and punish criminal violators in the insurance industry","topic":"The NAIC","explanation":"The NAIC is an association of state insurance commissioners that promotes uniformity through model laws. It has NO enforcement or prosecution authority — that power belongs to the states."},{"module":"Day 1 Module 2","group":"d1m2-naic","question":"The NAIC\'s primary purpose is to:","options":["Encourage uniformity in state insurance regulation through model legislation","Issue insurance licenses in every state","Prosecute insurance fraud at the federal level","Set nationwide premium rates"],"answer":"Encourage uniformity in state insurance regulation through model legislation","topic":"The NAIC","explanation":"The NAIC is an association of state insurance commissioners that promotes uniformity through model laws. It has NO enforcement or prosecution authority — that power belongs to the states."},{"module":"Day 1 Module 2","group":"d1m2-agentbroker","question":"In an insurance transaction, a licensed agent legally represents:","options":["The insurer","The applicant and insured","The state Office of Insurance Regulation","Whoever pays the higher fee"],"answer":"The insurer","topic":"Agent vs. Broker","explanation":"An agent legally represents the INSURER. A broker legally represents the APPLICANT/INSURED and shops the market on their behalf."},{"module":"Day 1 Module 2","group":"d1m2-agentbroker","question":"In Florida, a broker in an insurance transaction legally represents:","options":["The applicant and insured","The insurer","The Department of Financial Services","The reinsurer"],"answer":"The applicant and insured","topic":"Agent vs. Broker","explanation":"An agent legally represents the INSURER. A broker legally represents the APPLICANT/INSURED and shops the market on their behalf."},{"module":"Day 1 Module 2","group":"d1m2-agentbroker","question":"Lena shops the market on behalf of her clients and submits each application to whichever insurer fits best. In these transactions Lena is acting as a:","options":["Broker, representing the applicant","Agent, representing the insurer","Adjuster, representing the insurer","Consultant, representing the state"],"answer":"Broker, representing the applicant","topic":"Agent vs. Broker","explanation":"An agent legally represents the INSURER. A broker legally represents the APPLICANT/INSURED and shops the market on their behalf."},{"module":"Day 1 Module 2","group":"d1m2-companies","question":"From Florida\'s perspective, an insurer formed under the laws of Ontario, Canada and licensed to sell in Florida is:","options":["An alien company","A foreign company","A domestic company","An unauthorized company"],"answer":"An alien company","topic":"Domestic / Foreign / Alien","explanation":"Classification is from the viewpoint of the state: incorporated in that state = domestic; another U.S. state = foreign; another country = alien."},{"module":"Day 1 Module 2","group":"d1m2-companies","question":"An insurer incorporated in Georgia with offices in Tennessee and licensed to sell insurance in Florida is, from Florida\'s viewpoint, a ______ company.","options":["Foreign","Domestic","Alien","Surplus"],"answer":"Foreign","topic":"Domestic / Foreign / Alien","explanation":"Classification is from the viewpoint of the state: incorporated in that state = domestic; another U.S. state = foreign; another country = alien."},{"module":"Day 1 Module 2","group":"d1m2-companies","question":"An insurer incorporated in Florida and selling policies in Florida is classified there as a ______ company.","options":["Domestic","Foreign","Alien","Reciprocal"],"answer":"Domestic","topic":"Domestic / Foreign / Alien","explanation":"Classification is from the viewpoint of the state: incorporated in that state = domestic; another U.S. state = foreign; another country = alien."},{"module":"Day 1 Module 2","group":"d1m2-reinsurer","question":"After issuing several jumbo commercial policies, Coastal Life arranges for another company to assume part of the risk. The company accepting that risk is a:","options":["Reinsurer","Risk retention group","Third-party administrator","Service provider"],"answer":"Reinsurer","topic":"Reinsurers","explanation":"A reinsurer accepts portions of risk from other insurance companies. Its customers are insurers, not the public — that\'s why it\'s a specialized branch of the industry."},{"module":"Day 1 Module 2","group":"d1m2-reinsurer","question":"Reinsurers are considered a specialized branch of the industry because the customers they insure are:","options":["Insurance companies","Individual policyholders","Government agencies","Independent agents"],"answer":"Insurance companies","topic":"Reinsurers","explanation":"A reinsurer accepts portions of risk from other insurance companies. Its customers are insurers, not the public — that\'s why it\'s a specialized branch of the industry."},{"module":"Day 1 Module 2","group":"d1m2-regscope","question":"State regulation of the insurance industry does NOT include:","options":["Making insurance laws","Licensing producers","Reviewing policy forms","Examining insurer finances"],"answer":"Making insurance laws","topic":"Scope of State Regulation","explanation":"Regulators license producers, approve forms, and examine insurers — but they don\'t MAKE laws. Insurance statutes are enacted by the state legislature."},{"module":"Day 1 Module 2","group":"d1m2-regscope","question":"Which body actually enacts a state\'s insurance statutes?","options":["The state legislature","The insurance commissioner","The NAIC","The State Guaranty Association"],"answer":"The state legislature","topic":"Scope of State Regulation","explanation":"Regulators license producers, approve forms, and examine insurers — but they don\'t MAKE laws. Insurance statutes are enacted by the state legislature."},{"module":"Day 1 Module 2","group":"d1m2-buyersguide","question":"Which of the following is NOT a goal of the Buyer\'s Guide?","options":["Ensuring that buyers obtain the lowest price for insurance","Helping buyers understand basic policy types","Helping buyers compare policies","Helping buyers make informed decisions"],"answer":"Ensuring that buyers obtain the lowest price for insurance","topic":"Buyer\'s Guide","explanation":"The Buyer\'s Guide helps applicants understand and compare policies to make informed decisions. It does NOT guarantee the lowest price."},{"module":"Day 1 Module 2","group":"d1m2-buyersguide","question":"The Buyer\'s Guide exists primarily to:","options":["Help applicants understand and compare policies before purchasing","Guarantee the lowest available premium","Replace the policy summary","Advertise an insurer\'s strongest products"],"answer":"Help applicants understand and compare policies before purchasing","topic":"Buyer\'s Guide","explanation":"The Buyer\'s Guide helps applicants understand and compare policies to make informed decisions. It does NOT guarantee the lowest price."},{"module":"Day 1 Module 2","group":"d1m2-guaranty","question":"An insurer becomes insolvent while owing claim payments. Which entity steps in so covered claims are still paid?","options":["The State Guaranty Association","The NAIC","The Federal Reserve","The reinsurer of last resort"],"answer":"The State Guaranty Association","topic":"State Guaranty Association","explanation":"If an insurer becomes insolvent, the State Guaranty Association pays covered claims, within limits. It protects policyholders, not insurers."},{"module":"Day 1 Module 2","group":"d1m2-guaranty","question":"The State Guaranty Association guarantees that:","options":["Claims will be paid, within limits, if a member insurer becomes insolvent","Premiums will never increase","Every applicant will be approved for coverage","Agents will receive their commissions"],"answer":"Claims will be paid, within limits, if a member insurer becomes insolvent","topic":"State Guaranty Association","explanation":"If an insurer becomes insolvent, the State Guaranty Association pays covered claims, within limits. It protects policyholders, not insurers."},{"module":"Day 1 Module 2","group":"d1m2-distribution","question":"Which marketing system does NOT involve the sale of insurance through agents or brokers?","options":["The direct selling system","The independent agency system","The career agency system","The brokerage system"],"answer":"The direct selling system","topic":"Distribution Systems","explanation":"Agency, brokerage, and career systems all use producers. The direct selling (direct response) system sells by mail, phone, and internet with NO agents or brokers."},{"module":"Day 1 Module 2","group":"d1m2-distribution","question":"An insurer that markets policies exclusively by mail, phone, and internet — with no producers involved — uses the ______ system.","options":["Direct selling","Independent agency","Managing general agent","Career agency"],"answer":"Direct selling","topic":"Distribution Systems","explanation":"Agency, brokerage, and career systems all use producers. The direct selling (direct response) system sells by mail, phone, and internet with NO agents or brokers."},{"module":"Day 1 Module 2","group":"d1m2-advertising","question":"Rules pertaining to testimonials, statistics, and special offers in insurance marketing are found in:","options":["The Advertising Code","The Buyer\'s Guide","The policy summary","The entire contract provision"],"answer":"The Advertising Code","topic":"Advertising Code","explanation":"Rules governing testimonials, statistics, and special offers in insurance marketing live in the Advertising Code."},{"module":"Day 1 Module 2","group":"d1m2-advertising","question":"An insurer\'s TV spot features a celebrity endorsement and claims it is \\"rated #1 in claim payments.\\" Which set of rules governs these statements?","options":["The Advertising Code","The parole evidence rule","The free look provision","The USA Patriot Act"],"answer":"The Advertising Code","topic":"Advertising Code","explanation":"Rules governing testimonials, statistics, and special offers in insurance marketing live in the Advertising Code."},{"module":"Day 1 Module 2","group":"d1m2-rrg","question":"A group of pharmacists forms its own entity to insure the malpractice liability of its members. This entity is:","options":["A risk retention group","A reinsurer","A multiple employer trust","A service provider"],"answer":"A risk retention group","topic":"Risk Retention Groups","explanation":"An RRG is formed by similar businesses or professionals (e.g., pharmacists) to insure their own liability risks as a group."},{"module":"Day 1 Module 2","group":"d1m2-rrg","question":"Which statement about a risk retention group (RRG) is TRUE?","options":["It is formed by similar businesses or professionals to insure their own liability risks","It may insure any member of the general public","It is a federal agency that insures high-risk drivers","It only sells life insurance"],"answer":"It is formed by similar businesses or professionals to insure their own liability risks","topic":"Risk Retention Groups","explanation":"An RRG is formed by similar businesses or professionals (e.g., pharmacists) to insure their own liability risks as a group."},{"module":"Day 1 Module 2","group":"d1m2-license","question":"An agent\'s license will terminate if the agent allows how many years to pass without an appointment?","options":["Four","Two","Five","Seven"],"answer":"Four","topic":"License Termination","explanation":"A license terminates after FOUR years without an appointment. Count from the last appointment\'s end."},{"module":"Day 1 Module 2","group":"d1m2-license","question":"Glen\'s last appointment ended in 2020 and he never obtained another. What happens to his license in 2024?","options":["It terminates, because four years passed without an appointment","Nothing — licenses never expire","It converts to a temporary license","It is automatically renewed for two more years"],"answer":"It terminates, because four years passed without an appointment","topic":"License Termination","explanation":"A license terminates after FOUR years without an appointment. Count from the last appointment\'s end."},{"module":"Day 1 Module 2","group":"d1m2-patriot","question":"The USA Patriot Act was created in response to:","options":["The September 11th attacks","The 2008 financial crisis","Hurricane Andrew","The savings and loan scandal"],"answer":"The September 11th attacks","topic":"USA Patriot Act","explanation":"Passed in response to the September 11th attacks; imposes anti-money-laundering obligations that reach insurers."},{"module":"Day 1 Module 2","group":"d1m2-patriot","question":"Which federal law, passed after the September 11th attacks, imposes anti-money-laundering obligations that affect insurers?","options":["The USA Patriot Act","The McCarran-Ferguson Act","HIPAA","The Affordable Care Act"],"answer":"The USA Patriot Act","topic":"USA Patriot Act","explanation":"Passed in response to the September 11th attacks; imposes anti-money-laundering obligations that reach insurers."},{"module":"Day 1 Module 2","group":"d1m2-utpa","question":"The ______ gives the state its authority to fine, issue cease and desist orders, and impose penalties.","options":["Unfair Trade Practices Act","Advertising Code","Buyer\'s Guide","McCarran-Ferguson Act"],"answer":"Unfair Trade Practices Act","topic":"Unfair Trade Practices Act","explanation":"The UTPA is the state\'s enforcement hammer — fines, cease-and-desist orders, penalties. Note: in Florida, rebating is legal under strict conditions (§626.572), so it is NOT an unfair trade practice there."},{"module":"Day 1 Module 2","group":"d1m2-utpa","question":"Which of the following would NOT be found under the Unfair Trade Practices Act?","options":["Rebating","False advertising","Coercion","Unfair discrimination"],"answer":"Rebating","topic":"Unfair Trade Practices Act","explanation":"The UTPA is the state\'s enforcement hammer — fines, cease-and-desist orders, penalties. Note: in Florida, rebating is legal under strict conditions (§626.572), so it is NOT an unfair trade practice there."},{"module":"Day 1 Module 2","group":"d1m2-lloyds","question":"Which organization is NOT itself an insurer, but a marketplace where member syndicates underwrite risks?","options":["Lloyd\'s of London","Blue Cross Blue Shield","A mutual insurance company","A stock insurance company"],"answer":"Lloyd\'s of London","topic":"Lloyd\'s of London","explanation":"Lloyd\'s is not an insurer or service provider — it\'s a marketplace where member syndicates underwrite risks."},{"module":"Day 1 Module 2","group":"d1m2-lloyds","question":"Which of the following is NOT a service provider?","options":["Lloyd\'s of London","An HMO","A PPO","Blue Cross Blue Shield"],"answer":"Lloyd\'s of London","topic":"Lloyd\'s of London","explanation":"Lloyd\'s is not an insurer or service provider — it\'s a marketplace where member syndicates underwrite risks."},{"module":"Day 1 Module 2","group":"d1m2-industrial","question":"Industrial (home service) life insurance is characterized by:","options":["Relatively small face amounts with premiums collected frequently by an agent","Large face amounts with annual premiums","Coverage available only to factory workers","Policies sold exclusively online"],"answer":"Relatively small face amounts with premiums collected frequently by an agent","topic":"Industrial Insurance","explanation":"Industrial (home service) insurance = small face amounts with premiums collected frequently (weekly/monthly), often at the insured\'s home."},{"module":"Day 1 Module 2","group":"d1m2-industrial","question":"Which is typical of industrial insurance?","options":["Small face amounts","Million-dollar minimum coverage","No premium payments","Group underwriting only"],"answer":"Small face amounts","topic":"Industrial Insurance","explanation":"Industrial (home service) insurance = small face amounts with premiums collected frequently (weekly/monthly), often at the insured\'s home."},{"module":"Day 1 Module 2","group":"d1m2-standards","question":"Which of the following is NOT a standard producers are expected to follow to protect consumers and promote suitable sales?","options":["Assessing the prospect\'s financial ability to pay commissions","Selling to the customer\'s needs","Determining the suitability of recommended products","Providing full and accurate disclosure"],"answer":"Assessing the prospect\'s financial ability to pay commissions","topic":"Suitability Standards","explanation":"Producers must sell to needs, verify suitability, and disclose fully. The client\'s ability to pay COMMISSIONS is never a standard — commissions come from the insurer."},{"module":"Day 1 Module 2","group":"d1m2-standards","question":"Before recommending a policy, a producer must primarily determine that:","options":["The product suits the client\'s needs and financial situation","The product pays the highest available commission","The client can be persuaded quickly","The insurer is headquartered in the client\'s state"],"answer":"The product suits the client\'s needs and financial situation","topic":"Suitability Standards","explanation":"Producers must sell to needs, verify suitability, and disclose fully. The client\'s ability to pay COMMISSIONS is never a standard — commissions come from the insurer."},{"module":"Day 1 Module 2","group":"d1m2-mccarran","question":"Which law laid the basis for the principle that state governments are the primary regulators of the insurance industry?","options":["The McCarran-Ferguson Act","The USA Patriot Act","The Affordable Care Act","The Sherman Antitrust Act"],"answer":"The McCarran-Ferguson Act","topic":"McCarran-Ferguson Act","explanation":"McCarran-Ferguson (1945) established that the states, not the federal government, are the primary regulators of insurance."},{"module":"Day 1 Module 2","group":"d1m2-mccarran","question":"The McCarran-Ferguson Act provides that:","options":["Insurance is regulated by the states rather than the federal government","All insurers must register with the SEC","The federal government sets minimum premium rates","Insurance advertising is exempt from regulation"],"answer":"Insurance is regulated by the states rather than the federal government","topic":"McCarran-Ferguson Act","explanation":"McCarran-Ferguson (1945) established that the states, not the federal government, are the primary regulators of insurance."},{"module":"Day 1 Module 2","group":"ins-reinsure","topic":"Reinsurance","explanation":"Reinsurance is company-to-company. The insurer transferring (giving away) the risk is the CEDING company; the company accepting it is the reinsurer.","question":"ABC Insurance transfers part of a risk it has written to XYZ Insurance. In this arrangement, ABC is the:","options":["Ceding company","Reinsurer","Fraternal insurer","Captive agent"],"answer":"Ceding company"},{"module":"Day 1 Module 2","group":"ins-fraternal","topic":"Fraternal Benefit Societies","explanation":"A fraternal benefit society must be a nonprofit with a lodge system featuring ritualistic work and a representative form of government (elected officers). Example: Knights of Columbus.","question":"To be characterized as a fraternal benefit society, an organization must have all of the following EXCEPT:","options":["Stockholders who receive dividends","Nonprofit status","A lodge system with ritualistic work","Elected officers (representative government)"],"answer":"Stockholders who receive dividends"},{"module":"Day 2 Module 1","group":"d2m1-adhesion","question":"Because the insurer drafts the policy and the applicant cannot negotiate its terms, courts construe any ambiguity against the insurer. This reflects which characteristic of insurance contracts?","options":["It is a contract of adhesion","It is an aleatory contract","It is a unilateral contract","It is a valued contract"],"answer":"It is a contract of adhesion","topic":"Contract of Adhesion","explanation":"The insurer writes the contract; the applicant takes it or leaves it. Because of this, courts construe ambiguities AGAINST the insurer."},{"module":"Day 2 Module 1","group":"d2m1-adhesion","question":"An insurance policy is often called a \\"take it or leave it\\" contract. The legal term for this is a contract of:","options":["Adhesion","Indemnity","Subrogation","Consideration"],"answer":"Adhesion","topic":"Contract of Adhesion","explanation":"The insurer writes the contract; the applicant takes it or leaves it. Because of this, courts construe ambiguities AGAINST the insurer."},{"module":"Day 2 Module 1","group":"d2m1-aleatory","question":"Dario has paid only $2,000 in premiums when his $300,000 life policy pays out. The fact that the values exchanged may be very unequal — and depend on an uncertain event — makes the contract:","options":["Aleatory","Unilateral","Conditional","Adhesive"],"answer":"Aleatory","topic":"Aleatory Contract","explanation":"Aleatory = the exchange of value is unequal and depends on an uncertain event. Small premiums can buy a large benefit — or no benefit at all."},{"module":"Day 2 Module 1","group":"d2m1-aleatory","question":"Which feature of an insurance contract means there is an element of chance for both parties, and the dollars given by each side may not be equal?","options":["Aleatory","Consideration","Warranty","Estoppel"],"answer":"Aleatory","topic":"Aleatory Contract","explanation":"Aleatory = the exchange of value is unequal and depends on an uncertain event. Small premiums can buy a large benefit — or no benefit at all."},{"module":"Day 2 Module 1","group":"d2m1-unilateral","question":"In an insurance contract, only the insurer makes a legally enforceable promise — the insured can stop paying at any time without being sued. This makes the contract:","options":["Unilateral","Bilateral","Aleatory","Voidable"],"answer":"Unilateral","topic":"Unilateral Contract","explanation":"Only the insurer makes an enforceable promise. The insured can stop paying without breach — only the insurer can be sued for non-performance."},{"module":"Day 2 Module 1","group":"d2m1-unilateral","question":"In which type of contract can only one party be held liable in court for failing to perform?","options":["Unilateral","Bilateral","Adhesion","Valued"],"answer":"Unilateral","topic":"Unilateral Contract","explanation":"Only the insurer makes an enforceable promise. The insured can stop paying without breach — only the insurer can be sued for non-performance."},{"module":"Day 2 Module 1","group":"d2m1-interest","question":"At what point must insurable interest exist in a life or health insurance contract?","options":["At the inception of the policy","At the time of the claim","Both at inception and at claim","At each premium due date"],"answer":"At the inception of the policy","topic":"Insurable Interest","explanation":"Insurable interest must exist at the policy\'s INCEPTION (not at claim time), and it means the owner would suffer a real financial loss from the insured\'s death or disability."},{"module":"Day 2 Module 1","group":"d2m1-interest","question":"Which statement accurately describes insurable interest?","options":["The policy owner must expect to suffer a loss if the insured dies or becomes disabled","The policy owner must expect to benefit from the insured\'s death","A beneficiary always has an insurable interest in the insured by definition","The insured must be related to the beneficiary by blood or marriage"],"answer":"The policy owner must expect to suffer a loss if the insured dies or becomes disabled","topic":"Insurable Interest","explanation":"Insurable interest must exist at the policy\'s INCEPTION (not at claim time), and it means the owner would suffer a real financial loss from the insured\'s death or disability."},{"module":"Day 2 Module 1","group":"d2m1-interest","question":"Tia wants to insure the life of her business partner, whose death would create a serious financial loss for her. Does Tia have an insurable interest?","options":["Yes — she would suffer a financial loss if the partner died","No — only family members can have insurable interest","Only if the partner names her as beneficiary","Only if the partnership is incorporated"],"answer":"Yes — she would suffer a financial loss if the partner died","topic":"Insurable Interest","explanation":"Insurable interest must exist at the policy\'s INCEPTION (not at claim time), and it means the owner would suffer a real financial loss from the insured\'s death or disability."},{"module":"Day 2 Module 1","group":"d2m1-parole","question":"An applicant claims her agent verbally promised benefits that don\'t appear in the written policy. Which rule prevents oral statements from changing the written contract?","options":["The parole evidence rule","The free look provision","The doctrine of estoppel","The right of subrogation"],"answer":"The parole evidence rule","topic":"Parole Evidence Rule","explanation":"A written contract cannot be changed by oral evidence. Verbal promises that aren\'t in the policy don\'t count."},{"module":"Day 2 Module 1","group":"d2m1-parole","question":"What does the parole evidence rule provide?","options":["A written contract cannot be changed or modified by oral evidence","Verbal agreements always override the written contract","Contracts may be amended by either party at any time","Insurance contracts must be read aloud at delivery"],"answer":"A written contract cannot be changed or modified by oral evidence","topic":"Parole Evidence Rule","explanation":"A written contract cannot be changed by oral evidence. Verbal promises that aren\'t in the policy don\'t count."},{"module":"Day 2 Module 1","group":"d2m1-competent","question":"What makes an insurer a competent party to a contract?","options":["It is licensed or authorized by the state","It is registered with the NAIC","It is listed on a stock exchange","It maintains an office in every state"],"answer":"It is licensed or authorized by the state","topic":"Competent Parties","explanation":"An insurer is competent when licensed/authorized by the state. A person is incompetent when intoxicated, severely impaired, or (generally) a minor."},{"module":"Day 2 Module 1","group":"d2m1-competent","question":"Which of the following persons would NOT be considered competent to enter into an insurance contract?","options":["A 30-year-old who is heavily intoxicated at the time of application","A sober 40-year-old accountant","A 52-year-old retiree of sound mind","A licensed insurance company with a certificate of authority"],"answer":"A 30-year-old who is heavily intoxicated at the time of application","topic":"Competent Parties","explanation":"An insurer is competent when licensed/authorized by the state. A person is incompetent when intoxicated, severely impaired, or (generally) a minor."},{"module":"Day 2 Module 1","group":"d2m1-signatures","question":"Olive applies for a life policy on her employee Frank and names Frank\'s husband as beneficiary. Whose signatures must appear on the application?","options":["Olive\'s and Frank\'s","Only Olive\'s","Only Frank\'s","Olive\'s, Frank\'s, and the beneficiary\'s"],"answer":"Olive\'s and Frank\'s","topic":"Application Signatures","explanation":"Third-party policies require BOTH the applicant/owner\'s and the insured\'s signatures. The beneficiary never needs to sign."},{"module":"Day 2 Module 1","group":"d2m1-signatures","question":"When a business owner takes out life insurance on a key employee, the application must be signed by:","options":["Both the owner (as applicant) and the insured employee","The owner alone","The employee alone","The beneficiary and the agent"],"answer":"Both the owner (as applicant) and the insured employee","topic":"Application Signatures","explanation":"Third-party policies require BOTH the applicant/owner\'s and the insured\'s signatures. The beneficiary never needs to sign."},{"module":"Day 2 Module 1","group":"d2m1-authority","question":"The authority an agent is never given in writing, but which common sense dictates the agent must have to carry out routine business, is called:","options":["Implied authority","Express authority","Apparent authority","Statutory authority"],"answer":"Implied authority","topic":"Agent Authority","explanation":"Express = written in the agency contract. Implied = not written but necessary for routine business. Apparent = created by appearances the public reasonably relies on (e.g., a terminated agent still using company materials)."},{"module":"Day 2 Module 1","group":"d2m1-authority","question":"Rita was terminated by her insurer on May 1 but kept soliciting applications with her old company materials, and the public reasonably believed she still represented the company. The authority created by these circumstances is:","options":["Apparent authority","Express authority","Implied authority","Residual authority"],"answer":"Apparent authority","topic":"Agent Authority","explanation":"Express = written in the agency contract. Implied = not written but necessary for routine business. Apparent = created by appearances the public reasonably relies on (e.g., a terminated agent still using company materials)."},{"module":"Day 2 Module 1","group":"d2m1-authority","question":"The authority specifically granted to an agent in writing in the agency agreement is:","options":["Express authority","Implied authority","Apparent authority","Assumed authority"],"answer":"Express authority","topic":"Agent Authority","explanation":"Express = written in the agency contract. Implied = not written but necessary for routine business. Apparent = created by appearances the public reasonably relies on (e.g., a terminated agent still using company materials)."},{"module":"Day 2 Module 1","group":"d2m1-subrogation","question":"After paying a claim, an insurer acquires the insured\'s right to sue the third party who caused the loss. This right is called:","options":["Subrogation","Assignment","Estoppel","Reinstatement"],"answer":"Subrogation","topic":"Subrogation","explanation":"After paying a claim, the insurer takes over the insured\'s right to recover from the third party who caused the loss. It exists in INDEMNITY contracts, not valued contracts."},{"module":"Day 2 Module 1","group":"d2m1-subrogation","question":"The right of subrogation is found in which type of contract?","options":["Indemnity contracts","Valued contracts","Unilateral contracts only","Participating contracts"],"answer":"Indemnity contracts","topic":"Subrogation","explanation":"After paying a claim, the insurer takes over the insured\'s right to recover from the third party who caused the loss. It exists in INDEMNITY contracts, not valued contracts."},{"module":"Day 2 Module 1","group":"d2m1-valued","question":"Which of the following policies is NOT a valued contract?","options":["A medical expense policy","A life insurance policy","An AD&D policy","A disability income policy"],"answer":"A medical expense policy","topic":"Valued vs. Reimbursement","explanation":"Valued contracts (life, AD&D, disability income) pay a stated amount. Medical expense policies reimburse actual loss — they are NOT valued contracts."},{"module":"Day 2 Module 1","group":"d2m1-valued","question":"A contract that pays a stated, predetermined amount when a defined event occurs — regardless of the actual financial loss — is a:","options":["Valued contract","Reimbursement contract","Contract of indemnity","Conditional receipt"],"answer":"Valued contract","topic":"Valued vs. Reimbursement","explanation":"Valued contracts (life, AD&D, disability income) pay a stated amount. Medical expense policies reimburse actual loss — they are NOT valued contracts."},{"module":"Day 2 Module 1","group":"d2m1-personal","question":"Which statement about a life insurance contract is TRUE?","options":["It is not a personal contract, so ownership can be transferred or given away","It is a personal contract that can never change hands","It can only be assigned to a blood relative","It terminates automatically if ownership changes"],"answer":"It is not a personal contract, so ownership can be transferred or given away","topic":"Not a Personal Contract","explanation":"Life insurance is NOT a personal contract — ownership can be transferred or assigned, even to someone without insurable interest."},{"module":"Day 2 Module 1","group":"d2m1-personal","question":"Unlike property insurance, a life insurance policy can be assigned to someone with no insurable interest in the insured. This is because life insurance is:","options":["Not a personal contract","A bilateral contract","A contract of indemnity","An oral contract"],"answer":"Not a personal contract","topic":"Not a Personal Contract","explanation":"Life insurance is NOT a personal contract — ownership can be transferred or assigned, even to someone without insurable interest."},{"module":"Day 2 Module 1","group":"d2m1-beneficiary","question":"Hugo named his sister Ana as primary beneficiary and Ana\'s daughter Sofia as secondary. Ana dies before Hugo, and Hugo never updates the policy. At Hugo\'s death, the proceeds go to:","options":["Sofia, as the contingent beneficiary","Ana\'s estate","Hugo\'s estate","The state unclaimed property fund"],"answer":"Sofia, as the contingent beneficiary","topic":"Beneficiary Succession","explanation":"If the primary beneficiary dies before the insured, proceeds go to the contingent (secondary) beneficiary — not the primary\'s estate or heirs."},{"module":"Day 2 Module 1","group":"d2m1-beneficiary","question":"If the primary beneficiary dies before the insured and no changes are made, the death benefit is paid to:","options":["The contingent (secondary) beneficiary","The insured\'s estate automatically","The primary beneficiary\'s heirs","The insurer\'s surplus fund"],"answer":"The contingent (secondary) beneficiary","topic":"Beneficiary Succession","explanation":"If the primary beneficiary dies before the insured, proceeds go to the contingent (secondary) beneficiary — not the primary\'s estate or heirs."},{"module":"Day 2 Module 1","group":"d2m1-stoli","question":"An investor persuades Catherine, 78, to take out a new life policy. The investor funds the premiums and is named beneficiary. This arrangement is:","options":["A STOLI (stranger-originated life insurance) arrangement","A legitimate key-person policy","A viatical settlement","An ordinary third-party ownership arrangement"],"answer":"A STOLI (stranger-originated life insurance) arrangement","topic":"STOLI","explanation":"Stranger-originated life insurance: investors induce a stranger (often elderly) to take out a policy they fund and benefit from. Fraudulent because the investors have NO insurable interest."},{"module":"Day 2 Module 1","group":"d2m1-stoli","question":"Why do many states treat STOLI arrangements as fraudulent?","options":["The investors have no insurable interest in the insured","The premiums are paid too quickly","The policies exceed state face-amount limits","The insured is always underage"],"answer":"The investors have no insurable interest in the insured","topic":"STOLI","explanation":"Stranger-originated life insurance: investors induce a stranger (often elderly) to take out a policy they fund and benefit from. Fraudulent because the investors have NO insurable interest."},{"module":"Day 2 Module 1","group":"law-eo","topic":"E&O Insurance","explanation":"Errors & omissions (professional liability) insurance defends against groundless, false, or fraudulent lawsuits — it protects the AGENT/producer, not the applicant or insurer.","question":"Errors and omissions (E&O) insurance provides a defense against groundless or fraudulent lawsuits brought against:","options":["The agent","The applicant","The insurance company","The insured"],"answer":"The agent"},{"module":"Day 2 Module 1","group":"law-authority","topic":"Agent Authority (Bank Trap)","explanation":"COURSE-KEY WARNING: standard texts define IMPLIED authority as \'not expressly granted but necessary to transact the principal\'s business\' — yet this course\'s bank marked \'implied\' WRONG on exactly this wording and apparently keys APPARENT. If you see this wording on a course quiz, answer apparent; on the state exam, the textbook answer for \'authority the agent must have to transact business though not expressly granted\' is IMPLIED. Flag the discrepancy to your instructor.","question":"[Course bank] What type of authority is not overtly extended but must be used to enable the agent to transact the business of the principal?","options":["Apparent (this bank\'s key — standard texts say implied!)","Express","Fiduciary","Assumed"],"answer":"Apparent (this bank\'s key — standard texts say implied!)"},{"module":"Day 2 Module 1","group":"law-competent","topic":"Competent Parties","explanation":"Competent parties: legally capable of contracting. An insurer with a Certificate of Authority is competent. Per this course\'s key, a person UNDER THE INFLUENCE is the incompetent party — an Alzheimer\'s diagnosis alone was NOT keyed as incompetence, and in Florida minors 15+ may contract for insurance.","question":"All of the following are considered competent parties EXCEPT:","options":["A 25-year-old under the influence of alcohol","An insurance company holding a certificate of authority from the state","A 17-year-old who just graduated from high school","A 52-year-old recently diagnosed with early Alzheimer\'s"],"answer":"A 25-year-old under the influence of alcohol"},{"module":"Day 2 Module 2","group":"d2m2-misrep-when","question":"During the selling process, serious problems of misrepresentation are MOST likely to occur at which stage?","options":["Presentation of recommendations","Prospecting","Fact-finding","Policy delivery"],"answer":"Presentation of recommendations","topic":"When Misrepresentation Happens","explanation":"Misrepresentation problems peak at the presentation of recommendations — when the producer is describing products and making claims about them."},{"module":"Day 2 Module 2","group":"d2m2-misrep-when","question":"At which point in the sales process must a producer be most careful that product claims are accurate?","options":["When presenting recommendations to the client","When scheduling the first appointment","When mailing a birthday card","When filing the application"],"answer":"When presenting recommendations to the client","topic":"When Misrepresentation Happens","explanation":"Misrepresentation problems peak at the presentation of recommendations — when the producer is describing products and making claims about them."},{"module":"Day 2 Module 2","group":"d2m2-misrep","question":"An agent tells a prospect that a variable universal life policy is \\"basically the same thing as a mutual fund.\\" This statement is:","options":["Misrepresentation","Twisting","Rebating","Churning"],"answer":"Misrepresentation","topic":"Misrepresentation","explanation":"Any false or misleading statement about a policy — calling VUL a mutual fund, calling dividends guaranteed — is misrepresentation."},{"module":"Day 2 Module 2","group":"d2m2-misrep","question":"Telling a client that policy dividends are guaranteed, when they are not, is an example of:","options":["Misrepresentation","Defamation","Coercion","Rebating"],"answer":"Misrepresentation","topic":"Misrepresentation","explanation":"Any false or misleading statement about a policy — calling VUL a mutual fund, calling dividends guaranteed — is misrepresentation."},{"module":"Day 2 Module 2","group":"d2m2-presentation","question":"Which of the following does NOT belong in a product presentation?","options":["Pressure","Accurate product information","Disclosure documents","Answers to the client\'s questions"],"answer":"Pressure","topic":"The Sales Presentation","explanation":"The presentation\'s goal is to EDUCATE so the client decides — pressure and \'selling\' don\'t belong. Educate, disclose, answer honestly."},{"module":"Day 2 Module 2","group":"d2m2-presentation","question":"What is the main goal of a sales presentation?","options":["To educate clients, empowering them to make their own decisions","To close the sale before the client can compare options","To collect the first premium as quickly as possible","To demonstrate the agent\'s product knowledge"],"answer":"To educate clients, empowering them to make their own decisions","topic":"The Sales Presentation","explanation":"The presentation\'s goal is to EDUCATE so the client decides — pressure and \'selling\' don\'t belong. Educate, disclose, answer honestly."},{"module":"Day 2 Module 2","group":"d2m2-presentation","question":"What should a producer NOT do during a presentation?","options":["Sell a policy","Educate the client","Disclose product limitations","Answer questions honestly"],"answer":"Sell a policy","topic":"The Sales Presentation","explanation":"The presentation\'s goal is to EDUCATE so the client decides — pressure and \'selling\' don\'t belong. Educate, disclose, answer honestly."},{"module":"Day 2 Module 2","group":"d2m2-homeoffice","question":"All of the following are part of the Home Office underwriting process EXCEPT:","options":["The applicant\'s analyst report","Review of the application","The MIB report","Medical examination results"],"answer":"The applicant\'s analyst report","topic":"Home Office Underwriting","explanation":"Underwriters use the application, agent\'s report, MIB report, medical exams, and physician statements. A stock \'analyst report\' is not part of underwriting."},{"module":"Day 2 Module 2","group":"d2m2-homeoffice","question":"Which of the following would a home office underwriter NOT rely on when evaluating an application?","options":["The applicant\'s stock analyst report","The agent\'s report","The completed application","An attending physician statement"],"answer":"The applicant\'s stock analyst report","topic":"Home Office Underwriting","explanation":"Underwriters use the application, agent\'s report, MIB report, medical exams, and physician statements. A stock \'analyst report\' is not part of underwriting."},{"module":"Day 2 Module 2","group":"d2m2-ethics","question":"Ethics is best defined as:","options":["Standards of conduct and moral judgment governing how we deal with others","The body of state insurance statutes","A company\'s internal pricing rules","Federal regulations on advertising"],"answer":"Standards of conduct and moral judgment governing how we deal with others","topic":"Ethics","explanation":"Ethics = standards of conduct and moral judgment governing how we deal with others — beyond what laws require."},{"module":"Day 2 Module 2","group":"d2m2-ethics","question":"Standards of conduct, moral judgment, and guidance on interacting with fellow members of a profession define:","options":["Ethics","Compliance","Solicitation","Underwriting"],"answer":"Ethics","topic":"Ethics","explanation":"Ethics = standards of conduct and moral judgment governing how we deal with others — beyond what laws require."},{"module":"Day 2 Module 2","group":"d2m2-naic","question":"What does NAIC stand for?","options":["National Association of Insurance Commissioners","National Alliance of Insurance Companies","North American Insurance Council","National Agency for Insurance Compliance"],"answer":"National Association of Insurance Commissioners","topic":"NAIC Purpose","explanation":"NAIC = National Association of Insurance Commissioners. Its objective is uniformity in state insurance regulation via model laws."},{"module":"Day 2 Module 2","group":"d2m2-naic","question":"An objective of the National Association of Insurance Commissioners is to:","options":["Encourage uniformity in state insurance regulation","License agents in all fifty states","Set federal premium taxes","Underwrite high-risk applicants"],"answer":"Encourage uniformity in state insurance regulation","topic":"NAIC Purpose","explanation":"NAIC = National Association of Insurance Commissioners. Its objective is uniformity in state insurance regulation via model laws."},{"module":"Day 2 Module 2","group":"d2m2-illustrations","question":"Which of the following is NOT a provision of the NAIC\'s Life Insurance Illustrations Model Regulation?","options":["The words \\"vanish\\" and \\"vanishing premium\\" may be used sparingly in illustrations","Illustrations must distinguish guaranteed from non-guaranteed values","Illustrations must be clearly labeled","Certain misleading terminology is prohibited"],"answer":"The words \\"vanish\\" and \\"vanishing premium\\" may be used sparingly in illustrations","topic":"Illustrations Regulation","explanation":"The NAIC model regulation prohibits misleading terms like \'vanish\' and \'vanishing premium\' entirely — not even \'sparingly\' — and requires guaranteed vs. non-guaranteed values to be distinguished."},{"module":"Day 2 Module 2","group":"d2m2-illustrations","question":"Under the NAIC model regulation on illustrations, which phrase is prohibited?","options":["\\"Vanishing premium\\"","\\"Guaranteed values\\"","\\"Cash surrender value\\"","\\"Death benefit\\""],"answer":"\\"Vanishing premium\\"","topic":"Illustrations Regulation","explanation":"The NAIC model regulation prohibits misleading terms like \'vanish\' and \'vanishing premium\' entirely — not even \'sparingly\' — and requires guaranteed vs. non-guaranteed values to be distinguished."},{"module":"Day 2 Module 2","group":"d2m2-preprinted","question":"Preprinted materials are recommended for sales presentations because:","options":["They have generally been reviewed for compliance","They let the agent avoid answering the client\'s questions","They are cheaper than custom materials","They guarantee the sale will close"],"answer":"They have generally been reviewed for compliance","topic":"Preprinted Materials","explanation":"Company preprinted materials are preferred because they\'ve been reviewed for regulatory compliance — homemade handouts haven\'t."},{"module":"Day 2 Module 2","group":"d2m2-preprinted","question":"Why should a producer favor company-approved preprinted materials over homemade handouts?","options":["Company materials have been vetted for regulatory compliance","Homemade materials are illegal in all states","Preprinted materials earn higher commissions","Clients are not permitted to keep custom documents"],"answer":"Company materials have been vetted for regulatory compliance","topic":"Preprinted Materials","explanation":"Company preprinted materials are preferred because they\'ve been reviewed for regulatory compliance — homemade handouts haven\'t."},{"module":"Day 2 Module 2","group":"d2m2-disclosure","question":"The purpose behind full disclosure requirements is to:","options":["Help the client make an informed decision","Protect the agent from competition","Shorten the sales process","Increase policy premiums"],"answer":"Help the client make an informed decision","topic":"Full Disclosure","explanation":"Disclosure documents exist for one reason: to help the client make an informed decision."},{"module":"Day 2 Module 2","group":"d2m2-disclosure","question":"Documents like the policy summary and Buyer\'s Guide are given to applicants so that they can:","options":["Make an informed purchase decision","Waive the free look period","Lock in a guaranteed dividend","Avoid the underwriting process"],"answer":"Make an informed purchase decision","topic":"Full Disclosure","explanation":"Disclosure documents exist for one reason: to help the client make an informed decision."},{"module":"Day 2 Module 2","group":"d2m2-rebating","question":"An agent gives his client four concert tickets as a thank-you for purchasing a policy. This is an example of:","options":["Rebating","Churning","Twisting","Defamation"],"answer":"Rebating","topic":"Rebating","explanation":"Giving the client anything of value (gifts, tickets, commission kickbacks) as an inducement to buy = rebating. In Florida it\'s legal ONLY under the strict conditions of §626.572."},{"module":"Day 2 Module 2","group":"d2m2-rebating","question":"Returning a portion of the commission to a client as an inducement to buy a policy is called:","options":["Rebating","Coercion","Misrepresentation","Concealment"],"answer":"Rebating","topic":"Rebating","explanation":"Giving the client anything of value (gifts, tickets, commission kickbacks) as an inducement to buy = rebating. In Florida it\'s legal ONLY under the strict conditions of §626.572."},{"module":"Day 2 Module 2","group":"d2m2-churning","question":"An agent convinces a client to surrender an existing policy and buy a replacement from the SAME insurer, mainly to generate a new commission. This practice is:","options":["Churning","Twisting","Rebating","Subrogation"],"answer":"Churning","topic":"Churning","explanation":"Churning = replacing a policy with another from the SAME insurer mainly to earn new commissions. (Twisting is the same scheme with a DIFFERENT insurer.)"},{"module":"Day 2 Module 2","group":"d2m2-churning","question":"Churning is best described as:","options":["Replacing a policy with another from the same insurer with the intent of earning additional commissions","Replacing a policy with one from a different insurer","Selling multiple policies to one household","Backdating an application to save age"],"answer":"Replacing a policy with another from the same insurer with the intent of earning additional commissions","topic":"Churning","explanation":"Churning = replacing a policy with another from the SAME insurer mainly to earn new commissions. (Twisting is the same scheme with a DIFFERENT insurer.)"},{"module":"Day 2 Module 2","group":"d2m2-solicitation","question":"Which of the following activities are included in the solicitation of insurance?","options":["Presenting proposals, describing benefits, and urging a prospect to apply","Only the signing of the final application","Only paid television advertising","Only activities performed inside the insurer\'s office"],"answer":"Presenting proposals, describing benefits, and urging a prospect to apply","topic":"Solicitation","explanation":"Solicitation includes presenting proposals, describing benefits, and urging prospects to apply — anything that attempts to induce the purchase of insurance."},{"module":"Day 2 Module 2","group":"d2m2-solicitation","question":"Inviting prospects at a seminar to apply for coverage is part of:","options":["Solicitation","Underwriting","Claims adjustment","Policy delivery"],"answer":"Solicitation","topic":"Solicitation","explanation":"Solicitation includes presenting proposals, describing benefits, and urging prospects to apply — anything that attempts to induce the purchase of insurance."},{"module":"Day 2 Module 2","group":"d2m2-freelook","question":"The period specified in the free look provision begins:","options":["When the policy is delivered","When the application is signed","When the policy is issued","When the first claim is filed"],"answer":"When the policy is delivered","topic":"Free Look","explanation":"The free look period starts at policy DELIVERY — not issue, not application."},{"module":"Day 2 Module 2","group":"d2m2-freelook","question":"Yara\'s policy was issued on June 1 and delivered to her on June 9. Her free look period runs from:","options":["June 9 — the date of delivery","June 1 — the date of issue","The date she signed the application","The first premium due date"],"answer":"June 9 — the date of delivery","topic":"Free Look","explanation":"The free look period starts at policy DELIVERY — not issue, not application."},{"module":"Day 2 Module 2","group":"d2m2-educate","question":"The producer should educate the applicant on all of the following EXCEPT:","options":["How the DFS works with the CFO","The need for accuracy and honesty on the application","The meanings of terms such as waiver of premium","Why the requested information is required"],"answer":"How the DFS works with the CFO","topic":"Educating the Applicant","explanation":"Producers should explain honesty requirements, policy terms, and why information is collected. Internal department mechanics (DFS/CFO) aren\'t part of it."},{"module":"Day 2 Module 2","group":"d2m2-educate","question":"Which of the following SHOULD a producer review with an applicant?","options":["The need for honesty, the meaning of policy terms, and why information is collected","The agent\'s commission percentage on the sale","Other clients\' claim histories","The underwriter\'s personal contact information"],"answer":"The need for honesty, the meaning of policy terms, and why information is collected","topic":"Educating the Applicant","explanation":"Producers should explain honesty requirements, policy terms, and why information is collected. Internal department mechanics (DFS/CFO) aren\'t part of it."},{"module":"Day 2 Module 2","group":"d2m2-uwexplain","question":"When briefly explaining the underwriting process to a client, which of the following is NOT part of underwriting?","options":["Salary requirements","Medical examinations","MIB reports","Review of the application"],"answer":"Salary requirements","topic":"Explaining Underwriting","explanation":"Underwriting draws on the application, medical exams, MIB, and physician statements. Salary requirements and commissions are not underwriting sources."},{"module":"Day 2 Module 2","group":"d2m2-uwexplain","question":"Which of the following is NOT a source of underwriting information?","options":["The agent\'s commission schedule","The application","The MIB report","An attending physician statement"],"answer":"The agent\'s commission schedule","topic":"Explaining Underwriting","explanation":"Underwriting draws on the application, medical exams, MIB, and physician statements. Salary requirements and commissions are not underwriting sources."},{"module":"Day 2 Module 2","group":"eth-insuring","topic":"The Insuring Clause","explanation":"The insuring clause sits at the front of the policy, signed by the company\'s president and secretary — it is the insurer\'s basic promise to pay benefits if a covered condition occurs.","question":"The insurer\'s promise to pay, found on the first page of the policy and signed by the company\'s officers, is the:","options":["Insuring clause","Consideration clause","Entire contract clause","Free-look provision"],"answer":"Insuring clause"},{"module":"Day 2 Module 2","group":"eth-uwfactors","topic":"Underwriting Factors","explanation":"Health underwriters consider physical condition, medical history, occupation, personal habits/moral hazards — and yes, even the CREDIT rating (credit reports are part of the checks and balances). MARITAL STATUS is not an underwriting risk factor.","question":"Which of the following would probably NOT be considered in underwriting a health insurance risk?","options":["The individual\'s marital status","The individual\'s personal habits","The individual\'s credit rating","The individual\'s medical history"],"answer":"The individual\'s marital status"},{"module":"Day 2 Module 2","group":"eth-uwfactors","topic":"Underwriting Factors","explanation":"Primary health underwriting risk factors: physical condition, occupation, and moral hazards/lifestyle. Interest rates are a PREMIUM calculation factor (the I in MIST), not an underwriting risk factor about the applicant.","question":"Which of the following is NOT one of the primary risk factors used in health insurance underwriting?","options":["Interest rates","Physical condition","Moral hazards","Occupation"],"answer":"Interest rates"},{"module":"Day 3 Module 1","group":"m1-types","question":"Hannah\'s agent walks her through the main categories of health insurance. Which of the following does NOT actually exist as a basic form of health coverage?","options":["Limited pay health","Medical expense insurance","Disability income insurance","Accidental death and dismemberment"],"answer":"Limited pay health","topic":"Basic Types of Health Coverage","explanation":"The three basic types (MAD): Medical expense, AD&D, and Disability income. \'Limited pay health\' is a made-up distractor."},{"module":"Day 3 Module 1","group":"m1-types","question":"The three basic types of health insurance coverage are:","options":["Medical expense, disability income, and accidental death and dismemberment","Medical expense, long-term care, and annuities","Disability income, workers\' compensation, and Medicare","Major medical, limited pay health, and AD&D"],"answer":"Medical expense, disability income, and accidental death and dismemberment","topic":"Basic Types of Health Coverage","explanation":"The three basic types (MAD): Medical expense, AD&D, and Disability income. \'Limited pay health\' is a made-up distractor."},{"module":"Day 3 Module 1","group":"m1-medex","question":"Medical expense insurance covers which of the following?","options":["Hospitalization, surgical, and physician services expenses","Lost income while the insured is disabled","A lump sum payable upon accidental death","Funeral and burial expenses"],"answer":"Hospitalization, surgical, and physician services expenses","topic":"Medical Expense Insurance","explanation":"Medical expense insurance pays actual healthcare costs — hospitalization, surgery, physician services, outpatient care — on a reimbursement basis."},{"module":"Day 3 Module 1","group":"m1-medex","question":"Theo needs ongoing physical therapy, regular lab work, and an occasional outpatient procedure. Which type of insurance pays these healthcare costs?","options":["Medical expense insurance","Disability income insurance","Accidental death and dismemberment insurance","Credit health insurance"],"answer":"Medical expense insurance","topic":"Medical Expense Insurance","explanation":"Medical expense insurance pays actual healthcare costs — hospitalization, surgery, physician services, outpatient care — on a reimbursement basis."},{"module":"Day 3 Module 1","group":"m1-di","question":"The primary purpose of disability income insurance is to:","options":["Replace income lost when the insured cannot work due to disability","Pay the medical expenses arising from a disability","Provide a lump sum benefit for accidental dismemberment","Reimburse hospital and surgical costs"],"answer":"Replace income lost when the insured cannot work due to disability","topic":"Disability Income Insurance","explanation":"DI replaces lost INCOME when the insured can\'t work. It never pays the medical bills caused by the disability — that\'s medical expense insurance\'s job."},{"module":"Day 3 Module 1","group":"m1-di","question":"Which statement about disability income insurance is TRUE?","options":["It excludes coverage for medical expenses arising from the disability","It reimburses the insured for hospital expenses during a disability","It pays benefits only for work-related disabilities","It pays a lump sum upon proof of permanent disability"],"answer":"It excludes coverage for medical expenses arising from the disability","topic":"Disability Income Insurance","explanation":"DI replaces lost INCOME when the insured can\'t work. It never pays the medical bills caused by the disability — that\'s medical expense insurance\'s job."},{"module":"Day 3 Module 1","group":"m1-di","question":"Carlos was injured and cannot work for eight months. Which coverage would replace his lost paycheck during this period?","options":["Disability income insurance","Medical expense insurance","AD&D insurance","Medicare supplement insurance"],"answer":"Disability income insurance","topic":"Disability Income Insurance","explanation":"DI replaces lost INCOME when the insured can\'t work. It never pays the medical bills caused by the disability — that\'s medical expense insurance\'s job."},{"module":"Day 3 Module 1","group":"m1-add","question":"Which statement about accidental death and dismemberment (AD&D) insurance is CORRECT?","options":["It pays a lump sum benefit if the insured dies or is dismembered in an accident","It reimburses medical expenses resulting from an accident","It replaces income lost due to an accidental injury","It pays benefits for death from sickness or accident alike"],"answer":"It pays a lump sum benefit if the insured dies or is dismembered in an accident","topic":"AD&D","explanation":"AD&D pays a lump sum for accidental death or dismemberment only — never sickness. It\'s the purest form of accident insurance."},{"module":"Day 3 Module 1","group":"m1-add","question":"AD&D insurance is considered:","options":["The purest form of accident insurance","A form of limited pay whole life insurance","A government-sponsored benefit program","A type of medical expense reimbursement plan"],"answer":"The purest form of accident insurance","topic":"AD&D","explanation":"AD&D pays a lump sum for accidental death or dismemberment only — never sickness. It\'s the purest form of accident insurance."},{"module":"Day 3 Module 1","group":"m1-purchase","question":"Group health insurance differs from individual health insurance in that group coverage is:","options":["Provided through a master contract issued to a specific group","Issued as a separate contract to each covered member","Available only through government programs","Always issued on a nonparticipating basis"],"answer":"Provided through a master contract issued to a specific group","topic":"How Coverage Is Purchased","explanation":"Individual = contract between insured and insurer. Group = one master contract covering a group. Government: Medicaid (state, for the needy), Medicare and OASDI (federal)."},{"module":"Day 3 Module 1","group":"m1-purchase","question":"Which government health program is run by the states to provide coverage for low-income people?","options":["Medicaid","Medicare","OASDI","TRICARE"],"answer":"Medicaid","topic":"How Coverage Is Purchased","explanation":"Individual = contract between insured and insurer. Group = one master contract covering a group. Government: Medicaid (state, for the needy), Medicare and OASDI (federal)."},{"module":"Day 3 Module 1","group":"m1-purchase","question":"Individual health insurance is issued as a contract between:","options":["The insured and a commercial insurer or service organization","The employer and the insurance company","The state government and the insured","The insured and the federal government"],"answer":"The insured and a commercial insurer or service organization","topic":"How Coverage Is Purchased","explanation":"Individual = contract between insured and insurer. Group = one master contract covering a group. Government: Medicaid (state, for the needy), Medicare and OASDI (federal)."},{"module":"Day 3 Module 1","group":"m1-renew","question":"Which renewability provision provides the insured with the greatest degree of security?","options":["Noncancellable","Cancellable","Optionally renewable","Conditionally renewable"],"answer":"Noncancellable","topic":"Renewability Provisions","explanation":"From least to most protective (and cheapest to priciest): Cancellable → Optionally renewable → Conditionally renewable → Guaranteed renewable (must renew, premiums can rise by class) → Noncancellable (must renew, premiums fixed)."},{"module":"Day 3 Module 1","group":"m1-renew","question":"Under a guaranteed renewable health policy, the insurer:","options":["Must renew the policy but may increase premiums for an entire class of insureds","May cancel the policy at any time with proper notice","Must renew the policy and may never increase the premium","May refuse to renew for any reason at the anniversary date"],"answer":"Must renew the policy but may increase premiums for an entire class of insureds","topic":"Renewability Provisions","explanation":"From least to most protective (and cheapest to priciest): Cancellable → Optionally renewable → Conditionally renewable → Guaranteed renewable (must renew, premiums can rise by class) → Noncancellable (must renew, premiums fixed)."},{"module":"Day 3 Module 1","group":"m1-renew","question":"Which renewability classification is generally the LEAST expensive?","options":["Cancellable","Noncancellable","Guaranteed renewable","Conditionally renewable"],"answer":"Cancellable","topic":"Renewability Provisions","explanation":"From least to most protective (and cheapest to priciest): Cancellable → Optionally renewable → Conditionally renewable → Guaranteed renewable (must renew, premiums can rise by class) → Noncancellable (must renew, premiums fixed)."},{"module":"Day 3 Module 1","group":"m1-mode","question":"Which premium payment mode results in the highest overall cost to the policyowner?","options":["Weekly","Annually","Semiannually","Quarterly"],"answer":"Weekly","topic":"Premium Modes","explanation":"Annual payment = lowest total cost. Each step more frequent adds expense; weekly is most expensive overall."},{"module":"Day 3 Module 1","group":"m1-mode","question":"Which premium payment mode results in the lowest overall cost to the policyowner?","options":["Annually","Monthly","Weekly","Quarterly"],"answer":"Annually","topic":"Premium Modes","explanation":"Annual payment = lowest total cost. Each step more frequent adds expense; weekly is most expensive overall."},{"module":"Day 3 Module 1","group":"m1-factors","question":"Life insurance premiums are built on mortality tables. What is the equivalent factor insurers use to price health insurance?","options":["Morbidity","Mortality","Liquidity","Volatility"],"answer":"Morbidity","topic":"Premium Factors (MIX-T)","explanation":"Premiums are built from Morbidity, Interest, eXpense, and Types of benefits. Morbidity (sickness rates) is health insurance\'s counterpart to life insurance\'s mortality."},{"module":"Day 3 Module 1","group":"m1-factors","question":"Which of the following lists the factors used to calculate health insurance premiums?","options":["Morbidity, interest, expense, and types of benefits","Mortality, dividends, claims, and reserves","Age, occupation, residence, and income","Interest, inflation, taxes, and commissions"],"answer":"Morbidity, interest, expense, and types of benefits","topic":"Premium Factors (MIX-T)","explanation":"Premiums are built from Morbidity, Interest, eXpense, and Types of benefits. Morbidity (sickness rates) is health insurance\'s counterpart to life insurance\'s mortality."},{"module":"Day 3 Module 1","group":"m1-factors","question":"Morbidity is best defined as:","options":["The rate of sickness or disease within a particular population","The rate of death within a particular population","The insurer\'s cost of doing business","The expected investment return on premiums"],"answer":"The rate of sickness or disease within a particular population","topic":"Premium Factors (MIX-T)","explanation":"Premiums are built from Morbidity, Interest, eXpense, and Types of benefits. Morbidity (sickness rates) is health insurance\'s counterpart to life insurance\'s mortality."},{"module":"Day 3 Module 1","group":"m1-par","question":"Which statement regarding participating and nonparticipating health insurance is CORRECT?","options":["Individual policies are typically nonparticipating, while group policies are typically participating","Individual policies are typically participating, while group policies are typically nonparticipating","All health insurance policies are participating","Participating policies never pay dividends"],"answer":"Individual policies are typically nonparticipating, while group policies are typically participating","topic":"Participating vs. Nonparticipating","explanation":"Individual health policies = nonparticipating. Group policies = participating — eligible for dividends (a refund of premium) or experience-rating refunds."},{"module":"Day 3 Module 1","group":"m1-par","question":"Policy dividends paid to policyholders of a mutual insurer are best described as:","options":["A refund of premium","Taxable investment income","A guaranteed contract benefit","A loan against the policy"],"answer":"A refund of premium","topic":"Participating vs. Nonparticipating","explanation":"Individual health policies = nonparticipating. Group policies = participating — eligible for dividends (a refund of premium) or experience-rating refunds."},{"module":"Day 3 Module 1","group":"m1-divfactors","question":"Which two major factors determine whether dividends or experience-rating refunds are payable?","options":["Expenses and claims costs","Age and gender of insureds","Interest rates and taxes","Policy size and premium mode"],"answer":"Expenses and claims costs","topic":"Dividend Determinants","explanation":"Two factors decide whether dividends/experience refunds are payable: the insurer\'s EXPENSES and the group\'s CLAIMS COSTS."},{"module":"Day 3 Module 1","group":"m1-divfactors","question":"A group health plan is most likely to receive an experience-rating refund or premium credit when:","options":["The group\'s claims costs are low","The group\'s members are mostly young males","Interest rates rise during the year","The employer pays premiums annually"],"answer":"The group\'s claims costs are low","topic":"Dividend Determinants","explanation":"Two factors decide whether dividends/experience refunds are payable: the insurer\'s EXPENSES and the group\'s CLAIMS COSTS."},{"module":"Day 3 Module 1","group":"m1-reserves","question":"On an insurance company\'s books, reserves are treated as:","options":["A liability","An asset","Surplus","Earned income"],"answer":"A liability","topic":"Reserves","explanation":"Reserves are a LIABILITY on the insurer\'s books. Premium reserves = losses not yet occurred but premium received. Loss reserves = losses occurred but not yet settled."},{"module":"Day 3 Module 1","group":"m1-reserves","question":"Premium reserves represent the insurer\'s obligation for:","options":["Potential losses that have not yet occurred but for which premiums have already been received","Losses that have occurred but have not yet been settled","Dividends owed to participating policyholders","Commissions owed to producers"],"answer":"Potential losses that have not yet occurred but for which premiums have already been received","topic":"Reserves","explanation":"Reserves are a LIABILITY on the insurer\'s books. Premium reserves = losses not yet occurred but premium received. Loss reserves = losses occurred but not yet settled."},{"module":"Day 3 Module 1","group":"m1-reserves","question":"Loss reserves represent the insurer\'s liability for:","options":["Losses that have occurred but for which settlement is not yet complete","Losses that have not yet occurred","Future premium refunds to policyowners","Anticipated underwriting expenses"],"answer":"Losses that have occurred but for which settlement is not yet complete","topic":"Reserves","explanation":"Reserves are a LIABILITY on the insurer\'s books. Premium reserves = losses not yet occurred but premium received. Loss reserves = losses occurred but not yet settled."},{"module":"Day 3 Module 1","group":"m1-contracts","question":"Imani\'s policy promises a flat $1,200 per month while she is totally disabled, regardless of what her actual expenses are. This makes her policy a ______ contract.","options":["Valued","Reimbursement","Participating","Conditional"],"answer":"Valued","topic":"Valued vs. Reimbursement","explanation":"A policy paying a stated amount (e.g., $X/month while disabled) is VALUED. Medical expense insurance pays actual loss — a contract of REIMBURSEMENT (indemnity)."},{"module":"Day 3 Module 1","group":"m1-contracts","question":"Medical expense insurance is best described as:","options":["A contract of reimbursement that pays based on the actual amount of loss","A valued contract that pays a predetermined amount","A participating contract that pays annual dividends","A service contract that pays providers in advance"],"answer":"A contract of reimbursement that pays based on the actual amount of loss","topic":"Valued vs. Reimbursement","explanation":"A policy paying a stated amount (e.g., $X/month while disabled) is VALUED. Medical expense insurance pays actual loss — a contract of REIMBURSEMENT (indemnity)."},{"module":"Day 3 Module 1","group":"m1-contracts","question":"Which of the following are considered valued contracts?","options":["Life insurance, AD&D, and disability income insurance","Medical expense and Medicare supplement insurance","Group health and individual health insurance","Long-term care and major medical insurance"],"answer":"Life insurance, AD&D, and disability income insurance","topic":"Valued vs. Reimbursement","explanation":"A policy paying a stated amount (e.g., $X/month while disabled) is VALUED. Medical expense insurance pays actual loss — a contract of REIMBURSEMENT (indemnity)."},{"module":"Day 3 Module 1","group":"m1-aca-subsidy","question":"Under the Affordable Care Act, premium subsidies are available to individuals and families whose income falls within:","options":["100% to 400% of the Federal Poverty Level","50% to 100% of the Federal Poverty Level","138% to 250% of the Federal Poverty Level","200% to 500% of the Federal Poverty Level"],"answer":"100% to 400% of the Federal Poverty Level","topic":"ACA Subsidies","explanation":"Subsidies: income between 100% and 400% of the Federal Poverty Level. Medicaid expansion: at or below 138% FPL."},{"module":"Day 3 Module 1","group":"m1-aca-subsidy","question":"The ACA expanded Medicaid eligibility to nearly all individuals whose income is at or below what percentage of the poverty level?","options":["138%","100%","250%","400%"],"answer":"138%","topic":"ACA Subsidies","explanation":"Subsidies: income between 100% and 400% of the Federal Poverty Level. Medicaid expansion: at or below 138% FPL."},{"module":"Day 3 Module 1","group":"m1-aca-reforms","question":"Under the Affordable Care Act, children must be allowed to remain on a parent\'s health plan until age:","options":["26","21","18","25"],"answer":"26","topic":"ACA Reforms","explanation":"No denial for preexisting conditions; children stay on a parent\'s plan to age 26; the $695 individual mandate tax was zeroed out by the Tax Cuts and Jobs Act starting 2018."},{"module":"Day 3 Module 1","group":"m1-aca-reforms","question":"Which statement regarding preexisting conditions under the ACA is TRUE?","options":["Insurers cannot deny coverage to anyone based on a preexisting condition","Insurers may deny coverage to adults but not children with preexisting conditions","Insurers may impose a permanent exclusion for preexisting conditions","Preexisting condition protections apply only to group plans"],"answer":"Insurers cannot deny coverage to anyone based on a preexisting condition","topic":"ACA Reforms","explanation":"No denial for preexisting conditions; children stay on a parent\'s plan to age 26; the $695 individual mandate tax was zeroed out by the Tax Cuts and Jobs Act starting 2018."},{"module":"Day 3 Module 1","group":"m1-aca-reforms","question":"The individual mandate tax penalty was reduced to zero beginning in 2018 by:","options":["The Tax Cuts and Jobs Act","The Affordable Care Act itself","HIPAA","The Social Security Act"],"answer":"The Tax Cuts and Jobs Act","topic":"ACA Reforms","explanation":"No denial for preexisting conditions; children stay on a parent\'s plan to age 26; the $695 individual mandate tax was zeroed out by the Tax Cuts and Jobs Act starting 2018."},{"module":"Day 3 Module 1","group":"m1-aca-employer","question":"The ACA employer mandate applies to employers with at least how many full-time employees?","options":["50","25","100","10"],"answer":"50","topic":"ACA Employer Mandate","explanation":"Employers with 50+ full-time employees must offer qualifying coverage to at least 95% of them and their dependents, or face $2,000/worker/year if any worker takes federal assistance."},{"module":"Day 3 Module 1","group":"m1-aca-employer","question":"An employer subject to the ACA mandate that fails to offer qualifying coverage may face an annual penalty of:","options":["$2,000 per worker if any worker receives federal assistance to buy insurance","$695 per worker regardless of circumstances","$10,000 flat fine per year","10% of total payroll"],"answer":"$2,000 per worker if any worker receives federal assistance to buy insurance","topic":"ACA Employer Mandate","explanation":"Employers with 50+ full-time employees must offer qualifying coverage to at least 95% of them and their dependents, or face $2,000/worker/year if any worker takes federal assistance."},{"module":"Day 3 Module 1","group":"m1-aca-employer","question":"Under the employer mandate, qualifying coverage must be offered to at least what percentage of full-time employees and their dependents?","options":["95%","100%","75%","50%"],"answer":"95%","topic":"ACA Employer Mandate","explanation":"Employers with 50+ full-time employees must offer qualifying coverage to at least 95% of them and their dependents, or face $2,000/worker/year if any worker takes federal assistance."},{"module":"Day 3 Module 1","group":"hi-premfactors","topic":"Premium Factors","explanation":"The three SECONDARY premium factors in health insurance: claims experience, age & sex of the insured, and benefit amounts. \'Salary benefits\' is not one of them. (Primary factors = morbidity, interest, expenses, type of benefits — MIST.)","question":"Which of the following is NOT one of the three secondary premium factors in health insurance?","options":["Salary benefits","Claims experience","Age and sex of the insured","Benefit amounts"],"answer":"Salary benefits"},{"module":"Day 3 Module 2","group":"m2-commercial","question":"After surgery, Russ submits his hospital bills and receives a check made out to him personally. Which type of organization handles claims this way?","options":["A commercial insurer","A health maintenance organization","A preferred provider organization","An administrative-services-only plan"],"answer":"A commercial insurer","topic":"Commercial Insurers","explanation":"Commercial insurers use the REIMBURSEMENT approach — the insured submits bills and is paid back directly. HMOs/PPOs provide services instead."},{"module":"Day 3 Module 2","group":"m2-commercial","question":"Commercial insurance companies market health insurance using which approach?","options":["The reimbursement approach, in which policyholders receive care and submit bills for reimbursement","The prepayment approach, in which providers are paid before care is given","The service approach, in which benefits are provided as services","The capitation approach, in which providers receive a flat monthly fee"],"answer":"The reimbursement approach, in which policyholders receive care and submit bills for reimbursement","topic":"Commercial Insurers","explanation":"Commercial insurers use the REIMBURSEMENT approach — the insured submits bills and is paid back directly. HMOs/PPOs provide services instead."},{"module":"Day 3 Module 2","group":"m2-assignment","question":"The right of assignment in a health insurance policy allows:","options":["The insurance company to pay the medical provider directly","The insured to transfer ownership of the policy to a relative","The insurer to cancel the policy upon nonpayment","The provider to bill the patient for any unpaid balance"],"answer":"The insurance company to pay the medical provider directly","topic":"Right of Assignment","explanation":"Assignment lets the insurer pay the medical provider directly so the insured doesn\'t pay up front. It changes who gets the check, not the contract\'s nature."},{"module":"Day 3 Module 2","group":"m2-assignment","question":"The main advantage of the right of assignment is that it:","options":["Reduces the policyholder\'s need to pay the medical provider up front","Lowers the policy\'s premium","Converts the policy into a valued contract","Guarantees renewal of the policy"],"answer":"Reduces the policyholder\'s need to pay the medical provider up front","topic":"Right of Assignment","explanation":"Assignment lets the insurer pay the medical provider directly so the insured doesn\'t pay up front. It changes who gets the check, not the contract\'s nature."},{"module":"Day 3 Module 2","group":"m2-service","question":"When Blue Cross Blue Shield sells an HMO plan, it is acting as a:","options":["Service provider","Commercial insurer","Third-party administrator","Reinsurer"],"answer":"Service provider","topic":"Service Providers","explanation":"Service providers (like BCBS) sell benefits as SERVICES, not reimbursement. BCBS selling an HMO plan is acting as a service provider, not an insurer."},{"module":"Day 3 Module 2","group":"m2-service","question":"Service providers such as Blue Cross Blue Shield offer most benefits on what basis?","options":["A service basis rather than a reimbursement basis","A reimbursement basis rather than a service basis","A valued contract basis","A fee-for-service indemnity basis"],"answer":"A service basis rather than a reimbursement basis","topic":"Service Providers","explanation":"Service providers (like BCBS) sell benefits as SERVICES, not reimbursement. BCBS selling an HMO plan is acting as a service provider, not an insurer."},{"module":"Day 3 Module 2","group":"m2-hmo","question":"A managed care plan promotes free annual checkups, screenings, and wellness visits, aiming to catch illness early and reduce hospital admissions. This emphasis is the hallmark of:","options":["An HMO","A commercial indemnity plan","A multiple employer trust","A Medicare supplement policy"],"answer":"An HMO","topic":"HMO","explanation":"HMO = prepaid care, preventive-care emphasis, gatekeeper referrals required for specialists, no out-of-network coverage except emergencies."},{"module":"Day 3 Module 2","group":"m2-hmo","question":"Which of the following is TRUE of a health maintenance organization (HMO)?","options":["A referral from a primary care physician is needed to see a specialist","Members may see any specialist without a referral","Out-of-network care is fully covered at all times","Physicians are paid fee-for-service after each visit"],"answer":"A referral from a primary care physician is needed to see a specialist","topic":"HMO","explanation":"HMO = prepaid care, preventive-care emphasis, gatekeeper referrals required for specialists, no out-of-network coverage except emergencies."},{"module":"Day 3 Module 2","group":"m2-hmo","question":"Under an HMO plan, care received outside the network is:","options":["Not covered except in emergencies","Covered subject to a deductible and coinsurance","Covered in full after a referral","Covered at 50% of the usual charge"],"answer":"Not covered except in emergencies","topic":"HMO","explanation":"HMO = prepaid care, preventive-care emphasis, gatekeeper referrals required for specialists, no out-of-network coverage except emergencies."},{"module":"Day 3 Module 2","group":"m2-ppo","question":"Which of the following is a characteristic of a preferred provider organization (PPO)?","options":["Physicians are paid on a fee-for-service basis after the visit","Physicians are prepaid before services are rendered","A referral is required to see a specialist","Out-of-network care is never covered"],"answer":"Physicians are paid on a fee-for-service basis after the visit","topic":"PPO","explanation":"PPO = fee-for-service after the visit, no referral needed, out-of-network IS covered but acts like major medical (deductible + coinsurance)."},{"module":"Day 3 Module 2","group":"m2-ppo","question":"Under a PPO, treatment received out-of-network is:","options":["Covered, functioning like major medical with a deductible and coinsurance","Not covered under any circumstances","Covered only with a gatekeeper referral","Covered in full with no cost sharing"],"answer":"Covered, functioning like major medical with a deductible and coinsurance","topic":"PPO","explanation":"PPO = fee-for-service after the visit, no referral needed, out-of-network IS covered but acts like major medical (deductible + coinsurance)."},{"module":"Day 3 Module 2","group":"m2-ppo","question":"Which type of plan allows a member to see a specialist WITHOUT a referral?","options":["PPO","HMO","Medicaid managed care","A debit company plan"],"answer":"PPO","topic":"PPO","explanation":"PPO = fee-for-service after the visit, no referral needed, out-of-network IS covered but acts like major medical (deductible + coinsurance)."},{"module":"Day 3 Module 2","group":"m2-pos","question":"A point-of-service (POS) plan is best described as:","options":["A hybrid that works like an HMO in-network and like a PPO out-of-network","A government program for retired workers","A self-insured arrangement administered by a TPA","A prepaid plan with no out-of-network benefits"],"answer":"A hybrid that works like an HMO in-network and like a PPO out-of-network","topic":"POS Plans","explanation":"POS = hybrid. In-network it behaves like an HMO (highest benefits); out-of-network it behaves like a PPO (claim forms, more cost-sharing)."},{"module":"Day 3 Module 2","group":"m2-pos","question":"Under a POS plan, a member who receives care out-of-network:","options":["Must submit claim forms and receives PPO-like benefits","Receives no benefits whatsoever","Receives the plan\'s highest level of benefits","Pays nothing as long as the provider is licensed"],"answer":"Must submit claim forms and receives PPO-like benefits","topic":"POS Plans","explanation":"POS = hybrid. In-network it behaves like an HMO (highest benefits); out-of-network it behaves like a PPO (claim forms, more cost-sharing)."},{"module":"Day 3 Module 2","group":"m2-medicare","question":"Medicare provides coverage for which of the following groups?","options":["People 65 or older, Social Security disability income recipients, and people with chronic kidney disease","Only people 65 or older","Low-income individuals of any age","All workers injured on the job"],"answer":"People 65 or older, Social Security disability income recipients, and people with chronic kidney disease","topic":"Medicare Eligibility","explanation":"Medicare (federal): 65+, Social Security disability income recipients, and chronic kidney disease."},{"module":"Day 3 Module 2","group":"m2-medicare","question":"Medicare is administered by:","options":["The federal government","Each individual state","Private service organizations only","County health departments"],"answer":"The federal government","topic":"Medicare Eligibility","explanation":"Medicare (federal): 65+, Social Security disability income recipients, and chronic kidney disease."},{"module":"Day 3 Module 2","group":"m2-ssdi","question":"Priya became disabled in April. When will she receive her first Social Security disability benefit payment?","options":["November","September","October","December"],"answer":"November","topic":"Social Security Disability","explanation":"Must be unable to perform ANY substantial gainful work, impairment lasting 12+ months or fatal. Five-month waiting period — benefits accrue from month 6, with the first check arriving the month after. Disabled in July → first payment in February."},{"module":"Day 3 Module 2","group":"m2-ssdi","question":"Mark became disabled in March. When will he receive his first Social Security disability benefit payment?","options":["October","August","September","December"],"answer":"October","topic":"Social Security Disability","explanation":"Must be unable to perform ANY substantial gainful work, impairment lasting 12+ months or fatal. Five-month waiting period — benefits accrue from month 6, with the first check arriving the month after. Disabled in July → first payment in February."},{"module":"Day 3 Module 2","group":"m2-ssdi","question":"To qualify for Social Security disability income benefits, a person must be:","options":["Incapable of performing any substantial gainful work, with an impairment expected to last at least 12 months or result in death","Unable to perform the duties of his or her own occupation for 6 months","Over age 60 with any medically documented condition","Unemployed for at least 12 consecutive months"],"answer":"Incapable of performing any substantial gainful work, with an impairment expected to last at least 12 months or result in death","topic":"Social Security Disability","explanation":"Must be unable to perform ANY substantial gainful work, impairment lasting 12+ months or fatal. Five-month waiting period — benefits accrue from month 6, with the first check arriving the month after. Disabled in July → first payment in February."},{"module":"Day 3 Module 2","group":"m2-medicaid","question":"Darnell, 70, is wealthy but worried about future medical bills. He assumes Medicaid will cover him because of his age. Why is he mistaken?","options":["Medicaid eligibility is based on financial need, not age","Medicaid only covers people under 65","Medicaid requires 10 years of work history","Medicaid covers only children and pregnant women"],"answer":"Medicaid eligibility is based on financial need, not age","topic":"Medicaid","explanation":"Medicaid = need-based aid administered by the STATES with federal funding. No age requirement — and being blind or disabled without being poor doesn\'t qualify."},{"module":"Day 3 Module 2","group":"m2-medicaid","question":"Medicaid is administered by:","options":["The states, with federal funding","The federal government alone","Private insurers under contract","Local hospital districts"],"answer":"The states, with federal funding","topic":"Medicaid","explanation":"Medicaid = need-based aid administered by the STATES with federal funding. No age requirement — and being blind or disabled without being poor doesn\'t qualify."},{"module":"Day 3 Module 2","group":"m2-medicaid","question":"Medicaid eligibility is based primarily on:","options":["Financial need","Age 65 or older","Employment history","Prior insurance coverage"],"answer":"Financial need","topic":"Medicaid","explanation":"Medicaid = need-based aid administered by the STATES with federal funding. No age requirement — and being blind or disabled without being poor doesn\'t qualify."},{"module":"Day 3 Module 2","group":"m2-workers","question":"Which statement about workers\' compensation is TRUE?","options":["An injured worker is entitled to benefits without filing a lawsuit","Workers must sue their employer to receive benefits","Coverage is optional for most employers","It covers injuries whether or not they are work-related"],"answer":"An injured worker is entitled to benefits without filing a lawsuit","topic":"Workers\' Compensation","explanation":"Compulsory, state-mandated benefits for work-related injury/illness/death — no lawsuit required. Employers can insure, self-insure, or buy a state plan."},{"module":"Day 3 Module 2","group":"m2-workers","question":"Employers may meet their workers\' compensation obligations by:","options":["Purchasing an insurance policy, self-insuring, or purchasing a plan from the state","Only purchasing coverage from a federal program","Deducting claim costs from employee wages","Enrolling workers in an individual health plan"],"answer":"Purchasing an insurance policy, self-insuring, or purchasing a plan from the state","topic":"Workers\' Compensation","explanation":"Compulsory, state-mandated benefits for work-related injury/illness/death — no lawsuit required. Employers can insure, self-insure, or buy a state plan."},{"module":"Day 3 Module 2","group":"m2-self","question":"In a self-insured group plan that uses a third-party administrator (TPA), who retains the risk?","options":["The self-insured employer","The third-party administrator","The state insurance department","The employees"],"answer":"The self-insured employer","topic":"Self-Insurance / TPA / ASO","explanation":"A self-insured employer RETAINS all risk. TPAs and ASO arrangements only administer (claims paperwork) — they take no risk and use no actuaries."},{"module":"Day 3 Module 2","group":"m2-self","question":"An administrative-services-only (ASO) arrangement is one in which:","options":["An insurer provides administrative services, such as claims processing, to a self-insured employer","An insurer assumes full risk for an employer\'s health claims","Employees administer their own claims","The state processes claims for small employers"],"answer":"An insurer provides administrative services, such as claims processing, to a self-insured employer","topic":"Self-Insurance / TPA / ASO","explanation":"A self-insured employer RETAINS all risk. TPAs and ASO arrangements only administer (claims paperwork) — they take no risk and use no actuaries."},{"module":"Day 3 Module 2","group":"m2-self","question":"A company chooses not to buy insurance and instead sets aside its own funds to pay employee health claims directly. This company is:","options":["Self-insured","Fully insured","A service provider","A multiple employer trust"],"answer":"Self-insured","topic":"Self-Insurance / TPA / ASO","explanation":"A self-insured employer RETAINS all risk. TPAs and ASO arrangements only administer (claims paperwork) — they take no risk and use no actuaries."},{"module":"Day 3 Module 2","group":"m2-mpp","question":"A minimum premium plan (MPP) is used by self-insured businesses to:","options":["Protect against significant, unanticipated losses","Eliminate the need for a third-party administrator","Reduce employees\' share of the premium","Satisfy the ACA\'s individual mandate"],"answer":"Protect against significant, unanticipated losses","topic":"Minimum Premium Plans","explanation":"An MPP backstops a self-insured plan against large, unanticipated losses — catastrophe protection for the employer\'s own fund."},{"module":"Day 3 Module 2","group":"m2-mpp","question":"A self-insured employer wanting protection against catastrophic, unexpected claim levels would add:","options":["A minimum premium plan (MPP)","A direct primary care agreement","An optionally renewable rider","A participating dividend option"],"answer":"A minimum premium plan (MPP)","topic":"Minimum Premium Plans","explanation":"An MPP backstops a self-insured plan against large, unanticipated losses — catastrophe protection for the employer\'s own fund."},{"module":"Day 3 Module 2","group":"m2-dpc","question":"Which statement about a direct primary care agreement is TRUE?","options":["It is not insurance and does not satisfy the ACA\'s minimum coverage requirement","It qualifies as minimum essential coverage under the ACA","It indemnifies the patient for services rendered by third parties","It may be oral as long as both parties agree"],"answer":"It is not insurance and does not satisfy the ACA\'s minimum coverage requirement","topic":"Direct Primary Care","explanation":"A written agreement (signed by both physician and patient/representative) for direct payment. It is NOT insurance and does NOT satisfy ACA minimum essential coverage."},{"module":"Day 3 Module 2","group":"m2-dpc","question":"For a direct primary care agreement to be valid, it must be:","options":["In writing and signed by both the physician and the patient (or the patient\'s representative or employer)","Filed with the state insurance department","Underwritten by a licensed insurer","Approved by Medicare"],"answer":"In writing and signed by both the physician and the patient (or the patient\'s representative or employer)","topic":"Direct Primary Care","explanation":"A written agreement (signed by both physician and patient/representative) for direct payment. It is NOT insurance and does NOT satisfy ACA minimum essential coverage."},{"module":"Day 3 Module 2","group":"m2-met-mewa","question":"A multiple employer trust (MET) is best described as:","options":["Multiple employers pooling their employees through a trust that holds the master contract to obtain lower-cost coverage","A single large employer dividing employees into multiple plans","A federal program insuring small business employees","A reinsurance pool for commercial insurers"],"answer":"Multiple employers pooling their employees through a trust that holds the master contract to obtain lower-cost coverage","topic":"METs and MEWAs","explanation":"MET = employers pool employees through a trust holding the master contract. MEWA = a MET for same-industry employers with a common bond; tax-exempt. Both are state-regulated."},{"module":"Day 3 Module 2","group":"m2-met-mewa","question":"Which of the following is a requirement of a multiple employer welfare arrangement (MEWA)?","options":["Employees must share an employment-related common bond, such as being in the same industry","All member employers must have at least 500 employees","It must be administered by the federal government","Members must purchase coverage from a single commercial insurer"],"answer":"Employees must share an employment-related common bond, such as being in the same industry","topic":"METs and MEWAs","explanation":"MET = employers pool employees through a trust holding the master contract. MEWA = a MET for same-industry employers with a common bond; tax-exempt. Both are state-regulated."},{"module":"Day 3 Module 2","group":"m2-met-mewa","question":"METs and MEWAs are regulated by:","options":["The state, because they behave like insurance products","The federal government exclusively","The Securities and Exchange Commission","No regulatory body"],"answer":"The state, because they behave like insurance products","topic":"METs and MEWAs","explanation":"MET = employers pool employees through a trust holding the master contract. MEWA = a MET for same-industry employers with a common bond; tax-exempt. Both are state-regulated."},{"module":"Day 4 Module 1","group":"mp-basicmajor","topic":"Basic vs. Major Medical","explanation":"Basic plans give first-dollar coverage with low limits; major medical gives broad, high-limit coverage with deductibles and coinsurance.","question":"A plan that pays from the first dollar but only up to low stated limits per service is a:","options":["Basic medical expense plan","Major medical plan","Comprehensive major medical plan","High-deductible health plan"],"answer":"Basic medical expense plan"},{"module":"Day 4 Module 1","group":"mp-basicmajor","topic":"Basic vs. Major Medical","explanation":"Basic plans give first-dollar coverage with low limits; major medical gives broad, high-limit coverage with deductibles and coinsurance.","question":"Which features distinguish major medical insurance from basic plans?","options":["High maximum limits with deductibles and coinsurance","First-dollar coverage with low limits","Coverage limited to surgical schedules","No cost-sharing of any kind"],"answer":"High maximum limits with deductibles and coinsurance"},{"module":"Day 4 Module 1","group":"mp-costshare","topic":"Deductibles, Coinsurance & Stop-Loss","explanation":"Cost-sharing order: deductible first, then coinsurance (e.g., 80/20), until the stop-loss limit caps the insured\'s out-of-pocket — after which the plan pays 100%.","question":"After Roy meets his deductible, his plan pays 80% of covered charges until his out-of-pocket reaches $6,000, after which it pays 100%. The $6,000 figure is the:","options":["Stop-loss limit","Coinsurance percentage","Carryover deductible","UCR limit"],"answer":"Stop-loss limit"},{"module":"Day 4 Module 1","group":"mp-costshare","topic":"Deductibles, Coinsurance & Stop-Loss","explanation":"Cost-sharing order: deductible first, then coinsurance (e.g., 80/20), until the stop-loss limit caps the insured\'s out-of-pocket — after which the plan pays 100%.","question":"Three members of the Diaz family are injured in the same car crash. Their plan applies only one deductible for all three claims. This reflects a:","options":["Common accident provision","Carryover provision","Family stop-loss provision","Coordination of benefits provision"],"answer":"Common accident provision"},{"module":"Day 4 Module 1","group":"mp-carryover","topic":"Carryover Deductible","explanation":"A carryover provision lets expenses incurred in the last three months of the year count toward NEXT year\'s deductible.","question":"Expenses Quinn incurred in November and December that didn\'t satisfy this year\'s deductible may count toward next year\'s deductible under a:","options":["Carryover provision","Common accident provision","Stop-loss provision","Probationary provision"],"answer":"Carryover provision"},{"module":"Day 4 Module 1","group":"mp-carryover","topic":"Carryover Deductible","explanation":"A carryover provision lets expenses incurred in the last three months of the year count toward NEXT year\'s deductible.","question":"The carryover deductible provision applies to expenses incurred during:","options":["The last three months of the calendar year","The first 31 days of coverage","Any month premiums were waived","The elimination period"],"answer":"The last three months of the calendar year"},{"module":"Day 4 Module 1","group":"mp-hsa","topic":"HSA Eligibility","explanation":"HSAs require a high-deductible health plan (HDHP), no other first-dollar coverage, no Medicare enrollment, and not being claimed as a dependent. Contributions, growth, and qualified withdrawals are all tax-advantaged, and funds roll over.","question":"To be eligible to contribute to a Health Savings Account, a person must:","options":["Be covered by a high-deductible health plan","Be enrolled in Medicare Part A","Have a flexible spending account","Earn less than 400% of the poverty level"],"answer":"Be covered by a high-deductible health plan"},{"module":"Day 4 Module 1","group":"mp-hsa","topic":"HSA Eligibility","explanation":"HSAs require a high-deductible health plan (HDHP), no other first-dollar coverage, no Medicare enrollment, and not being claimed as a dependent. Contributions, growth, and qualified withdrawals are all tax-advantaged, and funds roll over.","question":"Which statement about Health Savings Accounts is TRUE?","options":["Unused funds roll over from year to year and belong to the account holder","Unused funds are forfeited each December 31","Only employers may contribute","Withdrawals for medical care are taxed as income"],"answer":"Unused funds roll over from year to year and belong to the account holder"},{"module":"Day 4 Module 1","group":"mp-fsa-hra","topic":"FSA vs. HRA","explanation":"FSA = employee-funded pre-tax, use-it-or-lose-it. HRA = employer-funded only, reimburses medical expenses, rollover at employer\'s discretion.","question":"Which account is funded ONLY by the employer?","options":["Health Reimbursement Arrangement (HRA)","Health Savings Account (HSA)","Flexible Spending Account (FSA)","Individual retirement account"],"answer":"Health Reimbursement Arrangement (HRA)"},{"module":"Day 4 Module 1","group":"mp-fsa-hra","topic":"FSA vs. HRA","explanation":"FSA = employee-funded pre-tax, use-it-or-lose-it. HRA = employer-funded only, reimburses medical expenses, rollover at employer\'s discretion.","question":"The \'use it or lose it\' rule is most associated with:","options":["Flexible Spending Accounts","Health Savings Accounts","Health Reimbursement Arrangements","High-deductible health plans"],"answer":"Flexible Spending Accounts"},{"module":"Day 4 Module 1","group":"mp-ucr","topic":"Usual, Customary & Reasonable","explanation":"UCR-based plans pay what providers in the geographic area typically charge; amounts billed above UCR are the insured\'s responsibility.","question":"Dr. Patel bills $500 for a procedure, but the plan\'s usual, customary and reasonable amount is $400. The insured is responsible for:","options":["The $100 above the UCR amount, plus any normal cost-sharing","Nothing — UCR protects the insured fully","The entire $500","Only the copayment"],"answer":"The $100 above the UCR amount, plus any normal cost-sharing"},{"module":"Day 4 Module 1","group":"mp-ucr","topic":"Usual, Customary & Reasonable","explanation":"UCR-based plans pay what providers in the geographic area typically charge; amounts billed above UCR are the insured\'s responsibility.","question":"\'Usual, customary and reasonable\' charges are based on:","options":["What providers in the same geographic area typically charge for the service","The insurer\'s home-office fee schedule","Medicare\'s national rates","The provider\'s costs plus 20%"],"answer":"What providers in the same geographic area typically charge for the service"},{"module":"Day 4 Module 1","group":"mp-dental","topic":"Dental Plan Tiers","explanation":"Dental coverage tiers: preventive/diagnostic ~100%, basic (fillings) ~80%, major (crowns, dentures) ~50% — often with waiting periods and annual maximums.","question":"Which dental services are typically covered at the HIGHEST percentage?","options":["Preventive and diagnostic services like cleanings and exams","Crowns and bridges","Dentures","Orthodontics"],"answer":"Preventive and diagnostic services like cleanings and exams"},{"module":"Day 4 Module 1","group":"mp-dental","topic":"Dental Plan Tiers","explanation":"Dental coverage tiers: preventive/diagnostic ~100%, basic (fillings) ~80%, major (crowns, dentures) ~50% — often with waiting periods and annual maximums.","question":"Compared with medical insurance, dental plans commonly include:","options":["Calendar-year maximums and waiting periods for major services","Unlimited lifetime benefits","No cost-sharing","Coverage only after hospitalization"],"answer":"Calendar-year maximums and waiting periods for major services"},{"module":"Day 4 Module 1","group":"mp-firstdollar","topic":"First Dollar Insurance","explanation":"Basic medical expense plans pay from the first dollar — no deductible. They control costs through benefit LIMITS instead, which is also why their premiums are least affected by rising medical costs... that distinction belongs to hospital indemnity. First dollar = basic plans.","question":"Which type of policy pays benefits up front, without a deductible, and is known as \'first dollar\' insurance?","options":["A basic medical expense policy","A major medical policy","A disability income policy","A business overhead expense policy"],"answer":"A basic medical expense policy"},{"module":"Day 4 Module 1","group":"mp-firstdollar","topic":"First Dollar Insurance","explanation":"Basic medical expense plans pay from the first dollar — no deductible. They control costs through benefit LIMITS instead.","question":"Basic medical plans avoid small claims and keep premiums down by:","options":["Imposing benefit limits","Using deductibles and coinsurance","Paying only catastrophic expenses","Restricting members to network physicians"],"answer":"Imposing benefit limits"},{"module":"Day 4 Module 1","group":"mp-misc","topic":"Miscellaneous Expense Benefit","explanation":"The basic hospital miscellaneous benefit covers hospital \'extras\': drugs, X-rays, anesthesia, lab fees, dressings, operating room, supplies. It does NOT cover room and board or physicians\' bedside visits, and its limit is often a multiple of the daily room-and-board benefit.","question":"The miscellaneous expense benefit in a basic hospital expense policy normally covers:","options":["Drugs and medicine administered in the hospital","Physicians\' bedside visits","Hospital room and board","The surgeon\'s professional fee"],"answer":"Drugs and medicine administered in the hospital"},{"module":"Day 4 Module 1","group":"mp-misc","topic":"Miscellaneous Expense Benefit","explanation":"The basic hospital miscellaneous benefit covers hospital \'extras\': drugs, X-rays, anesthesia, lab fees, dressings, operating room, supplies. It does NOT cover room and board or physicians\' bedside visits, and its limit is often a multiple of the daily room-and-board benefit.","question":"In a basic hospital expense policy, the limit for miscellaneous expenses is typically expressed as a multiple of the:","options":["Daily room and board benefit","Surgeon\'s scheduled fee","Annual deductible","Stop-loss limit"],"answer":"Daily room and board benefit"},{"module":"Day 4 Module 1","group":"mp-misc","topic":"Miscellaneous Expense Benefit","explanation":"The basic hospital miscellaneous benefit covers hospital \'extras\': drugs, X-rays, anesthesia, lab fees, dressings, operating room, supplies. It does NOT cover room and board or physicians\' bedside visits.","question":"Which of the following is NOT covered by the basic hospital expense policy\'s miscellaneous benefit?","options":["Physicians\' bedside visits","Use of the operating room","Anesthesia","Drugs and dressings"],"answer":"Physicians\' bedside visits"},{"module":"Day 4 Module 1","group":"mp-misc","topic":"Miscellaneous Expense Benefit","explanation":"Memorize the trio: anesthesia (the drug/substance) → covered as miscellaneous; the anesthesiologist (the physician administering it) → NOT covered — that\'s a physician\'s professional fee; physicians\' bedside visits → NOT covered. Watch the wording: \'anesthesia\' is right, \'the administering of anesthesia\' is the trap.","question":"Under a basic hospital expense policy\'s miscellaneous benefit, which of the following is NOT covered?","options":["The anesthesiologist\'s professional services","Anesthesia","X-rays and lab fees","Use of the operating room"],"answer":"The anesthesiologist\'s professional services"},{"module":"Day 4 Module 1","group":"mp-surgmethods","topic":"Surgical Payment Methods","explanation":"Three methods: surgical schedule (flat dollar value per procedure), reasonable & customary (regional comparison — excess is the patient\'s), relative value scale (points × conversion factor).","question":"Pavel\'s basic surgical policy assigns 60 points to an appendectomy and uses a $10 conversion factor. How much will the policy pay?","options":["$600","$500","$540","$700"],"answer":"$600"},{"module":"Day 4 Module 1","group":"mp-surgmethods","topic":"Surgical Payment Methods","explanation":"Three methods: surgical schedule (flat dollar value per procedure), reasonable & customary (regional comparison — excess is the patient\'s), relative value scale (points × conversion factor).","question":"Which basic surgical plan assigns a system of POINTS to surgical procedures?","options":["Relative value scale","Surgical schedule","Reasonable and customary","Stated charges"],"answer":"Relative value scale"},{"module":"Day 4 Module 1","group":"mp-surgmethods","topic":"Surgical Payment Methods","explanation":"Three methods: surgical schedule (flat dollar value), reasonable & customary (compares the charge to the typical cost in that geographic region), relative value scale (points × conversion factor).","question":"Determining the cost of a surgical procedure by comparing it to typical charges in the same geographic area describes the:","options":["Reasonable and customary approach","Surgical schedule method","Relative value scale","Conversion factor method"],"answer":"Reasonable and customary approach"},{"module":"Day 4 Module 1","group":"mp-fixedrate","topic":"Hospital Indemnity / Fixed-Rate Plans","explanation":"Fixed-rate (hospital indemnity) plans pay a flat daily/weekly/monthly amount per day hospitalized, directly TO THE INSURED. Fixed benefits mean claim costs aren\'t affected by medical inflation — and the premium is least affected by rising medical costs. BANK QUIRK: one bank question asks what \'basis\' a flat-per-day policy pays on and keys \'reimbursement\' even with \'fixed-rate plan\' as an option; another keys \'fixed-rate.\' Read the options: if the question describes WHAT it pays, answer flat amount per day / fixed-rate; if it asks the payment \'basis\' with reimbursement keyed, the bank uses the terms interchangeably.","question":"A hospital expense policy that pays a flat amount per day of hospitalization pays benefits on what basis?","options":["A fixed-rate plan","Reimbursement","Service","Assignment"],"answer":"A fixed-rate plan"},{"module":"Day 4 Module 1","group":"mp-fixedrate","topic":"Hospital Indemnity / Fixed-Rate Plans","explanation":"Fixed-rate (hospital indemnity) plans pay a flat daily amount per day hospitalized, directly TO THE INSURED — not to the hospital.","question":"Which statement about a hospital fixed-rate (indemnity) plan is NOT true?","options":["Benefits are paid directly to the hospital","Claim costs are not affected by rising healthcare costs","It offers high benefits for relatively low premiums","Underwriting and administration are simple"],"answer":"Benefits are paid directly to the hospital"},{"module":"Day 4 Module 1","group":"mp-fixedrate","topic":"Hospital Indemnity / Fixed-Rate Plans","explanation":"Because its benefit is a fixed dollar amount per day rather than a share of actual charges, hospital indemnity premiums are the least affected by rising medical costs.","question":"Which coverage\'s premium is LEAST affected by an increase in medical costs?","options":["Hospital indemnity","Major medical","Comprehensive medical","Basic medical expense"],"answer":"Hospital indemnity"},{"module":"Day 4 Module 1","group":"mp-dedtypes","topic":"Major Medical Deductible Types","explanation":"Three major medical deductibles: flat (fixed sum), corridor (insured pays the full deductible after BASIC benefits are exhausted), integrated (the deductible can be offset by what the basic plan pays). Stop-loss is NOT a deductible.","question":"Which of the following is NOT one of the three types of major medical deductibles?","options":["Stop-loss","Corridor","Integrated","Flat"],"answer":"Stop-loss"},{"module":"Day 4 Module 1","group":"mp-dedtypes","topic":"Major Medical Deductible Types","explanation":"Corridor: basic plan pays first, then the insured pays the full deductible before major medical kicks in. Integrated: basic plan payments can satisfy (offset) the deductible. Flat: a simple fixed sum.","question":"Hana\'s basic plan paid $2,400 of her hospital bill. She then paid a $200 deductible before her major medical coverage began paying. Her deductible is classified as:","options":["Corridor","Integrated","Flat","Split"],"answer":"Corridor"},{"module":"Day 4 Module 1","group":"mp-dedtypes","topic":"Major Medical Deductible Types","explanation":"Corridor: insured pays the full deductible after basic benefits are exhausted. Integrated: amounts the basic plan pays offset (satisfy) the deductible.","question":"If all or part of a $500 major medical deductible can be satisfied by benefits paid under a basic medical policy, the deductible is:","options":["Integrated","Corridor","Flat","Carryover"],"answer":"Integrated"},{"module":"Day 4 Module 1","group":"mp-majormath","topic":"Major Medical Math","explanation":"Deductible first, then coinsurance on what remains: insured pays deductible + their percentage of the balance, up to any stop-loss.","question":"Vera\'s hospital bill is $10,500. Her major medical policy has a $500 deductible and 80/20 coinsurance. How much does Vera pay in total?","options":["$2,500","$2,000","$500","$2,100"],"answer":"$2,500"},{"module":"Day 4 Module 1","group":"mp-majormath","topic":"Major Medical Math","explanation":"Deductible first, then coinsurance on what remains: insured pays deductible + their percentage of the balance.","question":"Andre\'s covered expenses total $8,000. His policy has a $500 flat deductible and an 80/20 coinsurance provision. The INSURER pays:","options":["$6,000","$7,500","$6,400","$5,500"],"answer":"$6,000"},{"module":"Day 4 Module 1","group":"mp-basicmath","topic":"Basic Plan Benefit Limits","explanation":"Basic plans pay each category only up to its stated limit: daily room-and-board rate × days (regardless of actual charges), the scheduled surgical amount, and miscellaneous up to its cap.","question":"Talia\'s basic hospital/surgical policy pays $60/day room and board, schedules her surgery at $400, and caps miscellaneous charges at $500. She is hospitalized 5 days at $90/day, billed $550 for surgery and $620 miscellaneous. The policy pays:","options":["$1,200","$1,470","$1,770","$900"],"answer":"$1,200"},{"module":"Day 4 Module 1","group":"mp-basicmath","topic":"Basic Plan Benefit Limits","explanation":"Basic plans pay each category only up to its stated limit: daily room-and-board rate × days, the scheduled surgical amount, and miscellaneous up to its cap. Amounts billed above each limit are the insured\'s responsibility.","question":"Under a schedule-approach basic policy, the surgeon bills $675 but the procedure is scheduled at $500. The policy pays:","options":["$500 — the scheduled amount","$675 — the billed amount","$587.50 — the average","Nothing until the deductible is met"],"answer":"$500 — the scheduled amount"},{"module":"Day 4 Module 1","group":"mp-limited","topic":"Limited Risk Policies","explanation":"Limited risk policies cover one specific peril or ailment: dread disease/cancer policies, travel accident, hospital indemnity, accident-only. They pay limited amounts for narrow risks.","question":"Dread disease, travel accident, and hospital indemnity policies are all examples of:","options":["Limited risk policies","Comprehensive major medical","Blanket policies","Basic physicians\' expense plans"],"answer":"Limited risk policies"},{"module":"Day 4 Module 1","group":"mp-limited","topic":"Limited Risk Policies","explanation":"A limited risk (dread disease) policy protects against one named ailment — cancer is the classic example.","question":"A limited risk policy pays benefits for dread diseases:","options":["Such as cancer","Only if terminal","Only if chronic","Of any kind, like major medical"],"answer":"Such as cancer"},{"module":"Day 4 Module 1","group":"mp-shortterm","topic":"Short-Term Medical (Florida)","explanation":"Florida defines short-term medical insurance as coverage expiring less than 12 months after its effective date, not exceeding 36 months including renewals.","question":"Under Florida\'s definition, a short-term medical policy must expire less than ______ after its effective date and cannot exceed ______ in total duration.","options":["12 months; 36 months","6 months; 12 months","12 months; 24 months","24 months; 48 months"],"answer":"12 months; 36 months"},{"module":"Day 4 Module 1","group":"mp-shortterm","topic":"Short-Term Medical (Florida)","explanation":"Short-term medical policies cover a specific limited period (e.g., 90 or 180 days); accident-only policies cover accidents but never illness.","question":"A policy that covers injuries from accidents but provides NO coverage for sickness is:","options":["Accident-only insurance","Short-term major medical","A dread disease policy","Comprehensive coverage"],"answer":"Accident-only insurance"},{"module":"Day 4 Module 1","group":"mp-suppcomp","topic":"Supplementary vs. Comprehensive","explanation":"Supplementary major medical layers on top of a basic plan, covering excluded expenses and amounts beyond the basic plan\'s limits. Comprehensive combines basic + major medical in one policy.","question":"A major medical plan that covers expenses a basic plan excludes — plus expenses exceeding the basic plan\'s limits — is a:","options":["Supplementary major medical plan","Comprehensive major medical plan","Hospital indemnity plan","Limited risk plan"],"answer":"Supplementary major medical plan"},{"module":"Day 4 Module 1","group":"mp-suppcomp","topic":"Supplementary vs. Comprehensive","explanation":"A supplementary major medical plan combines with BASIC medical coverage; a comprehensive plan covers nearly everything in one policy with a deductible and coinsurance.","question":"A supplementary major medical policy combines the benefits of which two plan types?","options":["Basic medical and major medical","Hospital expense and surgical expense","Major medical and disability income","AD&D and major medical"],"answer":"Basic medical and major medical"},{"module":"Day 4 Module 1","group":"mp-dedpurpose","topic":"Why Deductibles Exist","explanation":"Deductibles eliminate small claims and hold premiums down by making the insured pay initial expenses. They are common in MAJOR MEDICAL plans — basic plans are first-dollar coverage.","question":"Which statement about deductibles in medical insurance is NOT correct?","options":["They are most common in basic medical expense policies","They help eliminate small claims","They make the insured pay initial expenses up to a set amount","They help hold premium rates down"],"answer":"They are most common in basic medical expense policies"},{"module":"Day 4 Module 1","group":"mp-dedpurpose","topic":"Why Deductibles Exist","explanation":"Deductibles eliminate small claims; coinsurance discourages overutilization of benefits. Together they\'re the two main cost-sharing components of major medical.","question":"Which of the following is TRUE about coinsurance?","options":["It helps control overutilization of benefits","It applies to the deductible as well as claim payments","Premiums are higher with a coinsurance provision than without","The insurer can change the ratio after issue"],"answer":"It helps control overutilization of benefits"},{"module":"Day 4 Module 1","group":"mp-lostincome","topic":"What Medical Plans Don\'t Cover","explanation":"Medical expense insurance pays care costs — it never replaces lost income. Income replacement is disability income insurance\'s job.","question":"Basic medical expense policies generally provide NO coverage for:","options":["Lost income","Emergency room visits","Surgical expenses","Skilled nursing facility expenses"],"answer":"Lost income"},{"module":"Day 4 Module 1","group":"mp-lostincome","topic":"What Medical Plans Don\'t Cover","explanation":"Higher risks and greater potential losses call for major medical — broad coverage with high limits — not first-dollar basic plans or single-disease policies.","question":"Which medical expense plan is best suited for higher risks and greater potential loss?","options":["Major medical","First dollar (basic) coverage","A cancer policy","AD&D"],"answer":"Major medical"},{"module":"Day 4 Module 1","group":"mp-preexist","topic":"Preexisting Conditions","explanation":"A preexisting condition existed before the policy\'s effective date. Exclusion periods protected insurers from adverse selection — but the ACA eliminated preexisting-condition exclusions in ACA-compliant medical plans.","question":"Historically, preexisting-condition exclusion periods protected insurers against:","options":["Adverse selection","Catastrophic claims","Premium inflation","Overutilization of benefits"],"answer":"Adverse selection"},{"module":"Day 4 Module 1","group":"mp-preexist","topic":"Preexisting Conditions","explanation":"A preexisting condition existed before the policy\'s effective date. The ACA eliminated preexisting-condition exclusions in ACA-compliant medical expense plans.","question":"Under the Affordable Care Act, preexisting condition exclusions in compliant major medical plans are:","options":["Prohibited entirely","Limited to 12 months","Allowed for chronic illness only","Allowed with a premium surcharge"],"answer":"Prohibited entirely"},{"module":"Day 4 Module 2","group":"di-elim","topic":"Elimination vs. Probationary","explanation":"The elimination period is the \'time deductible\' before benefits start (longer = cheaper premium). Per this course\'s bank it applies to SICKNESS only — accidents are payable immediately. The probationary period applies once, at policy start, to sickness only.","question":"The waiting period between the onset of a disability and the start of benefit payments is the:","options":["Elimination period","Probationary period","Grace period","Benefit period"],"answer":"Elimination period"},{"module":"Day 4 Module 2","group":"di-elim","topic":"Elimination vs. Probationary","explanation":"The elimination period is the \'time deductible\' before benefits start (longer = cheaper premium). Per this course\'s bank it applies to SICKNESS only — accidents are payable immediately. The probationary period applies once, at policy start, to sickness only.","question":"Choosing a 180-day elimination period instead of 30 days will:","options":["Lower the premium","Raise the premium","Shorten the benefit period","Eliminate the probationary period"],"answer":"Lower the premium"},{"module":"Day 4 Module 2","group":"di-prob","topic":"Probationary Period","explanation":"The probationary period is a one-time window at the start of the policy during which sickness (never accidents) is not covered — it blocks preexisting-illness claims.","question":"A disability policy\'s probationary period applies to:","options":["Sickness only, during the period right after the policy is issued","Accidents only","Both sickness and accidents, on every claim","Claims filed after age 65"],"answer":"Sickness only, during the period right after the policy is issued"},{"module":"Day 4 Module 2","group":"di-prob","topic":"Probationary Period","explanation":"The probationary period is a one-time window at the start of the policy during which sickness (never accidents) is not covered — it blocks preexisting-illness claims.","question":"Two weeks after buying a disability policy with a 30-day probationary period, Lena is hurt in a car accident and cannot work. The insurer will:","options":["Pay — the probationary period does not apply to accidents","Deny — no claims are covered during the probationary period","Pay only half the benefit","Refund her premium and void the policy"],"answer":"Pay — the probationary period does not apply to accidents"},{"module":"Day 4 Module 2","group":"di-occ","topic":"Own vs. Any Occupation","explanation":"Own-occupation pays if you can\'t do YOUR job (easier to qualify, costlier). Any-occupation pays only if you can\'t do any job suited to your education, training, or experience.","question":"Under an own-occupation definition of disability, a surgeon who loses fine motor control but takes a teaching job will:","options":["Receive benefits, because she cannot perform her own occupation","Receive nothing, because she can still work","Receive benefits only after age 65","Forfeit the policy"],"answer":"Receive benefits, because she cannot perform her own occupation"},{"module":"Day 4 Module 2","group":"di-occ","topic":"Own vs. Any Occupation","explanation":"Counterintuitive but course-keyed: under the own-occupation definition, a PERMANENT inability to perform your own regular occupation is PERMANENT TOTAL disability — even if you can do other work. \'Partial\' means you can still perform SOME duties of your own occupation, not that you can do a different job.","question":"A worker is permanently unable to perform the duties of his own regular occupation, but is capable of working in a different field. Under the own-occupation definition, his disability is classified as:","options":["Permanent total disability","Permanent partial disability","Temporary total disability","Residual disability"],"answer":"Permanent total disability"},{"module":"Day 4 Module 2","group":"di-occ","topic":"Own vs. Any Occupation","explanation":"Own-occupation pays if you can\'t do YOUR job (easier to qualify, costlier). Any-occupation pays only if you can\'t do any job suited to your education, training, or experience.","question":"Which definition of total disability is most favorable to the insured?","options":["Own occupation","Any occupation","Presumptive occupation","Residual occupation"],"answer":"Own occupation"},{"module":"Day 4 Module 2","group":"di-residual","topic":"Partial vs. Residual","explanation":"Partial disability pays a flat percentage (often 50%) of the total benefit. Residual pays in proportion to lost INCOME — a 40% earnings drop pays 40% of the benefit.","question":"Marco returned to work part-time and his earnings dropped 40%. His policy pays 40% of his total disability benefit. This is a ______ benefit.","options":["Residual disability","Partial disability","Presumptive disability","Recurrent disability"],"answer":"Residual disability"},{"module":"Day 4 Module 2","group":"di-residual","topic":"Partial vs. Residual","explanation":"Partial disability pays a flat percentage (often 50%) of the total benefit. Residual pays in proportion to lost INCOME — a 40% earnings drop pays 40% of the benefit.","question":"A benefit that pays a flat 50% of the total disability benefit when the insured can work but cannot perform all duties is:","options":["Partial disability","Residual disability","Total disability","Presumptive disability"],"answer":"Partial disability"},{"module":"Day 4 Module 2","group":"di-presume","topic":"Presumptive Disability","explanation":"Presumptive disability automatically qualifies as total disability without further proof: loss of sight, hearing, speech, or two limbs.","question":"Which loss would trigger a presumptive total disability benefit?","options":["Loss of sight in both eyes","A sprained ankle","A 20% loss of income","Carpal tunnel syndrome"],"answer":"Loss of sight in both eyes"},{"module":"Day 4 Module 2","group":"di-presume","topic":"Presumptive Disability","explanation":"Presumptive disability automatically qualifies as total disability without further proof: loss of sight, hearing, speech, or two limbs.","question":"Under a presumptive disability provision, the insured who loses two limbs:","options":["Is automatically considered totally disabled, with no further proof required","Must still prove she cannot perform her occupation","Receives only partial benefits","Must satisfy a new probationary period"],"answer":"Is automatically considered totally disabled, with no further proof required"},{"module":"Day 4 Module 2","group":"di-boe","topic":"Business Overhead Expense","explanation":"BOE pays the business\'s operating expenses (rent, utilities, staff salaries) while the owner is disabled. It does NOT replace the owner\'s income.","question":"Tariq owns a dental practice. He wants coverage that pays the office rent and his hygienist\'s salary if he becomes disabled. He needs:","options":["Business overhead expense insurance","Personal disability income insurance","Key person life insurance","A disability buy-sell agreement"],"answer":"Business overhead expense insurance"},{"module":"Day 4 Module 2","group":"di-boe","topic":"Business Overhead Expense","explanation":"BOE pays the business\'s operating expenses (rent, utilities, staff salaries) while the owner is disabled. It does NOT replace the owner\'s income.","question":"Business overhead expense insurance does NOT cover:","options":["The disabled owner\'s lost personal income","Office rent","Employee salaries","Utility bills"],"answer":"The disabled owner\'s lost personal income"},{"module":"Day 4 Module 2","group":"di-buysell","topic":"Disability Buy-Sell","explanation":"A disability buy-sell funds the purchase of a disabled partner\'s interest in the business, usually as a lump sum after a long elimination period.","question":"A policy designed to fund the purchase of a totally disabled partner\'s share of the business is a:","options":["Disability buy-sell policy","Business overhead expense policy","Key person retention policy","Group disability conversion"],"answer":"Disability buy-sell policy"},{"module":"Day 4 Module 2","group":"di-buysell","topic":"Disability Buy-Sell","explanation":"A disability buy-sell funds the purchase of a disabled partner\'s interest in the business, usually as a lump sum after a long elimination period.","question":"Compared to personal disability income policies, disability buy-sell policies typically have:","options":["A longer elimination period and a lump-sum benefit","A shorter elimination period and monthly benefits","No elimination period","Benefits payable to the disabled partner\'s family"],"answer":"A longer elimination period and a lump-sum benefit"},{"module":"Day 4 Module 2","group":"di-waiver","topic":"Waiver of Premium","explanation":"Waiver of premium keeps the policy in force without payments while the insured is totally disabled, typically kicking in after 90 days and refunding premiums paid during that time.","question":"The provision that keeps a disability policy in force without premium payments while the insured is totally disabled is:","options":["Waiver of premium","Grace period","Reinstatement","Automatic premium loan"],"answer":"Waiver of premium"},{"module":"Day 4 Module 2","group":"di-waiver","topic":"Waiver of Premium","explanation":"Waiver of premium keeps the policy in force without payments while the insured is totally disabled, typically kicking in after 90 days and refunding premiums paid during that time.","question":"The Social Insurance Supplement (SIS) rider pays:","options":["An extra benefit while the insured awaits or is denied Social Security disability benefits","The insured\'s Social Security taxes","A funeral benefit","The employer\'s share of FICA"],"answer":"An extra benefit while the insured awaits or is denied Social Security disability benefits"},{"module":"Day 4 Module 2","group":"di-cause","topic":"Accidental Means vs. Bodily Injury","explanation":"Accidental means requires the CAUSE itself to be unintended — a deliberate act (like jumping into a lake) that produces an unintended injury is NOT covered. Accidental bodily injury only requires the RESULT to be unexpected, so it\'s broader.","question":"Mateo\'s disability policy uses an \'accidental means\' definition. He deliberately jumped from a dock into shallow water and broke his neck. The insurer will:","options":["Pay nothing — the jump was intentional, so the cause was not accidental","Pay in full — the injury was not planned","Pay half the benefit","Pay only medical expenses"],"answer":"Pay nothing — the jump was intentional, so the cause was not accidental"},{"module":"Day 4 Module 2","group":"di-cause","topic":"Accidental Means vs. Bodily Injury","explanation":"Accidental means requires the CAUSE itself to be unintended. Accidental bodily injury only requires the RESULT to be unexpected, so it\'s the broader, more favorable definition.","question":"Which definition of accident requires that BOTH the cause and the result be unexpected and unintended?","options":["Accidental means","Accidental bodily injury","Presumptive cause","Proximate cause"],"answer":"Accidental means"},{"module":"Day 4 Module 2","group":"di-cause","topic":"Accidental Means vs. Bodily Injury","explanation":"Under accidental bodily injury, only the result must be accidental — a hiker who accidentally falls is covered. Under accidental means, a deliberate act that goes wrong is not covered.","question":"While hiking, Joelle accidentally slips off a trail ledge and is paralyzed. Under an \'accidental bodily injury\' provision, her claim is:","options":["Covered — the injury was unexpected and accidental","Denied — hiking is a voluntary activity","Covered at 50%","Denied — falls are excluded"],"answer":"Covered — the injury was unexpected and accidental"},{"module":"Day 4 Module 2","group":"di-delayed","topic":"Delayed Disability","explanation":"The delayed disability provision covers a disability that develops after an accident — up to a maximum of 90 days following the accident.","question":"Under a delayed disability provision, a disability that develops after an accident is still covered if it begins within a maximum of:","options":["90 days of the accident","30 days of the accident","6 months of the accident","1 year of the accident"],"answer":"90 days of the accident"},{"module":"Day 4 Module 2","group":"di-delayed","topic":"Delayed Disability","explanation":"The delayed disability provision covers a disability that develops after an accident — up to a maximum of 90 days following the accident.","question":"Caleb is in a car crash in May but doesn\'t become disabled from his injuries until July (within 90 days). Which provision allows his claim?","options":["The delayed disability provision","The recurrent disability provision","The probationary period","The elective indemnity option"],"answer":"The delayed disability provision"},{"module":"Day 4 Module 2","group":"di-nondis","topic":"Non-Disabling Injury Benefit","explanation":"A non-disabling injury doesn\'t keep the insured from working — the benefit pays the ACTUAL COST of medical treatment for the injury, never a salary percentage.","question":"An injury that does not qualify the insured for monthly disability benefits may still make him eligible for:","options":["A non-disabling injury benefit","An emergency room benefit","Outpatient compensation","A presumptive benefit"],"answer":"A non-disabling injury benefit"},{"module":"Day 4 Module 2","group":"di-nondis","topic":"Non-Disabling Injury Benefit","explanation":"A non-disabling injury benefit pays the actual cost of medical treatment for an accidental injury that doesn\'t prevent the insured from working.","question":"The non-disabling injury benefit pays:","options":["The actual cost of medical treatment","A flat amount equal to the insured\'s salary","A percentage of the insured\'s salary","The full monthly disability benefit"],"answer":"The actual cost of medical treatment"},{"module":"Day 4 Module 2","group":"di-elective","topic":"Elective Indemnity","explanation":"Elective indemnity, available on some short-term disability policies, lets the insured choose a lump-sum payment for certain named injuries instead of income payments.","question":"An option on some short-term disability policies allowing the insured to take a LUMP SUM for certain named injuries is called:","options":["Elective indemnity","Residual indemnity","Double indemnity","Presumptive indemnity"],"answer":"Elective indemnity"},{"module":"Day 4 Module 2","group":"di-elective","topic":"Elective Indemnity","explanation":"Elective indemnity, available on some short-term disability policies, lets the insured choose a lump-sum payment for certain named injuries instead of weekly or monthly income.","question":"Instead of receiving monthly income for his fractured arm, Drew elects a one-time lump-sum payment named in his short-term policy. He has exercised:","options":["An elective indemnity option","A waiver of premium","A COLA adjustment","A Social Security rider"],"answer":"An elective indemnity option"},{"module":"Day 4 Module 2","group":"di-benper","topic":"Benefit Periods & Premium Cost","explanation":"Short-term individual DI benefit periods run six months to two years. Premium cost rises with longer benefit periods and falls with longer elimination periods — so long elimination + short benefit period is cheapest.","question":"Individual short-term disability policy benefit periods typically range from:","options":["Six months to two years","One to 12 months","Three months to three years","One to five years"],"answer":"Six months to two years"},{"module":"Day 4 Module 2","group":"di-benper","topic":"Benefit Periods & Premium Cost","explanation":"Premium cost rises with longer benefit periods and falls with longer elimination periods — long elimination + short benefit period is the cheapest combination.","question":"Which disability policy configuration carries the LOWEST premium?","options":["A long elimination period with a short benefit period","A short elimination period with a long benefit period","A long elimination period with a long benefit period","A short elimination period with a short benefit period"],"answer":"A long elimination period with a short benefit period"},{"module":"Day 4 Module 2","group":"di-benper","topic":"Benefit Periods & Premium Cost","explanation":"A benefit period \'to age 65\' ends at 65 no matter when disability begins. Disabled at 64½ with a 6-month waiting period, the insured reaches 65 just as the wait ends — nothing is payable.","question":"Imelda has a $1,500/month disability policy with benefits to age 65 and a six-month waiting period. She becomes disabled at age 64½. She will receive:","options":["Nothing — the benefit period ends at 65, just as her waiting period is satisfied","$1,500 for one month","$9,000","$18,000"],"answer":"Nothing — the benefit period ends at 65, just as her waiting period is satisfied"},{"module":"Day 4 Module 2","group":"di-payment","topic":"Payment of Benefits","explanation":"Individual disability income claims must be paid no less frequently than monthly.","question":"At a minimum, disability income claim payments must be made to the insured:","options":["Monthly","Weekly","Quarterly","Annually"],"answer":"Monthly"},{"module":"Day 4 Module 2","group":"di-payment","topic":"Payment of Benefits","explanation":"Disability benefits are paid as periodic income — monthly at minimum — not as lump sums (except under elective indemnity options).","question":"Disability income benefits are typically paid:","options":["Monthly","Quarterly","Semiannually","In a single lump sum"],"answer":"Monthly"},{"module":"Day 4 Module 2","group":"di-occnon","topic":"Occupational vs. Nonoccupational","explanation":"Occupational coverage protects on AND off the job. Nonoccupational covers only off-the-job disabilities — on-the-job injuries fall to workers\' compensation.","question":"A nonoccupational disability policy covers:","options":["Only disabilities occurring OFF the job","Only disabilities occurring on the job","All disabilities, on or off the job","Only occupational diseases"],"answer":"Only disabilities occurring OFF the job"},{"module":"Day 4 Module 2","group":"di-occnon","topic":"Occupational vs. Nonoccupational","explanation":"Occupational coverage protects on AND off the job. Nonoccupational covers only off-the-job disabilities — on-the-job injuries fall to workers\' compensation.","question":"Why are most group disability plans written as NONoccupational coverage?","options":["On-the-job injuries are already covered by workers\' compensation","Off-the-job injuries are rarer","Federal law prohibits occupational coverage","Premiums are higher for nonoccupational plans"],"answer":"On-the-job injuries are already covered by workers\' compensation"},{"module":"Day 4 Module 2","group":"di-recur","topic":"Recurrent Disability","explanation":"If the same disability returns within the stated window (commonly 6 months), benefits resume immediately — no new elimination period. But beware the course\'s flip side: full recovery + return to work can make a later disability a NEW claim with a new elimination period (see the Marcus question).","question":"Rosa was disabled January 15 to April 15, returned to work, then was stricken by the same condition on September 1. Under the recurrent disability provision, her benefits:","options":["Resume September 1, with no new elimination period","Begin after a brand-new elimination period","Begin after a new probationary period","Are denied as a preexisting condition"],"answer":"Resume September 1, with no new elimination period"},{"module":"Day 4 Module 2","group":"di-recur","topic":"Recurrent Disability","explanation":"A recurrence within the stated window continues the original claim. A NEW, separate disability starts a new elimination period and a fresh benefit period.","question":"The purpose of the recurrent disability provision is to:","options":["Treat a relapse within a stated period as a continuation of the original claim, with no new elimination period","Reduce benefits for repeat claims","Extend the probationary period after each claim","Convert the policy to medical expense coverage"],"answer":"Treat a relapse within a stated period as a continuation of the original claim, with no new elimination period"},{"module":"Day 4 Module 2","group":"di-recur","topic":"Recurrent Disability","explanation":"Course-keyed distinction: a relapse within the recurrence window continues the original claim (no new elimination period). But FULL recovery plus a return to work means a later disability — even from the same cause — is treated as a NEW disability: a new elimination period applies and a fresh benefit period begins.","question":"Marcus was disabled by a stroke, fully recovered, and returned to work for three months before a second stroke disabled him on June 1. His policy has a 30-day elimination period and a 5-year benefit period. The insurer will:","options":["Begin benefits July 1 and pay up to a fresh 5-year benefit period","Resume benefits June 1 under the recurrent disability provision","Pay only the remainder of the original benefit period","Deny the claim as a preexisting condition"],"answer":"Begin benefits July 1 and pay up to a fresh 5-year benefit period"},{"module":"Day 4 Module 2","group":"di-totaldef","topic":"Occupational Suitability","explanation":"Any-occupation tests look at education, training, and experience. Job interest is never a criterion. House confinement and inability to perform own/any occupation have been used in definitions of total disability.","question":"Which of the following is NOT a criterion used to assess total disability based on occupational suitability?","options":["Job interest","Education","Training","Experience"],"answer":"Job interest"},{"module":"Day 4 Module 2","group":"di-totaldef","topic":"Occupational Suitability","explanation":"\'Any occupation for which the insured is qualified by education or experience\' is the ANY-occupation definition — the more restrictive one (hardest to qualify under). Own-occupation is less restrictive and more favorable. WARNING: this course\'s bank has keyed this BOTH ways (\'more restrictive\' and \'less restrictive\'). Standard/state-exam answer: any-occupation = MORE restrictive. Flag the contradiction to your instructor if marked wrong.","question":"A policy defines total disability as the inability to perform ANY occupation for which the insured is qualified by education or experience. This definition is:","options":["The any-occupation definition, and it is more restrictive than own-occupation","The own-occupation definition, and it is more restrictive","The any-occupation definition, and it is less restrictive","The own-occupation definition, and it is less restrictive"],"answer":"The any-occupation definition, and it is more restrictive than own-occupation"},{"module":"Day 4 Module 2","group":"di-elimscenario","topic":"Elimination Period Scenarios","explanation":"Benefits never accrue during the elimination period and are NOT retroactive. If the insured recovers before the elimination period ends, nothing is paid.","question":"Jonas has a 30-day elimination period. He is sick and out of work for 15 days, then returns. His disability benefit is paid:","options":["Never — he recovered before satisfying the elimination period","Beginning on day 1, retroactively","Beginning on day 16","Beginning on day 31"],"answer":"Never — he recovered before satisfying the elimination period"},{"module":"Day 4 Module 2","group":"di-elimscenario","topic":"Elimination Period Scenarios","explanation":"Statements that elimination benefits are paid retroactively, or that elimination periods apply to sickness but not accidents, are FALSE — that second description fits the probationary period.","question":"Which statement about elimination periods is NOT correct?","options":["Benefits are paid retroactively to the start of the period if the insured stays disabled through it","It follows the start of each disability","It functions like a time deductible","Longer elimination periods reduce the premium"],"answer":"Benefits are paid retroactively to the start of the period if the insured stays disabled through it"},{"module":"Day 4 Module 2","group":"di-probscenario","topic":"Probationary + Elimination Together","explanation":"Probationary periods (commonly 15 or 30 days) block SICKNESS claims early in the policy; accidents are covered immediately. After the probationary period, sickness claims still face the elimination period.","question":"A disability policy typically covers:","options":["Accidents immediately, sickness only after the probationary period","Sickness immediately, accidents after 15 days","Both only after 15 days","Both immediately, with no waiting of any kind"],"answer":"Accidents immediately, sickness only after the probationary period"},{"module":"Day 4 Module 2","group":"di-probscenario","topic":"Probationary + Elimination Together","explanation":"Probationary periods for sickness typically run 15 or 30 days. Accidents are covered from day one.","question":"Sickness claims during a disability policy\'s probationary period are typically excluded for:","options":["15 or 30 days","Three or five days","60 or 90 days","90 or 180 days"],"answer":"15 or 30 days"},{"module":"Day 4 Module 2","group":"di-probscenario","topic":"Probationary + Elimination Together","explanation":"COURSE KEY: in this course\'s bank, the elimination period — like the probationary period — applies to SICKNESS only and does NOT apply to accidents. Hit by a truck/train = benefits payable immediately on the date of the accident. (The book says elimination periods \'may apply only to sickness depending on the policy\' — this bank treats that as the default.)","question":"Hugo\'s policy has a 15-day probationary period and a 30-day elimination period. He is hit by a truck on September 1 (after the probationary period) and disabled for six months. Benefits first become payable:","options":["September 1 — immediately, because elimination periods do not apply to accidents","October 1 — 30 days after the accident","September 15","November 1"],"answer":"September 1 — immediately, because elimination periods do not apply to accidents"},{"module":"Day 4 Module 2","group":"di-girdetail","topic":"Guaranteed Insurability (DI)","explanation":"The guaranteed insurability rider lets the insured buy additional coverage at predetermined intervals without new evidence of insurability; in disability policies the increase is tied to an earnings test — you can\'t insure income you don\'t earn.","question":"A guaranteed insurability rider on a disability income policy allows the insured to purchase additional coverage:","options":["Based on an earnings test, without new evidence of insurability","Based solely on inflation","Only after age 65","Whenever premiums are waived"],"answer":"Based on an earnings test, without new evidence of insurability"},{"module":"Day 4 Module 2","group":"di-girdetail","topic":"Guaranteed Insurability (DI)","explanation":"Waiver of premium applies to disability income policies (not typically medical expense policies), may apply retroactively, and usually drops off at age 60 or 65.","question":"Which statement about the waiver of premium provision is NOT correct?","options":["It normally applies to both medical expense and disability income policies","It may apply retroactively","It usually drops off at age 60 or 65","It exempts the insured from premiums during total and permanent disability"],"answer":"It normally applies to both medical expense and disability income policies"},{"module":"Day 5 Module 1","group":"add-sums","topic":"Principal vs. Capital Sum","explanation":"Principal sum = the death benefit paid for accidental death. Capital sum = the dismemberment/loss-of-sight benefit, usually a percentage of the principal sum.","question":"The amount payable as a death benefit in an accidental death and dismemberment policy is called the:","options":["Principal sum","Capital sum","Primary amount","Indemnity amount"],"answer":"Principal sum"},{"module":"Day 5 Module 1","group":"add-sums","topic":"Principal vs. Capital Sum","explanation":"Dismemberment or loss-of-sight benefits are the CAPITAL sum — usually a percentage of the principal (death) sum.","question":"Alexander loses one eye in an accident and receives $15,000 from his $100,000 AD&D policy. The $15,000 is the policy\'s:","options":["Capital sum","Principal sum","Secondary sum","Contingent amount"],"answer":"Capital sum"},{"module":"Day 5 Module 1","group":"add-nature","topic":"Nature of AD&D","explanation":"AD&D is pure accident insurance and a VALUED contract. It never pays for death by sickness (heart attack); a triple-indemnity policy pays three times the principal sum for qualifying accidental deaths.","question":"Which of the following AD&D examples is ACCURATE?","options":["Laura\'s $40,000 AD&D policy pays triple indemnity; killed in a train wreck, her beneficiary receives $120,000","Merle dies of a heart attack; his $50,000 AD&D policy pays the death benefit","Karen\'s $15,000 benefit for loss of one hand is called the principal sum","Derek\'s $30,000 accidental death benefit is the policy\'s capital sum"],"answer":"Laura\'s $40,000 AD&D policy pays triple indemnity; killed in a train wreck, her beneficiary receives $120,000"},{"module":"Day 5 Module 1","group":"add-nature","topic":"Nature of AD&D","explanation":"AD&D pays predetermined, stated amounts — making it a valued contract (a policy of value), not a contract of indemnity.","question":"An AD&D policy is best described as:","options":["A valued contract that is pure accident insurance","A contract of indemnity","A reimbursement contract","A medical expense policy"],"answer":"A valued contract that is pure accident insurance"},{"module":"Day 5 Module 1","group":"add-forms","topic":"Limited & Special Risk","explanation":"A round-trip travel accident policy bought at the airport covers one specific named risk — a LIMITED risk policy. Special risk covers unusual hazards like a violinist\'s hands.","question":"Edith purchases a round-trip travel accident policy at the airport before a business trip. Her policy is a:","options":["Limited risk policy","Special risk policy","Business overhead expense policy","Industrial health policy"],"answer":"Limited risk policy"},{"module":"Day 5 Module 1","group":"add-forms","topic":"Limited & Special Risk","explanation":"Special risk policies cover unusual hazards not insurable under standard AD&D — like a professional violinist insuring her hands.","question":"A professional violinist who insures her hands against loss has purchased a:","options":["Special risk policy","Limited risk policy","Dread disease policy","Franchise policy"],"answer":"Special risk policy"},{"module":"Day 5 Module 1","group":"add-means","topic":"Means vs. Results (AD&D)","explanation":"Accidental MEANS requires both cause and result to be unintentional (jumping = no coverage). Accidental RESULTS requires only the injury to be unintentional (jumping and getting hurt = covered).","question":"Under an \'accidental means\' definition, which loss would be covered?","options":["Falling off a ladder and breaking a leg","Jumping off a ladder and breaking a leg","An intentionally self-inflicted injury","A heart attack while at rest"],"answer":"Falling off a ladder and breaking a leg"},{"module":"Day 5 Module 1","group":"add-rules","topic":"AD&D Payment Rules","explanation":"True: dismemberment benefits MAY be paid for loss of USE, and accidental death benefits pay only if death results from accidental bodily injury as defined in the policy. False: death must typically occur within 90 days of the accident — not 60.","question":"Which statements about AD&D coverage are true? I. Death benefits are paid only if death occurs within 60 days of an accident. II. Dismemberment benefits may be paid for loss of use. III. Accidental death benefits are paid only if death results from accidental bodily injury as defined in the policy.","options":["II and III","I and II","I and III","All statements apply"],"answer":"II and III"},{"module":"Day 5 Module 1","group":"add-rules","topic":"AD&D Payment Rules","explanation":"Per the course bank: losing all fingers EXCEPT the thumb is NOT dismemberment (severance must be of the entire hand), but permanent LOSS OF USE of a hand/arm DOES qualify.","question":"Which would qualify as dismemberment? I. Sally loses all fingers on her left hand except the thumb. II. Ed permanently loses the USE of his right hand and arm in an auto accident.","options":["II only","I only","I and II","Neither I nor II"],"answer":"II only"},{"module":"Day 5 Module 1","group":"add-sums","topic":"Principal vs. Capital Sum","explanation":"COURSE KEY: the principal sum pays for LOSS OF LIFE ONLY. Loss of hands, partial foot, or fingers — even severe multiple losses — were keyed to the CAPITAL sum, not principal. (Note the bank is loose here: another of its questions says loss of two limbs pays the same amount as death — but when asked what the principal sum \'pays for,\' answer death only.)","question":"[Course bank] The principal sum in a $25,000 AD&D policy will pay for which of the following? I. Loss of hands above the wrist. II. Loss of 3/4 of the foot. III. Loss of life in a boating accident. IV. All fingers (including thumbs) on both hands.","options":["III only","I and III","I, II, and III","II and IV"],"answer":"III only"},{"module":"Day 5 Module 1","group":"add-sums","topic":"Principal vs. Capital Sum","explanation":"COURSE KEY: the capital sum covers the dismemberment losses — this bank keyed ALL the listed dismemberments (hands above the wrist, partial foot, an eye, all fingers including thumbs) as payable under the capital sum schedule (at varying percentages). Death is the only loss paid by the principal sum.","question":"[Course bank] The capital sum in an AD&D policy will pay for which of the following? I. Loss of hands above the wrist. II. Loss of 3/4 of the foot. III. Loss of an eye. IV. All fingers (including thumbs) on both hands.","options":["I, II, III, and IV","I and III","II and IV","I, II, and III"],"answer":"I, II, III, and IV"},{"module":"Day 5 Module 2","group":"mc-parts","topic":"Parts of Medicare","explanation":"Part A = hospital (premium-free with 40 work quarters). Part B = doctors/outpatient, 80/20 after deductible, monthly premium. Part C = Advantage (requires A+B). Part D = drugs.","question":"Inpatient hospital care is covered under which part of Medicare?","options":["Part A","Part B","Part C","Part D"],"answer":"Part A"},{"module":"Day 5 Module 2","group":"mc-parts","topic":"Parts of Medicare","explanation":"Part A = hospital (premium-free with 40 work quarters). Part B = doctors/outpatient, 80/20 after deductible, monthly premium. Part C = Advantage (requires A+B). Part D = drugs.","question":"After the annual deductible, Medicare Part B generally pays what share of approved charges?","options":["80%","100%","50%","20%"],"answer":"80%"},{"module":"Day 5 Module 2","group":"mc-partc","topic":"Medicare Advantage","explanation":"Part C (Medicare Advantage) plans are private plans that replace original Medicare; enrollees must be enrolled in BOTH Part A and Part B.","question":"To enroll in a Medicare Advantage (Part C) plan, a person must:","options":["Be enrolled in both Part A and Part B","Be enrolled in Part D only","Have a Medigap policy","Be under age 65"],"answer":"Be enrolled in both Part A and Part B"},{"module":"Day 5 Module 2","group":"mc-partc","topic":"Medicare Advantage","explanation":"Part C (Medicare Advantage) plans are private plans that replace original Medicare; enrollees must be enrolled in BOTH Part A and Part B.","question":"Prescription drug coverage under Medicare is provided by:","options":["Part D plans offered by private companies","Part A automatically","Part B with no premium","Medigap Plan A"],"answer":"Part D plans offered by private companies"},{"module":"Day 5 Module 2","group":"mc-parta","topic":"Medicare Part A","explanation":"Part A is compulsory hospital insurance financed by FICA taxes, and it is provided AUTOMATICALLY when a qualified person applies for Social Security benefits.","question":"Choose the CORRECT statement pertaining to Medicare.","options":["When a qualified individual applies for Social Security benefits, Medicare Part A is automatically provided","Individuals enrolled in Part A are allowed one 90-day benefit period annually","Medicare Part B pays 80% of the deductible","Part A is financed by monthly premiums"],"answer":"When a qualified individual applies for Social Security benefits, Medicare Part A is automatically provided"},{"module":"Day 5 Module 2","group":"mc-parta","topic":"Medicare Part A","explanation":"For the first 60 days of hospitalization, Part A covers all eligible services except the initial deductible. Past 90 days, the patient draws on a 60-day lifetime reserve.","question":"Except for an initial deductible, Medicare Part A pays 100% of covered services for the first ____ days of hospitalization.","options":["60","30","90","100"],"answer":"60"},{"module":"Day 5 Module 2","group":"mc-parta","topic":"Medicare Part A","explanation":"When hospitalization exceeds 90 days, patients tap a LIFETIME RESERVE of 60 additional hospital days — once used, they never renew.","question":"After 90 days of hospitalization in one benefit period, a Medicare patient draws on:","options":["A lifetime reserve of 60 hospital days","A new annual benefit period","Unlimited extended coverage","Medicaid automatically"],"answer":"A lifetime reserve of 60 hospital days"},{"module":"Day 5 Module 2","group":"mc-parta","topic":"Medicare Part A","explanation":"Medicare pays up to 100 days of skilled nursing facility care per benefit period (following a qualifying hospital stay).","question":"Medicare will pay for how many days of skilled nursing facility care?","options":["100","30","60","90"],"answer":"100"},{"module":"Day 5 Module 2","group":"mc-partb","topic":"Medicare Part B","explanation":"Part B participants pay a monthly premium, an annual deductible, and 20% of covered charges. There is NO per-benefit deductible.","question":"Under Medicare Part B, which of the following do participants NOT have to pay?","options":["A per-benefit deductible","An annual deductible","20% of covered charges above the deductible","A monthly premium"],"answer":"A per-benefit deductible"},{"module":"Day 5 Module 2","group":"mc-partb","topic":"Medicare Part B","explanation":"Part B is VOLUNTARY — not compulsory. It covers what Part A doesn\'t (doctors, outpatient) and is financed by monthly premiums plus general tax revenues.","question":"Choose the INCORRECT statement regarding Medicare Part B.","options":["Medicare Part B is a compulsory program","Part B covers services and supplies not covered by Part A","Part B is financed by monthly premiums","Part B is financed in part by tax revenues"],"answer":"Medicare Part B is a compulsory program"},{"module":"Day 5 Module 2","group":"mc-payor","topic":"Primary vs. Secondary Payor","explanation":"A working person 65+ at an employer with 20 or more employees keeps the employer-sponsored plan as PRIMARY coverage; Medicare is SECONDARY.","question":"Joan, 67, still works for a firm with 75 employees and has the company health plan. Which is true?","options":["The employer plan is primary; Medicare is secondary","Medicare is primary; the employer plan is secondary","She must drop the employer plan at 65","She cannot have both coverages"],"answer":"The employer plan is primary; Medicare is secondary"},{"module":"Day 5 Module 2","group":"mc-exclusions","topic":"Medicare Exclusions","explanation":"Medicare excludes: private duty nursing, private rooms (unless medically necessary), first 3 pints of blood, skilled nursing past 100 days, charges above Medicare-approved amounts, care outside the U.S., custodial care at home, and well care (dental, vision, hearing, routine physicals, immunizations, acupuncture).","question":"Which of the following IS excluded under Medicare?","options":["The first three pints of blood","Inpatient hospital care","Hospice care","Home health care"],"answer":"The first three pints of blood"},{"module":"Day 5 Module 2","group":"mc-medicaid2","topic":"Medicaid & Florida Programs","explanation":"Unlike Medicare, Medicaid DOES cover custodial/assisted nursing-home care — for people of any age who can demonstrate financial need.","question":"Which program covers custodial care in a nursing home for a person who can demonstrate financial need?","options":["Medicaid","Medicare Part A","Medicare Part B","Workers\' compensation"],"answer":"Medicaid"},{"module":"Day 5 Module 2","group":"mc-medicaid2","topic":"Medicaid & Florida Programs","explanation":"Florida penalizes asset transfers below market value made to qualify for Medicaid: eligibility can be delayed for transfers within the 5-year look-back period.","question":"Transferring assets below market value to qualify for Medicaid can delay eligibility if done within the look-back period of:","options":["5 years","1 year","3 years","10 years"],"answer":"5 years"},{"module":"Day 5 Module 2","group":"mc-medicaid2","topic":"Medicaid & Florida Programs","explanation":"The Deficit Reduction Act (DRA) let states modernize Medicaid through cost sharing, flexible benefits, and healthy opportunity accounts. Florida Healthy Kids Corporation (1990) expands children\'s coverage.","question":"The Florida Healthy Kids Corporation, established in 1990, was created to:","options":["Enhance access to health insurance for uninsured children","Replace Medicaid for seniors","Provide workers\' compensation to minors","Sell Medicare Advantage plans"],"answer":"Enhance access to health insurance for uninsured children"},{"module":"Day 5 Module 2","group":"mc-wc","topic":"Workers\' Compensation","explanation":"Workers\' comp is NO-FAULT — benefits are paid regardless of who caused the work-related injury. It exists in all 50 states, pays health-care costs and disability income, and aims to return workers to work.","question":"Choose the statement concerning workers\' compensation that is NOT correct.","options":["Workers receive benefits only if they are not at fault for their work-related injury","One purpose of workers\' compensation laws is to return injured persons to work","Benefits include healthcare costs and disability income","All 50 states have workers\' compensation laws"],"answer":"Workers receive benefits only if they are not at fault for their work-related injury"},{"module":"Day 5 Module 2","group":"mc-wc","topic":"Workers\' Compensation","explanation":"Employers can meet their WC obligation through a state program, a private insurer, or self-insurance.","question":"Employers may provide workers\' compensation coverage through all of the following EXCEPT:","options":["Deducting premiums from employee paychecks","A state program","A private insurer","Self-insurance"],"answer":"Deducting premiums from employee paychecks"},{"module":"Day 5 Module 3","group":"mc-medigap","topic":"Medigap Open Enrollment","explanation":"Medigap plans are standardized by letter. The 6-month open enrollment starts when a person is 65+ AND enrolled in Part B — guaranteed issue, no underwriting. Florida allows a 30-day free look.","question":"Ruth turned 65 and enrolled in Part B this month. Her guaranteed-issue window to buy any Medigap policy lasts:","options":["6 months","30 days","12 months","Until age 70"],"answer":"6 months"},{"module":"Day 5 Module 3","group":"mc-medigap","topic":"Medigap Open Enrollment","explanation":"Medigap plans are standardized by letter. The 6-month open enrollment starts when a person is 65+ AND enrolled in Part B — guaranteed issue, no underwriting. Florida allows a 30-day free look.","question":"Which statement about Medicare supplement (Medigap) plans is TRUE?","options":["Benefits for a given lettered plan are identical no matter which insurer sells it","Each insurer designs its own unique benefits","They replace Medicare entirely","They include long-term custodial care"],"answer":"Benefits for a given lettered plan are identical no matter which insurer sells it"},{"module":"Day 5 Module 3","group":"mc-ltctrigger","topic":"LTC Benefit Triggers","explanation":"LTC benefits trigger on inability to perform 2 of 6 ADLs (bathing, dressing, eating, transferring, toileting, continence) or cognitive impairment.","question":"Long-term care policy benefits are typically triggered when the insured cannot perform:","options":["Two of six activities of daily living, or has cognitive impairment","Any one household chore","All six activities of daily living","Gainful employment of any kind"],"answer":"Two of six activities of daily living, or has cognitive impairment"},{"module":"Day 5 Module 3","group":"mc-ltctrigger","topic":"LTC Benefit Triggers","explanation":"LTC benefits trigger on inability to perform 2 of 6 ADLs (bathing, dressing, eating, transferring, toileting, continence) or cognitive impairment.","question":"Which of the following is an activity of daily living (ADL) used in LTC benefit triggers?","options":["Bathing","Driving","Cooking","Managing finances"],"answer":"Bathing"},{"module":"Day 5 Module 3","group":"mc-ltccare","topic":"Levels of LTC Care","explanation":"Skilled = daily medical care by professionals; intermediate = occasional skilled care; custodial = help with daily living, the most common need — and NOT covered by Medicare.","question":"Help with bathing, dressing, and eating provided by aides without medical training is called:","options":["Custodial care","Skilled nursing care","Intermediate care","Acute care"],"answer":"Custodial care"},{"module":"Day 5 Module 3","group":"mc-ltccare","topic":"Levels of LTC Care","explanation":"Skilled = daily medical care by professionals; intermediate = occasional skilled care; custodial = help with daily living, the most common need — and NOT covered by Medicare.","question":"Which statement about Medicare and long-term care is TRUE?","options":["Medicare does NOT cover custodial care — the most common long-term care need","Medicare covers unlimited nursing home stays","Medicare Part D covers custodial care","Medicare covers custodial care after a 3-day hospital stay"],"answer":"Medicare does NOT cover custodial care — the most common long-term care need"},{"module":"Day 5 Module 3","group":"mc-partner","topic":"Florida LTC Partnership","explanation":"Florida\'s LTC Partnership lets buyers of qualifying policies protect assets equal to benefits paid when later applying for Medicaid. LTC policies must be at least guaranteed renewable; FL free look is 30 days.","question":"Esme\'s Florida Partnership LTC policy paid $200,000 in benefits before she applied for Medicaid. The Partnership program lets her:","options":["Protect $200,000 of assets from Medicaid spend-down requirements","Skip Medicaid\'s income test entirely","Transfer all assets to her children penalty-free","Double her Medicaid benefits"],"answer":"Protect $200,000 of assets from Medicaid spend-down requirements"},{"module":"Day 5 Module 3","group":"mc-partner","topic":"Florida LTC Partnership","explanation":"Florida\'s LTC Partnership lets buyers of qualifying policies protect assets equal to benefits paid when later applying for Medicaid. LTC policies must be at least guaranteed renewable; FL free look is 30 days.","question":"Long-term care policies sold in Florida must be at least:","options":["Guaranteed renewable","Cancellable","Optionally renewable","Annually re-underwritten"],"answer":"Guaranteed renewable"},{"module":"Day 5 Module 3","group":"mg-core","topic":"Medigap Basics","explanation":"The NAIC core policy (Plan A) covers Part A coinsurance, the first 3 pints of blood yearly, and the 20% Part B coinsurance — it does NOT cover the Part A deductible.","question":"Which of the following is NOT part of the core (Plan A) standard Medicare supplement policy?","options":["The Medicare Part A deductible","Coinsurance amounts of Medicare Part A","The first three pints of blood each year","The 20% coinsurance for Medicare-approved Part B services"],"answer":"The Medicare Part A deductible"},{"module":"Day 5 Module 3","group":"mg-core","topic":"Medigap Basics","explanation":"Medigap fills the gaps in Medicare Parts A and B. A Medicare Advantage enrollee doesn\'t need one — and selling an MA plan to a Medigap owner is ILLEGAL because it duplicates coverage.","question":"Selling a Medicare Advantage plan to someone who already owns a Medigap policy is:","options":["Illegal, because it duplicates coverage","Encouraged, for extra protection","Allowed with a signed waiver","Required by the ACA"],"answer":"Illegal, because it duplicates coverage"},{"module":"Day 5 Module 3","group":"ltc-def","topic":"LTC Fundamentals","explanation":"LTC serves people who lost full independence, with care typically extending beyond 90 days; the policy pays a SET daily benefit regardless of actual expenses.","question":"Long-term care insurance pays benefits on what basis?","options":["A set dollar amount per day of care, regardless of actual expenses","Reimbursement of all actual expenses","A percentage of the insured\'s income","Whatever Medicare doesn\'t pay"],"answer":"A set dollar amount per day of care, regardless of actual expenses"},{"module":"Day 5 Module 3","group":"ltc-def","topic":"LTC Fundamentals","explanation":"A chronic illness can be managed but not cured (diabetes, heart disease, asthma); an acute illness can be fully recovered from with care (pneumonia).","question":"A medical condition requiring ongoing care and management, such as diabetes or heart disease, is a(n):","options":["Chronic illness","Acute illness","Sudden illness","Prolonged illness"],"answer":"Chronic illness"},{"module":"Day 5 Module 3","group":"ltc-levels","topic":"Levels of LTC Care","explanation":"Skilled nursing care must be available round-the-clock (24 hours); intermediate care is provided periodically under physician supervision, not continuously.","question":"How does skilled nursing care differ from intermediate care?","options":["Skilled care is continuous 24-hour care; intermediate care is periodic","Skilled care requires no medical training","Intermediate care is only given in hospitals","Skilled care only covers bathing and dressing"],"answer":"Skilled care is continuous 24-hour care; intermediate care is periodic"},{"module":"Day 5 Module 3","group":"ltc-levels","topic":"Levels of LTC Care","explanation":"Respite care provides short-term relief for FAMILY CAREGIVERS. Adult day care supports people during the day; home health care is delivered in the home.","question":"Short-term care designed to give relief to a family member who normally cares for the insured is called:","options":["Respite care","Custodial care","Continuing care","Alternative care"],"answer":"Respite care"},{"module":"Day 5 Module 3","group":"ltc-prov","topic":"LTC Provisions & Limits","explanation":"LTC exclusions typically include drug and alcohol dependence, self-inflicted injuries, acts of war, and nonorganic mental illness. Alzheimer\'s, dementia, and Parkinson\'s ARE covered.","question":"Which condition is generally NOT covered by a long-term care policy?","options":["Alcohol dependency","Alzheimer\'s disease","Senile dementia","Parkinson\'s disease"],"answer":"Alcohol dependency"},{"module":"Day 5 Module 3","group":"ltc-prov","topic":"LTC Provisions & Limits","explanation":"Premiums depend on age and health, benefit type/level, the presence and length of an elimination period, AND riders/options — not solely on age, health, and benefit type. Policies must be guaranteed renewable; benefit periods typically run 2–6 years.","question":"Which statement about long-term care policies is NOT correct?","options":["Premiums are based solely on the insured\'s age, health, and type of benefit","Maximum coverage periods typically extend from two to six years","LTC policies must be guaranteed renewable","Longer elimination periods generally mean lower premiums"],"answer":"Premiums are based solely on the insured\'s age, health, and type of benefit"},{"module":"Day 5 Module 3","group":"ltc-group","topic":"Group LTC & Taxation","explanation":"Group LTC advantages: no individual underwriting and coverage for multiple family members. LTC benefits received are excluded from income for tax purposes.","question":"Benefits received from a long-term care policy are:","options":["Excluded from income for tax purposes","Taxed as ordinary income","Taxed at capital gains rates","Taxable above $10,000 per year"],"answer":"Excluded from income for tax purposes"},{"module":"Day 5 Module 3","group":"mc-partner","topic":"Florida LTC Partnership","explanation":"The State Partnership Program is a partnership among the STATES, the INSURANCE INDUSTRY, and INSUREDS — allowing Medicaid reimbursement without impoverishment. The insurance commissioner is not a party to the partnership.","question":"The State Partnership Program for Long-Term Care includes all of the following EXCEPT:","options":["The insurance commissioner","The states","The insurance industry","Insureds"],"answer":"The insurance commissioner"},{"module":"Next: Policy Provisions","group":"pp-grace","topic":"Grace Periods","explanation":"Florida grace periods follow the premium mode: 7 days (weekly), 10 days (monthly), 31 days (all other modes). Coverage continues during the grace period.","question":"Tessa pays her health insurance premium monthly. If she misses a payment, how long is her grace period?","options":["10 days","7 days","31 days","45 days"],"answer":"10 days"},{"module":"Next: Policy Provisions","group":"pp-grace","topic":"Grace Periods","explanation":"Florida grace periods follow the premium mode: 7 days (weekly), 10 days (monthly), 31 days (all other modes). Coverage continues during the grace period.","question":"A health policy with premiums paid quarterly has a grace period of:","options":["31 days","10 days","7 days","60 days"],"answer":"31 days"},{"module":"Next: Policy Provisions","group":"pp-reinstate","topic":"Reinstatement","explanation":"If the insurer requires a reinstatement application and gives a conditional receipt, the policy reinstates automatically on the 45th day unless disapproved in writing. A reinstated policy covers accidents immediately but sickness only after 10 days.","question":"Omar applied to reinstate his lapsed health policy and received a conditional receipt. The insurer never responded. His policy is automatically reinstated after:","options":["45 days","10 days","31 days","90 days"],"answer":"45 days"},{"module":"Next: Policy Provisions","group":"pp-reinstate","topic":"Reinstatement","explanation":"If the insurer requires a reinstatement application and gives a conditional receipt, the policy reinstates automatically on the 45th day unless disapproved in writing. A reinstated policy covers accidents immediately but sickness only after 10 days.","question":"Three days after his policy was reinstated, Felix came down with pneumonia. Five days after reinstatement, he broke his wrist. What does the reinstated policy cover?","options":["The broken wrist, but not the pneumonia — sickness is covered only after 10 days","Both losses in full","Neither loss for 31 days","The pneumonia, but not the wrist"],"answer":"The broken wrist, but not the pneumonia — sickness is covered only after 10 days"},{"module":"Next: Policy Provisions","group":"pp-claims","topic":"The Claims Clock","explanation":"Claims deadlines in order: notice of claim 20 days → insurer sends forms within 15 days → proof of loss within 90 days → payment immediately (DI at least monthly) → legal action no sooner than 60 days, up to 5 years in Florida.","question":"After a loss, the insured must give the insurer notice of claim within:","options":["20 days","15 days","90 days","60 days"],"answer":"20 days"},{"module":"Next: Policy Provisions","group":"pp-claims","topic":"The Claims Clock","explanation":"Claims deadlines in order: notice of claim 20 days → insurer sends forms within 15 days → proof of loss within 90 days → payment immediately (DI at least monthly) → legal action no sooner than 60 days, up to 5 years in Florida.","question":"If the insurer fails to send claim forms within 15 days of notice, the insured:","options":["May submit proof of loss in any written form","Loses the right to claim","Must wait 90 days and renotify","Automatically wins the claim"],"answer":"May submit proof of loss in any written form"},{"module":"Next: Policy Provisions","group":"pp-proof","topic":"Proof of Loss","explanation":"Proof of loss is due within 90 days of the loss; legal action must wait at least 60 days after proof and, in Florida, may be brought up to 5 years.","question":"Written proof of loss must generally be furnished to the insurer within:","options":["90 days of the loss","20 days of the loss","15 days of the loss","12 months of the loss"],"answer":"90 days of the loss"},{"module":"Next: Policy Provisions","group":"pp-proof","topic":"Proof of Loss","explanation":"Proof of loss is due within 90 days of the loss; legal action must wait at least 60 days after proof and, in Florida, may be brought up to 5 years.","question":"How long after submitting proof of loss must an insured wait before filing a lawsuit against the insurer?","options":["60 days","20 days","90 days","5 years"],"answer":"60 days"},{"module":"Next: Policy Provisions","group":"pp-defenses","topic":"Incontestability","explanation":"After 2 years, the insurer cannot void the policy or deny claims based on application misstatements — except fraudulent ones. Misstated age just adjusts the benefit.","question":"Under the time limit on certain defenses provision, an insurer cannot deny a claim due to misstatements on the application after:","options":["2 years, unless the misstatement was fraudulent","1 year, without exception","5 years, unless premiums lapsed","6 months, unless sickness-related"],"answer":"2 years, unless the misstatement was fraudulent"},{"module":"Next: Policy Provisions","group":"pp-defenses","topic":"Incontestability","explanation":"After 2 years, the insurer cannot void the policy or deny claims based on application misstatements — except fraudulent ones. Misstated age just adjusts the benefit.","question":"The insurer discovers the insured understated her age on the application. Under the misstatement of age provision, the insurer will:","options":["Adjust benefits to what the premium would have purchased at her true age","Void the policy retroactively","Deny all pending claims","Cancel the policy with 45 days notice"],"answer":"Adjust benefits to what the premium would have purchased at her true age"},{"module":"Next: Policy Provisions","group":"pp-freelook","topic":"Free Look Periods","explanation":"Florida health policies carry a 10-day free look; Medicare supplement and long-term care policies carry 30 days. The clock starts at delivery.","question":"In Florida, the free look period for a standard individual health policy and for a Medicare supplement policy are, respectively:","options":["10 days and 30 days","30 days and 10 days","10 days and 10 days","31 days and 45 days"],"answer":"10 days and 30 days"},{"module":"Next: Policy Provisions","group":"pp-freelook","topic":"Free Look Periods","explanation":"Florida health policies carry a 10-day free look; Medicare supplement and long-term care policies carry 30 days. The clock starts at delivery.","question":"Nadia\'s long-term care policy was delivered on March 1. How long does she have to return it for a full refund?","options":["30 days from delivery","10 days from delivery","45 days from issue","No return is permitted"],"answer":"30 days from delivery"},{"module":"Next: Policy Provisions","group":"pp-entire","topic":"Entire Contract","explanation":"The policy plus attached application form the entire contract. Only an executive officer of the insurer — never the agent — may modify it.","question":"Who has the authority to modify the terms of an issued health insurance policy?","options":["An executive officer of the insurer","The selling agent","The policyowner\'s attorney","Any licensed adjuster"],"answer":"An executive officer of the insurer"},{"module":"Next: Policy Provisions","group":"pp-entire","topic":"Entire Contract","explanation":"The policy plus attached application form the entire contract. Only an executive officer of the insurer — never the agent — may modify it.","question":"The entire contract provision states that the contract consists of:","options":["The policy and the attached application","The policy, the agent\'s notes, and any verbal promises","The application alone","The policy and the insurer\'s underwriting file"],"answer":"The policy and the attached application"},{"module":"Next: Policy Provisions","group":"pp-riders","topic":"Exclusion Riders","explanation":"An impairment (exclusion) rider removes a named preexisting condition from coverage, letting an otherwise uninsurable applicant obtain a policy.","question":"Dimitri has a chronic knee condition. The insurer offers him a policy that covers everything EXCEPT that knee. This is accomplished through:","options":["An impairment (exclusion) rider","A guaranteed insurability rider","A waiver of premium rider","A cost-of-living rider"],"answer":"An impairment (exclusion) rider"},{"module":"Next: Policy Provisions","group":"pp-riders","topic":"Exclusion Riders","explanation":"An impairment (exclusion) rider removes a named preexisting condition from coverage, letting an otherwise uninsurable applicant obtain a policy.","question":"The rider that allows an insured to purchase additional coverage later without evidence of insurability is the:","options":["Guaranteed insurability rider","Impairment rider","Multiple indemnity rider","Probationary rider"],"answer":"Guaranteed insurability rider"},{"module":"Next: Group Health & COBRA","group":"gh-group","topic":"Group Plan Mechanics","explanation":"Group insurance: the employer holds the master contract, employees get certificates, and eligible employees who enroll on time face no individual underwriting.","question":"In a group health plan, individual employees receive:","options":["Certificates of insurance under the employer\'s master contract","Their own individual policies","Copies of the master contract to sign","Conditional receipts"],"answer":"Certificates of insurance under the employer\'s master contract"},{"module":"Next: Group Health & COBRA","group":"gh-group","topic":"Group Plan Mechanics","explanation":"Group insurance: the employer holds the master contract, employees get certificates, and eligible employees who enroll on time face no individual underwriting.","question":"An eligible employee who enrolls in the group plan during the enrollment period:","options":["Cannot be required to prove individual insurability","Must pass a physical exam","Must provide an attending physician statement","Is underwritten individually like any applicant"],"answer":"Cannot be required to prove individual insurability"},{"module":"Next: Group Health & COBRA","group":"gh-cobra","topic":"COBRA Durations","explanation":"COBRA (employers with 20+ employees): 18 months for termination/reduced hours, 29 months if disabled, 36 months for dependent events (death, divorce, Medicare entitlement, child aging out). Premium may be up to 102%.","question":"Priscilla quit her job at a 200-employee firm. Under COBRA she may continue her group coverage for up to:","options":["18 months","29 months","36 months","12 months"],"answer":"18 months"},{"module":"Next: Group Health & COBRA","group":"gh-cobra","topic":"COBRA Durations","explanation":"COBRA (employers with 20+ employees): 18 months for termination/reduced hours, 29 months if disabled, 36 months for dependent events (death, divorce, Medicare entitlement, child aging out). Premium may be up to 102%.","question":"After her divorce from a covered employee, Renata may continue group coverage under COBRA for up to:","options":["36 months","18 months","29 months","60 months"],"answer":"36 months"},{"module":"Next: Group Health & COBRA","group":"gh-cobra102","topic":"COBRA Premium","explanation":"COBRA continuants pay their own premium, which may be up to 102% of the group rate — the extra 2% covers administration.","question":"A COBRA continuant may be charged up to what percentage of the group premium?","options":["102%","100%","150%","115%"],"answer":"102%"},{"module":"Next: Group Health & COBRA","group":"gh-cobra102","topic":"COBRA Premium","explanation":"COBRA continuants pay their own premium, which may be up to 102% of the group rate — the extra 2% covers administration.","question":"Under COBRA, the cost of continued coverage is paid by:","options":["The former employee or beneficiary, at up to 102% of the group rate","The employer, as a severance benefit","The state continuation fund","Medicare"],"answer":"The former employee or beneficiary, at up to 102% of the group rate"},{"module":"Next: Group Health & COBRA","group":"gh-flcont","topic":"Florida Continuation","explanation":"Florida\'s Health Insurance Coverage Continuation Act (§627.6692) gives employees of small employers (under 20 employees) continuation rights — generally 18 months — where federal COBRA doesn\'t apply.","question":"Jonas works for a 12-person company in Florida and loses his job. His group continuation rights come from:","options":["Florida\'s Health Insurance Coverage Continuation Act — federal COBRA doesn\'t apply to employers under 20","Federal COBRA","ERISA preemption","The ACA employer mandate"],"answer":"Florida\'s Health Insurance Coverage Continuation Act — federal COBRA doesn\'t apply to employers under 20"},{"module":"Next: Group Health & COBRA","group":"gh-flcont","topic":"Florida Continuation","explanation":"Florida\'s Health Insurance Coverage Continuation Act (§627.6692) gives employees of small employers (under 20 employees) continuation rights — generally 18 months — where federal COBRA doesn\'t apply.","question":"Federal COBRA applies to employers with at least how many employees?","options":["20","2","50","100"],"answer":"20"},{"module":"Next: Group Health & COBRA","group":"gh-cob","topic":"Coordination of Benefits","explanation":"COB prevents collecting more than 100% across two plans. The employee\'s own plan is primary; for dependent children, the birthday rule makes the plan of the parent with the earlier birthday in the calendar year primary.","question":"Both of Mia\'s parents cover her under their group plans. Dad\'s birthday is March 3; Mom\'s is January 28 (Dad is older). Which plan is primary for Mia?","options":["Mom\'s — her birthday falls earlier in the calendar year","Dad\'s — he is older","Whichever plan has higher benefits","Both pay 50% each"],"answer":"Mom\'s — her birthday falls earlier in the calendar year"},{"module":"Next: Group Health & COBRA","group":"gh-cob","topic":"Coordination of Benefits","explanation":"COB prevents collecting more than 100% across two plans. The employee\'s own plan is primary; for dependent children, the birthday rule makes the plan of the parent with the earlier birthday in the calendar year primary.","question":"The purpose of the coordination of benefits provision is to:","options":["Prevent the insured from collecting more than 100% of a claim across multiple plans","Increase total benefits for two-income families","Let insurers split commissions","Guarantee dual coverage for dependents"],"answer":"Prevent the insured from collecting more than 100% of a claim across multiple plans"},{"module":"Next: Group Health & COBRA","group":"gh-convert","topic":"Conversion Privilege","explanation":"An employee leaving a group has 31 days to convert to an individual policy without proving insurability — at individual (higher) rates.","question":"After leaving the group, an employee may convert to an individual policy without evidence of insurability within:","options":["31 days","10 days","60 days","6 months"],"answer":"31 days"},{"module":"Next: Group Health & COBRA","group":"gh-convert","topic":"Conversion Privilege","explanation":"An employee leaving a group has 31 days to convert to an individual policy without proving insurability — at individual (higher) rates.","question":"Which statement about group conversion is TRUE?","options":["No proof of insurability is required, but the individual premium will be higher than the group rate","The group rate is locked in for life","A physical exam is always required","Conversion is available only to disabled employees"],"answer":"No proof of insurability is required, but the individual premium will be higher than the group rate"},{"module":"Day 7 Module 1","group":"d7m1-license-action","topic":"License Suspension","explanation":"Selling a replacement policy that causes a lapse is NOT automatic grounds for suspension — replacement is legal when done with proper disclosure. All other options (misrepresenting financial condition, obtaining a license solely for controlled business, demonstrating incompetency) ARE grounds for license action.","question":"Which of the following actions would NOT result in an agent\'s license being suspended?","options":["Misrepresenting an insurer\'s financial condition","Selling a replacement policy that causes an insured to lapse an existing policy","Obtaining a license for the sole purpose of handling-controlled business","Demonstrating incompetency to transact business as an insurance agent"],"answer":"Selling a replacement policy that causes an insured to lapse an existing policy"},{"module":"Day 7 Module 1","group":"d7m1-defamation","topic":"Defamation","explanation":"Defamation by definition IS maliciously critical. If a statement is \'not meant to be maliciously critical,\' it does NOT meet the definition of defamation — making this the correct answer for what is NOT a condition.","question":"Which of the following is not a condition of defamation?","options":["It may be derogatory.","It is not meant to be maliciously critical.","It can be written (libel).","It can be spoken (slander)."],"answer":"It is not meant to be maliciously critical."},{"module":"Day 7 Module 1","group":"d7m1-flahiga","topic":"Guaranty Association","explanation":"FLAHIGA covers annuity, health, and Medicare supplement contracts. Insurance contracts issued by fraternal benefit societies are specifically excluded from coverage.","question":"Which of the following insurance contracts does the State Life and Health Guarantee Association NOT cover?","options":["Annuity contracts","Health insurance contracts","Insurance contracts issued by fraternal benefit societies","Medicare supplement contracts"],"answer":"Insurance contracts issued by fraternal benefit societies"},{"module":"Day 7 Module 1","group":"d7m1-rebating","topic":"Rebating","explanation":"Rebates cannot be given at the agent\'s discretion to \'special\' policyowners. In Florida, rebates must follow strict rules: available to all in the same actuarial class, from the agent\'s commission, per a filed schedule.","question":"Which of the following descriptions of rebating is FALSE?","options":["Rebating is a form of unfair competition","Readjustment of a premium rate for a group insurance policy based on loss or expense","Rebates can be given to special policyowners at the agent\'s discretion","Issuing disability insurance policies on a payroll deduction at a reduced rate"],"answer":"Rebates can be given to special policyowners at the agent\'s discretion"},{"module":"Day 7 Module 1","group":"d7m1-ce","topic":"Continuing Education","explanation":"For licensees with fewer than 6 years, 24 hours of CE are required, including a 4-hour law and ethics update. The question asks what \'percentage\' (or number) of hours — the answer is 3 (referring to the answer option format in the self-assessment).","question":"If a licensee has had their license for fewer than six years, they must fulfill a mandatory 24-hour continuing education course. What percentage of those hours are needed for law and ethics?","options":["5","3","4","1"],"answer":"3"},{"module":"Day 7 Module 1","group":"d7m1-agent-broker","topic":"Agent vs. Broker","explanation":"Brokers represent the client (applicant/insured) and shop the market on their behalf. Agents represent the insurer (the company). This is the fundamental distinction.","question":"What is the major difference between producers acting as agents and producers acting as brokers?","options":["Agents represent the client, and brokers represent the company.","Brokers are not required to follow the same laws and regulations as agents.","Brokers represent the client, and agents represent the company.","Brokers cannot solicit prospects for the purpose of selling insurance."],"answer":"Brokers represent the client, and agents represent the company."},{"module":"Day 7 Module 1","group":"d7m1-controlled","topic":"Controlled Business","explanation":"Controlled business includes writing on self, family, officers, directors, partners, stockholders, or employees. A neighbor is none of these — writing business on a neighbor is regular business, not controlled.","question":"Which of these doesn\'t fit the definition of a controlled business?","options":["An agent writing business solely on his family","An agent writing business on his partner","An agent writing business on his employees","An agent writing business on his neighbor"],"answer":"An agent writing business on his neighbor"},{"module":"Day 7 Module 1","group":"d7m1-true-statements","topic":"Agent Rules Composite","explanation":"All four statements are true: record retention is 5 years, only licensed/appointed agents may collect commissions, a fiduciary holds a position of special trust, and elder abuse revocation (65+) is permanent.","question":"Which statement(s) is/are true?\\nI – Record retention requirements for agents is five years\\nII - No person other than a licensed and appointed agent may accept any commission or other valuable compensation for soliciting and negotiating insurance.\\nIII – A fiduciary is a person in a position of special trust and confidence.\\nIV – If a license as an agent has been revoked from soliciting or sale of insurance products to a person over 65 years of age or older, the department may not thereafter grant or issue any insurance license to such individual.","options":["I","I, II, and III","IV","I, II, III, and IV"],"answer":"I, II, III, and IV"},{"module":"Day 7 Module 1","group":"d7m1-rebating","topic":"Rebating","explanation":"In Florida, rebating is legal under §626.572 but ONLY if the rebate is available to all in the same actuarial class and the insurer does not prohibit it. Giving rebates from an insurer that prohibits rebating is incorrect.","question":"Which of the following statements concerning rebating is not correct?","options":["The rebate must be available to all insureds in the same actuarial class.","The percentage of rebate cannot discriminate.","Rebates should be given to insureds who purchase a policy from an insurer that prohibits rebating.","Rebating is legal in Florida."],"answer":"Rebates should be given to insureds who purchase a policy from an insurer that prohibits rebating."},{"module":"Day 7 Module 1","group":"d7m1-agent-broker","topic":"Agent vs. Broker","explanation":"Brokers represent the client and agents represent the company. This is the fundamental distinction between the two producer roles.","question":"What distinguishes producers operating as brokers from producers functioning as agents?","options":["Agents represent the client, and brokers represent the company.","Brokers are not required to follow the same laws and regulations as agents.","Brokers represent the client, and agents represent the company.","Brokers cannot solicit prospects for the purpose of selling insurance."],"answer":"Brokers represent the client, and agents represent the company."},{"module":"Day 7 Module 1","group":"d7m1-sliding","topic":"Sliding","explanation":"Sliding occurs when an insurance policy is started, carried out, bound, or issued without the property owner\'s prior informed consent — charging for or attaching products the buyer did not agree to purchase.","question":"The following occurs when an insurance policy is started, carried out, bound, or issued in any other way without the owner of the property to be insured\'s prior informed consent.","options":["excess charges","sliding","rebating","excess insurance"],"answer":"sliding"},{"module":"Day 7 Module 1","group":"d7m1-licensing","topic":"Producer Licensing","explanation":"To be a licensed resident producer in Florida, you must provide a background check, finish pre-licensing education, and provide required information. The application fee is NONREFUNDABLE, not refundable.","question":"To be a licensed resident producer in Florida, you must complete all the following tasks EXCEPT _____.","options":["provide a criminal background check","pay a refundable application fee","finish the pre-licensing education requirements","provide any other information required by the state"],"answer":"pay a refundable application fee"},{"module":"Day 7 Module 1","group":"d7m1-flahiga","topic":"Guaranty Association","explanation":"FLAHIGA covers annuity, health, and Medicare supplement contracts. Fraternal benefit societies are specifically excluded.","question":"Which insurance agreements are NOT covered by the State Life and Health Guarantee Association?","options":["Annuity contracts","Health insurance contracts","Insurance contracts issued by fraternal benefit societies","Medicare supplement contracts"],"answer":"Insurance contracts issued by fraternal benefit societies"},{"module":"Day 7 Module 1","group":"d7m1-controlled","topic":"Controlled Business","explanation":"Controlled business includes self, family, officers, directors, partners, stockholders, employees. A neighbor is NOT in any of these categories.","question":"Which of the following would not be considered controlled business?","options":["An agent writing business solely on his family","An agent writing business on his partner","An agent writing business on his employees","An agent writing business on his neighbor"],"answer":"An agent writing business on his neighbor"},{"module":"Day 7 Module 1","group":"d7m1-licensing","topic":"Producer Licensing","explanation":"The application fee for a Florida producer license is nonrefundable. All other requirements listed are accurate.","question":"With one exception, you need to do all of the following in order to obtain a Florida resident producer license: _____.","options":["provide a criminal background check","pay a refundable application fee","finish the pre-licensing education requirements","provide any other information required by the state"],"answer":"pay a refundable application fee"},{"module":"Day 7 Module 1","group":"d7m1-notification","topic":"Notification Requirements","explanation":"Statement I (30-day address change notification) and IV (4-year non-appointment terminates license) are true. The change of company notification is not specifically a 30-day requirement to DFS, and 1-year non-appointment does NOT cause licensure loss (it\'s 4 years).","question":"Which statement(s) is/are true?\\nI - Notification to the Department of Insurance is required within 30 days of change of address.\\nII - Notification to the Department of Insurance is required within 30 days of change of company.\\nIII - An agent will lose licensure as a result of 1-year non-appointment.\\nIV - An agent will lose licensure as a result of 4 years non-appointment.","options":["I","I, II, and III","IV","I and IV"],"answer":"I and IV"},{"module":"Day 7 Module 1","group":"d7m1-definitions","topic":"Agency Definition","explanation":"The term \'agency\' encompasses agents, adjusters, and locations — all of the above.","question":"The term agency refers to which of the following?","options":["Agent","Adjuster","Location","All of the above"],"answer":"All of the above"},{"module":"Day 7 Module 1","group":"d7m1-controlled","topic":"Controlled Business Threshold","explanation":"An agent may write controlled business provided she writes at least 75% of other similar (non-controlled) business.","question":"An agent may write controlled business provided she writes at least what percentage of other similar business?","options":["25%","50%","75%","100%"],"answer":"75%"},{"module":"Day 7 Module 1","group":"d7m1-license-action","topic":"License Grounds","explanation":"All three are grounds for license refusal, revocation, or suspension: failing to pay insurer money, violating twisting provisions, and willfully overinsuring.","question":"Which of the following are grounds for an agent\'s license to be refused, revoked, or suspended?","options":["Failing to pay to an insurer any money belonging to the insurer","Violating the provision against twisting","Willfully over insuring any property or health risk","All the above"],"answer":"All the above"},{"module":"Day 7 Module 1","group":"d7m1-true-statements","topic":"Agent Rules Composite","explanation":"All four statements are true: 5-year record retention, only licensed agents collect commissions, fiduciary = special trust, and elder abuse revocation is permanent.","question":"Which claim or claims are true?\\nI – Record retention requirements for agents is five years\\nII - No person other than a licensed and appointed agent may accept any commission or other valuable compensation for soliciting and negotiating insurance.\\nIII – A fiduciary is a person in a position of special trust and confidence.\\nIV – If a license as an agent has been revoked from soliciting or sale of insurance products to a person over 65 years of age or older, the department may not thereafter grant or issue any insurance license to such individual.","options":["I","I, II, and III","IV","I, II, III, and IV"],"answer":"I, II, III, and IV"},{"module":"Day 7 Module 1","group":"d7m1-distribution","topic":"Distribution Systems","explanation":"The direct selling system sells policies by mail, phone, and internet without agents or brokers. The other three systems all involve agents or brokers.","question":"Which of the following does NOT support the sale of insurance through agents and brokers?","options":["Independent agency system","Personal producing general agency system","Career agency system","Direct selling system"],"answer":"Direct selling system"},{"module":"Day 7 Module 1","group":"d7m1-regulation","topic":"Regulation History","explanation":"The FTC does NOT directly supervise the marketing techniques of all insurance companies. Insurance regulation is a state function under McCarran-Ferguson.","question":"Which statement below does NOT indicate landmark cases and laws involving the regulation of insurance?","options":["When an applicant\'s consumer or credit history is being investigated, insurers are required to disclose this information to the applicant.","The NAIC has standing committees working regularly to examine numerous aspects of the insurance industry.","The Federal Trade Commission (FTC) directly supervises the marketing techniques of all insurance companies.","The McCarran-Ferguson Act laid the basis for our current understanding that state governments are the primary regulators of the insurance industry."],"answer":"The Federal Trade Commission (FTC) directly supervises the marketing techniques of all insurance companies."},{"module":"Day 7 Module 1","group":"d7m1-rrg","topic":"Risk Retention Group","explanation":"An RRG is formed by members of the same business, occupation, or profession (e.g., pharmacists) to insure their shared liability risks.","question":"Which of the following is an example of a risk retention group (RRG)?","options":["Labor unions","A group of pharmacists","A local church","NAIFA"],"answer":"A group of pharmacists"},{"module":"Day 7 Module 1","group":"d7m1-advertising","topic":"Advertising Code","explanation":"The Advertising Code contains rules about testimonials, statistics, and special offers in insurance marketing.","question":"Rules pertaining to testimonials, statistics, and special offers would be found in ______.","options":["the policy summary","the entire contract","the Advertising Code","the Buyers Guide"],"answer":"the Advertising Code"},{"module":"Day 7 Module 1","group":"d7m1-appointment","topic":"License Termination","explanation":"An agent\'s license terminates after 4 years (48 months) without an appointment.","question":"An agent\'s license will terminate if he or she allows ______ years to pass without an appointment.","options":["one","four","two","eight"],"answer":"four"},{"module":"Day 7 Module 1","group":"d7m1-utpa","topic":"Unfair Trade Practices Act","explanation":"The Unfair Trade Practices Act gives the state the authority to fine, issue cease and desist orders, and impose penalties.","question":"The ______ gives the state their ability to fine, issue cease and desist orders, and impose penalties.","options":["Unfair Trade Practices Act","National Association of Health Underwriters (NAHU)","State Guaranty Associations","The McCarran-Ferguson Act"],"answer":"Unfair Trade Practices Act"},{"module":"Day 7 Module 1","group":"d7m1-contracts","topic":"Valued Contracts","explanation":"Medical expense policies are indemnity/reimbursement contracts that pay actual expenses, NOT valued contracts. Life insurance, disability income, and AD&D are valued contracts.","question":"Which of the following are NOT valued contracts?","options":["Life insurance","Disability income insurance","Accidental Death & Dismemberment","Medical Expense policies"],"answer":"Medical Expense policies"},{"module":"Day 7 Module 1","group":"d7m1-contracts","topic":"Aleatory Contracts","explanation":"An aleatory contract involves unequal exchanges — Mary pays $1,500 annually for $250,000 in potential benefits. Both parties accept this element of chance.","question":"Mary pays a premium of $1500 annually for benefits of $250,000 worth of life insurance. This scenario describes what insurance feature?","options":["Unilateral","Aleatory","Adhesion","Conditional"],"answer":"Aleatory"},{"module":"Day 7 Module 1","group":"d7m1-beneficiary","topic":"Common Disaster","explanation":"Under the Uniform Simultaneous Death Act, when the insured and primary beneficiary die in a common disaster and it\'s impossible to determine who died first, benefits go to the contingent (secondary) beneficiary.","question":"Bill Wilson has a life insurance policy and has named his brother Kenneth Wilson as the primary beneficiary. The secondary beneficiary is Mary, Kenneth\'s wife. Bill and Kenneth were riding in a car with Mary. Both Bill and Kenneth died in the car crash. Mary was the only survivor. Who will receive the life insurance proceeds?","options":["The insurance does not go to anyone because we don\'t know who died first.","Mary will receive the proceeds as the secondary or contingent beneficiary.","We have to look at Kenneth\'s estate to see who will receive the proceeds.","No one because the insured and the beneficiary have passed away."],"answer":"Mary will receive the proceeds as the secondary or contingent beneficiary."},{"module":"Day 7 Module 1","group":"d7m1-contracts","topic":"Subrogation","explanation":"Subrogation — the insurer acquiring the insured\'s rights against liable third parties — is found in indemnity contracts (property, health), not valued contracts like life insurance.","question":"The \\"right of subrogation\\" means the insurance company may acquire the insured\'s rights against liable third parties, those that may have contributed to the loss if a claim is paid. This could be found in which type of contract?","options":["A life insurance contract","A valued contract","Disability contracts","Indemnity contracts"],"answer":"Indemnity contracts"},{"module":"Day 7 Module 1","group":"d7m1-contracts","topic":"Unilateral Contract","explanation":"A unilateral contract is one where only one party (the insurer) makes an enforceable promise. The insured is not legally obligated to pay premiums.","question":"Which of the following is a contract where only one party is liable in court?","options":["Aleatory","Unilateral","Conditional","Adhesion"],"answer":"Unilateral"},{"module":"Day 7 Module 1","group":"d7m1-insurable-interest","topic":"Insurable Interest","explanation":"A policy obtained by a person WITHOUT insurable interest in the insured CANNOT be enforced — it is void. Insurable interest must exist at the time of application for life insurance.","question":"Identify which statement is incorrect regarding insurable interest.","options":["Insurable interest exists when the applicant is the insured.","A policy obtained by a person without insurable interest in the insured can be enforced.","The applicant must be subject to loss upon the death, illness, or disability of the insured.","With the exception of a minor, the person to be insured must give consent before a policy is issued."],"answer":"A policy obtained by a person without insurable interest in the insured can be enforced."},{"module":"Day 7 Module 1","group":"d7m1-solicitation","topic":"Solicitation","explanation":"Solicitation includes extending invitations, making recommendations, comparing products, providing advice, and explaining coverages — all of the above.","question":"Identify which of the following is included in the solicitation of insurance.","options":["Extending an invitation to prospective purchasers to enter a contract for an insurance product.","Making recommendations concerning insurance products.","Comparing various insurance products, providing advice on insurance matters, or explaining policies or coverages.","All of the above"],"answer":"All of the above"},{"module":"Day 7 Module 1","group":"d7m1-rebating","topic":"Rebating Example","explanation":"An agent giving tickets to a sporting event as an inducement to purchase a policy is rebating — offering something of value to influence a sale.","question":"An agent giving his client four tickets to a sporting event for purchasing a policy is an example of ______.","options":["rebating","twisting","replacement","churning"],"answer":"rebating"},{"module":"Day 7 Module 1","group":"d7m1-presentation","topic":"Product Presentation","explanation":"Pressure is NOT part of a proper product presentation. Education, discussion, and full disclosure are the cornerstones of ethical selling.","question":"Which of the following is NOT involved in the product presentation?","options":["Pressure","Education","Discussion","Full Disclosure"],"answer":"Pressure"},{"module":"Day 7 Module 1","group":"d7m1-presentation","topic":"Producer Education","explanation":"The producer should educate the applicant on accuracy, meanings of terms, and why information is required. How the DFS works with the CFO is not part of client education.","question":"The producer should educate the applicant on all the following EXCEPT ______.","options":["the need for accuracy and honesty","meanings of various terms such as waiver of premiums, etc.","why information is required","how the DFS works with the CFO"],"answer":"how the DFS works with the CFO"},{"module":"Day 7 Module 1","group":"d7m1-presentation","topic":"Misrepresentation in Selling","explanation":"Serious problems of misrepresentation are most likely to occur during the presentation of recommendations, when agents may overstate benefits or make unsupported claims.","question":"In the selling process, when are serious problems of misrepresentation likely to occur?","options":["Approach","Presentation of recommendations","Fact-finding and needs analysis","Policy delivery and ongoing service"],"answer":"Presentation of recommendations"},{"module":"Day 7 Module 1","group":"d7m1-underwriting","topic":"Rating and Rejection","explanation":"All the listed items apply to rating and rejection — explaining how the underwriter rated the policy, knowing if it was unfavorable and why, and explaining if additional information is needed.","question":"The producers have as much information as possible on the rating and rejection of the policy. Which of the following does not apply to the rating and rejection?","options":["They need to explain how the underwriter rated the policy.","They need to know if it was unfavorable and why.","They need to explain if additional information is needed.","All the above are correct"],"answer":"All the above are correct"},{"module":"Day 7 Module 1","group":"d7m1-health-contracts","topic":"Valued Health Contracts","explanation":"A valued contract pays a stated amount. A disability income policy paying a stated monthly amount is a valued contract.","question":"What type of health insurance contract would agree to pay a stated amount each month to the insured if he or she becomes totally disabled?","options":["Participating contracts","Valued contracts","Inclusive contracts","Reimbursement contracts"],"answer":"Valued contracts"},{"module":"Day 7 Module 1","group":"d7m1-health-basics","topic":"Basic Health Insurance","explanation":"The three basic forms of health insurance are medical expense, disability income, and AD&D. \'Limited pay health\' is not a recognized basic form of health insurance coverage.","question":"Three of the following are examples of a basic form of health insurance. Which one is NOT a basic form of health insurance coverage?","options":["Medical expense","Limited pay health","Disability income","Accidental death and dismemberment"],"answer":"Limited pay health"},{"module":"Day 7 Module 1","group":"d7m1-noncancellable","topic":"Noncancellable Policies","explanation":"A noncancellable policy means the insurer CANNOT increase the premium rate after the policy is in effect. The statement about increasing premiums by class describes a guaranteed renewable policy, not a noncancellable one.","question":"Choose the UNTRUE statement about noncancellable policies.","options":["A noncancellable policy is also called a noncancellable and guaranteed renewable policy.","The only right to cancel the noncancellable policy is for nonpayment of premiums.","The insurer may increase the premium rate after the policy is in effect provided it does so by classes of insureds.","The insurer may regain the right to cancel or not to renew when the insured reaches an age specified in the policy."],"answer":"The insurer may increase the premium rate after the policy is in effect provided it does so by classes of insureds."},{"module":"Day 7 Module 1","group":"d7m1-reserves","topic":"Health Insurance Reserves","explanation":"All statements are correct: reserves are designated for future claims, the annual statement breaks them down in detail, and the two types are premium reserves and loss reserves.","question":"Which of the following statements are true regarding health insurance companies\' reserves?","options":["They are designated for future claims.","The annual statement required by the state insurance departments breaks down a company\'s reserves in considerable detail.","Two types of health insurance reserves are premium reserves and loss reserves.","All of these are correct."],"answer":"All of these are correct."},{"module":"Day 7 Module 1","group":"d7m1-premium-factors","topic":"Health Insurance Premiums","explanation":"Morbidity (the expected rate of sickness/injury) is unique to health insurance. Life insurance uses mortality. Age, sex, and interest are common to both.","question":"In contrast to life insurance, which of the following premium factors is unique to health insurance?","options":["Age","Sex","Morbidity","Interest"],"answer":"Morbidity"},{"module":"Day 7 Module 1","group":"d7m1-health-contracts","topic":"Valued Contracts","explanation":"A valued contract pays a stated, predetermined amount when the covered event occurs, regardless of actual financial loss.","question":"What type of contract pays a stated amount in the event of loss?","options":["Reimbursement","Stated","Loss of value","Valued"],"answer":"Valued"},{"module":"Day 7 Module 1","group":"d7m1-ssdi","topic":"Social Security Disability","explanation":"Social Security Disability benefits have a 6-month (180-day) waiting period before benefits may begin.","question":"If one becomes totally disabled, Social Security Disability benefits:","options":["May begin after 30 days","May begin after 60 days","May begin after three months","May begin after six months"],"answer":"May begin after six months"},{"module":"Day 7 Module 1","group":"d7m1-self-insured","topic":"Self-Insured Plans","explanation":"TPAs, ASOs, and insurance companies can all administer self-insured plans. Actuaries calculate rates and reserves but do not administer plans.","question":"All of the following may administer self-insured plans except:","options":["Third Party Administrators - TPAs","Administrative Services Organizations - ASOs","Actuaries","Insurance Companies"],"answer":"Actuaries"},{"module":"Day 7 Module 1","group":"d7m1-managed-care","topic":"Point of Service Plans","explanation":"A POS plan combines features of HMOs and PPOs: it has a primary care physician (like an HMO) but also allows out-of-network care (like a PPO).","question":"Which of the following service providers allows for a primary care physician and out-of-network care?","options":["Health Maintenance Organization (HMO)","Preferred Provider (PPO)","Point of Service Plan (POS)","Exclusive Provider Organization (EPO)"],"answer":"Point of Service Plan (POS)"},{"module":"Day 7 Module 1","group":"d7m1-hmo","topic":"HMOs","explanation":"An insurance company may sponsor or assist an HMO by offering contractual services. HMOs are NOT insurance companies, members are not billed per service (they pay prepaid fees), and HMOs generally do NOT assess deductibles.","question":"Choose the CORRECT statement pertaining to health maintenance organizations.","options":["An HMO is an insurance company that also markets group health insurance.","Anna joined an HMO and then had a physical examination; she will be billed for the exam and each subsequent medical service as it is performed.","An insurance company may sponsor or assist an HMO by offering contractual services.","Like commercial insurers, HMOs generally assess deductibles."],"answer":"An insurance company may sponsor or assist an HMO by offering contractual services."},{"module":"Day 7 Module 1","group":"d7m1-medicare","topic":"Medicare Eligibility","explanation":"Medicare covers people 65+, those under 65 receiving Social Security disability, and those with chronic kidney problems (end-stage renal disease). Chronic liver problems do not qualify.","question":"Which of the following are eligible for Medicare benefits?\\nI - Individuals aged 65 and over\\nII - Individuals under age 65 receiving Social Security disability benefits\\nIII - Individuals with chronic liver problems\\nIV - Individuals with chronic kidney problems","options":["I, II, and III","I, II, and IV","I, III, and IV","All of the above"],"answer":"I, II, and IV"},{"module":"Day 7 Module 1","group":"d7m1-medicaid","topic":"Medicaid","explanation":"Medicaid does NOT limit financial assistance only to persons aged 65 or over. It covers eligible needy persons of all ages including children, pregnant women, individuals with disabilities, and more.","question":"Choose the INCORRECT statement pertaining to Medicaid.","options":["Medicaid provides federal matching funds to states for medical public assistance plans.","The purpose of Medicaid is to help eligible needy persons with medical assistance.","Medicaid benefits can be applied to the deductible and coinsurance amounts of Medicare.","Medicaid limits financial assistance to persons aged 65 or over who cannot afford necessary medical services."],"answer":"Medicaid limits financial assistance to persons aged 65 or over who cannot afford necessary medical services."},{"module":"Day 7 Module 1","group":"d7m1-basic-medical","topic":"Basic Medical Plans","explanation":"Basic medical plans avoid small claims and keep premiums down by imposing benefit limits — maximum daily room charges, surgical schedules, and capped miscellaneous expenses.","question":"How does a basic medical plan avoid small claims and keep the cost of premiums down?","options":["By utilizing deductibles and co-insurance","By imposing benefit limits","By paying only catastrophic medical expenses","By providing a network of physicians and hospitals"],"answer":"By imposing benefit limits"},{"module":"Day 7 Module 1","group":"d7m1-calculation","topic":"Policy Benefit Calculation","explanation":"Hospital: $50/day × 7 days = $350 (pays $50 not $80). Surgical: $500 (schedule max, not $675). Misc: $750 (policy max, not $800). Total: $350 + $500 + $750 = $1,600.","question":"Jessica has a basic hospital/surgical expense policy which provides benefits of $50 per day for up to 30 days of hospitalization and $750 for miscellaneous charges. It bases its surgical benefits on a schedule approach. Jessica is hospitalized for a severely broken leg that requires surgery. The surgical procedures have been assigned $500 by the policy, though the customary charge in the area is $600. Jessica incurs the following covered expenses:\\n$80 per day for seven days hospital charge\\n$675 for the surgical procedure\\n$800 for miscellaneous\\nHow much will Jessica\'s policy pay?","options":["$1,600","$1,700","$1,810","$2,035"],"answer":"$1,600"},{"module":"Day 7 Module 1","group":"d7m1-hospital-expense","topic":"Hospital Expense Coverage","explanation":"A basic hospital expense policy covers room and board, use of the operating room, drugs, and supplies. It does NOT cover the anesthesiologist (a physician\'s service), though it covers anesthesia supplies.","question":"A basic hospital expense policy only covers certain expenses. What is not covered?","options":["Anesthesia","Anesthesiologist","Use of the operating room","Drugs"],"answer":"Anesthesiologist"},{"module":"Day 7 Module 1","group":"d7m1-hospital-expense","topic":"Hospital Expense Plan Type","explanation":"A hospital expense policy is a fixed-rate plan that pays a specified amount per day of hospitalization.","question":"Jackie is covered under a hospital expense policy. Based on what you know about this plan, what type of plan is this?","options":["Service","Limited","Fixed-rate plan","Special risk"],"answer":"Fixed-rate plan"},{"module":"Day 7 Module 1","group":"d7m1-indemnity","topic":"Hospital Indemnity","explanation":"Hospital indemnity pays a fixed daily amount regardless of actual charges. Since it doesn\'t track actual medical costs, its premium is least affected by rising medical costs.","question":"Which type of coverage premium is least affected by an increase in medical costs?","options":["Basic Medical Expense","Hospital Indemnity","Comprehensive Medical","Major Medical"],"answer":"Hospital Indemnity"},{"module":"Day 7 Module 1","group":"d7m1-hra","topic":"Health Reimbursement Accounts","explanation":"HRAs are established by the EMPLOYER, not the employee. They are employer-funded only.","question":"Which of the following statements about health reimbursement accounts (HRAs) is correct?","options":["HRAs are established by the employer.","HRAs are established by the employee.","HRAs are established with after-tax dollars.","HRAs are the least common of high deductible health plans."],"answer":"HRAs are established by the employer."},{"module":"Day 7 Module 1","group":"d7m1-disability","topic":"Residual Disability","explanation":"Residual disability pays proportional to lost income. 40% loss of disability income × $2,500 total benefit = $1,000.","question":"Roger has a residual disability income policy and a $2,500 monthly benefit for total disability under. If he suffers a 40% loss of his disability income, how much will his benefit be?","options":["$0","$1,000","$1,500","$2,500"],"answer":"$1,000"},{"module":"Day 7 Module 1","group":"d7m1-disability","topic":"Total Disability Definition","explanation":"Total disability may be defined as inability to perform any occupation (any-occ) or inability to perform own occupation (own-occ). House-confinement is NOT a standard definition of total disability.","question":"Which of the following may normally be used as a definition of total disability?\\nI. House-confined\\nII. Inability to perform the duties of any occupation\\nIII. Inability to perform the duties of the insured\'s own occupation","options":["I only","I and II","II and III","I and III"],"answer":"II and III"},{"module":"Day 7 Module 1","group":"d7m1-disability","topic":"Probationary Period","explanation":"During the probationary period, disabilities caused by sickness are typically excluded for 15 or 30 days. Accidents are covered immediately.","question":"How long are payments typically excluded for disabilities caused by sickness during the probationary period under a disability policy?","options":["Three or five days","15 or 30 days","60 or 90 days","90 or 180 days"],"answer":"15 or 30 days"},{"module":"Day 7 Module 1","group":"d7m1-add","topic":"Accidental Means","explanation":"Under an \'accidental means\' definition, BOTH the cause and the result must be unintentional. Lorenzo intentionally jumped into the river — the cause was not accidental. The policy pays nothing.","question":"Lorenzo had a disability income policy with an \\"accidental means\\" definition. He jumped into a river and broke his back leaving him paralyzed. What course of action would the insurance company take?","options":["The policy should pay the full amount since Lorenzo\'s accident was not planned.","The policy should pay 1/2 the amount since the jump was planned but the injury was not.","The policy should pay nothing since his jump was no accident. The injury does not matter.","The policy should pay nothing since it was still in the reinstatement phase."],"answer":"The policy should pay nothing since his jump was no accident. The injury does not matter."},{"module":"Day 7 Module 1","group":"d7m1-disability","topic":"Any Occupation Definition","explanation":"The \'any occupation\' definition is MORE restrictive because the insured must be unable to perform ANY job they\'re qualified for, not just their own occupation.","question":"Under an insured\'s disability income policy \\"total disability\\" is defined as the insured\'s inability to perform the duties of any occupation with which they are qualified by education or experience. Which of the following is true about this definition?","options":["This is known as the own occupation definition and is more restrictive than other definitions.","It is the any occupation definition and is more restrictive than other definitions.","This is known as the own occupation definition and is less restrictive than other definitions.","This is the any occupation definition and is less restrictive than other definitions."],"answer":"It is the any occupation definition and is more restrictive than other definitions."},{"module":"Day 7 Module 1","group":"d7m1-disability","topic":"Disability Premium Factors","explanation":"Longer elimination period = lower premium. Shorter benefit period = lower premium. Both together = the lowest premium combination.","question":"Which of the following disability policies would have the lowest premium?","options":["A long elimination period with a long benefit period","A long elimination period with a short benefit period","A short elimination period with a long benefit period","A short elimination period with a short benefit period"],"answer":"A long elimination period with a short benefit period"},{"module":"Day 7 Module 1","group":"d7m1-add","topic":"AD&D Insurance","explanation":"Triple indemnity means 3× the principal sum. Cara\'s $40,000 policy × 3 = $120,000 for accidental death while riding as a passenger on public transportation.","question":"Choose the CORRECT example pertaining to accidental death and dismemberment insurance.","options":["Kyle has a $50,000 AD&D policy and dies unexpectedly of a heart attack. His beneficiary will receive $50,000 as the death benefit.","Cara has a $40,000 AD&D policy that pays triple indemnity. This means if she dies as a result of an accident while riding as a passenger on public transportation, her beneficiary will receive $120,000.","Jackie has an AD&D policy that pays $15,000 for the loss of one hand or foot or the sight of one eye. This $15,000 benefit is called the \\"principal sum.\\"","Eric has an AD&D policy. He is killed in an auto accident. The $30,000 his beneficiary receives as a death benefit is the policy\'s capital sum."],"answer":"Cara has a $40,000 AD&D policy that pays triple indemnity. This means if she dies as a result of an accident while riding as a passenger on public transportation, her beneficiary will receive $120,000."},{"module":"Day 7 Module 1","group":"d7m1-add","topic":"Dismemberment","explanation":"Dismemberment under AD&D policies means the complete loss of a hand, foot, or sight — or permanent loss of use. Jared\'s permanent loss of use of his right hand and arm qualifies. Taylor losing fingers except the thumb does not qualify as dismemberment.","question":"Under the typical health insurance policy, which of the following would qualify as dismemberment?\\nI. Taylor loses all the fingers on his left hand except the thumb.\\nII. Jared, is right handed and permanently loses the use of his right hand and arm in an auto accident.","options":["I only","II only","I and II","Neither I nor II"],"answer":"II only"},{"module":"Day 7 Module 1","group":"d7m1-add","topic":"Accidental Means","explanation":"Under \'accidental means,\' BOTH the cause and the result must be unintentional. Arnold intentionally dove — the cause was intentional, so under \'accidental means\' the policy pays nothing.","question":"Arnold took a dive off a boat into a crystal-clear lake, striking his head on a submerged rock. They buried him on the third day. Under an Accidental Death & Dismemberment policy, with an \\"accidental means\\" definition, what is the company\'s obligation?","options":["To pay nothing","To pay the full benefit","To return the premiums","To pay twice the amount known as double indemnity"],"answer":"To pay nothing"},{"module":"Day 7 Module 1","group":"d7m1-limited-risk","topic":"Limited Risk Policies","explanation":"A limited risk policy covers death/dismemberment from one specific named risk, such as injuries while riding in a car (travel accident).","question":"Which of the following policies would cover an accidental death or injury while riding in a car?","options":["Limited risk","Special risk","Dread disease","Long-term care"],"answer":"Limited risk"},{"module":"Day 7 Module 1","group":"d7m1-add","topic":"AD&D Benefits","explanation":"AD&D policies pay the principal sum for death and the capital sum (a percentage) for loss of a hand, foot, or sight. Losing a finger alone (without the whole hand) typically pays nothing under AD&D.","question":"Spencer has an AD&D policy that has $25,000 for the principal sum and $10,000 for the loss of a hand or foot, he gets into an accident and loses a finger. How much will his policy pay?","options":["$25,000","$10,000","nothing","$35,000"],"answer":"nothing"},{"module":"Day 7 Module 1","group":"d7m1-limited-health","topic":"Limited Health Insurance","explanation":"Limited health insurance policies provide specific, narrow benefits — such as critical illness (lump sum), travel accident, vision, or hospital indemnity. They supplement, not replace, major medical.","question":"Maria works as an HR coordinator for a growing tech company in Florida. As part of updating the employee benefits package, she reviews several optional insurance products offered by their carrier. These products include a policy that pays a lump sum if the insured is diagnosed with a serious illness, a plan that covers injuries during travel, a policy that helps pay for routine eye exams and glasses, and another that pays a fixed amount per day of hospitalization. Maria notices that these plans are not designed to replace major medical insurance but instead provide limited, specific benefits.\\nWhat type of insurance products is Maria reviewing?","options":["Comprehensive major medical policies","Limited health insurance policies","Employer sponsored retirement benefits","Managed care plans"],"answer":"Limited health insurance policies"},{"module":"Day 7 Module 1","group":"d7m1-medicare","topic":"Medicare Part B","explanation":"Medicare Part B has BOTH an annual deductible and a 20% coinsurance requirement. Both statements are true.","question":"Which of the statements below about Medicare Part B is true?","options":["There is an annual deductible.","The insured is required to pay 20% after the deductible is met.","The insured is required to pay 20% after the deductible is met, and there is an annual deductible.","There is no annual deductible, and the insured is required to pay 20% of all costs."],"answer":"The insured is required to pay 20% after the deductible is met, and there is an annual deductible."},{"module":"Day 7 Module 1","group":"d7m1-medicare","topic":"Medicare Part A","explanation":"Part A has a deductible per benefit period. Those with 40 work quarters get Part A premium-free, but everyone pays the deductible.","question":"Which is true about Part A of Medicare?","options":["The insured must pay a premium.","The insured must pay a deductible.","The insured must pay a deductible and a premium.","The insured does not have to pay a deductible or a premium."],"answer":"The insured must pay a deductible."},{"module":"Day 7 Module 1","group":"d7m1-medicare","topic":"Medicare Part B","explanation":"Medicare Part B\'s 20% coinsurance does NOT have a stop-loss (out-of-pocket maximum), meaning the insured\'s 20% share is unlimited. Part B does not cover skilled nursing, prescription drugs, or is compulsory.","question":"Which of the following is true of Medicare Part B?","options":["The 20% coinsurance does not have a stop-loss.","Medicare Part B covers skilled nursing.","Medicare Part B covers prescription drugs.","Medicare Part B is compulsory."],"answer":"The 20% coinsurance does not have a stop-loss."},{"module":"Day 7 Module 1","group":"d7m1-medicare","topic":"Medicare Facts","explanation":"Both statements are true: Part A payments go directly to the hospital (not the recipient), and Part A provides home health care and skilled nursing facility care.","question":"Which of the following statements about Medicare is true?\\nI. Payments are made directly to the hospital, not to the Medicare recipient.\\nII. Home health care benefits and skilled facility care are provided under Part A","options":["I only","II only","I and II","Neither I nor II"],"answer":"I and II"},{"module":"Day 7 Module 1","group":"d7m1-medicare","topic":"Medicare Exclusions","explanation":"Medicare Parts A and B do NOT cover routine physical exams (preventive care has limited exceptions). They do cover durable medical equipment rental, home health aides, and ambulance services.","question":"Medicare Part A and Part B do not cover which of the following?","options":["Rental of durable medical equipment","Home health aides","Ambulance","Routine physical exams"],"answer":"Routine physical exams"},{"module":"Day 7 Module 1","group":"d7m1-medicare","topic":"Medicare Part A Exclusions","explanation":"Medicare Part A does NOT cover medical equipment rental for 30 days as a standalone benefit. Part A covers inpatient care, skilled nursing, hospice, and home health care.","question":"What is not covered under Part A of Medicare?","options":["x-rays","medical equipment rental for 30 days","nursing care","medical supplies"],"answer":"medical equipment rental for 30 days"},{"module":"Day 7 Module 1","group":"d7m1-ltc","topic":"Acute vs Chronic Illness","explanation":"An acute illness is a serious condition from which a patient CAN fully recover with proper medical attention (like pneumonia). A chronic illness is ongoing and manageable but not curable (like diabetes).","question":"A (An) ______ illness is a serious condition from which a patient can fully recover with proper medical attention.","options":["chronic illness","long-term illness","acute illness","severe illness"],"answer":"acute illness"},{"module":"Day 7 Module 1","group":"d7m1-ltc","topic":"LTC Partnership Program","explanation":"The State Partnership Program includes states, the insurance industry, and insureds. The Insurance Commissioner is NOT a named participant in the partnership plan.","question":"The State Partnership Program for Long-Term Care allows individuals to access Medicaid reimbursement without impoverishing themselves. Who is not included in this partnership plan?","options":["States","Insurance industry","Insurance commissioner","Insureds"],"answer":"Insurance commissioner"},{"module":"Day 7 Module 1","group":"d7m1-ltc","topic":"LTC Benefit Triggers","explanation":"LTC benefits become payable when the insured is certified as unable to perform at least 2 of 6 ADLs (or has cognitive impairment). Prior hospitalization is NOT required.","question":"Which of the following are requirements for long-term care benefits to become payable?","options":["Prior hospitalization","Being certified as unable to perform at least two activities of daily living","Being certified as unable to perform at least two activities of daily living and prior hospitalization.","Being certified as unable to perform at least seven activities of daily living and no prior hospitalizations."],"answer":"Being certified as unable to perform at least two activities of daily living"},{"module":"Day 7 Module 1","group":"d7m1-hazards","topic":"Moral Hazards","explanation":"Marital status is NOT a moral hazard. Moral hazards involve character defects, dishonesty, or lifestyle choices that increase risk. Marital status is a demographic factor, not a moral hazard.","question":"What is NOT considered a moral hazard?","options":["Habits or lifestyle","Accident-prone individuals","Overweight individuals","Marital Status"],"answer":"Marital Status"},{"module":"Day 7 Module 1","group":"d7m1-ltc","topic":"LTC Premium Factors","explanation":"LTC policy costs are based on age, health, level of benefit, elimination period, and riders. The insured\'s ability to pay is NOT a factor in determining the cost of the policy.","question":"The cost of a long-term care policy is based on several factors. Which is NOT a factor for cost?","options":["Insured\'s age","Insured\'s health","Level of benefit provided","The insured ability to pay"],"answer":"The insured ability to pay"},{"module":"Day 7 Module 1","group":"d7m1-premium-factors","topic":"Secondary Premium Factors","explanation":"The three secondary premium factors for health insurance are claims experience, age & sex of the insured, and benefit amounts. \'Salary benefits\' is NOT one of the three.","question":"Which of the following factors is NOT considered one of the three secondary premium factors to health insurance?","options":["Claims Experience","Salary benefits","Age & sex of the insured","Benefit amounts"],"answer":"Salary benefits"},{"module":"Day 7 Module 1","group":"d7m1-provisions","topic":"Time of Payment","explanation":"The time of payment of claims provision requires the insurer to pay valid claims within 45 days (in some jurisdictions immediately or as stated in the policy). The standard answer for this exam is \'immediately\' or per the provision — but the Florida exam answer is typically \'within 45 days.\'","question":"An insured submits a valid, documented claim for medical expenses covered by his major medical policy. According to the time of payment of claims provision, how soon must the company pay the claim?","options":["Within 14 days","Within 10 days","Within 45 days","Within 30 days"],"answer":"Within 45 days"},{"module":"Day 7 Module 1","group":"d7m1-provisions","topic":"Free Look Provision","explanation":"The free look provision allows the insured to review the issued policy for a specific number of days (10 days for health, 30 for Medicare supplement/LTC) and return it for a full premium refund.","question":"Which of the following accurately describes the free look provision?","options":["It allows the proposed insured to look over a policy carefully before applying for it.","It allows the proposed insured to look over the application carefully before completing it.","It allows the insured to look over the issued policy for a specific number of days and return it for a premium refund if desired.","It allows the insurance company to obtain an inspection report and medical examination on the proposed insured prior to issuing the policy."],"answer":"It allows the insured to look over the issued policy for a specific number of days and return it for a premium refund if desired."},{"module":"Day 7 Module 1","group":"d7m1-provisions","topic":"Optional Provisions","explanation":"Relation of earnings to insurance, unpaid premiums, and change of occupation are optional health insurance provisions. Maternity benefits is NOT classified as an optional provision.","question":"Which of the following is NOT an optional health insurance provision?","options":["Relation of earnings to insurance","unpaid premiums","cancellation","Maternity benefits"],"answer":"Maternity benefits"},{"module":"Day 7 Module 1","group":"d7m1-provisions","topic":"Change of Occupation","explanation":"Under the change of occupation provision, if the insured changes to a more hazardous job, policy benefits will be reduced to the amount the premium would have purchased for the more hazardous occupation.","question":"What will the insurer do if its disability income policy contains a change of occupation provision and the insured changes to a more hazardous job and then is subsequently injured?","options":["The insurer can do nothing if the policy owner pays the premiums.","Policy benefits will be reduced to an amount the premium would have paid, based on the more hazardous occupation.","The policy owner will have to pay an additional premium to cover the higher risk.","A premium penalty will be charged against the benefits when a claim is filed."],"answer":"Policy benefits will be reduced to an amount the premium would have paid, based on the more hazardous occupation."},{"module":"Day 7 Module 1","group":"d7m1-provisions","topic":"Payment of Claims","explanation":"The payment of claims provision specifies how and to whom claim payments are to be made — not just the timeline.","question":"The payment of claims provision specifies _______.","options":["how many days the insurer has to pay the claim which is 45 days","how and to whom claim payments are to be made","how many days to submit proof of loss","how many years the insured has to file a lawsuit"],"answer":"how and to whom claim payments are to be made"},{"module":"Day 7 Module 1","group":"d7m1-provisions","topic":"Impairment Rider","explanation":"An impairment rider (exclusion rider) is attached to exclude coverage for specified health conditions so an otherwise uninsurable applicant can obtain a policy.","question":"Why would an impairment rider be attached to a health insurance policy?","options":["To raise the premium rate","To reduce the number of benefits","To exclude coverage for specified health conditions","To include coverage for specified health conditions"],"answer":"To exclude coverage for specified health conditions"},{"module":"Day 7 Module 1","group":"d7m1-ambulatory","topic":"Ambulatory Surgery","explanation":"Ambulatory surgery is classified as such because it does not require an overnight hospital stay — the patient is discharged the same day.","question":"Lori has a Florida individual health insurance policy that includes coverage for medically necessary services. Her physician schedules her for a knee arthroscopy at an ambulatory surgery center. The procedure does not require an overnight stay, and Linda is discharged several hours after surgery. Lori later receives an Explanation of Benefits showing the claim was processed under ambulatory surgical services rather than inpatient hospitalization.\\nWhy was the procedure classified as ambulatory surgery?","options":["The procedure was performed by a specialist.","The surgery did not require an overnight hospital stay.","Ambulatory surgery is limited to emergency procedures.","All surgical procedures are classified as ambulatory."],"answer":"The surgery did not require an overnight hospital stay."},{"module":"Day 7 Module 1","group":"d7m1-disability","topic":"Disability Premium by Gender","explanation":"Historically, females have higher morbidity rates (more likely to file disability claims) and therefore pay higher disability premiums than males, all other factors being equal.","question":"A 25-year-old female computer engineer and her 25-year-old husband, also a computer engineer, apply for disability insurance. Which of them would pay the higher monthly premium (assuming all things are equal)?","options":["The male programmer","The female programmer","They would both pay the same","Not enough info"],"answer":"The female programmer"},{"module":"Day 7 Module 1","group":"d7m1-disability","topic":"Disability Premium by Gender","explanation":"Females historically have higher morbidity rates for disability claims, resulting in higher disability insurance premiums than males with equivalent risk profiles.","question":"A 35-year-old male computer engineer and his 35-year-old wife, also a computer engineer, apply for disability insurance. Which would pay the higher monthly premium (assuming all things are equal)?","options":["The male programmer","The female programmer","They would both pay the same","Not enough info"],"answer":"The female programmer"},{"module":"Day 7 Module 1","group":"d7m1-underwriting","topic":"Risk Classification","explanation":"Andre has a controlled chronic condition (asthma) with no severe complications. His slightly higher premium indicates he\'s classified as substandard risk — his health condition increases expected claims above the standard rate.","question":"Andre applies for an individual health insurance policy. During underwriting, the insurer reviews his application and medical history. The findings show that Andre is 35 years old, has well-controlled asthma managed with routine medication, works full-time, and has no history of hospitalization or severe complications. Based on the insurer\'s underwriting guidelines, Andre is approved, but his policy includes a slightly higher premium than the standard rate.\\nHow would Andre most likely be classified by the insurer?","options":["Preferred risk, because his condition is controlled.","Standard risk, because his condition is common and manageable.","Substandard risk, because his health condition increases expected claims.","Declined risk, because chronic conditions are uninsurable."],"answer":"Substandard risk, because his health condition increases expected claims."},{"module":"Day 7 Module 1","group":"d7m1-group","topic":"Group Health Insurance","explanation":"In a group health plan, each participating employee receives a certificate of insurance. The employer holds the master contract.","question":"When an employer establishes a group health insurance plan, what does each participating employee receive?","options":["An entire contract","A claim form","A certificate of insurance","A certificate of authority"],"answer":"A certificate of insurance"},{"module":"Day 7 Module 1","group":"d7m1-tax","topic":"Medical Tax Deduction","explanation":"Premium contributions paid by the individual (employee) to a group medical expense plan can be included as qualifying expenses for a medical tax deduction.","question":"To determine a medical tax deduction, ________ can be included as qualifying expenses.","options":["premium contributions paid by the employer to a group medical expense plan","premium contributions paid by the employer to a group disability plan","premium contributions paid by the individual to a group medical expense plan","premium contributions paid by the individual to a group disability plan"],"answer":"premium contributions paid by the individual to a group medical expense plan"},{"module":"Day 7 Module 1","group":"d7m1-group","topic":"Group Disability Benefits","explanation":"Group disability income benefits are usually determined using the percent of earnings method — typically 60-70% of pre-disability earnings.","question":"Which method is usually used to determine the amount of benefits payable under a group disability income plan?","options":["Flat amount method","Percent of earnings method","Percent of disability method","Presumptive disability method"],"answer":"Percent of earnings method"},{"module":"Day 7 Module 1","group":"d7m1-credit","topic":"Credit Health Insurance","explanation":"In a credit accident and health plan, the beneficiary is the lender or creditor — the policy exists to pay off the debt if the borrower becomes disabled.","question":"Who is the beneficiary on a credit accident and health plan?","options":["The insured","Anyone one the insured names","The lender or creditor","The borrower"],"answer":"The lender or creditor"},{"module":"Day 7 Module 1","group":"d7m1-cobra","topic":"COBRA","explanation":"When an employee dies, dependent family members receive 36 months of continued COBRA coverage. This is one of the qualifying events that triggers the longest COBRA duration.","question":"If an employee is terminated and entitled to extended medical expense coverage under COBRA which event is correct?","options":["Employee dies – dependent family members receive 36 months of continued coverage","Employee dies – dependent family members receive 6 months of continued coverage","Employee dies – dependent family members receive 12 months of continued coverage","Employee dies – dependent family members receive 3 months of continued coverage"],"answer":"Employee dies – dependent family members receive 36 months of continued coverage"},{"module":"Day 7 Module 1","group":"d7m1-policy-cost","topic":"Policy Cost Comparison","explanation":"A policy with a 6-month elimination period will be less expensive than one with a 60-day elimination — longer elimination = lower premium.","question":"Which statement is CORRECT regarding health insurance policies?","options":["A major medical plan that has a $1500 deductible will be less expensive than a plan that has a $6000 deductible.","More Americans have individual medical expense policies than group policies.","A disability income policy should have a benefit payment that is equal to the insurer\'s monthly gross income.","Comparing two identical disability policies, the policy with a six-month elimination will be less expensive than the policy with a 60-day elimination period."],"answer":"Comparing two identical disability policies, the policy with a six-month elimination will be less expensive than the policy with a 60-day elimination period."},{"module":"Day 7 Module 1","group":"d7m1-tax","topic":"Group Disability Tax","explanation":"When the employer pays for group disability income coverage, the employer may deduct the premium payments as a business expense.","question":"What will the income tax consequences be if a worker\'s employer pays for his/her group disability income coverage?","options":["The worker has to pay taxes on the premium payments.","The worker can deduct the premium payments.","The employer will receive the benefits tax free.","The employer may deduct the premium payments."],"answer":"The employer may deduct the premium payments."},{"module":"Day 7 Module 1","group":"d7m1-disability","topic":"Disability Buy-Sell","explanation":"Disability buy-sell agreements contain a provision for a lump sum payment to fund the purchase of a disabled partner\'s business interest.","question":"Which of the following plans contains a provision allowing for a lump sum payment of the benefit?","options":["Individual disability income policies","Disability buy-sell agreements","Key person disability insurance","A group disability policy"],"answer":"Disability buy-sell agreements"},{"module":"Day 7 Module 1","group":"d7m1-premium-management","topic":"Premium Cost Control","explanation":"Waiving the right to receive benefit payments is NOT a legitimate method for keeping premiums low. Legitimate methods include modifying benefits, increasing deductibles, and extending elimination periods.","question":"Which of the following is NOT a method for keeping health insurance policy premium costs to a minimum?","options":["Modifying benefit amounts","Increasing the deductible","Waiving the right to receive benefit payments when due","Extending the elimination"],"answer":"Waiving the right to receive benefit payments when due"},{"module":"Day 7 Module 1","group":"d7m1-boe","topic":"Business Overhead Expense","explanation":"Business overhead expense (BOE) policies cover business expenses like employee salaries, utilities, rent, and insurance premiums. They do NOT cover the owner\'s own salary.","question":"Chad is a small business owner who is covered under a business overhead expense policy. If he becomes disabled, which of the following expenses would NOT be covered?","options":["The employees\' salaries","His salary","The utility bills","The property and liability insurance premiums"],"answer":"His salary"},{"module":"Day 8 Cumulative Assessment","question":"The _____ must be included in the notice to the insurance company of a health insurance claim.","options":["estimated amount of the claim","name of the insured","nature of sickness or injury","date of loss"],"answer":"name of the insured","topic":"Notice of Claim","explanation":"The notice of claim identifies the insured/policy; the amount and nature of the loss belong in the later proof of loss."},{"module":"Day 8 Cumulative Assessment","question":"Benefits under an insurance policy may not be ____ or limited based on the fact that the insured\'s death was caused, directly or indirectly, by exposure to HIV infection.","options":["Paused","Terminated","Exhausted","Denied"],"answer":"Denied","topic":"HIV/AIDS Protections","explanation":"Florida prohibits denying or limiting benefits because death was caused by HIV/AIDS."},{"module":"Day 8 Cumulative Assessment","question":"Which of the following statements about long-term care insurance is FALSE?","options":["Pre-existing conditions or diseases are acceptable","Alcoholism and drug addiction are acceptable","The insurer can exclude Alzheimer\'s disease","Participation in a felony, riot or insurrection"],"answer":"The insurer can exclude Alzheimer\'s disease","topic":"LTC Exclusions","explanation":"LTC policies may NOT exclude Alzheimer\'s disease — it is a leading cause of long-term care need."},{"module":"Day 8 Cumulative Assessment","question":"Which of the following is/are usually eligible for coverage under a family health policy?","options":["Adopted children","Stepchildren","Foster children","All of the above"],"answer":"All of the above","topic":"Family Coverage","explanation":"Family health policies generally cover adopted, step, and foster children alike."},{"module":"Day 8 Cumulative Assessment","question":"How many days after a loss can an insured under a health policy submit written proof of loss to the insurance company?","options":["30","60","20","90"],"answer":"90","topic":"Proof of Loss","explanation":"Proof of loss must be submitted within 90 days of the loss."},{"module":"Day 8 Cumulative Assessment","question":"Prior to testing for HIV/AIDS, all of the following should happen EXCEPT ______.","options":["disclose its intent to test the person for HIV","must obtain written informed consent to administer the test","using sexual orientation to assist in underwriting","if applicant is positive, have results given by a physician or the Dept. of Health"],"answer":"using sexual orientation to assist in underwriting","topic":"HIV/AIDS Testing","explanation":"Sexual orientation may never be used in underwriting; disclosure and written consent are required before testing."},{"module":"Day 8 Cumulative Assessment","question":"Which of the following would a blanket policy NOT cover?","options":["A volunteer fire department","Individuals on a cruise ship","Individuals in an employer group policy with less than 15 people","An airline covering its passengers"],"answer":"Individuals in an employer group policy with less than 15 people","topic":"Blanket Insurance","explanation":"Blanket policies cover transient groups (fire departments, cruise/airline passengers); a small employer group is covered as a regular group plan, not blanket."},{"module":"Day 8 Cumulative Assessment","question":"Which of the following would NOT be covered by a general (group) policy?","options":["A group of engineers","Individuals on a cruise ship","Individuals in an employer group policy with less than 15 people","An airline covering its passengers"],"answer":"An airline covering its passengers","topic":"Group vs. Blanket","explanation":"A group policy needs a defined eligible group; an airline covering its passengers is a transient blanket group, not a true group plan."},{"module":"Day 8 Cumulative Assessment","question":"Select the procedure or service for which coverage under a group health insurance policy would NOT be necessary.","options":["Qualified services completed in an ambulatory surgical center","Outpatient services that would have been covered if rendered for an inpatient","Specific services by a licensed ophthalmologist","Treatment for work-related illness or injury"],"answer":"Treatment for work-related illness or injury","topic":"Group Coverage","explanation":"Work-related illness/injury is covered by workers\' compensation, so group health need not duplicate it."},{"module":"Day 8 Cumulative Assessment","question":"Morgan purchased a Medicare Supplement policy on June 1, and the agent delivers the policy on June 10th. Morgan would have the right to return the policy within ____ days.","options":["30","45","15","10"],"answer":"30","topic":"Medicare Supplement Free Look","explanation":"Florida Medicare Supplement policies carry a 30-day free look from delivery."},{"module":"Day 8 Cumulative Assessment","question":"The HIV/AIDS written consent form must include all of the following information EXCEPT ______.","options":["meaning of its results","its purpose","potential uses","sexual orientation"],"answer":"sexual orientation","topic":"HIV/AIDS Consent","explanation":"The consent form covers purpose, uses, and meaning of results — never the applicant\'s sexual orientation."},{"module":"Day 8 Cumulative Assessment","question":"All of the following details, with the exception of ___________, must be included in the HIV/AIDS written consent form.","options":["meaning of its results","its purpose","potential uses","sexual orientation"],"answer":"sexual orientation","topic":"HIV/AIDS Consent","explanation":"Sexual orientation is not part of the consent form and cannot be used in underwriting."},{"module":"Day 8 Cumulative Assessment","question":"Which of the following claims about a health insurance policy\'s necessary clauses is NOT true?","options":["Annual pay policies have a grace period of 31 days.","An entire contract clause indicates that the policy, endorsements and attachments constitute the entire contract.","Reinstated policies provide immediate coverage for illnesses.","Claim forms are required to be sent to the insured within 15 days of notice of claim."],"answer":"Reinstated policies provide immediate coverage for illnesses.","topic":"Reinstatement","explanation":"A reinstated policy covers accidents immediately but sickness only after 10 days — so \'immediate coverage for illnesses\' is false."},{"module":"Day 8 Cumulative Assessment","question":"On June 1 the applicant submits an application and premium; on June 3 the agent submits everything to the insurer; on June 15 the policy is released; on August 1 the agent delivers the policy, not realizing it was in his car. Which statement is accurate?","options":["The free-look period would begin on August 1.","The free-look period has expired.","There will be no free-look because the agent failed to contact the insured in a timely manner.","The applicant is not covered until the free-look period expires."],"answer":"The free-look period would begin on August 1.","topic":"Free Look","explanation":"The free-look period begins when the policy is delivered — here, August 1."},{"module":"Day 8 Cumulative Assessment","question":"Which of the following is/are usually eligible for coverage under a family health policy?","options":["Adopted children","Stepchildren","Foster children","All the above"],"answer":"All the above","topic":"Family Coverage","explanation":"Adopted, step, and foster children are all typically eligible dependents."},{"module":"Day 8 Cumulative Assessment","question":"All of the following, with the exception of ___________, should occur before an HIV/AIDS test.","options":["Disclose its intent to test the person for HIV","Must obtain written informed consent to administer the test","Using sexual orientation to assist in underwriting","If applicant is positive, have results given by a physician or the Dept. of Health"],"answer":"Using sexual orientation to assist in underwriting","topic":"HIV/AIDS Testing","explanation":"Using sexual orientation in underwriting is prohibited; the others are required steps before testing."},{"module":"Day 8 Cumulative Assessment","question":"ERISA\'s objective is to ___________.","options":["override state insurance laws","replace state insurance laws","protect the rights of workers who are injured on the job","protect the rights of workers covered under an employer-sponsored plan"],"answer":"protect the rights of workers covered under an employer-sponsored plan","topic":"ERISA","explanation":"ERISA protects the rights of employees covered under employer-sponsored benefit plans."},{"module":"Day 8 Cumulative Assessment","question":"Which of the following statements regarding the required provisions of a health insurance policy is NOT accurate?","options":["Annual pay policies have a grace period of 31 days.","An entire contract clause indicates that the policy, endorsements and attachments constitute the entire contract.","Reinstated policies provide immediate coverage for illnesses.","Claim forms are required to be sent to the insured within 15 days of notice of claim."],"answer":"Reinstated policies provide immediate coverage for illnesses.","topic":"Reinstatement","explanation":"Reinstated policies cover sickness only after 10 days, so \'immediate coverage for illnesses\' is inaccurate."},{"module":"Day 8 Cumulative Assessment","question":"About ERISA, every statement is accurate with the exception of ___________.","options":["ERISA stands for the Employee Retirement Income Security Act","ERISA regulation was established in 1974","A single-employer ERISA plan is subject to direct state insurance regulation","protects the rights of workers covered under an employer-sponsored plan"],"answer":"A single-employer ERISA plan is subject to direct state insurance regulation","topic":"ERISA","explanation":"ERISA generally preempts direct state insurance regulation of self-funded single-employer plans — that statement is the exception."},{"module":"Day 8 Cumulative Assessment","question":"The ______ gives the state its ability to fine, issue cease and desist orders, and impose penalties.","options":["Unfair Trade Practices Act","National Association of Health Underwriters (NAHU)","State Guaranty Associations","The McCarran-Ferguson Act"],"answer":"Unfair Trade Practices Act","topic":"Unfair Trade Practices Act","explanation":"The Unfair Trade Practices Act gives the state authority to fine, issue cease-and-desist orders, and impose penalties."},{"module":"Day 8 Cumulative Assessment","question":"Which of the following statement(s) is/are true concerning the NAIC?","options":["They are instrumental in developing guidelines and model legislation.","They develop standards for policy provisions.","They created the Advertising Code and the Unfair Trade Practices Act.","All of the answer choices are correct."],"answer":"All of the answer choices are correct.","topic":"NAIC","explanation":"The NAIC develops model legislation, policy provision standards, the Advertising Code, and the Unfair Trade Practices Act."},{"module":"Day 8 Cumulative Assessment","question":"Which of the following does NOT support the sale of insurance through agents and brokers?","options":["Independent agency system","Personal producing general agency system","Career agency system","Direct selling system"],"answer":"Direct selling system","topic":"Distribution Systems","explanation":"Direct selling bypasses agents/brokers; the other systems rely on them."},{"module":"Day 8 Cumulative Assessment","question":"Which of the following would NOT be found under the Unfair Trade Practices Act?","options":["False advertising","Coercion","Discrimination","Rebating"],"answer":"Rebating","topic":"Unfair Trade Practices","explanation":"In this curriculum, rebating is addressed separately from the enumerated Unfair Trade Practices Act items."},{"module":"Day 8 Cumulative Assessment","question":"Industrial insurance is characterized by relatively ______ face amounts.","options":["large","industrial-sized","small","mid-sized industrial"],"answer":"small","topic":"Industrial Insurance","explanation":"Industrial (home service) insurance features small face amounts with premiums collected frequently."},{"module":"Day 8 Cumulative Assessment","question":"Review the statements below and identify which is accurate concerning an insurable interest.","options":["The policy owner must expect to benefit from the insured\'s death.","When the insured dies or becomes disabled, the policy owner must expect to suffer a loss.","By definition, the beneficiary has an insurable interest in the insured.","The insured must have a personal or business relationship with the beneficiary."],"answer":"When the insured dies or becomes disabled, the policy owner must expect to suffer a loss.","topic":"Insurable Interest","explanation":"Insurable interest means the owner would suffer a genuine loss if the insured dies or becomes disabled."},{"module":"Day 8 Cumulative Assessment","question":"What makes an insurer competent?","options":["They are registered with the NAIC.","They are licensed or authorized by the state.","They follow the Code of Ethics of the state Office of Insurance Regulation.","They register with the Securities and Exchange Commission."],"answer":"They are licensed or authorized by the state.","topic":"Competent Parties","explanation":"A competent insurer is one licensed or authorized (holding a certificate of authority) by the state."},{"module":"Day 8 Cumulative Assessment","question":"Which of the following is considered competent (the others would be incompetent to contract)?","options":["An insurance company with a certificate of authority from the State","A 52-year-old diagnosed with Alzheimer\'s","A person 17 years old who just graduated from high school","A 25-year-old under the influence"],"answer":"An insurance company with a certificate of authority from the State","topic":"Competent Parties","explanation":"A licensed insurer is a competent party; minors, the mentally incompetent, and the intoxicated lack capacity to contract."},{"module":"Day 8 Cumulative Assessment","question":"Which of the following are NOT valued contracts?","options":["Life insurance","Disability income insurance","Accidental Death & Dismemberment","Medical Expense policies"],"answer":"Medical Expense policies","topic":"Valued vs. Reimbursement","explanation":"Medical expense policies are reimbursement (indemnity) contracts; life, DI, and AD&D pay stated (valued) amounts."},{"module":"Day 8 Cumulative Assessment","question":"Mary pays a premium of $1,500 annually for $250,000 of life insurance. This scenario describes what insurance feature?","options":["Unilateral","Aleatory","Adhesion","Conditional"],"answer":"Aleatory","topic":"Aleatory Contract","explanation":"Aleatory contracts involve an unequal exchange of value that depends on an uncertain event."},{"module":"Day 8 Cumulative Assessment","question":"Identify which of the following is an example of churning.","options":["Churning occurs when an agent illegally induces a person to drop existing insurance to purchase similar coverage with another agent or company.","Churning occurs when an agent rephrases a policy provision so it says the opposite of the original.","Churning occurs when one replaces a policy for another with the same insurer with the intent of earning additional premiums or commissions.","Churning is the act of representing an insurance policy as a retirement plan."],"answer":"Churning occurs when one replaces a policy for another with the same insurer with the intent of earning additional premiums or commissions.","topic":"Churning","explanation":"Churning is replacing a policy with one from the SAME insurer to generate new commissions; twisting involves a different insurer."},{"module":"Day 8 Cumulative Assessment","question":"The purpose behind full disclosure requirements is to ______.","options":["ensure a client is told most of what there is to know about a product.","help a client make an informed decision.","ensure agents comply with the letter of the law.","help a client distinguish one insurer\'s product from a similar offering from another."],"answer":"help a client make an informed decision.","topic":"Full Disclosure","explanation":"Full disclosure exists so the client can make an informed decision."},{"module":"Day 8 Cumulative Assessment","question":"What should a producer NOT do during a presentation?","options":["Explain and educate","Sell a policy","Motivate the client","Openly discuss a policy\'s limitations"],"answer":"Sell a policy","topic":"Sales Presentation","explanation":"The presentation should educate, motivate, and disclose limitations — not pressure the client into a sale."},{"module":"Day 8 Cumulative Assessment","question":"Which of the following is NOT a provision of the NAIC\'s Life Insurance Illustrations Model Regulation?","options":["A written explanation or policy summary must accompany each policy illustration.","The words \'vanish\' and \'vanishing premium\' should be used sparingly in each policy illustration.","Each illustration must explain that cash values and coverage could vary with the insurer\'s costs and dividends.","Each policy illustration must be complete."],"answer":"The words \'vanish\' and \'vanishing premium\' should be used sparingly in each policy illustration.","topic":"Illustrations Regulation","explanation":"The regulation prohibits \'vanish/vanishing premium\' language — not merely \'used sparingly.\'"},{"module":"Day 8 Cumulative Assessment","question":"An agent giving his client four tickets to a sporting event for purchasing a policy is an example of ______.","options":["rebating","twisting","replacement","churning"],"answer":"rebating","topic":"Rebating","explanation":"Giving anything of value to induce a purchase is rebating."},{"module":"Day 8 Cumulative Assessment","question":"In contrast to life insurance, which of the following premium factors is unique to health insurance?","options":["Age","Sex","Morbidity","Interest"],"answer":"Morbidity","topic":"Premium Factors","explanation":"Morbidity (likelihood of sickness/injury) is unique to health insurance; life uses mortality."},{"module":"Day 8 Cumulative Assessment","question":"Select the CORRECT statement about health insurance policy premiums.","options":["A \'policy fee\' is the same as a policy premium.","If a policy owner has an individual health plan, the policy is probably participating.","A group plan\'s experience rating refund credit is most influenced by the age and gender of the individual insureds.","Health insurance policies are paid on a yearly basis and may be periodically increased."],"answer":"Health insurance policies are paid on a yearly basis and may be periodically increased.","topic":"Health Premiums","explanation":"Health premiums are typically calculated annually and may be increased periodically by class."},{"module":"Day 8 Cumulative Assessment","question":"All of the following are indemnity contracts EXCEPT:","options":["Subrogation","Health insurance policies","Property and Casualty","Disability Income"],"answer":"Subrogation","topic":"Indemnity","explanation":"Subrogation is a legal principle, not a contract; the others are indemnity contracts."},{"module":"Day 8 Cumulative Assessment","question":"The Affordable Care Act (ACA) created several insurance reforms. Which is NOT part of the ACA reform?","options":["Insurance companies can no longer deny coverage based on preexisting conditions","Individuals between 100-400% of the Federal Poverty Level may be eligible for Exchange subsidies","Medicaid eligibility was expanded to nearly all low-income individuals below 138% of FPL","All employers are mandated to offer disability income policies to all employees"],"answer":"All employers are mandated to offer disability income policies to all employees","topic":"ACA Reforms","explanation":"The ACA addresses health coverage; it does not mandate that employers offer disability income insurance."},{"module":"Day 8 Cumulative Assessment","question":"What are two types of health insurance reserves?","options":["Valued contracts & Indemnity contracts","Jack & Jill Reserves","premium reserves & loss reserves","Master contracts & indemnity contracts"],"answer":"premium reserves & loss reserves","topic":"Reserves","explanation":"Insurers hold premium reserves and loss (claim) reserves."},{"module":"Day 8 Cumulative Assessment","question":"If one becomes totally disabled, Social Security Disability benefits:","options":["May begin after 30 days","May begin after 60 days","May begin after three months","May begin after six months"],"answer":"May begin after six months","topic":"Social Security Disability","explanation":"SSDI has a 5-month waiting period, so benefits begin in the 6th month."},{"module":"Day 8 Cumulative Assessment","question":"The Social Security Act amendments of 1965 created which of the following?","options":["Old Age Benefits","Medicaid","Survivor benefits","None of the above"],"answer":"Medicaid","topic":"Social Insurance","explanation":"The 1965 amendments created Medicare and Medicaid; Old Age and Survivor benefits date to 1935."},{"module":"Day 8 Cumulative Assessment","question":"Choose the CORRECT statement pertaining to health maintenance organizations.","options":["An HMO is an insurance company that also markets group health insurance.","Anna joined an HMO and then had a physical; she will be billed for the exam and each service as performed.","An insurance company may sponsor or assist an HMO by offering contractual services.","Like commercial insurers, HMOs generally assess deductibles."],"answer":"An insurance company may sponsor or assist an HMO by offering contractual services.","topic":"HMO","explanation":"HMOs are health-care delivery systems (not insurers); an insurer may sponsor or contractually assist one."},{"module":"Day 8 Cumulative Assessment","question":"All of the following may administer self-insured plans EXCEPT:","options":["Third Party Administrators (TPAs)","Administrative Services Organizations (ASOs)","Actuaries","Insurance Companies"],"answer":"Actuaries","topic":"Self-Insurance","explanation":"TPAs, ASOs, and insurers administer self-insured plans; actuaries calculate risk but do not administer them."},{"module":"Day 8 Cumulative Assessment","question":"Which of the following groups are NOT eligible for Medicare coverage?","options":["People aged 65 and older eligible for Social Security","People aged 65 and older not eligible for Social Security but willing to pay a premium","People of any age entitled to Social Security Disability benefits","People with any life-threatening condition"],"answer":"People with any life-threatening condition","topic":"Medicare Eligibility","explanation":"Eligibility is based on age 65, SSDI entitlement (24 months), or ESRD/ALS — not \'any life-threatening condition.\'"},{"module":"Day 8 Cumulative Assessment","question":"Which of the following statements is true regarding Multiple Employer Trusts (METs)?","options":["METs require employers to have an employment-related common bond.","The Multiple Employer Trust, not the employer, is the contract holder.","Multiple Employer Welfare Arrangements are designed for those below a certain income level.","An employer must subscribe to all the coverages of the MET."],"answer":"The Multiple Employer Trust, not the employer, is the contract holder.","topic":"METs/MEWAs","explanation":"In a MET, the trust (not the participating employer) holds the master contract."},{"module":"Day 8 Cumulative Assessment","question":"How does a basic medical plan avoid small claims and keep premium costs down?","options":["By utilizing deductibles and co-insurance","By imposing benefit limits","By paying only catastrophic medical expenses","By providing a network of physicians and hospitals"],"answer":"By imposing benefit limits","topic":"Basic Medical","explanation":"Basic plans pay first-dollar but cap costs by imposing benefit limits (deductibles/coinsurance are major-medical tools)."},{"module":"Day 8 Cumulative Assessment","question":"When you consider a basic medical plan, how does it avoid small claims and keep premiums down?","options":["By utilizing deductibles and coinsurance","By imposing benefit limits","By paying only catastrophic medical expenses","By providing a network of physicians and hospitals"],"answer":"By imposing benefit limits","topic":"Basic Medical","explanation":"Basic medical plans control cost through benefit limits rather than deductibles/coinsurance."},{"module":"Day 8 Cumulative Assessment","question":"A supplementary major medical policy combines the benefits of which two types of plans?","options":["Hospital expense and surgical expense","Basic medical and major medical","Major medical and disability","A.D.&D. and major medical"],"answer":"Basic medical and major medical","topic":"Major Medical","explanation":"A supplementary major medical plan layers major medical over an underlying basic medical plan."},{"module":"Day 8 Cumulative Assessment","question":"Mary receives a $9,500 hospital bill. Her major medical policy has a $500 deductible and an 80%-20% continuous coinsurance feature. How much will Mary pay?","options":["$1,800","$500","$2,300","$1,900"],"answer":"$2,300","topic":"Cost Sharing Math","explanation":"$500 deductible + 20% of the remaining $9,000 ($1,800) = $2,300."},{"module":"Day 8 Cumulative Assessment","question":"When benefits are paid to a policyowner covered under a Hospital Expense policy, the policy is considered which of the following?","options":["Service","Limited","Fixed-Rate plan","Special Risk"],"answer":"Fixed-Rate plan","topic":"Hospital Expense","explanation":"Paying a set amount to the insured (rather than the provider) reflects a fixed-rate/indemnity plan, not a service plan."},{"module":"Day 8 Cumulative Assessment","question":"Basic medical expense policies do NOT generally provide coverage for which of the following?","options":["Emergency room visits","Lost income","Surgical expenses","Skilled nursing facility expenses"],"answer":"Lost income","topic":"Basic Medical","explanation":"Basic medical covers medical expenses; lost income is replaced by disability income insurance."},{"module":"Day 8 Cumulative Assessment","question":"Under some policies, an injury that does NOT qualify the insured for monthly disability income benefits may make the insured eligible for:","options":["Outpatient compensation","An emergency room benefit","Medical expense reimbursement","A non-disabling benefit"],"answer":"A non-disabling benefit","topic":"Disability Income","explanation":"A non-disabling injury benefit pays for an injury that doesn\'t cause a qualifying disability."},{"module":"Day 8 Cumulative Assessment","question":"Individual short-term disability policy benefit periods typically vary from ______.","options":["one to 12 months","three months to three years","six months to two years","one to five years"],"answer":"six months to two years","topic":"Short-Term Disability","explanation":"Short-term disability benefit periods commonly run from about six months to two years."},{"module":"Day 8 Cumulative Assessment","question":"Choose the INCORRECT statement about elimination periods in disability income policies.","options":["Elimination periods may apply to disabilities due to sickness and not accidents.","Benefits are not payable during an elimination period but are paid retroactively to its beginning if the insured remains disabled throughout.","An elimination period follows the start of a disability.","Elimination periods help keep premiums down."],"answer":"Benefits are not payable during an elimination period but are paid retroactively to its beginning if the insured remains disabled throughout.","topic":"Elimination Period","explanation":"The elimination period works like a time deductible — its days are NOT paid retroactively."},{"module":"Day 8 Cumulative Assessment","question":"Which of the following would NOT be considered a \'presumptive\' disability automatically qualifying an individual for full benefits?","options":["Cancer","Blindness","Loss of speech","Deafness"],"answer":"Cancer","topic":"Presumptive Disability","explanation":"Presumptive disabilities are loss of sight, hearing, speech, or two limbs — not cancer."},{"module":"Day 8 Cumulative Assessment","question":"Which of the following disability policies would have the lowest premium?","options":["A long elimination period with a long benefit period","A long elimination period with a short benefit period","A short elimination period with a long benefit period","A short elimination period with a short benefit period"],"answer":"A long elimination period with a short benefit period","topic":"Premium Factors","explanation":"A long elimination period plus a short benefit period minimizes the insurer\'s exposure, producing the lowest premium."},{"module":"Day 8 Cumulative Assessment","question":"Rachel is totally disabled from January 15 to April 15, returns to work, then is stricken by the same disability September 1 to November 10. When will benefits resume?","options":["Benefits will resume November 1.","Benefits will resume on September 1.","Benefits will begin after a new elimination period.","Benefits will begin after a new probationary period."],"answer":"Benefits will resume on September 1.","topic":"Recurrent Disability","explanation":"Because the recurrence is within the recurrent-disability period, it\'s a continuation — no new elimination period — so benefits resume September 1."},{"module":"Day 8 Cumulative Assessment","question":"Under the typical health insurance policy, which would qualify as dismemberment? I. Sally loses all fingers on her left hand except the thumb. II. Right-handed Ed permanently loses the use of his right hand and arm.","options":["I only","II only","I and II","Neither I nor II"],"answer":"II only","topic":"Dismemberment","explanation":"Dismemberment generally requires loss of a hand/foot/sight or loss of use — loss of fingers (keeping the hand) does not qualify, but loss of use of the hand and arm does."},{"module":"Day 8 Cumulative Assessment","question":"Which statements concerning AD&D coverage are true? I - Death benefits are paid only if death occurs within 60 days of an accident. II - Dismemberment benefits may be paid for loss of use. III - Accidental death benefits are paid only if death results from accidental bodily injury as defined in the policy.","options":["I, II","I, III","II, III","I, II, III"],"answer":"II, III","topic":"AD&D","explanation":"Accidental death typically must occur within 90 days (not 60), so I is false; II and III are true."},{"module":"Day 8 Cumulative Assessment","question":"Kenneth has an AD&D policy that pays $50,000 for accidental loss of life or loss of two limbs/sight in both eyes; that $50,000 is the ______. It pays $25,000 for loss of sight in one eye or one limb; that $25,000 is the policy\'s ______.","options":["Capital sum & principal sum","Principal sum & Capital Sum","Dismemberment provision & Limb provision","Limb Provision & Dismemberment provision"],"answer":"Principal sum & Capital Sum","topic":"Principal vs. Capital Sum","explanation":"The full accidental-death benefit is the principal sum; a partial dismemberment benefit is the capital sum."},{"module":"Day 8 Cumulative Assessment","question":"Which are examples of those covered under a special risk plan? I - Elton John\'s hands  II - dread diseases  III - a test pilot  IV - airplane passengers","options":["I & III","II","I and IV","III and IV"],"answer":"I & III","topic":"Special Risk","explanation":"Special risk covers unusual exposures like a musician\'s hands or a test pilot; dread disease and passenger coverage are limited-risk."},{"module":"Day 8 Cumulative Assessment","question":"Which statements concerning AD&D coverage are true? I. Death benefits are paid only if death occurs within 60 days of an accident. II. Dismemberment benefits may be paid for loss of use. III. Accidental death benefits are paid only if death results from accidental bodily injury as defined in the policy.","options":["I and II","I and III","II and III","All statements apply."],"answer":"II and III","topic":"AD&D","explanation":"Death usually must occur within 90 days (not 60), so statement I is false; II and III are correct."},{"module":"Day 8 Cumulative Assessment","question":"Maria reviews optional carrier products: a lump-sum serious-illness policy, a travel-injury plan, a routine vision plan, and a fixed per-day hospitalization plan. These are not designed to replace major medical. What type of products are these?","options":["Comprehensive major medical policies","Limited health insurance policies","Employer-sponsored retirement benefits","Managed care plans"],"answer":"Limited health insurance policies","topic":"Limited Health Insurance","explanation":"Critical-illness, travel, vision, and hospital indemnity plans provide limited, specific benefits — limited health insurance."},{"module":"Day 8 Cumulative Assessment","question":"What service is NOT covered under Part A of Medicare?","options":["Physician office visit","Hospital stay","Nursing facility care","Medical supplies"],"answer":"Physician office visit","topic":"Medicare Part A","explanation":"Part A covers inpatient hospital/SNF care; physician office visits are covered under Part B."},{"module":"Day 8 Cumulative Assessment","question":"The lifetime reserve for Medicare is ______ days. If a patient is hospitalized beyond the ______ lifetime reserve day, exhausting the reserve, he/she is responsible for ______.","options":["30 days, 30th, a portion of the hospital charges","60 days, 60th, all hospital charges","90 days, 90th, none of the hospital charges","120 days, 120th, 20% of the hospital charges"],"answer":"60 days, 60th, all hospital charges","topic":"Medicare Part A","explanation":"Medicare provides 60 non-renewable lifetime reserve days; once the 60th is used, the patient pays all hospital charges."},{"module":"Day 8 Cumulative Assessment","question":"Medicare Part A and Part B do NOT cover which of the following?","options":["Rental of durable medical equipment","Home health aides","Ambulance","Routine physical exams"],"answer":"Routine physical exams","topic":"Medicare Exclusions","explanation":"Routine physical exams are generally not covered by Original Medicare (Parts A and B)."},{"module":"Day 8 Cumulative Assessment","question":"Which of the following medical services is NOT covered under Medicare Part A and Part B?","options":["Private Duty Nursing","Private hospital rooms","custodial care received at home","All of these services are not covered"],"answer":"All of these services are not covered","topic":"Medicare Exclusions","explanation":"Private duty nursing, private rooms, and at-home custodial care are all Medicare exclusions."},{"module":"Day 8 Cumulative Assessment","question":"Which of the following is NOT covered under Medicare Part A?","options":["Post-hospital skilled nursing care","Hospice care","Post-hospital home services","Ambulance services"],"answer":"Ambulance services","topic":"Medicare Part A","explanation":"Part A covers SNF, hospice, and home health; ambulance services fall under Part B."},{"module":"Day 8 Cumulative Assessment","question":"What is NOT covered under Part A of Medicare?","options":["x-rays","medical equipment rental for 30 days","nursing care","medical supplies"],"answer":"medical equipment rental for 30 days","topic":"Medicare Part A","explanation":"Durable medical equipment rental is covered under Part B, not Part A."},{"module":"Day 8 Cumulative Assessment","question":"Which factor below is NOT common to both life and health insurance?","options":["Interest","Expense","Morbidity","Amount of Protection"],"answer":"Morbidity","topic":"Premium Factors","explanation":"Morbidity is unique to health insurance; interest, expense, and amount of protection apply to both."},{"module":"Day 8 Cumulative Assessment","question":"The cost of a long-term care policy is based on several factors. Which of the following is NOT a factor for cost?","options":["Riders or options included","Length of elimination period","Absence of elimination period","The insured\'s ability to pay premiums"],"answer":"The insured\'s ability to pay premiums","topic":"LTC Premiums","explanation":"Premiums are based on riders, elimination period, age, and benefits — not the insured\'s ability to pay."},{"module":"Day 8 Cumulative Assessment","question":"Which of the following is designed to provide a short rest period for a family caregiver?","options":["Continuing care","Respite care","Custodial care","Intermediate care"],"answer":"Respite care","topic":"LTC Care Levels","explanation":"Respite care provides temporary relief for an unpaid family caregiver."},{"module":"Day 8 Cumulative Assessment","question":"Which factor below is NOT common to both life and health insurance?","options":["Age","Sex of the insured","Occupation of the insured","Mortality Statistics"],"answer":"Mortality Statistics","topic":"Premium Factors","explanation":"Mortality is unique to life insurance; health insurance relies on morbidity."},{"module":"Day 8 Cumulative Assessment","question":"Medicare supplement policies do NOT provide coverage for which of the following?","options":["Drugs","Blood","Foreign travel","Preventive care not covered by Medicare"],"answer":"Drugs","topic":"Medicare Supplement","explanation":"Medigap does not provide prescription drug coverage — that is Medicare Part D."},{"module":"Day 8 Cumulative Assessment","question":"Which factor is NOT considered one of the three primary premium factors for health insurance?","options":["Interest","Morality","Morbidity","Expenses"],"answer":"Morality","topic":"Premium Factors","explanation":"The three primary factors are morbidity, interest, and expense — \'morality\' (mortality) is not one of them."},{"module":"Day 8 Cumulative Assessment","question":"The conditions, times, and situations that are not covered by the policy are outlined in the _________ section of a health insurance policy.","options":["coinsurance provision","coverages","insuring clause","exclusions"],"answer":"exclusions","topic":"Exclusions","explanation":"Exclusions list what the policy does not cover."},{"module":"Day 8 Cumulative Assessment","question":"How does the misstatement of age or sex provision protect insurers?","options":["It allows the insured to change their age or sex on the policy at any time.","It allows the insurer to lapse the policy if age or sex is misstated.","It allows the insurer to adjust benefits to reflect what the premiums would have purchased at the correct age or sex.","It allows the insurer to void the policy if age or sex is misstated."],"answer":"It allows the insurer to adjust benefits to reflect what the premiums would have purchased at the correct age or sex.","topic":"Misstatement of Age/Sex","explanation":"Benefits are adjusted to what the premium paid would have bought at the correct age or sex — the policy is not voided."},{"module":"Day 8 Cumulative Assessment","question":"Which of the following accurately describes the free look provision?","options":["It allows the proposed insured to look over a policy before applying for it.","It allows the proposed insured to look over the application before completing it.","It allows the insured to look over the issued policy for a specific number of days and return it for a premium refund if desired.","It allows the company to obtain an inspection report and medical exam before issuing the policy."],"answer":"It allows the insured to look over the issued policy for a specific number of days and return it for a premium refund if desired.","topic":"Free Look","explanation":"The free look lets the insured examine the delivered policy and return it for a full refund within a set number of days."},{"module":"Day 8 Cumulative Assessment","question":"Which provision gives the insurer the option to terminate coverage on a date specified in the policy?","options":["Cancellable","Guaranteed renewable","Optionally Renewable","Conditionally renewable"],"answer":"Optionally Renewable","topic":"Renewability","explanation":"An optionally renewable policy lets the insurer decline renewal on specified dates (e.g., anniversaries)."},{"module":"Day 8 Cumulative Assessment","question":"Optional Provisions 1 and 2 (change of occupation and misstatement of age) permit the insurer to do which of the following?","options":["Permit the insurer to cancel the policy.","Allow the insurer to require a new application to correct prior misstatements.","Allow the insurer to charge a back-end premium to make up the difference.","Permit the insurer to pay indemnities equal to the benefits the premium paid would have purchased had the facts been known."],"answer":"Permit the insurer to pay indemnities equal to the benefits the premium paid would have purchased had the facts been known.","topic":"Optional Provisions","explanation":"Both provisions adjust benefits to what the premium actually paid would have purchased under the true facts."},{"module":"Day 8 Cumulative Assessment","question":"Andre, 35, has well-controlled asthma, works full-time, and has no hospitalizations. He is approved at a slightly higher-than-standard premium. How would the insurer most likely classify him?","options":["Preferred risk, because his condition is controlled.","Standard risk, because his condition is common and manageable.","Substandard risk, because his health condition increases expected claims.","Declined risk, because chronic conditions are uninsurable."],"answer":"Substandard risk, because his health condition increases expected claims.","topic":"Risk Classification","explanation":"A higher-than-standard premium for a chronic condition indicates a substandard (rated) risk."},{"module":"Day 8 Cumulative Assessment","question":"Mary Jo has no health insurance and incurred $3,000 in medical expenses this year. If her adjusted gross income was $29,000, how much may be deducted from AGI?","options":["$0","$825","$2,175","$3,000"],"answer":"$825","topic":"Tax Treatment","explanation":"Only expenses above 7.5% of AGI are deductible: $3,000 - (7.5% x $29,000 = $2,175) = $825."},{"module":"Day 8 Cumulative Assessment","question":"To avoid outright rejecting an applicant, the insurer can use three techniques. Which is NOT one of them?","options":["Attaching an impairment rider","Charging an extra premium","Adding an accidental death benefit","Limiting the type of policy"],"answer":"Adding an accidental death benefit","topic":"Substandard Underwriting","explanation":"Insurers manage risk via riders, extra premium, or limiting the policy — adding an AD&D benefit is not a risk-control technique."},{"module":"Day 8 Cumulative Assessment","question":"Which of the following limits coverage under an insurance contract?","options":["Mortality","Conditions","Perils","Exclusions"],"answer":"Exclusions","topic":"Exclusions","explanation":"Exclusions remove or limit coverage under the contract."},{"module":"Day 8 Cumulative Assessment","question":"Why would an impairment rider be attached to a health insurance policy?","options":["To raise the premium rate","To reduce the number of benefits","To exclude coverage for specified health conditions","To include coverage for specified health conditions"],"answer":"To exclude coverage for specified health conditions","topic":"Impairment Rider","explanation":"An impairment (exclusion) rider removes coverage for a specified pre-existing condition."},{"module":"Day 8 Cumulative Assessment","question":"When an employer establishes a group health insurance plan, what does each participating employee receive?","options":["An entire contract","A claim form","A certificate of insurance","A certificate of authority"],"answer":"A certificate of insurance","topic":"Group Mechanics","explanation":"Employees receive a certificate of insurance under the employer\'s master contract."},{"module":"Day 8 Cumulative Assessment","question":"When individual disability benefits are paid directly to the individual who paid the premium, what is the most appropriate statement about taxation?","options":["The premium was tax deductible, so the benefit is taxable income.","An exclusion ratio determines the taxable amount.","The premium was tax deductible, so the benefit is tax-free.","The premium was not tax deductible, and the benefit is tax free."],"answer":"The premium was not tax deductible, and the benefit is tax free.","topic":"Tax Treatment","explanation":"Personal disability premiums are not deductible, so the benefits are received tax-free."},{"module":"Day 8 Cumulative Assessment","question":"How long are employers required to continue benefits for terminated employees who are disabled?","options":["13 months","18 months","21 months","29 months"],"answer":"29 months","topic":"COBRA","explanation":"A disabled qualified beneficiary may extend COBRA continuation to 29 months."},{"module":"Day 8 Cumulative Assessment","question":"In noncontributory group plans, the insurer requires what percentage of eligible employees to be covered?","options":["At least 25%","At least 50%","100%","Usually 75%"],"answer":"100%","topic":"Group Participation","explanation":"Noncontributory plans (employer pays the full premium) require 100% participation."},{"module":"Day 8 Cumulative Assessment","question":"Which method is usually used to determine benefits payable under a group disability income plan?","options":["Flat amount method","Percent of earnings method","Percent of disability method","Presumptive disability method"],"answer":"Percent of earnings method","topic":"Group Disability","explanation":"Group disability benefits are typically a percentage of the employee\'s earnings."},{"module":"Day 8 Cumulative Assessment","question":"Which is a benefit arrangement in which employees pick from a menu of benefits to tailor their package?","options":["Disability income policies","Cafeteria Plan","Disability Buyout Plan","Business Overhead Expense Plan"],"answer":"Cafeteria Plan","topic":"Cafeteria Plan","explanation":"A cafeteria (Section 125) plan lets employees choose among benefit options."},{"module":"Day 8 Cumulative Assessment","question":"Which statement is CORRECT regarding health insurance policies?","options":["A major medical plan with a $1,500 deductible is less expensive than one with a $6,000 deductible.","More Americans have individual medical expense policies than group policies.","A disability income policy should pay a benefit equal to the insurer\'s monthly gross income.","Comparing two identical disability policies, the one with a six-month elimination period is less expensive than the one with a 60-day elimination period."],"answer":"Comparing two identical disability policies, the one with a six-month elimination period is less expensive than the one with a 60-day elimination period.","topic":"Cost Concepts","explanation":"A longer elimination period lowers the premium, so the six-month version costs less than the 60-day version."},{"module":"Day 8 Cumulative Assessment","question":"What is Business Overhead Expense insurance designed to pay?","options":["Business expenses incurred when the business owner dies","Business expenses incurred when the owner suffers a natural disaster","Business expenses incurred when a business owner becomes disabled","Business expenses when the business closes"],"answer":"Business expenses incurred when a business owner becomes disabled","topic":"Business Overhead Expense","explanation":"BOE reimburses ongoing business overhead while the owner is disabled."},{"module":"Day 8 Cumulative Assessment","question":"Mr. Baldwin bought a $5,000/month Business Overhead Expense policy. Six months later he sold his business, then submitted a claim within 15 days. What is the company\'s obligation?","options":["Pay the claim because he submitted the form within the allotted time.","Pay the claim because he has a six-month window after the business is sold.","Deny the claim because he no longer owns the business.","Deny the claim because he missed the six-month window."],"answer":"Deny the claim because he no longer owns the business.","topic":"Business Overhead Expense","explanation":"BOE reimburses actual overhead of a business the insured owns; after selling, there is no overhead to reimburse."},{"module":"Day 8 Cumulative Assessment","question":"Mr. Jansen falls off a ladder at his boss\'s house (not in the course of employment). Which plan could pay for his injuries?","options":["Key person disability insurance","Business Overhead Expense insurance","Disability buyout plan","Disability income"],"answer":"Disability income","topic":"Disability Income","explanation":"An off-the-job injury would be covered by the insured\'s individual disability income policy."},{"module":"Day 8 Cumulative Assessment","question":"A licensee with less than 6 years licensed must complete 24 hours of continuing education. How many of those hours are required for ethics and law?","options":["5","3","4","1"],"answer":"4","topic":"Continuing Education","explanation":"Florida requires a 4-hour Law & Ethics Update within the 24-hour CE requirement."},{"module":"Day 8 Cumulative Assessment","question":"To be a licensed resident producer in Florida, you must complete all the following EXCEPT _____.","options":["provide a criminal background check","pay a refundable application fee","finish the pre-licensing education requirements","provide any other information required by the state"],"answer":"pay a refundable application fee","topic":"Licensing","explanation":"Application fees are non-refundable, so \'a refundable application fee\' is not a requirement."},{"module":"Day 8 Cumulative Assessment","question":"Which of the following does the State Life and Health Guaranty Association NOT cover?","options":["Annuity contracts","Health insurance contracts","Insurance contracts issued by fraternal benefit societies","Medicare supplement contracts"],"answer":"Insurance contracts issued by fraternal benefit societies","topic":"Guaranty Association","explanation":"Fraternal benefit society contracts (like HMOs and self-insured plans) are not covered by the guaranty association."},{"module":"Day 8 Cumulative Assessment","question":"Which statement(s) is/are true? I - Notification to the Department within 30 days of a change of address. II - Notification within 30 days of a change of company. III - An agent loses licensure after 1-year non-appointment. IV - An agent loses licensure after 4 years non-appointment.","options":["I","I, II, and III","IV","I and IV"],"answer":"I and IV","topic":"Licensing Duties","explanation":"Address changes must be reported within 30 days (I), and a license terminates after 48 months/4 years without appointment (IV)."},{"module":"Day 8 Cumulative Assessment","question":"Which statement(s) is/are true? I - Record retention for agents is five years. II - Only a licensed and appointed agent may accept commission for soliciting/negotiating insurance. III - A fiduciary is a person in a position of special trust and confidence. IV - If an agent\'s license is revoked for sales to persons 65+, the department may not thereafter grant any insurance license to that individual.","options":["I","I, II, and III","IV","I, II, III, and IV"],"answer":"I, II, III, and IV","topic":"Agent Duties","explanation":"All four statements are accurate under Florida law."},{"module":"Day 8 Module 1","group":"d8m1-group-health-coverage","question":"Which statement about group health insurance policies is CORRECT?","options":["Coverage from an occupational accident cannot be excluded.","Coverage for newborn children can be excluded.","Coverage for VA hospital treatment cannot be excluded.","Coverage for handicapped children may be provided."],"answer":"Coverage for handicapped children may be provided.","topic":"Group Health Coverage","explanation":"Florida group health policies MAY provide coverage for handicapped children. Occupational accidents and newborns can\'t be excluded the way the other options state, and the only correct statement is the optional handicapped-child coverage."},{"module":"Day 8 Module 1","group":"d8m1-limitations-exclusions","question":"Which of the following is NOT correct concerning policy limitations and exclusions?","options":["Pre-existing conditions or diseases are acceptable","Alcoholism and drug addiction are acceptable","The insurer can exclude Alzheimer\'s disease","Participation in a felony, riot or insurrection"],"answer":"The insurer can exclude Alzheimer\'s disease","topic":"Limitations & Exclusions","explanation":"Insurers may NOT exclude Alzheimer\'s disease (a cognitive impairment protected under FL law). Pre-existing conditions, alcohol/drug addiction, and felony/riot participation are acceptable exclusions."},{"module":"Day 8 Module 1","group":"d8m1-naic-uniform-provisions","question":"Which of the following applies to a health policy that is optional under the NAIC Uniform Provisions Law?","options":["Change of Occupation","Entire Contract","Physical Exam & Autopsy","Time Limit on Certain Defenses"],"answer":"Change of Occupation","topic":"NAIC Uniform Provisions","explanation":"Change of Occupation is an OPTIONAL provision. Entire Contract, Physical Exam & Autopsy, and Time Limit on Certain Defenses are mandatory provisions."},{"module":"Day 8 Module 1","group":"d8m1-group-health-coverage","question":"Choose the service or treatment that a group health insurance policy would NOT be required to provide coverage.","options":["Qualified services completed in an ambulatory surgical center","Outpatient services that would have been covered if rendered for an inpatient","Specific services by a licensed ophthalmologists","Treatment for work-related illness or injury"],"answer":"Treatment for work-related illness or injury","topic":"Group Health Coverage","explanation":"A group health policy is NOT required to cover treatment for work-related illness or injury — that belongs to workers\' compensation. The other services are required."},{"module":"Day 8 Module 1","group":"d8m1-hiv-aids-rules","question":"Which of the following statements is NOT true?","options":["The agent is responsible for completing the application.","An insurer may cancel or not renew for diagnosis of HIV/AIDS but may not cancel or not renew for treatment of HIV/AIDS.","A long-term are policy can have an elimination period for up to 180 days","An applicant shall be notified of a positive test result of HIV/AIDS by the agent withint 10 days."],"answer":"An insurer may cancel or not renew for diagnosis of HIV/AIDS but may not cancel or not renew for treatment of HIV/AIDS.","topic":"HIV/AIDS Rules","explanation":"An insurer may NOT cancel or non-renew for diagnosis OR treatment of HIV/AIDS, so this statement is false. The agent completing the application, the 180-day LTC elimination period, and HIV notification are otherwise correct."},{"module":"Day 8 Module 1","group":"d8m1-naic-uniform-provisions","question":"Under the NAIC Uniform Provisions Law, which of the following is optional for a health policy?","options":["Change of Occupation","Entire Contract","Physical Exam & Autopsy","Time Limit on Certain Defenses"],"answer":"Change of Occupation","topic":"NAIC Uniform Provisions","explanation":"Change of Occupation is the optional provision; the other three are mandatory under the Uniform Provisions Law."},{"module":"Day 8 Module 1","group":"d8m1-hiv-aids-rules","question":"Which of the following statements is true?","options":["An insurer may not cancel or not renew for diagnosis of HIV/AIDS, but it may cancel or not renew for treatment of HIV/AIDS.","An insurer may cancel or not renew for diagnosis of HIV/AIDS but may not cancel or not renew for treatment of HIV/AIDS.","An insurer may cancel or not renew for diagnosis or treatment of HIV/AIDS.","An insurer may not cancel or not renew for diagnosis or treatment of HIV/AIDS."],"answer":"An insurer may not cancel or not renew for diagnosis or treatment of HIV/AIDS.","topic":"HIV/AIDS Rules","explanation":"TRUE: An insurer may not cancel or non-renew for diagnosis OR treatment of HIV/AIDS. HIV status cannot be a basis for cancellation or non-renewal."},{"module":"Day 8 Module 1","group":"d8m1-hiv-aids-rules","question":"Which of the following claims does not apply?","options":["The agent is responsible for completing the application.","An insurer may cancel or not renew for diagnosis of HIV/AIDS but may not cancel or not renew for treatment of HIV/AIDS.","A long-term are policy can have an elimination period for up to 180 days","An applicant shall be notified of a positive test result of HIV/AIDS by the agent within 10 days."],"answer":"An insurer may cancel or not renew for diagnosis of HIV/AIDS but may not cancel or not renew for treatment of HIV/AIDS.","topic":"HIV/AIDS Rules","explanation":"Same rule as Q5/Q7 — the false statement is that an insurer may cancel for diagnosis but not treatment. Insurers may not act on either diagnosis or treatment of HIV/AIDS."},{"module":"Day 8 Module 1","group":"d8m1-erisa","question":"The purpose of ERISA is to ___________.","options":["override state insurance laws","replace state insurance laws","protect the rights of workers who are injured on the job","protect the rights of workers covered under an employer-sponsored plan"],"answer":"protect the rights of workers covered under an employer-sponsored plan","topic":"ERISA","explanation":"ERISA exists to protect the rights of workers covered under employer-sponsored benefit plans (pension and welfare benefit plans)."},{"module":"Day 8 Module 1","group":"d8m1-group-health-coverage","question":"Which of the following claims regarding group health insurance plans is TRUE?","options":["Coverage from an occupational accident cannot be excluded.","Coverage for newborn children can be excluded.","Coverage for VA hospital treatment cannot be excluded.","Coverage for handicapped children may be provided."],"answer":"Coverage for handicapped children may be provided.","topic":"Group Health Coverage","explanation":"Only the handicapped-children statement is true; the others misstate the rules on occupational accidents and newborn coverage."},{"module":"Day 8 Module 1","group":"d8m1-blanket-insurance","question":"Which of the following would NOT be covered by a general policy?","options":["A group of pharmacists","A school bus covering the children riding it","A neighborhood playground","An airline covering its passengers"],"answer":"A neighborhood playground","topic":"Blanket Insurance","explanation":"A neighborhood playground is not a definable group and would NOT be covered by a blanket/group policy. Schools, airlines, and professional groups are eligible."},{"module":"Day 8 Module 1","group":"d8m1-wellness-rebates","question":"Rebates for Wellness Program Participation may not exceed ______ of paid premiums.","options":["50%","30%","25%","10%"],"answer":"10%","topic":"Wellness Rebates","explanation":"Premium rebates for wellness-program participation cannot exceed 10% of paid premiums under Florida law."},{"module":"Day 8 Module 1","group":"d8m1-hiv-testing-duties","question":"Regarding the insurer\'s duty to the applicant for HIV testing, which of the following is FALSE?","options":["The insurer must disclose its intent to test a person for HIV prior to testing for HIV/AIDS.","The insurer must get the person\'s written consent to administer the test.","The insurer must notify the insured of any positive results.","The insurer may inquire whether a person has been tested positive for exposure to the HIV infection."],"answer":"The insurer may inquire whether a person has been tested positive for exposure to the HIV infection.","topic":"HIV Testing Duties","explanation":"FALSE statement: an insurer may NOT simply inquire whether someone has tested positive for HIV. It must disclose intent, get written consent, and notify of positive results."},{"module":"Day 8 Module 1","group":"d8m1-fl-required-provisions","question":"Which of the following DOES NOT have to be included in a group health insurance policy requirement under Florida law?","options":["Group health policies must provide coverage for mental and nervous disorders.","A newborn infant is covered from the moment of birth.","Coverage must be provided for a handicapped child who is a family member until he or she reaches the age of 25.","Group health policies must provide coverage for a newborn infant of a covered family member until the infant reaches 18 months of age."],"answer":"Coverage must be provided for a handicapped child who is a family member until he or she reaches the age of 25.","topic":"FL Required Provisions","explanation":"Coverage for a handicapped child is NOT limited to age 25 — it continues as long as the child remains disabled and dependent. That statement does not have to be (and isn\'t) part of the policy."},{"module":"Day 8 Module 1","group":"d8m1-florida-healthy-kids","question":"Participation in the Florida Healthy Kids Corporation is on a ______ basis.","options":["mandatory","as needed","recommended","voluntary"],"answer":"voluntary","topic":"Florida Healthy Kids","explanation":"Participation in the Florida Healthy Kids Corporation is on a voluntary basis."},{"module":"Day 8 Module 1","group":"d8m1-family-coverage","question":"What type of coverage is typically available under a family health policy?","options":["Adopted children","Stepchildren","Foster children","All of the above"],"answer":"All of the above","topic":"Family Coverage","explanation":"Family health policies typically cover adopted, step, and foster children — all of the above."},{"module":"Day 8 Module 1","group":"d8m1-hiv-testing-duties","question":"Which of the following is not correct concerning the insurer\'s obligation to the applicant regarding HIV testing?","options":["The insurer must disclose its intent to test a person for HIV prior to testing for HIV/AIDS.","The insurer must get the person\'s written consent to administer the test.","The insurer must notify the insured of any positive results.","The insurer may inquire whether a person has been tested positive for exposure to the HIV infection."],"answer":"The insurer may inquire whether a person has been tested positive for exposure to the HIV infection.","topic":"HIV Testing Duties","explanation":"Insurers may not ask whether a person has previously tested positive for HIV. The other duties (disclose intent, written consent, notify of positive results) are required."},{"module":"Day 8 Module 1","group":"d8m1-hiv-aids-rules","question":"Which of these claims about the following is true?","options":["An insurer may not cancel or not renew for diagnosis of HIV/AIDS, but it may cancel or not renew for treatment of HIV/AIDS.","An insurer may cancel or not renew for diagnosis of HIV/AIDS but may not cancel or not renew for treatment of HIV/AIDS.","An insurer may cancel or not renew for diagnosis or treatment of HIV/AIDS.","An insurer may not cancel or not renew for diagnosis or treatment of HIV/AIDS."],"answer":"An insurer may not cancel or not renew for diagnosis or treatment of HIV/AIDS.","topic":"HIV/AIDS Rules","explanation":"TRUE: insurers may not cancel or non-renew for diagnosis OR treatment of HIV/AIDS."},{"module":"Day 8 Module 1","group":"d8m1-fl-required-provisions","question":"Which of the following is NOT a provision that is required by Florida law for group health insurance policies?","options":["Group health policies must provide coverage for mental and nervous disorders.","A newborn infant is covered from the moment of birth.","Coverage must be provided for a handicapped child who is a family member until he or she reaches the age of 25.","Group health policies must provide coverage for a newborn infant of a covered family member until the infant reaches 18 months of age."],"answer":"Coverage must be provided for a handicapped child who is a family member until he or she reaches the age of 25.","topic":"FL Required Provisions","explanation":"The age-25 handicapped-child statement is not a required Florida provision; disabled dependent coverage continues without that cutoff."},{"module":"Day 8 Module 1","group":"d8m1-insurance-regulation","question":"Which statement below does NOT indicate landmark cases and laws involving the regulation of insurance?","options":["When an applicant\'s consumer or credit history is being investigated, insurers are required to disclose this information to the applicant.","The NAIC has standing committees working regularly to examine numerous aspects of the insurance industry.","The Federal Trade Commission (FTC) directly supervises the marketing techniques of all insurance companies.","The McCarran-Ferguson Act laid the basis for our current understanding that state governments are the primary regulators of the insurance industry."],"answer":"The Federal Trade Commission (FTC) directly supervises the marketing techniques of all insurance companies.","topic":"Insurance Regulation","explanation":"FALSE: the FTC does NOT directly supervise insurance marketing. Under McCarran-Ferguson, states are the primary regulators of insurance."},{"module":"Day 8 Module 1","group":"d8m1-advertising-code","question":"Rules pertaining to testimonials, statistics, and special offers would be found in ______.","options":["the policy summary","the entire contract","the Advertising Code","the Buyers Guide"],"answer":"the Advertising Code","topic":"Advertising Code","explanation":"Rules on testimonials, statistics, and special offers are found in the Advertising Code."},{"module":"Day 8 Module 1","group":"d8m1-reinsurance","question":"Reinsurers are a specialized branch of the insurance industry. This is because they insure ______.","options":["insurers","employers with high risk","applicants from Lloyds of London","applicants with low risk"],"answer":"insurers","topic":"Reinsurance","explanation":"Reinsurers insure other insurers, spreading large or catastrophic risk."},{"module":"Day 8 Module 1","group":"d8m1-insurer-domicile","question":"A life insurance company organized in Wisconsin, with an office in Pittsburg, and licensed to sell insurance in Florida is a ______.","options":["domestic company","alien company","foreign company","regional company"],"answer":"foreign company","topic":"Insurer Domicile","explanation":"Organized in Wisconsin but doing business in Florida makes it a FOREIGN company (a U.S. insurer domiciled in another state). The Pittsburgh office is irrelevant."},{"module":"Day 8 Module 1","group":"d8m1-reinsurance","question":"Jordan works as an underwriter for a mid sized insurance company in Florida. His company recently issued several large commercial policies and now wants to reduce its exposure to potential high value claims. To accomplish this, the company decides to transfer part of its risk to another entity that specializes in assuming portions of insurers’ liabilities. Which group does this specialized entity—known as a reinsurer—primarily insure?","options":["Individual policyholders","Government agencies","Insurance companies","Independent insurance agents"],"answer":"Insurance companies","topic":"Reinsurance","explanation":"A reinsurer primarily insures insurance companies, assuming portions of their liabilities."},{"module":"Day 8 Module 1","group":"d8m1-insurable-interest","question":"At what time must an insurable interest exist in life and health contracts?","options":["After the policy is issued","Before the beneficiary is named","While the policy is enforced","At the inception of the policy"],"answer":"At the inception of the policy","topic":"Insurable Interest","explanation":"In life and health contracts, insurable interest must exist at the inception of the policy (time of application)."},{"module":"Day 8 Module 1","group":"d8m1-contract-types","question":"Which of the following is a \\"take it or leave it\\" type of contract?","options":["Aleatory","Unilateral","Conditional","Adhesion"],"answer":"Adhesion","topic":"Contract Types","explanation":"A \'take it or leave it\' contract is a contract of adhesion — one party writes it and the other accepts as-is."},{"module":"Day 8 Module 1","group":"d8m1-agent-authority","question":"What type of authority is not overtly extended but must be used to enable the agent to transact business of the principle?","options":["Express","Implied","Apparent","Fiduciary"],"answer":"Implied","topic":"Agent Authority","explanation":"Implied authority is not expressly granted but is needed for the agent to transact the principal\'s business."},{"module":"Day 8 Module 1","group":"d8m1-contract-types","question":"Which of the following is a contract where only one party is liable in court?","options":["Aleatory","Unilateral","Conditional","Adhesion"],"answer":"Unilateral","topic":"Contract Types","explanation":"A unilateral contract has only one legally enforceable promise — only the insurer can be held to its promise."},{"module":"Day 8 Module 1","group":"d8m1-stoli","question":"Which of the following is an example of a STOLI?","options":["Brenda takes out a policy on her sister Pam.","Emanuel takes out a policy on his employees.","An investor has Catherine, 78, to take out a policy and names herself as the beneficiary.","Destiny takes out a policy on her mother, Ann."],"answer":"An investor has Catherine, 78, to take out a policy and names herself as the beneficiary.","topic":"STOLI","explanation":"STOLI (stranger-originated life insurance) is when an investor with no insurable interest induces someone to take out a policy for the investor\'s benefit."},{"module":"Day 8 Module 1","group":"d8m1-underwriting","question":"All of the following are part of the Home Office underwriting process EXCEPT______.","options":["credit report","Medical Information Bureau report","applicant\'s analyst report","inspection report"],"answer":"applicant\'s analyst report","topic":"Underwriting","explanation":"There is no \'applicant\'s analyst report.\' Home-office underwriting uses credit reports, MIB reports, and inspection reports."},{"module":"Day 8 Module 1","group":"d8m1-deceptive-practices","question":"What is a deceptive sales presentation?","options":["Any presentation that gives the prospect the wrong impression about any aspect of an insurance policy","Any presentation that does not provide complete disclosure","Any presentation that includes any misleading or inconclusive product comparison","All of these are correct."],"answer":"All of these are correct.","topic":"Deceptive Practices","explanation":"All of these — wrong impressions, incomplete disclosure, and misleading comparisons — make a sales presentation deceptive."},{"module":"Day 8 Module 1","group":"d8m1-misrepresentation","question":"If the agent states mutual funds are the same as variable universal life insurance, this would be considered ______.","options":["twisting","misrepresentation","replacement","rebating"],"answer":"misrepresentation","topic":"Misrepresentation","explanation":"Claiming mutual funds are the same as variable universal life is a misrepresentation (a false statement about the product)."},{"module":"Day 8 Module 1","group":"d8m1-producer-duties","question":"The producer should educate the applicant on all the following EXCEPT ______.","options":["the need for accuracy and honesty","meanings of various terms such as waiver of premiums, etc.","why information is required","how the DFS works with the CFO"],"answer":"how the DFS works with the CFO","topic":"Producer Duties","explanation":"The producer need not teach the applicant how the DFS works with the CFO. They must explain accuracy/honesty, policy terms, and why information is required."},{"module":"Day 8 Module 1","group":"d8m1-naic","question":"An objective of the National Association of Insurance Commissioners is to ______.","options":["promote federal legislation of the insurance industry","encourage uniformity in state insurance laws and regulations","develop continuing education courses for insurance producers","create model insurance policies for adoption by insurers"],"answer":"encourage uniformity in state insurance laws and regulations","topic":"NAIC","explanation":"An NAIC objective is to encourage uniformity in state insurance laws and regulations (it does not promote federal regulation)."},{"module":"Day 8 Module 1","group":"d8m1-indemnity","question":"Which of the following is not an example of an indemnity contract?","options":["Subrogation","Health insurance policies","Property and casualty","Disability Income"],"answer":"Subrogation","topic":"Indemnity","explanation":"Subrogation is a legal principle, not a type of indemnity contract. Health, property/casualty, and disability are insurance contracts."},{"module":"Day 8 Module 1","group":"d8m1-valued-contracts","question":"What type of health insurance contract would agree to pay a stated amount each month to the insured if he or she becomes totally disabled?","options":["Participating contracts","Valued contracts","Inclusive contracts","Reimbursement contracts"],"answer":"Valued contracts","topic":"Valued Contracts","explanation":"A contract that pays a stated amount each month for total disability is a valued contract (pays a set amount, not actual expenses)."},{"module":"Day 8 Module 1","group":"d8m1-valued-contracts","question":"All of the following are valued contracts except:","options":["Life insurance policies","AD&D policies","Disability income policies","Long-term care"],"answer":"Long-term care","topic":"Valued Contracts","explanation":"Long-term care is reimbursement/expense-incurred coverage, not a valued contract. Life, AD&D, and disability income are valued contracts."},{"module":"Day 8 Module 1","group":"d8m1-premium-modes","question":"Which premium mode is least expensive?","options":["Annual","Semiannual","Quarterly","Monthly"],"answer":"Annual","topic":"Premium Modes","explanation":"Annual is the least expensive premium mode — more frequent payments add cost."},{"module":"Day 8 Module 1","group":"d8m1-reserves","question":"What does an insurance company set aside to pay future claims?","options":["Valued contracts","Indemnity contracts","Reserves","Master contracts"],"answer":"Reserves","topic":"Reserves","explanation":"Insurers set aside reserves to pay future claims."},{"module":"Day 8 Module 1","group":"d8m1-hmos","question":"Why are HMOs a distinct form of health care provider?","options":["They are popular for large groups of employers.","They provide financing for the health care plus the health care itself.","They provide a large variety of options.","The doctors operate on a fee for service arrangement."],"answer":"They provide financing for the health care plus the health care itself.","topic":"HMOs","explanation":"HMOs are distinct because they provide both the financing for care AND the health care itself."},{"module":"Day 8 Module 1","group":"d8m1-social-security-disability","question":"All of the following statements concerning Social Security disability benefits are true EXCEPT:","options":["The impairment must be expected to last at least 12 months.","The waiting period is 5 months.","The waiting period may be waived in certain circumstances.","Benefits are retroactive to the time of disability."],"answer":"Benefits are retroactive to the time of disability.","topic":"Social Security Disability","explanation":"FALSE: SSDI benefits are NOT retroactive to the time of disability. The impairment must last 12+ months and there is a 5-month waiting period."},{"module":"Day 8 Module 1","group":"d8m1-multiple-employer-trust","question":"Grouping small businesses together to obtain group insurance as one large group is characteristic of which of the following?","options":["A Health Maintenance Organization (HMO)","A Franchise Health plan","A Multiple Employer Trust (MET)","A Fictitious group"],"answer":"A Multiple Employer Trust (MET)","topic":"Multiple Employer Trust","explanation":"Grouping small businesses together to buy group insurance as one large group describes a Multiple Employer Trust (MET)."},{"module":"Day 8 Module 1","group":"d8m1-social-security-disability","question":"Choose the individual who is most likely to qualify for Social Security disability benefits.","options":["Randy, a ski instructor who breaks his leg","Sarah, who is sick from a viral infection and is not expected to be able to work for the next 6 months","Perry, a mechanic who loses his dominant hand in an accident","Grace, who experiences serious early-onset Alzheimer\'s and is unable to remember how to get to work"],"answer":"Grace, who experiences serious early-onset Alzheimer\'s and is unable to remember how to get to work","topic":"Social Security Disability","explanation":"Grace, with serious early-onset Alzheimer\'s preventing any work for 12+ months, best meets SSDI\'s strict \'any occupation\' standard. The others can likely do other work or recover within 12 months."},{"module":"Day 8 Module 1","group":"d8m1-social-security-disability","question":"What is the waiting period before someone can qualify for Social Security disability benefits?","options":["3 months","5 months","6 months","12 months"],"answer":"5 months","topic":"Social Security Disability","explanation":"The SSDI waiting (elimination) period is 5 months."},{"module":"Day 8 Module 1","group":"d8m1-assignment","question":"In a health insurance policy, which term describes a situation where a policyowner has medical benefits assigned or paid directly to the hospital or physician?","options":["Collateral assignment","Absolute assignment","Transfer assignment","Right of assignment"],"answer":"Right of assignment","topic":"Assignment","explanation":"Directing benefits to be paid to the hospital or physician is done under the insured\'s right of assignment (assignment of benefits)."},{"module":"Day 8 Module 1","group":"d8m1-deductibles","question":"Deductible provisions are common in medical insurance policies. Which statement about the deductible provision is NOT correct?","options":["They help to eliminate small claims.","They provide that initial expenses up to a specified amount are to be paid by the insured.","They are most common in basic medical expense policies.","They help to hold down premium rates."],"answer":"They are most common in basic medical expense policies.","topic":"Deductibles","explanation":"NOT correct: deductibles are most common in MAJOR medical, not basic medical expense policies. They do eliminate small claims, shift initial costs to the insured, and hold down premiums."},{"module":"Day 8 Module 1","group":"d8m1-coinsurance","question":"Which of the following is the most common type of co-insurance in a major medical policy?","options":["5 and 10%","10 and 15%","20 and 25%","25 and 30%"],"answer":"20 and 25%","topic":"Coinsurance","explanation":"The most common major-medical coinsurance splits are 80/20 and 75/25, i.e., the insured pays 20% and 25%."},{"module":"Day 8 Module 1","group":"d8m1-hras","question":"Which of the following statements about health reimbursement accounts (HRAs) is correct?","options":["HRAs are established by the employer.","HRAs are established by the employee.","HRAs are established with after-tax dollars.","HRAs are the least common of high deductible health plans."],"answer":"HRAs are established by the employer.","topic":"HRAs","explanation":"Health Reimbursement Accounts are established and funded by the employer."},{"module":"Day 8 Module 1","group":"d8m1-hospital-expense","question":"Jackie is covered under a hospital expense policy. Based on what you know about this plan, what type of plan is this?","options":["Service","Limited","Fixed-rate plan","Special risk"],"answer":"Service","topic":"Hospital Expense","explanation":"A hospital expense policy reimburses actual hospital expenses — a service (reimbursement) plan rather than a fixed-rate indemnity plan."},{"module":"Day 8 Module 1","group":"d8m1-r-c-charges","question":"The determination of the cost of a surgical procedure based on the location or general area where the procedure will take place is known as ______.","options":["reasonable and customary approach charges","stated charges","percentage of stated charges","designated charges"],"answer":"reasonable and customary approach charges","topic":"R&C Charges","explanation":"Pricing a surgical procedure by the location/area is the reasonable and customary (R&C) charge approach."},{"module":"Day 8 Module 1","group":"d8m1-hospital-indemnity","question":"Which type of coverage premium is least affected by an increase in medical costs?","options":["Basic Medical Expense","Hospital Indemnity","Comprehensive Medical","Major Medical"],"answer":"Hospital Indemnity","topic":"Hospital Indemnity","explanation":"Hospital indemnity pays a fixed dollar amount regardless of actual cost, so its premium is least affected by rising medical costs."},{"module":"Day 8 Module 1","group":"d8m1-accidental-means","question":"Lorenzo had a disability income policy with an \\"accidental means\\" definition. He jumped into a river and broke his back leaving him paralyzed. What course of action would the insurance company take?","options":["The policy should pay the full amount since Lorenzo\'s accident was not planned.","The policy should pay 1/2 the amount since the jump was planned but the injury was not.","The policy should pay nothing since his jump was no accident. The injury does not matter.","The policy should pay nothing since it was still in the reinstatement phase."],"answer":"The policy should pay nothing since his jump was no accident. The injury does not matter.","topic":"Accidental Means","explanation":"Under an \'accidental means\' definition, the cause must be unintentional. The jump was intentional, so nothing is paid — the injury result doesn\'t matter."},{"module":"Day 8 Module 1","group":"d8m1-presumptive-disability","question":"What type of disability automatically qualifies the insured for full benefits based on a permanent physical impairment which left the individual incapable of performing their previous occupation but allows them to perform other work?","options":["Presumptive Disability","Permanent partial disability","Temporary total disability","Temporary partial disability"],"answer":"Presumptive Disability","topic":"Presumptive Disability","explanation":"\'Automatically qualifies for full benefits\' signals presumptive disability, which pays full benefits for specified permanent impairments."},{"module":"Day 8 Module 1","group":"d8m1-accidental-means","question":"Eric had a disability income policy with an \\"accidental means\\" definition. He jumped into a lake and broke his neck leaving him paralyzed. What course of action would the insurance company take?","options":["Pay the full amount, since Eric\'s accident was not planned","Pay 1/2 the amount, since the jump was planned but the injury was not","Pay nothing, his jump was no accident, the injury does not matter","Pay nothing, since the policy was still in the reinstatement phase"],"answer":"Pay nothing, his jump was no accident, the injury does not matter","topic":"Accidental Means","explanation":"\'Accidental means\' requires the cause to be accidental. Eric intentionally jumped, so the policy pays nothing."},{"module":"Day 8 Module 1","group":"d8m1-total-disability","question":"Which of the following may normally be used as a definition of total disability? I. House-confined II. Inability to perform the duties of any occupation III. Inability to perform the duties of the insured\'s own occupation","options":["I only","I and II","II and III","I and III"],"answer":"II and III","topic":"Total Disability","explanation":"Total disability is normally defined as inability to perform the duties of ANY occupation (II) or the insured\'s OWN occupation (III). House-confined is not a standard definition."},{"module":"Day 8 Module 1","group":"d8m1-permanent-partial","question":"Regarding disability, a disability that is a permanent physical impairment leaving the individual incapable of performing the previous regular occupation, but capable of performing some other type of work, is:","options":["Permanent total disability.","Permanent partial disability","Temporary total disability","Temporary partial disability"],"answer":"Permanent partial disability","topic":"Permanent Partial","explanation":"A permanent impairment preventing the prior occupation but allowing other work is permanent partial disability."},{"module":"Day 8 Module 1","group":"d8m1-disability-benefits","question":"Maria had a $1,000 per month disability policy with a benefit period to age 65 and a six-month waiting period. She became disabled at age 64 1/2. What would be the amount she receives?","options":["$2,000","$1,000","$12,000","Nothing"],"answer":"Nothing","topic":"Disability Benefits","explanation":"With a 6-month waiting period, benefits would start at age 65 — but the benefit period ends at 65, so Maria receives nothing."},{"module":"Day 8 Module 1","group":"d8m1-limited-policies","question":"Dread disease, a travel accident, vision care, and hospital indemnity policies are all examples of:","options":["LTC policies","Limited risk policies","Special risk","Blanket policies"],"answer":"Limited risk policies","topic":"Limited Policies","explanation":"Dread disease, travel accident, vision, and hospital indemnity are all limited (limited-risk) policies covering specific risks."},{"module":"Day 8 Module 1","group":"d8m1-capital-sum","question":"Ginny has a $50,000 accidental death and dismemberment policy. She received a $15,000 cash benefit her for the accidental loss of one eye. The $15,000 benefit could be identified as the policy\'s ______.","options":["principal sum","secondary sum","capital sum","contingent amount"],"answer":"capital sum","topic":"Capital Sum","explanation":"The amount paid for accidental loss of one eye (a single dismemberment) is the capital sum. The full death benefit is the principal sum."},{"module":"Day 8 Module 1","group":"d8m1-accidental-results","question":"If John has an AD&D policy, which plan will pay if he jumps off a ladder and severely injures his leg that it must be amputated?","options":["Accidental results","Accidental means","Accidental measures","Accidental restitution"],"answer":"Accidental results","topic":"Accidental Results","explanation":"Under an \'accidental results\' (accidental bodily injury) definition, the unexpected RESULT is covered even though jumping off the ladder was intentional — so it pays."},{"module":"Day 8 Module 1","group":"d8m1-limited-risk","question":"A limited risk policy covers ______.","options":["risks not covered by accident and health policies","specific risks","all risks","unusual types of risks"],"answer":"specific risks","topic":"Limited Risk","explanation":"A limited-risk policy covers specific named risks."},{"module":"Day 8 Module 1","group":"d8m1-special-risk","question":"Which of the following policies would cover an accidental death or injury while riding in a car?","options":["Limited risk","Special risk","Dread disease","Long-term care"],"answer":"Special risk","topic":"Special Risk","explanation":"A policy covering accidental death or injury while riding in a car (a travel-type hazard) is a special risk policy."},{"module":"Day 8 Module 1","group":"d8m1-dismemberment","question":"Under the typical health insurance policy, which of the following would qualify as dismemberment? I. Taylor loses all the fingers on his left hand except the thumb. II. Jared, is right handed and permanently loses the use of his right hand and arm in an auto accident.","options":["I only","II only","I and II","Neither I nor II"],"answer":"II only","topic":"Dismemberment","explanation":"Permanent loss of use of the hand and arm (II) qualifies as dismemberment. Losing fingers while keeping the thumb (I) is not a covered dismemberment."},{"module":"Day 8 Module 1","group":"d8m1-medicare-part-a","question":"Which is true about Part A of Medicare?","options":["The insured must pay a premium.","The insured must pay a deductible.","The insured must pay a deductible and a premium.","The insured does not have to pay a deductible or a premium."],"answer":"The insured must pay a deductible.","topic":"Medicare Part A","explanation":"Most people pay NO premium for Part A (premium-free with enough work credits) but they DO pay a deductible."},{"module":"Day 8 Module 1","group":"d8m1-medicare-eligibility","question":"Which of the following is NOT eligible for Medicare coverage?","options":["People aged 65 and older eligible for Social Security","People aged 65 and older not eligible for Social Security, but willing to pay a monthly premium","People of any age who have been entitled to Social Security Disability benefits","People with any life-threatening condition"],"answer":"People with any life-threatening condition","topic":"Medicare Eligibility","explanation":"Having \'any life-threatening condition\' does not make someone Medicare-eligible. Eligibility is 65+, certain disability beneficiaries, or specific conditions (ESRD/ALS)."},{"module":"Day 8 Module 1","group":"d8m1-medicare-part-b","question":"Under Medicare Part B, which of the following do participants NOT have to pay?","options":["An annual deductible","A per benefit deductible","20% of covered charges above the deductible","A monthly premium"],"answer":"A per benefit deductible","topic":"Medicare Part B","explanation":"Part B has an annual deductible, 20% coinsurance, and a monthly premium — but NOT a per-benefit (per-benefit-period) deductible, which is a Part A feature."},{"module":"Day 8 Module 1","group":"d8m1-medicare-eligibility","question":"Which of the following groups is NOT eligible for Medicare coverage?","options":["People aged 65 and older eligible for Social Security","People aged 65 and older not eligible for Social Security but willing to pay a monthly premium","People of any age who have been entitled to Social Security disability benefits","People with any life-threatening condition"],"answer":"People with any life-threatening condition","topic":"Medicare Eligibility","explanation":"\'Any life-threatening condition\' is not a Medicare eligibility category."},{"module":"Day 8 Module 1","group":"d8m1-medicare-reserve-days","question":"Select the answer that fills all three blanks correctly: The lifetime reserve for Medicare is ______ days. If a patient is hospitalized beyond the ______ lifetime reserve day, thereby exhausting the reserve, he/she is responsible for ______.","options":["30 days, 30th, a portion of the hospital charges","60 days, 60th, all hospital charges","90 days, 90th, none of the hospital charges","120 days, 120th, 20% of the hospital charges"],"answer":"60 days, 60th, all hospital charges","topic":"Medicare Reserve Days","explanation":"Medicare provides 60 lifetime reserve days; beyond the 60th reserve day the patient is responsible for ALL hospital charges."},{"module":"Day 8 Module 1","group":"d8m1-medicare-premiums","question":"Which part of Medicare requires premium payments by the most eligible participants?","options":["Part A, basic hospital insurance","Part B, supplementary medical insurance","Respite care","All of the answer choices are correct."],"answer":"Part B, supplementary medical insurance","topic":"Medicare Premiums","explanation":"Part B (supplementary medical insurance) requires a monthly premium from most participants; Part A is premium-free for most."},{"module":"Day 8 Module 1","group":"d8m1-moral-hazard","question":"What is considered a moral hazard?","options":["Age","Gender","Lifestyle","Occupation"],"answer":"Lifestyle","topic":"Moral Hazard","explanation":"Lifestyle (behavior/character-based tendencies that increase loss) reflects a moral/morale hazard, unlike age, gender, or occupation."},{"module":"Day 8 Module 1","group":"d8m1-underwriting","question":"Which of the following factors is a primary risk factor in underwriting individual health insurance policies?","options":["Geographical location","Salary requirements","Zip code of the insured","Physical condition"],"answer":"Physical condition","topic":"Underwriting","explanation":"Physical condition is a primary risk factor in underwriting individual health insurance."},{"module":"Day 8 Module 1","group":"d8m1-underwriting","question":"Which of the following would probably NOT be considered in underwriting a health insurance risk?","options":["An individual\'s avocations","An individual\'s age","An individual\'s sex – male or female","The address of the individual"],"answer":"The address of the individual","topic":"Underwriting","explanation":"An individual\'s address is generally NOT used in underwriting a health risk; age, sex, and avocations are."},{"module":"Day 8 Module 1","group":"d8m1-managed-care","question":"Which of the following is NOT a reason insurers use MCOs use for medical cost management?","options":["Controls claims expenses","MCOs encourage overutilization by insureds","MCOs control how policyowners use their policy","MCOs seek to raise the cost for the insurer to provide better benefits for insureds"],"answer":"MCOs encourage overutilization by insureds","topic":"Managed Care","explanation":"NOT a reason to use MCOs: \'encouraging overutilization\' — MCOs exist to control utilization and claims expenses, not increase use."},{"module":"Day 8 Module 1","group":"d8m1-chronic-illness","question":"All the following are true concerning chronic illnesses except:","options":["Most people ignore chronic conditions and the pain they cause","A chronic condition frequently goes beyond being a nuisance and begins to inhibit a person\'s independence","Chronic conditions are can affect other parts of the body","Chronic conditions allow the body to fully recover and can be managed"],"answer":"Chronic conditions allow the body to fully recover and can be managed","topic":"Chronic Illness","explanation":"FALSE: chronic conditions do NOT allow full recovery — by definition they persist and are managed rather than cured."},{"module":"Day 8 Module 1","group":"d8m1-medigap","question":"All of the following are true regarding Medicare supplement or Medigap policies except:","options":["Medicare supplements are sold by private insurance companies.","Medicare supplements are the same as Medigap policies.","Medicare supplements pay costs for Part C & Part D.","It\'s best to have a Medicare Advantage plan and a Medigap plan combined for more benefits."],"answer":"It\'s best to have a Medicare Advantage plan and a Medigap plan combined for more benefits.","topic":"Medigap","explanation":"FALSE: you cannot combine a Medicare Advantage plan with a Medigap policy — it is illegal to sell Medigap to an MA enrollee. Medigap supplements Original Medicare only."},{"module":"Day 8 Module 1","group":"d8m1-proof-of-loss","question":"With the exception of instances of legal incapacity, proof of loss for surgical expense benefits must be furnished to the insurance company within _______.","options":["60 days","90 days","6 months","1 year"],"answer":"90 days","topic":"Proof of Loss","explanation":"Written proof of loss for surgical/expense benefits must be furnished within 90 days of the loss."},{"module":"Day 8 Module 1","group":"d8m1-proof-of-loss","question":"Under a health policy, an insured is required to provide written proof of loss to the insurance company within a maximum of how many days after a loss?","options":["60 days","90 days","20 days","30 days"],"answer":"90 days","topic":"Proof of Loss","explanation":"An insured must provide written proof of loss within a maximum of 90 days after a loss."},{"module":"Day 8 Module 1","group":"d8m1-renewability","question":"Given that a company can change premium rates on a class basis, a ______ health insurance policy will always be renewable until the insured reaches a certain age.","options":["noncancellable","guaranteed renewable","optional renewable","cancellable"],"answer":"guaranteed renewable","topic":"Renewability","explanation":"A guaranteed renewable policy must be renewed until a stated age, though premiums may change on a class basis."},{"module":"Day 8 Module 1","group":"d8m1-exclusions","question":"Which of the following limits coverage under an insurance contract?","options":["Waiver of premium","Conditions","Exclusions of declarations","20501"],"answer":"Exclusions of declarations","topic":"Exclusions","explanation":"Exclusions limit coverage by stating what the policy will not cover."},{"module":"Day 8 Module 1","group":"d8m1-misstatement-of-age","question":"Optional Provision on misstatement of age, permit the insurer to do which of the following?","options":["The insurer will return premiums and cancel the policy","The agents commission is charged back and the policy is cancelled","The policy is cancelled and no return of premiums.","The insurer has the right to review the policy to determine what benefits would have been paid based on the actual age of the insured."],"answer":"The insurer has the right to review the policy to determine what benefits would have been paid based on the actual age of the insured.","topic":"Misstatement of Age","explanation":"The misstatement-of-age provision lets the insurer adjust benefits to what the premium paid would have purchased at the insured\'s correct age."},{"module":"Day 8 Module 1","group":"d8m1-occupational-class","question":"Which occupational class identifies professionals and those in office settings?","options":["A+","AAA","A","C"],"answer":"A","topic":"Occupational Class","explanation":"Class A identifies professionals and office/clerical occupations (lowest risk)."},{"module":"Day 8 Module 1","group":"d8m1-impairment-rider","question":"Which of the following would exclude certain conditions from coverage under a health insurance policy?","options":["Pre-existing conditions","Impairment rider","The insuring clause","The consideration clause"],"answer":"Impairment rider","topic":"Impairment Rider","explanation":"An impairment (exclusion) rider excludes specified conditions from coverage."},{"module":"Day 8 Module 1","group":"d8m1-underwriting-factors","question":"Choose the option that is NOT a primary risk factor for underwriting individual health insurance policies?","options":["Geographic location","Moral hazard","Profession","Physical condition"],"answer":"Geographic location","topic":"Underwriting Factors","explanation":"Geographic location is NOT a primary risk factor for individual health underwriting; physical condition, moral hazard, and profession are."},{"module":"Day 8 Module 1","group":"d8m1-managed-care","question":"A managed care organization uses all the following EXCEPT _____.","options":["mandatory second opinions","precertification reviews","case management","referrals"],"answer":"mandatory second opinions","topic":"Managed Care","explanation":"Managed care relies on precertification, case management, and referrals; mandatory second opinions are not a defining MCO tool here, making it the exception."},{"module":"Day 8 Module 1","group":"d8m1-premium-factors","question":"Which factor would NOT affect a health insurance policy\'s premium?","options":["An insured\'s age","An insured\'s occupation","The types of benefits provided","The location of the insured\'s residence"],"answer":"The location of the insured\'s residence","topic":"Premium Factors","explanation":"The location of the insured\'s residence would not affect the health premium; age, occupation, and benefit types do."},{"module":"Day 8 Module 1","group":"d8m1-tax-deductions","question":"To determine a medical tax deduction, ________ can be included as qualifying expenses.","options":["premium contributions paid by the employer to a group medical expense plan","premium contributions paid by the employer to a group disability plan","premium contributions paid by the individual to a group medical expense plan","premium contributions paid by the individual to a group disability plan"],"answer":"premium contributions paid by the individual to a group medical expense plan","topic":"Tax Deductions","explanation":"Premiums the individual pays toward a group MEDICAL expense plan can count as qualifying medical expenses for a deduction; disability premiums and employer-paid premiums do not."},{"module":"Day 8 Module 1","group":"d8m1-group-disability-tax","question":"Which of the following concerning group disability insurance is true? I. Premiums are tax deductible by the employer, and benefits are taxable to the employee. II. Premiums are not tax deductible by the employer, and the benefits are taxable to the employees. III. Any amount contributed by the employee toward the premium makes the entire benefit tax free. IV. The percentage contributed to the premium by the employee makes the same percentage deductible by the employer.","options":["I","II","I & III","I & IV"],"answer":"I","topic":"Group Disability Tax","explanation":"TRUE (I): employer-paid group disability premiums are tax-deductible to the employer, and the benefits are taxable to the employee."},{"module":"Day 8 Module 1","group":"d8m1-blanket-insurance","question":"The CEO of a cruise ship line would like to purchase group health coverage for the cruise ship passengers. What kind of insurance would the CEO need to purchase?","options":["Franchise health insurance","Wholesale health insurance","Blanket health insurance","Credit health insurance"],"answer":"Blanket health insurance","topic":"Blanket Insurance","explanation":"Covering cruise-ship passengers (a transient, unnamed group) requires blanket health insurance."},{"module":"Day 8 Module 1","group":"d8m1-cobra","question":"If an employee is terminated and entitled to extended medical expense coverage under COBRA which event is correct?","options":["Employee dies – dependent family members receive 36 months of continued coverage","Employee dies – dependent family members receive 6 months of continued coverage","Employee dies – dependent family members receive 12 months of continued coverage","Employee dies – dependent family members receive 3 months of continued coverage"],"answer":"Employee dies – dependent family members receive 36 months of continued coverage","topic":"COBRA","explanation":"On the death of the employee, dependent family members receive up to 36 months of continued coverage under COBRA."},{"module":"Day 8 Module 1","group":"d8m1-contributory-plans","question":"In contributory group plan, the insurance company requires what percentage of eligible employees?","options":["At least 25%","At least 50%","100%","Usually 75%"],"answer":"Usually 75%","topic":"Contributory Plans","explanation":"A contributory group plan usually requires at least 75% of eligible employees to participate."},{"module":"Day 8 Module 1","group":"d8m1-premium-cost-control","question":"Which of the following is NOT a method for keeping health insurance policy premium costs to a minimum?","options":["Modifying benefit amounts","Increasing the deductible","Waiving the right to receive benefit payments when due","Extending the elimination"],"answer":"Waiving the right to receive benefit payments when due","topic":"Premium Cost Control","explanation":"Waiving the right to receive benefit payments when due is NOT a premium-reduction method. Modifying benefits, raising deductibles, and extending the elimination period are."},{"module":"Day 8 Module 1","group":"d8m1-key-person-disability","question":"A disability insurance policy that indemnifies the business for the lost services of a key person is called:","options":["A cafeteria plan","Section 125 plan","Key person disability plan","Disability buy-out plan"],"answer":"Key person disability plan","topic":"Key Person Disability","explanation":"A policy indemnifying the business for the lost services of a key person is key person disability insurance."},{"module":"Day 8 Module 1","group":"d8m1-disability-income","question":"Mr. Jansen falls off a ladder at his boss’ house. Which of the following plans will replace her income?","options":["Key person disability insurance","Business Overhead Expense insurance","Disability buyout plan","Disability income"],"answer":"Disability income","topic":"Disability Income","explanation":"To replace Mr. Jansen\'s own income, the relevant coverage is disability income insurance."},{"module":"Day 8 Module 1","group":"d8m1-business-continuation","question":"A Business Continuation plan may include all of the following except:","options":["Life insurance","Group insurance","Credit insurance","Disability insurance"],"answer":"Credit insurance","topic":"Business Continuation","explanation":"A business continuation (buy-sell) plan uses life, disability, and group insurance — not credit insurance."},{"module":"Day 8 Module 1","group":"d8m1-cost-sharing-math","question":"An individual major medical plan with a $1,000 individual deductible is going to cost _______ than a comparable plan with a $5,000 individual deductible; and a plan with an 80/20 coinsurance provision will cost ______ than a comparable plan with a 75/25 coinsurance provision.","options":["more/more","less/less","less/more","more/less"],"answer":"more/more","topic":"Cost Sharing Math","explanation":"A lower ($1,000) deductible costs MORE than a higher ($5,000) one; and 80/20 (insurer pays more) costs MORE than 75/25 — so more/more."},{"module":"Day 8 Module 1","group":"d8m1-unfair-discrimination","question":"A company that charges different premiums for people in the same actuarial class could be found guilty of _____.","options":["twisting","unfair discrimination","segregation","unfair trade practices"],"answer":"unfair discrimination","topic":"Unfair Discrimination","explanation":"Charging different premiums to people in the same actuarial class is unfair discrimination."},{"module":"Day 8 Module 1","group":"d8m1-controlled-business","question":"Which of the following would not be considered controlled business?","options":["An agent writing business solely on his family","An agent writing business on his partner","An agent writing business on his employees","An agent writing business on his neighbor"],"answer":"An agent writing business on his neighbor","topic":"Controlled Business","explanation":"Writing business on a neighbor is NOT controlled business. Controlled business is writing on yourself, family, or employees."},{"module":"Day 8 Module 1","group":"d8m1-financial-services-commission","question":"Who comprises the Financial Services Commission?","options":["The Governor, CFO, Attorney General, & the Insurance Commissioner","The Governor, CFO, Attorney General, & the Agriculture Commissioner","The Governor, CFO, Insurance Commissioner, & the Agriculture Commissioner","The Governor, CFO, Insurance Commissioner, & the Speaker of the House"],"answer":"The Governor, CFO, Attorney General, & the Agriculture Commissioner","topic":"Financial Services Commission","explanation":"The Financial Services Commission is the Governor, CFO, Attorney General, and Commissioner of Agriculture (the Florida Cabinet)."},{"module":"Day 8 Module 1","group":"d8m1-agents-vs-brokers","question":"What is the major difference between producers acting as agents and producers acting as brokers?","options":["Agents represent the client, and brokers represent the company.","Brokers are not required to follow the same laws and regulations as agents.","Brokers represent the client, and agents represent the company.","Brokers cannot solicit prospects for the purpose of selling insurance."],"answer":"Brokers represent the client, and agents represent the company.","topic":"Agents vs Brokers","explanation":"Brokers represent the client; agents represent the insurer/company."},{"module":"Day 8 Module 1","group":"d8m1-rebating","question":"Which of the following statements concerning rebating is not correct?","options":["The rebate must be available to all insureds in the same actuarial class.","The percentage of rebate cannot discriminate.","Rebates should be given to insureds who purchase a policy from an insurer that prohibits rebating.","Rebating is legal in Florida."],"answer":"Rebates should be given to insureds who purchase a policy from an insurer that prohibits rebating.","topic":"Rebating","explanation":"NOT correct: rebates should NOT be given based on buying from an insurer that prohibits rebating — that statement is nonsensical. Rebates, where allowed, must be non-discriminatory within an actuarial class."},{"module":"Day 9 Cumulative Final","group":"d9m1-human-life-value","question":"The purpose and function of insurance has its roots in economics and ______.","options":["perils and hazards","human life value","risk avoidance","risk reduction"],"answer":"human life value","topic":"Human Life Value","explanation":"Insurance has its roots in economics and human life value — the economic worth of a person\'s future earnings."},{"module":"Day 9 Cumulative Final","group":"d9m1-perils-hazards","question":"A hurricane is an example of ______.","options":["a physical hazard","a speculative risk","a peril","a storm"],"answer":"a peril","topic":"Perils & Hazards","explanation":"A hurricane is a peril — the actual cause of a loss. A hazard increases the chance of loss."},{"module":"Day 9 Cumulative Final","group":"d9m1-handling-risk","question":"Kara and her husband Jamal want to raise a family. They understand risk, and they have decided the best way to handle risk is to ______ the loss to another party.","options":["reduce","retain","transfer","carry"],"answer":"transfer","topic":"Handling Risk","explanation":"Buying insurance transfers the risk of loss to another party (the insurer)."},{"module":"Day 9 Cumulative Final","group":"d9m1-purpose-of-insurance","question":"Life and health insurance evolved to provide a practical solution to the economic losses associated with ______, ______, and ______.","options":["death, sickness, accidents","loss, mourning, risk","risks, earnings, perils","hunger, pain, money"],"answer":"death, sickness, accidents","topic":"Purpose of Insurance","explanation":"Life and health insurance addresses the economic losses of death, sickness, and accidents."},{"module":"Day 9 Cumulative Final","group":"d9m1-insurable-risk","question":"Which of the following statements is CORRECT?","options":["Only speculative risks are insurable.","Only pure risks are insurable.","Both pure risks and speculative risks are insurable.","Neither pure risks nor speculative risks are insurable."],"answer":"Only pure risks are insurable.","topic":"Insurable Risk","explanation":"Only pure risks (chance of loss or no loss, no chance of gain) are insurable; speculative risks are not."},{"module":"Day 9 Cumulative Final","group":"d9m1-insurable-risk","question":"Which of the following statements describe an element of an insurable risk? I - The loss must be due to chance. II - The loss must be definite and measurable. III - The loss must not be catastrophic. IV - The loss exposures to be insured must be large.","options":["I and II","I, II, and III","II & III","I, II, III, IV"],"answer":"I, II, III, IV","topic":"Insurable Risk","explanation":"All four are elements of an insurable risk: due to chance, definite/measurable, not catastrophic, and a large number of similar exposures."},{"module":"Day 9 Cumulative Final","group":"d9m1-human-life-value","question":"Human life value is the essence of an individual’s or family’s ______.","options":["economic existence","risk tolerance","risk transference","charitable contributions"],"answer":"economic existence","topic":"Human Life Value","explanation":"Human life value represents the essence of an individual\'s or family\'s economic existence."},{"module":"Day 9 Cumulative Final","group":"d9m1-insurable-risk","question":"Insurable interest can be present in a variety of areas. Which statement does not identify an insurable risk?","options":["The loss cannot be due to chance.","The loss must be definite and measurable.","The loss cannot be catastrophic.","The loss exposures to be insured must be large."],"answer":"The loss cannot be due to chance.","topic":"Insurable Risk","explanation":"The false statement is \'the loss cannot be due to chance\' — an insurable loss MUST be due to chance."},{"module":"Day 9 Cumulative Final","group":"d9m1-handling-risk","question":"People buy insurance because it is one of the most effective ways of ______.","options":["avoiding risk","transferring risk","reducing risk","retaining risk"],"answer":"transferring risk","topic":"Handling Risk","explanation":"Insurance is one of the most effective ways of transferring risk."},{"module":"Day 9 Cumulative Final","group":"d9m1-human-life-value","question":"Another way of looking at human life value is called future ______.","options":["career moves","earning potential","personal goals","personal expectations"],"answer":"earning potential","topic":"Human Life Value","explanation":"Human life value is another way of expressing future earning potential."},{"module":"Day 9 Cumulative Final","group":"d9m1-naic","question":"Which of the following statements about the National Association of Insurance Commissioners (NAIC) is NOT correct?","options":["The NAIC has the authority to prosecute and punish criminal violators in the insurance industry.","The NAIC seeks to preserve state, not federal, regulations of the insurance industry.","The NAIC promotes uniformity to state insurance laws and regulations.","The NAIC works to ensure the efficient administration of insurance laws and regulations."],"answer":"The NAIC has the authority to prosecute and punish criminal violators in the insurance industry.","topic":"NAIC","explanation":"FALSE: the NAIC has no authority to prosecute or punish criminal violators — it has no direct enforcement power; states enforce."},{"module":"Day 9 Cumulative Final","group":"d9m1-unfair-trade-practices","question":"Which of the following would not be found under the Unfair Trade Practices Act?","options":["False advertising","Coercion","Discrimination","Rebating"],"answer":"Rebating","topic":"Unfair Trade Practices","explanation":"Rebating is regulated under its own statute and is conditionally permitted in Florida, so it is the item not strictly defined as an Unfair Trade Practice here; false advertising, coercion, and unfair discrimination are core UTPA violations."},{"module":"Day 9 Cumulative Final","group":"d9m1-service-providers","question":"Which of the following is NOT a service provider?","options":["HMO","Benefit plans offering medical services to subscribers","Lloyds of London","PPO"],"answer":"Lloyds of London","topic":"Service Providers","explanation":"Lloyd\'s of London is an insurance marketplace/insurer, not a service provider. HMOs, PPOs, and subscriber benefit plans are service providers."},{"module":"Day 9 Cumulative Final","group":"d9m1-brokers","question":"In Florida, brokers in insurance transactions may legally represent ______.","options":["an insurer","the applicant and insured","the state Office of Insurance Regulation","themselves"],"answer":"the applicant and insured","topic":"Brokers","explanation":"In Florida a broker represents the applicant and insured (the client), not the insurer."},{"module":"Day 9 Cumulative Final","group":"d9m1-insurance-regulation","question":"Which statement below does NOT indicate landmark cases and laws involving the regulation of insurance?","options":["When an applicant\'s consumer or credit history is being investigated, insurers are required to disclose this information to the applicant.","The NAIC has standing committees working regularly to examine numerous aspects of the insurance industry.","The Federal Trade Commission (FTC) directly supervises the marketing techniques of all insurance companies.","The McCarran-Ferguson Act laid the basis for our current understanding that state governments are the primary regulators of the insurance industry."],"answer":"The Federal Trade Commission (FTC) directly supervises the marketing techniques of all insurance companies.","topic":"Insurance Regulation","explanation":"FALSE: the FTC does not directly supervise insurance marketing. Under McCarran-Ferguson, states are the primary regulators."},{"module":"Day 9 Cumulative Final","group":"d9m1-buyer-s-guide","question":"Which of the following is NOT a goal of the Buyer\'s Guide?","options":["Help buyers choose the most suitable plan","Explain basic product features","Provide information about the recommended policy","Ensure that buyers obtain the lowest price for insurance"],"answer":"Ensure that buyers obtain the lowest price for insurance","topic":"Buyer\'s Guide","explanation":"The Buyer\'s Guide is not meant to ensure the lowest price; it helps buyers understand and compare products to choose a suitable plan."},{"module":"Day 9 Cumulative Final","group":"d9m1-guaranty-association","question":"What does the State Guaranty Association guarantee?","options":["That a policy will be issued","That a claim will be paid if an insurer becomes insolvent","That dividends will be paid","The rate of return on a policy"],"answer":"That a claim will be paid if an insurer becomes insolvent","topic":"Guaranty Association","explanation":"The State Guaranty Association guarantees that claims will be paid if a member insurer becomes insolvent."},{"module":"Day 9 Cumulative Final","group":"d9m1-reinsurance","question":"Review the statements below and identify which is correct regarding the purpose of a reinsurer.","options":["A reinsurer accepts all risk from another insurer.","A reinsurer assumes a portion of the risk from another insurer.","A reinsurer cedes the risk.","A reinsurer does not take any risk."],"answer":"A reinsurer assumes a portion of the risk from another insurer.","topic":"Reinsurance","explanation":"A reinsurer assumes a portion of the risk ceded by another insurer."},{"module":"Day 9 Cumulative Final","group":"d9m1-industrial-insurance","question":"Industrial insurance is characterized by relatively ______ face amounts.","options":["large","industrial-sized","small","mid-sized industrial"],"answer":"small","topic":"Industrial Insurance","explanation":"Industrial (home service) insurance is characterized by relatively small face amounts."},{"module":"Day 9 Cumulative Final","group":"d9m1-reinsurance","question":"Reinsurers are a specialized branch of the insurance industry. This is because they insure ______.","options":["insurers","employers with high risk","applicants from Lloyds of London","applicants with low risk"],"answer":"insurers","topic":"Reinsurance","explanation":"Reinsurers insure other insurers."},{"module":"Day 9 Cumulative Final","group":"d9m1-insurable-interest","question":"At what time must an insurable interest exist in life and health contracts?","options":["After the policy is issued","Before the beneficiary is named","While the policy is enforced","At the inception of the policy"],"answer":"At the inception of the policy","topic":"Insurable Interest","explanation":"Insurable interest in life/health must exist at the inception of the policy."},{"module":"Day 9 Cumulative Final","group":"d9m1-parol-evidence","question":"What is the parole evidence rule?","options":["Once a written contract is signed, it cannot be changed.","An oral contract cannot be modified by written evidence.","A written contract cannot be changed by oral evidence.","An oral contract takes preference over any earlier written contracts."],"answer":"A written contract cannot be changed by oral evidence.","topic":"Parol Evidence","explanation":"The parol evidence rule means a written contract cannot be changed by prior oral evidence."},{"module":"Day 9 Cumulative Final","group":"d9m1-valued-contracts","question":"Which of the following are NOT valued contracts?.","options":["Life insurance","Disability income insurance","Accidental Death & Dismemberment","Medical Expense policies"],"answer":"Medical Expense policies","topic":"Valued Contracts","explanation":"Medical expense policies are reimbursement/indemnity contracts, NOT valued contracts. Life, disability income, and AD&D are valued."},{"module":"Day 9 Cumulative Final","group":"d9m1-insurable-interest","question":"Identify which statement is incorrect regarding insurable interest.","options":["Insurable interest exists when the applicant is the insured.","A policy obtained by a person without insurable interest in the insured can be enforced.","The applicant must be subject to loss upon the death, illness, or disability of the insured.","With the exception of a minor, the person to be insured must give consent before a policy is issued."],"answer":"A policy obtained by a person without insurable interest in the insured can be enforced.","topic":"Insurable Interest","explanation":"FALSE: a policy obtained without insurable interest is NOT enforceable."},{"module":"Day 9 Cumulative Final","group":"d9m1-competent-parties","question":"Which of the following are considered competent instead of incompetent except:","options":["An insurance company with a certificate of authority from the State","A 52-year-old diagnosed with Alzheimer\'s","A person 17 years old who just graduated from high school.","A 25-year-old under the influence"],"answer":"An insurance company with a certificate of authority from the State","topic":"Competent Parties","explanation":"The insurer holding a certificate of authority is the competent party; the Alzheimer\'s patient, the 17-year-old minor, and the intoxicated person are not legally competent."},{"module":"Day 9 Cumulative Final","group":"d9m1-contract-types","question":"Which of the following is a \\"take it or leave it\\" type of contract?","options":["Aleatory","Unilateral","Conditional","Adhesion"],"answer":"Adhesion","topic":"Contract Types","explanation":"A \'take it or leave it\' contract is a contract of adhesion."},{"module":"Day 9 Cumulative Final","group":"d9m1-insurable-interest","question":"Review the statements below and identify which is accurate concerning an insurable interest.","options":["The policy owner must expect to benefit from the insured\'s death.","When the insured dies or becomes disabled, the policy owner must expect to suffer a loss.","By definition, the beneficiary has an insurable interest in the insured.","The insured must have a personal or business relationship with the beneficiary."],"answer":"When the insured dies or becomes disabled, the policy owner must expect to suffer a loss.","topic":"Insurable Interest","explanation":"Insurable interest means the policy owner would suffer a loss if the insured dies or becomes disabled."},{"module":"Day 9 Cumulative Final","group":"d9m1-adhesion","question":"An insurance contract is not negotiated, rather it is prepared by the insurer. Which of the following statements explains this characteristic of insurance?","options":["The insurance contract is an aleatory contract.","The insurance contract is a contract of acceptance.","The insurance contract is a contract of adhesion.","The insurance contract names only the insurer as the competent party."],"answer":"The insurance contract is a contract of adhesion.","topic":"Adhesion","explanation":"Because the insurer writes the contract and the applicant accepts it as-is, it is a contract of adhesion."},{"module":"Day 9 Cumulative Final","group":"d9m1-competent-parties","question":"What makes an insurer competent?","options":["They are registered with the NAIC.","They are licensed or authorized by the state.","They follow the Code of Ethics of the state Office of Insurance Regulation.","They register with the Security and Exchange Commission."],"answer":"They are licensed or authorized by the state.","topic":"Competent Parties","explanation":"An insurer is a competent party when it is licensed or authorized by the state."},{"module":"Day 9 Cumulative Final","group":"d9m1-common-disaster","question":"Bill Wilson has a life insurance policy and has named his brother Kenneth Wilson as the primary beneficiary. The secondary beneficiary is Mary, Kenneth’s wife. Bill and Kenneth were riding in a car with Mary. Both Bill and Kenneth died in the car crash. Mary was the only survivor. Who will receive the life insurance proceeds?","options":["The insurance does not go to anyone because we don\'t know who died first.","Mary will receive the proceeds as the secondary or contingent beneficiary.","We have to look at Kenneth\'s estate to see who will receive the proceeds.","No one because the insured and the beneficiary have passed away."],"answer":"Mary will receive the proceeds as the secondary or contingent beneficiary.","topic":"Common Disaster","explanation":"With the primary beneficiary (Kenneth) dying with the insured, proceeds pass to the surviving contingent beneficiary, Mary."},{"module":"Day 9 Cumulative Final","group":"d9m1-free-look","question":"The period specified in the free look provision begins______.","options":["when the policy is issued","when the policy is delivered","when the application is signed","when the application is approved"],"answer":"when the policy is delivered","topic":"Free Look","explanation":"The free-look period begins when the policy is delivered."},{"module":"Day 9 Cumulative Final","group":"d9m1-deceptive-practices","question":"What is a deceptive sales presentation?","options":["Any presentation that gives the prospect the wrong impression about any aspect of an insurance policy","Any presentation that does not provide complete disclosure","Any presentation that includes any misleading or inconclusive product comparison","All of these are correct."],"answer":"All of these are correct.","topic":"Deceptive Practices","explanation":"All listed presentations — wrong impressions, incomplete disclosure, misleading comparisons — are deceptive."},{"module":"Day 9 Cumulative Final","group":"d9m1-sales-presentation","question":"What should a producer NOT do during a presentation?","options":["Explain and educate","Sell a policy","Motivate the client","Openly discuss a policy\'s limitations"],"answer":"Sell a policy","topic":"Sales Presentation","explanation":"A producer should educate, motivate, and disclose limitations — not high-pressure \'sell\' a policy; the goal is to let the client decide."},{"module":"Day 9 Cumulative Final","group":"d9m1-misrepresentation","question":"In the selling process, when are serious problems of misrepresentation likely to occur?","options":["Approach","Presentation of recommendations","Fact-finding and needs analysis","Policy delivery and ongoing service"],"answer":"Presentation of recommendations","topic":"Misrepresentation","explanation":"Serious misrepresentation problems most often arise during the presentation of recommendations."},{"module":"Day 9 Cumulative Final","group":"d9m1-sales-presentation","question":"A sales presentation is critical in the insurance industry. What is the main goal of it?","options":["To educate clients, empowering them to make their own decisions about what\'s right for them.","To sell as many products as possible to the client","To convince the client that the producer\'s recommendations are best.","To explain to the client the various rules and regulations around insurance products."],"answer":"To educate clients, empowering them to make their own decisions about what\'s right for them.","topic":"Sales Presentation","explanation":"The main goal of a sales presentation is to educate clients so they can make their own informed decisions."},{"module":"Day 9 Cumulative Final","group":"d9m1-illustrations-model-reg","question":"Which of the following is NOT a provision of NAIC\'s Life Insurance Illustrations Model Regulations?","options":["A written explanation or policy summary must accompany each policy illustration.","The words \\"vanish\\" and \\"vanishing premium\\" should be used sparingly in each policy illustration.","Each policy illustration needs to explain that cash values and coverage could vary based on changes in an insurer\'s costs and dividends.","Each policy illustration must be complete."],"answer":"The words \\"vanish\\" and \\"vanishing premium\\" should be used sparingly in each policy illustration.","topic":"Illustrations Model Reg","explanation":"NOT a provision: the regulation PROHIBITS the terms \'vanish/vanishing premium\' — it doesn\'t merely say to use them \'sparingly.\'"},{"module":"Day 9 Cumulative Final","group":"d9m1-preprinted-materials","question":"The reason preprinted materials are recommended in the sales presentation is ______.","options":["the agent may not know exactly how a product works.","preprinted materials save time and improve explanations.","preprinted materials have generally been reviewed for compliance.","preprinted materials act as a way for the agent to avoid answering the client\'s questions."],"answer":"preprinted materials have generally been reviewed for compliance.","topic":"Preprinted Materials","explanation":"Preprinted materials are recommended because they have generally been reviewed for compliance."},{"module":"Day 9 Cumulative Final","group":"d9m1-full-disclosure","question":"The purpose behind full disclosure requirements is to ______.","options":["ensure a client is told most of what there is to know about a product.","help a client make an informed decision.","ensure agents comply with the letter of the law.","help a client distinguish one insurer\'s product from a similar offering from another insurer."],"answer":"help a client make an informed decision.","topic":"Full Disclosure","explanation":"Full disclosure exists to help a client make an informed decision."},{"module":"Day 9 Cumulative Final","group":"d9m1-rating-rejection","question":"The producers have as much information as possible on the rating and rejection of the policy. Which of the following does not apply to the rating and rejection?","options":["They need to explain how the underwriter rated the policy.","They need to know if it was unfavorable and why.","They need to explain if additional information is needed.","All the above are correct"],"answer":"All the above are correct","topic":"Rating & Rejection","explanation":"All of the listed duties (explaining the rating, the reason, and any additional information needed) apply to rating and rejection."},{"module":"Day 9 Cumulative Final","group":"d9m1-naic","question":"What does the NAIC stand for?","options":["National Aviation Insurance Commission","National Association of Inspector Commissioners","National Association of Insurance Commissioners","Naval Academy Insurance Commission"],"answer":"National Association of Insurance Commissioners","topic":"NAIC","explanation":"NAIC stands for the National Association of Insurance Commissioners."},{"module":"Day 9 Cumulative Final","group":"d9m1-premium-modes","question":"Which premium mode is least expensive?","options":["Annual","Semiannual","Quarterly","Monthly"],"answer":"Annual","topic":"Premium Modes","explanation":"Annual is the least expensive premium mode."},{"module":"Day 9 Cumulative Final","group":"d9m1-health-insurance-basics","question":"Select the CORRECT health insurance statement.","options":["Health insurance policies cannot be canceled by the insurer once they are issued.","Many premium-payment options are available.","Medical expense policies reimburse the insured for the costs of medical care.","Disability income policies cover hospital expenses related to a disability."],"answer":"Medical expense policies reimburse the insured for the costs of medical care.","topic":"Health Insurance Basics","explanation":"CORRECT: medical expense policies reimburse the insured for the costs of medical care."},{"module":"Day 9 Cumulative Final","group":"d9m1-reserves","question":"Which of the following statements about reserves are true?","options":["Reserves are set aside by an insurance company.","They are funds set aside for the payment of future claims.","A portion of each premium is set aside for reserves.","All of these are correct."],"answer":"All of these are correct.","topic":"Reserves","explanation":"All are true: reserves are set aside by the insurer from a portion of each premium to pay future claims."},{"module":"Day 9 Cumulative Final","group":"d9m1-participating-basis","question":"Most individual health insurance is issued on a ______ basis.","options":["participating","non-participating","claims","cost"],"answer":"non-participating","topic":"Participating Basis","explanation":"Most individual health insurance is issued on a non-participating basis (no dividends)."},{"module":"Day 9 Cumulative Final","group":"d9m1-premiums","question":"Select the CORRECT statement about health insurance policy premiums.","options":["A \\"policy fee\\" is the same as a policy premium.","If a policy owner has an individual health plan, then the policy is probably a participating policy.","A group health insurance policy\'s experience rating refund credit is most influenced by the age and gender of the individual insureds.","Health insurance policies are paid on yearly basis and may be periodically increased."],"answer":"Health insurance policies are paid on yearly basis and may be periodically increased.","topic":"Premiums","explanation":"Health insurance premiums are generally paid on a periodic basis and may be increased over time (on a class basis)."},{"module":"Day 9 Cumulative Final","group":"d9m1-reserves","question":"What are two types of health insurance reserves?","options":["Valued contracts & Indemnity contracts","Jack & Jill Reserves","premium reserves & loss reserves","Master contracts & indemnity contracts"],"answer":"premium reserves & loss reserves","topic":"Reserves","explanation":"The two types of health insurance reserves are premium reserves and loss reserves."},{"module":"Day 9 Cumulative Final","group":"d9m1-disability-income","question":"Which statements is true about a disability income policy?","options":["A disability income policy replaces income when wages are lost due to disability","A disability income policy covers medical expenses incurred from a disability","A disability income policy pays benefits indefinitely","A disability income policy protects the insured if he/she lives too long"],"answer":"A disability income policy replaces income when wages are lost due to disability","topic":"Disability Income","explanation":"A disability income policy replaces income lost when the insured cannot work due to disability."},{"module":"Day 9 Cumulative Final","group":"d9m1-reserves","question":"What does an insurance company set aside to pay future claims?","options":["Valued contracts","Indemnity contracts","Reserves","Master contracts"],"answer":"Reserves","topic":"Reserves","explanation":"Insurers set aside reserves to pay future claims."},{"module":"Day 9 Cumulative Final","group":"d9m1-hsas","question":"Which of the following plans used with High Deductible Health Plans is employee owned?","options":["Health Savings Accounts (HSAs)","Flexible Spending Accounts (FSAs)","Health Reimbursement Accounts (HRAs)","Health Maintanance Organizations (HMOs)"],"answer":"Health Savings Accounts (HSAs)","topic":"HSAs","explanation":"A Health Savings Account (HSA) is owned by the employee."},{"module":"Day 9 Cumulative Final","group":"d9m1-participating-basis","question":"Group health insurance is generally issued on a ______ basis.","options":["participating","non-participating","claims","cost"],"answer":"non-participating","topic":"Participating Basis","explanation":"Group health insurance is generally issued on a non-participating basis."},{"module":"Day 9 Cumulative Final","group":"d9m1-assignment","question":"In a health insurance policy, which term describes a situation where a policyowner has medical benefits assigned or paid directly to the hospital or physician?","options":["Collateral assignment","Absolute assignment","Transfer assignment","Right of assignment"],"answer":"Right of assignment","topic":"Assignment","explanation":"Directing benefits to the hospital or physician is the insured\'s right of assignment."},{"module":"Day 9 Cumulative Final","group":"d9m1-medicaid","question":"Choose the INCORRECT statement pertaining to Medicaid.","options":["Medicaid provides federal matching funds to states for medical public assistance plans.","The purpose of Medicaid is to help eligible needy persons with medical assistance.","Medicaid benefits can be applied to the deductible and coinsurance amounts of Medicare.","Medicaid limits financial assistance to persons aged 65 or over who cannot afford necessary medical services."],"answer":"Medicaid limits financial assistance to persons aged 65 or over who cannot afford necessary medical services.","topic":"Medicaid","explanation":"INCORRECT: Medicaid is need-based for all ages, not limited to those 65+ (that describes Medicare)."},{"module":"Day 9 Cumulative Final","group":"d9m1-social-security-disability","question":"All of the following statements concerning Social Security disability benefits are true EXCEPT:","options":["The impairment must be expected to last at least 12 months.","The waiting period is 5 months.","The waiting period may be waived in certain circumstances.","Benefits are retroactive to the time of disability."],"answer":"Benefits are retroactive to the time of disability.","topic":"Social Security Disability","explanation":"EXCEPT: SSDI benefits are NOT retroactive to the time of disability."},{"module":"Day 9 Cumulative Final","group":"d9m1-medicare-eligibility","question":"All of the following are eligible for Medicare EXCEPT:","options":["Those 65 or older","Dependents of those 65 or older","Folks with a chronic kidney disorder","Folks receiving Social Security Disability benefits"],"answer":"Dependents of those 65 or older","topic":"Medicare Eligibility","explanation":"Medicare is individual coverage — dependents of those 65+ are not eligible on that basis."},{"module":"Day 9 Cumulative Final","group":"d9m1-multiple-employer-trust","question":"Grouping small businesses together to obtain group insurance as one large group is characteristic of which of the following?","options":["A Health Maintenance Organization (HMO)","A Franchise Health plan","A Multiple Employer Trust (MET)","A Fictitious group"],"answer":"A Multiple Employer Trust (MET)","topic":"Multiple Employer Trust","explanation":"Combining small businesses into one large insured group describes a Multiple Employer Trust (MET)."},{"module":"Day 9 Cumulative Final","group":"d9m1-self-insured-plans","question":"All of the following may administer self-insured plans except:","options":["Third Party Administrators - TPAs","Administrative Services Organizations - ASOs","Actuaries","Insurance Companies"],"answer":"Actuaries","topic":"Self-Insured Plans","explanation":"Actuaries calculate rates/reserves but do not administer self-insured plans; TPAs, ASOs, and insurers do."},{"module":"Day 9 Cumulative Final","group":"d9m1-social-security-disability","question":"Choose the individual who is most likely to qualify for Social Security disability benefits.","options":["Randy, a ski instructor who breaks his leg","Sarah, who is sick from a viral infection and is not expected to be able to work for the next 6 months","Perry, a mechanic who loses his dominant hand in an accident","Grace, who experiences serious early-onset Alzheimer\'s and is unable to remember how to get to work"],"answer":"Grace, who experiences serious early-onset Alzheimer\'s and is unable to remember how to get to work","topic":"Social Security Disability","explanation":"Grace\'s early-onset Alzheimer\'s best meets SSDI\'s strict any-occupation, 12-month standard."},{"module":"Day 9 Cumulative Final","group":"d9m1-basic-medical-expense","question":"Basic Medical expense policies do not contain which feature?","options":["Deductibles","Room & Board benefits","Physician office visits","Miscellaneous benefits"],"answer":"Deductibles","topic":"Basic Medical Expense","explanation":"Basic medical expense (first-dollar) policies do NOT contain deductibles."},{"module":"Day 9 Cumulative Final","group":"d9m1-social-security-act","question":"The Social Security Act of 1965 created which of the following?","options":["Old Age Benefits","Medicaid","Survivor benefits","None of the above"],"answer":"Medicaid","topic":"Social Security Act","explanation":"The Social Security Act of 1965 created Medicare and Medicaid; this answer is Medicaid."},{"module":"Day 9 Cumulative Final","group":"d9m1-basic-expense-policies","question":"Which of the following statement is true about Basic Hospital, Medical, and Surgical Expense Policies?","options":["They have high deductibles.","The benefits provided are usually equal to the actual expenses incurred.","They usually have a stated limit for specific expenses.","Benefits are provided for loss of income."],"answer":"They usually have a stated limit for specific expenses.","topic":"Basic Expense Policies","explanation":"Basic hospital/medical/surgical policies usually have a stated dollar limit for specific expenses."},{"module":"Day 9 Cumulative Final","group":"d9m1-hospital-fixed-rate","question":"Considering what you know about a hospital fixed-rate plan, which statement is NOT true?","options":["Claim costs are not affected by rising healthcare costs.","This plan provides high benefits for relatively low premiums.","They feature simple underwriting and administration.","Benefits are paid directly to the hospital."],"answer":"This plan provides high benefits for relatively low premiums.","topic":"Hospital Fixed-Rate","explanation":"NOT true: a fixed-rate (indemnity) plan pays modest fixed amounts — not \'high benefits.\' Its costs aren\'t affected by rising charges and underwriting is simple."},{"module":"Day 9 Cumulative Final","group":"d9m1-first-dollar-coverage","question":"The term FIRST DOLLAR often is used to describe benefits payable by which type of policy?","options":["A Basic Medical Expense policy","A Disability Income policy","A Business Overhead Expense policy","A Major Medical policy"],"answer":"A Basic Medical Expense policy","topic":"First-Dollar Coverage","explanation":"\'First dollar\' coverage (no deductible) describes a Basic Medical Expense policy."},{"module":"Day 9 Cumulative Final","group":"d9m1-major-medical-deductibles","question":"There are three types of major medical policy deductibles. Which of the following is NOT one of those deductibles?","options":["corridor","integrated","stop loss","flat"],"answer":"stop loss","topic":"Major Medical Deductibles","explanation":"Stop-loss is a coinsurance limit, not a deductible. The three deductible types are corridor, integrated, and flat."},{"module":"Day 9 Cumulative Final","group":"d9m1-coinsurance","question":"Which of the following is true about coinsurance?","options":["Coinsurance applies to the deductible as well as to claim payments.","Premiums are higher for a policy that contains a coinsurance provision than for one that does not.","It helps control overutilization of benefits.","Insurance companies can change the coinsurance ratio after the policy has been issued."],"answer":"It helps control overutilization of benefits.","topic":"Coinsurance","explanation":"Coinsurance helps control overutilization of benefits by making the insured share in costs."},{"module":"Day 9 Cumulative Final","group":"d9m1-basic-medical-cost-control","question":"How does a basic medical plan avoid small claims and keep the cost of premiums down?","options":["By utilizing deductibles and co-insurance","By imposing benefit limits","By paying only catastrophic medical expenses","By providing a network of physicians and hospitals"],"answer":"By imposing benefit limits","topic":"Basic Medical Cost Control","explanation":"Basic medical (first-dollar) plans control premium cost by imposing benefit limits/maximums."},{"module":"Day 9 Cumulative Final","group":"d9m1-miscellaneous-expense","question":"What is included under the basic hospital miscellaneous expense benefit?","options":["Surgical expenses","Anesthesia","Physician fees","Room and board"],"answer":"Anesthesia","topic":"Miscellaneous Expense","explanation":"The basic hospital miscellaneous expense benefit covers items like anesthesia, lab, drugs, and supplies — not room/board or physician fees."},{"module":"Day 9 Cumulative Final","group":"d9m1-integrated-deductible","question":"If all or part of a $500 deductible is offset by a Basic Medical policy, what type of deductible applies?","options":["Integrated","Corridor","Flat","Split"],"answer":"Integrated","topic":"Integrated Deductible","explanation":"When a basic medical policy offsets the deductible, it is an integrated deductible."},{"module":"Day 9 Cumulative Final","group":"d9m1-integrated-deductible","question":"Cindy has a $500 deductible with her plan where the deductible is offset when the expense is incurred. What type of deductible is this?","options":["Integrated","Corridor","Flat","Split"],"answer":"Integrated","topic":"Integrated Deductible","explanation":"A deductible offset by other (basic) coverage as expenses are incurred is an integrated deductible."},{"module":"Day 9 Cumulative Final","group":"d9m1-r-c-charges","question":"The determination of the cost of a surgical procedure based on the location or general area where the procedure will take place is known as ______.","options":["reasonable and customary approach charges","stated charges","percentage of stated charges","designated charges"],"answer":"reasonable and customary approach charges","topic":"R&C Charges","explanation":"Pricing surgery by the area/location is the reasonable and customary (R&C) charge approach."},{"module":"Day 9 Cumulative Final","group":"d9m1-hospital-expense","question":"Jackie is covered under a hospital expense policy. Based on what you know about this plan, what type of plan is this?","options":["Service","Limited","Fixed-rate plan","Special risk"],"answer":"Service","topic":"Hospital Expense","explanation":"A hospital expense policy reimburses actual expenses — a service plan."},{"module":"Day 9 Cumulative Final","group":"d9m1-disability-coverage","question":"Which statement accurately describes a feature of a disability policy?","options":["Sickness and accidents are covered immediately.","Sickness is covered immediately; accidents are covered after 15 days.","Accidents are covered immediately; sickness is covered after 15 days.","Sickness and accidents are covered after 15 days."],"answer":"Accidents are covered immediately; sickness is covered after 15 days.","topic":"Disability Coverage","explanation":"A common feature: accidents are covered immediately while sickness is covered after a probationary period (e.g., 15 days)."},{"module":"Day 9 Cumulative Final","group":"d9m1-presumptive-disability","question":"What type of disability automatically qualifies the insured for full benefits based on a permanent physical impairment which left the individual incapable of performing their previous occupation but allows them to perform other work?","options":["Presumptive Disability","Permanent partial disability","Temporary total disability","Temporary partial disability"],"answer":"Presumptive Disability","topic":"Presumptive Disability","explanation":"\'Automatically qualifies for full benefits\' signals presumptive disability."},{"module":"Day 9 Cumulative Final","group":"d9m1-non-disabling-benefit","question":"In certain policies, if an injury does not qualify the insured for monthly disability income benefits, what else might it make them eligible for?","options":["Outpatient compensation","An emergency room benefit","Medical expense reimbursement","A non-disabling benefit"],"answer":"A non-disabling benefit","topic":"Non-Disabling Benefit","explanation":"An injury that doesn\'t cause disability may still qualify the insured for a non-disabling (medical) benefit."},{"module":"Day 9 Cumulative Final","group":"d9m1-waiver-of-premium","question":"Which endorsement is attached to a health insurance policy, stipulating that the insurer will maintain coverage without additional premiums if the insured becomes totally and permanently disabled?","options":["Guaranteed insurability","Impairment rider","Multiple indemnity","Waiver of premium"],"answer":"Waiver of premium","topic":"Waiver of Premium","explanation":"The waiver of premium rider keeps coverage in force without premiums if the insured is totally and permanently disabled."},{"module":"Day 9 Cumulative Final","group":"d9m1-non-disabling-benefit","question":"Regarding a non-disabling injury benefit, which of the following options illustrates what the policy pays? I. A flat amount equal to the insured\'s salary II. A percentage amount equal to the insured\'s salary III. The actual cost of medical treatment IV. A percentage amount equal to the weekly or monthly benefit","options":["I","II, III","III, & IV","IV"],"answer":"IV","topic":"Non-Disabling Benefit","explanation":"The non-disabling injury benefit pays a percentage amount equal to the weekly or monthly disability benefit (toward medical treatment)."},{"module":"Day 9 Cumulative Final","group":"d9m1-delayed-disability","question":"Total disability does not always occur immediately after an accident but does develop days or weeks later. A specified time frame is allowed for this, and the insured would still be eligible for benefits. What is the maximum amount of time specified in a disability income policy?","options":["30 days","60 days","90 days","Six months"],"answer":"90 days","topic":"Delayed Disability","explanation":"Total disability may develop after an accident; the policy allows up to 90 days for it to begin and still qualify."},{"module":"Day 9 Cumulative Final","group":"d9m1-non-disabling-benefit","question":"The non-disabling injury benefit pays: a. a flat amount equal to the insured\'s salary b. a percentage amount equal to the insured\'s salary c. the actual cost of medical treatment d. a percentage amount equal to the weekly or monthly benefit","options":["a","b, c","c, d","d"],"answer":"d","topic":"Non-Disabling Benefit","explanation":"The non-disabling injury benefit pays a percentage amount equal to the weekly or monthly benefit."},{"module":"Day 9 Cumulative Final","group":"d9m1-presumptive-disability","question":"Which of the following would not be considered a \\"presumptive\\" disability, automatically qualifying an individual for full benefits under a disability policy?","options":["Cancer","Blindness","Loss of speech","Deafness"],"answer":"Cancer","topic":"Presumptive Disability","explanation":"Cancer is NOT a presumptive disability. Presumptive losses are sight, hearing, speech, and limbs."},{"module":"Day 9 Cumulative Final","group":"d9m1-recurrent-disability","question":"Marcus has a disability policy with a 5-year benefit period and a 30-day elimination period. Two years into the policy, Marcus has a stroke on February 1 and is out of work for one month, returning to work the following month on March 1. Then, on June 1 of the same year, Marcus has another stroke that leaves him permanently and totally disabled. Which of the following statements is true?","options":["Benefits will begin on June 1 and pay for 2 years.","Benefits will begin on June 1 and pay for 5 years.","Benefits will begin on June 1 and pay for 2 years.","Benefits will begin on July 1 and pay for 2 years."],"answer":"Benefits will begin on June 1 and pay for 5 years.","topic":"Recurrent Disability","explanation":"The second, permanent disability is treated as a continuation (recurrent), so benefits begin June 1 and pay the full 5-year benefit period."},{"module":"Day 9 Cumulative Final","group":"d9m1-own-vs-any-occupation","question":"Which type of total disability insurance policy is more favorable to the insured: own occupation or any occupation?","options":["Own occupation","Any occupation","Own occupation policies and any occupation policies are the same in terms of benefits to the insured.","There is not enough information to make a determination."],"answer":"Own occupation","topic":"Own vs Any Occupation","explanation":"An \'own occupation\' definition is more favorable to the insured — it pays if they can\'t perform their own job."},{"module":"Day 9 Cumulative Final","group":"d9m1-capital-sum","question":"Ginny has a $50,000 accidental death and dismemberment policy. She received a $15,000 cash benefit her for the accidental loss of one eye. The $15,000 benefit could be identified as the policy\'s ______.","options":["principal sum","secondary sum","capital sum","contingent amount"],"answer":"capital sum","topic":"Capital Sum","explanation":"The amount paid for accidental loss of one eye is the capital sum."},{"module":"Day 9 Cumulative Final","group":"d9m1-special-risk","question":"Which of the following are examples of those covered under a special risk plan? I - An acclaimed ballerina’s legs II - Dread diseases III - Alicia Keys hands IV - Airplane passengers","options":["I and III","II","I and IV","III and IV"],"answer":"I and III","topic":"Special Risk","explanation":"Insuring a performer\'s specific body parts (a ballerina\'s legs, Alicia Keys\' hands) is special-risk coverage."},{"module":"Day 9 Cumulative Final","group":"d9m1-special-risk","question":"Which of the following policies would cover a student pilot taking flying lessons?","options":["Limited risk","Special risk","Dread disease","Long-term care"],"answer":"Special risk","topic":"Special Risk","explanation":"A student pilot taking flying lessons would be covered by a special risk policy."},{"module":"Day 9 Cumulative Final","group":"d9m1-special-risk","question":"Which of the following is/are examples of those covered under a special risk plan? I - Elton John\'s hands II - dread diseases III - a test pilot IV - airplane passengers","options":["I & III","II","I and IV","III and IV"],"answer":"I & III","topic":"Special Risk","explanation":"Special risk covers unusual exposures like Elton John\'s hands (I) and a test pilot (III)."},{"module":"Day 9 Cumulative Final","group":"d9m1-ad-d-schedule","question":"Spencer has an AD&D policy that has $25,000 for the principal sum and $10,000 for the loss of a hand or foot. He gets into an accident and loses a finger. How much will his policy pay?","options":["$25,000","$10,000","Nothing","$35,000"],"answer":"Nothing","topic":"AD&D Schedule","explanation":"Losing a finger is not a scheduled loss (hand/foot), so the AD&D policy pays nothing."},{"module":"Day 9 Cumulative Final","group":"d9m1-accidental-results","question":"If John has an AD&D policy, which plan will pay if he jumps off a ladder and severely injures his leg that it must be amputated?","options":["Accidental results","Accidental means","Accidental measures","Accidental restitution"],"answer":"Accidental results","topic":"Accidental Results","explanation":"Under an \'accidental results\' definition, an unexpected result is covered even when the act (jumping) was intentional."},{"module":"Day 9 Cumulative Final","group":"d9m1-ad-d-rider","question":"The circumstances under which an AD&D policy benefits are paid are somewhat limited. It is widely used but is sometimes attached as a ______ on a basic life or health policy and in group insurance plans.","options":["renewability provision","rider","golden ticket","special risk"],"answer":"rider","topic":"AD&D Rider","explanation":"AD&D is often attached as a rider to a basic life or health policy."},{"module":"Day 9 Cumulative Final","group":"d9m1-special-risk","question":"Which of the following policies would cover an accidental death or injury while riding in a car?","options":["Limited risk","Special risk","Dread disease","Long-term care"],"answer":"Special risk","topic":"Special Risk","explanation":"Accidental death or injury while riding in a car is covered by a special risk policy."},{"module":"Day 9 Cumulative Final","group":"d9m1-limited-risk","question":"A limited risk policy covers ______.","options":["risks not covered by accident and health policies","specific risks","all risks","unusual types of risks"],"answer":"specific risks","topic":"Limited Risk","explanation":"A limited risk policy covers specific named risks."},{"module":"Day 9 Cumulative Final","group":"d9m1-capital-sum","question":"The capital sum in an accidental death and dismemberment policy will pay for which of the following? I - loss of hands above the wrist II - loss of 3/4 of the foot III - loss of an eye IV - all fingers (including the thumbs) on both hands","options":["II and IV","I, II, and III","I and III","I, II, III, and IV"],"answer":"I and III","topic":"Capital Sum","explanation":"The capital sum pays for loss of a hand above the wrist (I) and loss of an eye (III); partial-foot and finger losses don\'t qualify."},{"module":"Day 9 Cumulative Final","group":"d9m1-medicare-coverage","question":"Medicare Part A & Part B do not cover which of the following?","options":["Rental of durable medical equipment","Home health aides","Ambulance","Routine physical exams"],"answer":"Routine physical exams","topic":"Medicare Coverage","explanation":"Medicare Parts A and B do not cover routine physical exams."},{"module":"Day 9 Cumulative Final","group":"d9m1-medicare-coverage","question":"Which of the following medical services is NOT covered under Medicare Part A and Part B?","options":["Private Duty Nursing","Private hospital rooms","custodial care received at home","All of these services are not covered"],"answer":"All of these services are not covered","topic":"Medicare Coverage","explanation":"Private duty nursing, private rooms, and at-home custodial care are all NOT covered by Medicare A and B."},{"module":"Day 9 Cumulative Final","group":"d9m1-medicare-part-b","question":"Under Medicare Part B, which of the following do participants NOT have to pay?","options":["An annual deductible","A per benefit deductible","20% of covered charges above the deductible","A monthly premium"],"answer":"A per benefit deductible","topic":"Medicare Part B","explanation":"Part B has no per-benefit (per-benefit-period) deductible — that\'s a Part A feature. It has an annual deductible, 20% coinsurance, and a monthly premium."},{"module":"Day 9 Cumulative Final","group":"d9m1-medicare-part-b","question":"Which of the statements below about Medicare Part B is/are true? I. There is an annual deductible. ll. The insured is required to pay 20% after the deductible is met.","options":["I only","II only","I and II","Neither I nor II"],"answer":"I and II","topic":"Medicare Part B","explanation":"Both are true: Part B has an annual deductible and the insured pays 20% after it is met."},{"module":"Day 9 Cumulative Final","group":"d9m1-medicare","question":"Which of the following statements concerning Medicare is true?","options":["Part B Voluntary","Part A is compulsory","Part A is paid for out of FICA taxes","All of these statements are true"],"answer":"All of these statements are true","topic":"Medicare","explanation":"All true: Part B is voluntary, Part A is compulsory, and Part A is funded by FICA payroll taxes."},{"module":"Day 9 Cumulative Final","group":"d9m1-medicare-part-a","question":"Which of the following is NOT covered under Medicare Part A?","options":["Post-hospital skilled nursing care","Hospice care","Post-hospital home services","Ambulance services"],"answer":"Ambulance services","topic":"Medicare Part A","explanation":"Ambulance services fall under Part B, not Part A."},{"module":"Day 9 Cumulative Final","group":"d9m1-medicare-eligibility","question":"Which of the following groups is NOT eligible for Medicare coverage?","options":["People aged 65 and older eligible for Social Security","People aged 65 and older not eligible for Social Security but willing to pay a monthly premium","People of any age who have been entitled to Social Security disability benefits","People with any life-threatening condition"],"answer":"People with any life-threatening condition","topic":"Medicare Eligibility","explanation":"\'Any life-threatening condition\' is not a Medicare eligibility category."},{"module":"Day 9 Cumulative Final","group":"d9m1-medicare-part-a","question":"What service is NOT covered under Part A of Medicare?","options":["Physician office visit","Hospital stay","Nursing facility care","Medical supplies"],"answer":"Physician office visit","topic":"Medicare Part A","explanation":"A physician office visit is covered under Part B, not Part A."},{"module":"Day 9 Cumulative Final","group":"d9m1-medicare-premiums","question":"Which part of Medicare requires most of the eligible participants to make premium payments?","options":["Part A, basic hospital insurance","Part B, supplementary medical insurance","Respite care","All require a premium"],"answer":"Part B, supplementary medical insurance","topic":"Medicare Premiums","explanation":"Part B requires most participants to pay a monthly premium; Part A is premium-free for most."},{"module":"Day 9 Cumulative Final","group":"d9m1-medicare-reserve-days","question":"The lifetime reserve for Medicare is ______ days. If a patient is hospitalized beyond the ______ lifetime reserve day, thereby exhausting the reserve, he/she is responsible for ______?","options":["30 days, 30th, a portion of the hospital charges","60 days, 60th, all hospital charges","90 days, 90th, none of the hospital charges","120 days, 120th, 20% of the hospital charges"],"answer":"60 days, 60th, all hospital charges","topic":"Medicare Reserve Days","explanation":"Medicare provides 60 lifetime reserve days; beyond the 60th the patient pays all hospital charges."},{"module":"Day 9 Cumulative Final","group":"d9m1-premium-factors","question":"Which of the following factors is NOT considered one of the three primary premiums factors to health insurance?","options":["Interest","Morality","Morbidity","Expenses"],"answer":"Morality","topic":"Premium Factors","explanation":"For health insurance the three primary factors are morbidity, interest, and expenses — \'mortality (morality)\' is a life-insurance factor."},{"module":"Day 9 Cumulative Final","group":"d9m1-premium-factors","question":"Which factor below is NOT common to both life and health insurance?","options":["Interest","Expense","Morbidity","Amount of Protection"],"answer":"Morbidity","topic":"Premium Factors","explanation":"Morbidity is unique to health insurance; interest, expense, and amount of protection are common to both life and health."},{"module":"Day 9 Cumulative Final","group":"d9m1-underwriting","question":"Which of the following factors is a primary risk factor in underwriting individual health insurance policies?","options":["Geographical location","Salary requirements","Zip code of the insured","Physical condition"],"answer":"Physical condition","topic":"Underwriting","explanation":"Physical condition is a primary risk factor in individual health underwriting."},{"module":"Day 9 Cumulative Final","group":"d9m1-moral-hazard","question":"What is NOT considered a moral hazard?","options":["Habits or lifestyle","Accident-prone individuals","Overweight individuals","Marital Status"],"answer":"Marital Status","topic":"Moral Hazard","explanation":"Marital status is not a moral hazard. Risky habits/lifestyle, accident-proneness, and being overweight relate to moral/morale hazards."},{"module":"Day 9 Cumulative Final","group":"d9m1-respite-care","question":"Which of the following is designed to provide a short rest period for a family care giver?","options":["Continuing care","Respite care","Custodial care","Intermediate care"],"answer":"Respite care","topic":"Respite Care","explanation":"Respite care provides a short rest period for a family caregiver."},{"module":"Day 9 Cumulative Final","group":"d9m1-chronic-illness","question":"All are examples of chronic illnesses except ______.","options":["pneumonia","arthritis","heart disease","hypertension"],"answer":"pneumonia","topic":"Chronic Illness","explanation":"Pneumonia is an acute illness, not chronic. Arthritis, heart disease, and hypertension are chronic."},{"module":"Day 9 Cumulative Final","group":"d9m1-medigap","question":"All of the following are true regarding Medicare supplement or Medigap policies except:","options":["Medicare supplements are sold by private insurance companies.","Medicare supplements are the same as Medigap policies.","Medicare supplements pay costs for Part C & Part D.","It\'s best to have a Medicare Advantage plan and a Medigap plan combined for more benefits."],"answer":"It\'s best to have a Medicare Advantage plan and a Medigap plan combined for more benefits.","topic":"Medigap","explanation":"EXCEPT: you cannot combine a Medicare Advantage plan with a Medigap policy — Medigap supplements Original Medicare only."},{"module":"Day 9 Cumulative Final","group":"d9m1-long-term-care","question":"Which statement regarding long-term care insurance policies is NOT correct?","options":["Maximum coverage periods typically extend from two to six years.","All long-term care policies currently sold must be guaranteed renewable.","Long-term care policies with long probationary periods have lower premiums than those with shorter probationary periods.","Long-term care policy premiums are solely based on the insured\'s age, health, and the type of benefit provided."],"answer":"Long-term care policy premiums are solely based on the insured\'s age, health, and the type of benefit provided.","topic":"Long-Term Care","explanation":"NOT correct: LTC premiums are not based \'solely\' on age, health, and benefit type — factors like the elimination period and inflation protection also matter."},{"module":"Day 9 Cumulative Final","group":"d9m1-risk-factors","question":"Which of the following is NOT considered a primary risk factor in health insurance?","options":["Treatment for chronic conditions","Excessive drinking","Mortality statistics","Occupation involving heavy equipment"],"answer":"Mortality statistics","topic":"Risk Factors","explanation":"Mortality statistics are a life-insurance factor; health insurance uses morbidity."},{"module":"Day 9 Cumulative Final","group":"d9m1-chronic-illness","question":"All the following are true concerning chronic illnesses except:","options":["Most people ignore chronic conditions and the pain they cause","A chronic condition frequently goes beyond being a nuisance and begins to inhibit a person\'s independence","Chronic conditions are can affect other parts of the body","Chronic conditions allow the body to fully recover and can be managed"],"answer":"Chronic conditions allow the body to fully recover and can be managed","topic":"Chronic Illness","explanation":"EXCEPT: chronic conditions do not allow full recovery — they are managed, not cured."},{"module":"Day 9 Cumulative Final","group":"d9m1-renewability","question":"The more favorable the renewability provision is to the insured policyholder, the ______.","options":["premium is guaranteed","lower the premium","premium remains unchanged","higher the premium"],"answer":"higher the premium","topic":"Renewability","explanation":"The more favorable the renewability (e.g., noncancellable), the higher the premium."},{"module":"Day 9 Cumulative Final","group":"d9m1-free-look","question":"Which of the following accurately describes the free look provision?","options":["It allows the proposed insured to look over a policy carefully before applying for it.","It allows the proposed insured to look over the application carefully before completing it.","It allows the insured to look over the issued policy for a specific number of days and return it for a premium refund if desired.","It allows the insurance company to obtain an inspection report and medical examination on the proposed insured prior to issuing the policy."],"answer":"It allows the insured to look over the issued policy for a specific number of days and return it for a premium refund if desired.","topic":"Free Look","explanation":"The free-look lets the insured review the issued policy for a set number of days and return it for a full refund."},{"module":"Day 9 Cumulative Final","group":"d9m1-misstatement-of-age","question":"How does the misstatement of the age or sex provision in a health insurance policy protect insurers?","options":["It allows the insurer to lapse the policy if the insured\'s age or sex is misstated on the application.","It allows the insurer to adjust the benefits to reflect what the premiums would have purchased at the correct age or sex.","It allows the insured to change their age or sex on the policy at any time.","It allows the insurer to void the policy if the insured\'s age or sex is misstated on the application."],"answer":"It allows the insurer to adjust the benefits to reflect what the premiums would have purchased at the correct age or sex.","topic":"Misstatement of Age","explanation":"It lets the insurer adjust benefits to what the premium would have purchased at the correct age or sex."},{"module":"Day 9 Cumulative Final","group":"d9m1-uniform-provisions","question":"The wording of a uniform policy provision in health insurance policies may be changed by a company only if the ______.","options":["change is approved by the company\'s board of directors","modified provision is not less favorable to the insurer","applicant directs that it be changed","modified provision is not less favorable to the insured"],"answer":"modified provision is not less favorable to the insured","topic":"Uniform Provisions","explanation":"A provision\'s wording may be changed only if the modified version is not less favorable to the insured."},{"module":"Day 9 Cumulative Final","group":"d9m1-mandatory-provisions","question":"Which of the following is a mandatory health insurance provision?","options":["Reinstatement","Time Limit on Certain Defenses","Notice of Claim","All answer choices are mandatory health insurance provisions."],"answer":"All answer choices are mandatory health insurance provisions.","topic":"Mandatory Provisions","explanation":"Reinstatement, Time Limit on Certain Defenses, and Notice of Claim are all mandatory provisions."},{"module":"Day 9 Cumulative Final","group":"d9m1-conditionally-renewable","question":"The premiums for a conditionally renewable policy may be increased ______.","options":["reinstatement period","if increase applies to an entire class of policies","at a specified age 60 or 65","the renewability period"],"answer":"if increase applies to an entire class of policies","topic":"Conditionally Renewable","explanation":"Premiums on a conditionally renewable policy may be increased only if the increase applies to an entire class of policies."},{"module":"Day 9 Cumulative Final","group":"d9m1-change-of-occupation","question":"Henry was a fire juggler who purchased a $5,000-per-month disability benefit back in his fire juggling days. He was issued a standard policy for which he had been paying premiums for five years. Since the policy was purchased, Henry has completed his education and is now practicing law as a trial attorney. He is attacked by a client which resulted in the loss his hand, he submits a claim. Which course of action would the company most likely follow?","options":["The company would pay Henry $5,000 per month.","The company would pay a higher benefit to reflect what the premium would have paid at an attorney\'s occupational classification.","The company would pay Henry $5,000 and refund any higher premium cost incurred since he became an attorney.","The company would deny the claim."],"answer":"The company would pay Henry $5,000 per month.","topic":"Change of Occupation","explanation":"Henry moved to a LESS hazardous occupation (attorney), so benefits aren\'t reduced — the company pays the contracted $5,000 per month."},{"module":"Day 9 Cumulative Final","group":"d9m1-optional-provisions","question":"Optional Provisions I and 2, addressing changes of occupation and misstatement of age, permit the insurer to do which of the following?","options":["They permit the insurer to cancel the policy.","They allow the insurer to request the insured to fill out a new application, to correct previous misstatements or alter information that has changed since the application was originally submitted.","They allow the insurer to charge a \'back-end\' premium to make up for the premium the insurer would have charged had the true situation been known.","They permit the insurer to pay indemnities equal to benefits that would have been purchased at the premium paid had the insurer known the facts when the premium was established."],"answer":"They permit the insurer to pay indemnities equal to benefits that would have been purchased at the premium paid had the insurer known the facts when the premium was established.","topic":"Optional Provisions","explanation":"These provisions let the insurer pay indemnities equal to what the premium paid would have purchased had the true facts been known."},{"module":"Day 9 Cumulative Final","group":"d9m1-grace-period","question":"Luke has had a disability income policy for seven years in which the premium is paid semi-annually. He forgot to pay the premium that was due on July 1, 2023. On July 31, 2023, he became totally disabled and notified the insurance company immediately. How will the insurance company respond?","options":["The company will pay the full benefit.","The company will deny the benefit.","The company will adjust the benefit to reflect the premium amount that was paid to reflect the current age and sex of the insured.","The company will pay the full benefit less the premium owed."],"answer":"The company will pay the full benefit less the premium owed.","topic":"Grace Period","explanation":"July 31 is within the 31-day grace period for a semiannual policy, so the insurer pays the full benefit less the premium owed."},{"module":"Day 9 Cumulative Final","group":"d9m1-free-look","question":"When an insured returns a policy to the insurance company within the free look period, the insurance company must do which of the following?","options":["Refund all premiums paid","Refund the premiums paid, less issue expense charges","Refund the premiums paid, less the agent\'s commissions","Refund the premiums paid in excess of the cost of coverage for the time the insured had the policy"],"answer":"Refund all premiums paid","topic":"Free Look","explanation":"Returning a policy within the free-look period requires a refund of all premiums paid."},{"module":"Day 9 Cumulative Final","group":"d9m1-disability-premiums","question":"A 35-year-old male computer engineer and his 35-year-old wife, also a computer engineer, apply for disability insurance. Which would pay the higher monthly premium (assuming all things are equal)?","options":["The male programmer","The female programmer","They would both pay the same","Not enough info"],"answer":"The female programmer","topic":"Disability Premiums","explanation":"Women have higher morbidity (disability) rates, so the female applicant pays the higher disability premium."},{"module":"Day 9 Cumulative Final","group":"d9m1-disability-premiums","question":"A 25-year-old female computer engineer and her 25-year-old husband, also a computer engineer, apply for disability insurance. Which of them would pay the higher monthly premium (assuming all things are equal)?","options":["The male programmer","The female programmer","They would both pay the same","Not enough info"],"answer":"The female programmer","topic":"Disability Premiums","explanation":"Because of higher morbidity, the female applicant pays the higher disability income premium."},{"module":"Day 9 Cumulative Final","group":"d9m1-premium-factors","question":"Which factor would NOT affect a health insurance policy\'s premium?","options":["An insured\'s age","An insured\'s occupation","The types of benefits provided","The location of the insured\'s residence"],"answer":"The location of the insured\'s residence","topic":"Premium Factors","explanation":"The location of the insured\'s residence does not affect the health premium; age, occupation, and benefit types do."},{"module":"Day 9 Cumulative Final","group":"d9m1-impairment-rider","question":"Which of the following would exclude certain conditions from coverage under a health insurance policy?","options":["Pre-existing conditions","Impairment rider","The insuring clause","The consideration clause"],"answer":"Impairment rider","topic":"Impairment Rider","explanation":"An impairment rider excludes specified conditions from coverage."},{"module":"Day 9 Cumulative Final","group":"d9m1-underwriting","question":"It is likely that ______ would NOT be considered in underwriting a health insurance risk.","options":["personal habits","credit rating","medical history","marital status"],"answer":"credit rating","topic":"Underwriting","explanation":"A credit rating is generally not used in underwriting a health insurance risk; habits, medical history, and (sometimes) marital status are."},{"module":"Day 9 Cumulative Final","group":"d9m1-impairment-rider","question":"Which options would result in certain conditions being ineligible for coverage in a health insurance policy?","options":["Pre-existing conditions","Impairment rider","The insuring clause","The consideration clause"],"answer":"Impairment rider","topic":"Impairment Rider","explanation":"An impairment rider makes specified conditions ineligible for coverage."},{"module":"Day 9 Cumulative Final","group":"d9m1-underwriting","question":"Which of the following statements regarding health insurance underwriting is correct?","options":["Limited risk policies are usually issued at standard rates for all occupations","The \\"change of occupation\\" provision does not apply to disability policies","Men show a lower rate of disability than women","All the above are true"],"answer":"Men show a lower rate of disability than women","topic":"Underwriting","explanation":"TRUE: men show a lower rate of disability than women."},{"module":"Day 9 Cumulative Final","group":"d9m1-morbidity-table","question":"A(An) _____ table would show the average number of disabilities due to sickness or accidents for people in specific age groups.","options":["mortality","morbidity","morbid","underwriting"],"answer":"morbidity","topic":"Morbidity Table","explanation":"A morbidity table shows the average number of disabilities by age group."},{"module":"Day 9 Cumulative Final","group":"d9m1-managed-care","question":"The purpose of a managed care organization is to __________.","options":["contain rising health care costs","provide referrals for other providers","promote the HMO and PPO programs","eliminate referrals to other providers"],"answer":"contain rising health care costs","topic":"Managed Care","explanation":"The purpose of a managed care organization is to contain rising health care costs."},{"module":"Day 9 Cumulative Final","group":"d9m1-risk-factors","question":"There are other risk factors used to underwrite health insurance contracts. Which one is not a risk factor?","options":["Age","Salary","Avocations","Sex"],"answer":"Salary","topic":"Risk Factors","explanation":"Salary is not a health-underwriting risk factor; age, avocations, and sex are."},{"module":"Day 9 Cumulative Final","group":"d9m1-disability-taxation","question":"Sally pays a premium of $50 per month for her company\'s noncontributory group disability income plan. If became disabled and received $1,000 a month in benefits, how much, if any, would be considered taxable income?","options":["$0","$50","$950","$1,000"],"answer":"$1,000","topic":"Disability Taxation","explanation":"Under a noncontributory plan the employer pays all premiums, so the entire $1,000 monthly benefit is taxable income."},{"module":"Day 9 Cumulative Final","group":"d9m1-disability-taxation","question":"When individual disability benefits are paid directly to the individual who has paid the premium, a question of taxation arises. Which would be the most appropriate response?","options":["The premium was tax deductible, the benefit will be considered as taxable income.","An exclusion ratio is used to determine the amount of benefit considered taxable.","The premium was tax deductible, therefore the benefit will be considered tax-free.","The premium was not tax deductible, and the benefit is tax free."],"answer":"The premium was not tax deductible, and the benefit is tax free.","topic":"Disability Taxation","explanation":"Individual disability premiums are not tax-deductible, so the benefits are received tax-free."},{"module":"Day 9 Cumulative Final","group":"d9m1-cobra","question":"How long are employers required to continue benefits for terminated employees?","options":["12 months","15 months","18 months","24 months"],"answer":"18 months","topic":"COBRA","explanation":"Under COBRA, terminated employees may continue coverage for 18 months."},{"module":"Day 9 Cumulative Final","group":"d9m1-blanket-insurance","question":"The CEO of a cruise ship line would like to purchase group health coverage for the cruise ship passengers. What kind of insurance would the CEO need to purchase?","options":["Franchise health insurance","Wholesale health insurance","Blanket health insurance","Credit health insurance"],"answer":"Blanket health insurance","topic":"Blanket Insurance","explanation":"Covering cruise-ship passengers (a transient group) requires blanket health insurance."},{"module":"Day 9 Cumulative Final","group":"d9m1-group-disability","question":"Which method is usually used to determine the amount of benefits payable under a group disability income plan?","options":["Flat amount method","Percent of earnings method","Percent of disability method","Presumptive disability method"],"answer":"Percent of earnings method","topic":"Group Disability","explanation":"Group disability income benefits are usually determined by the percent-of-earnings method."},{"module":"Day 9 Cumulative Final","group":"d9m1-credit-disability","question":"Maggie has an automobile loan, and she purchased group credit, accident, and health insurance coverage. Following an accident, she was disabled for seven months. What benefits were paid under the policy?","options":["Monthly income benefits to the insured","A total equal to 7 months of loan payments to the creditor","A total equal to one year of loan payments to the insured\'s creditor","Monthly income benefits to the insured and a total equal to 7 months of loan payments to the insured\'s creditor"],"answer":"A total equal to 7 months of loan payments to the creditor","topic":"Credit Disability","explanation":"Credit disability pays the creditor the loan payments during disability — here, 7 months of payments to the creditor."},{"module":"Day 9 Cumulative Final","group":"d9m1-cobra","question":"Participants in group medical expense plans are protected by a __________ law that guarantees a ___________ of their group coverage if their employment is terminated for reasons other than gross misconduct.","options":["State law/continuation","Federal law/continuation","State law/portion","Federal law/portion"],"answer":"Federal law/continuation","topic":"COBRA","explanation":"COBRA is a federal law guaranteeing continuation of group coverage after termination for reasons other than gross misconduct."},{"module":"Day 9 Cumulative Final","group":"d9m1-cobra","question":"How long are employers required to continue benefits for dependents if an employee dies?","options":["12 months","24 months","29 months","36 months"],"answer":"36 months","topic":"COBRA","explanation":"On the employee\'s death, dependents may continue coverage for 36 months under COBRA."},{"module":"Day 9 Cumulative Final","group":"d9m1-conversion-privilege","question":"_______ group health coverage usually does NOT contain a conversion privilege.","options":["Basic medical expense","Comprehensive medical expense","Disability income","Accidental death and dismemberment"],"answer":"Disability income","topic":"Conversion Privilege","explanation":"Group disability income coverage usually does NOT include a conversion privilege (medical expense plans do)."},{"module":"Day 9 Cumulative Final","group":"d9m1-credit-insurance","question":"Who is the beneficiary on a credit accident and health plan?","options":["The insured","Anyone one the insured names","The lender or creditor","The borrower"],"answer":"The lender or creditor","topic":"Credit Insurance","explanation":"On a credit accident and health plan, the lender/creditor is the beneficiary."},{"module":"Day 9 Cumulative Final","group":"d9m1-premium-cost-control","question":"Which of the following is NOT a method for keeping health insurance policy premium costs to a minimum?","options":["Modifying benefit amounts","Increasing the deductible","Waiving the right to receive benefit payments when due","Extending the elimination"],"answer":"Waiving the right to receive benefit payments when due","topic":"Premium Cost Control","explanation":"Waiving the right to receive benefits is not a premium-reduction method; modifying benefits, raising deductibles, and extending the elimination period are."},{"module":"Day 9 Cumulative Final","group":"d9m1-cafeteria-plan","question":"Which is a benefit arrangement in which employees can pick and choose from a menu of benefits to tailor their benefit package to their needs:","options":["Disability income policies","Cafeteria Plan","Disability Buyout Plan","Business Overhead Expense Plan"],"answer":"Cafeteria Plan","topic":"Cafeteria Plan","explanation":"A benefit menu employees choose from is a cafeteria plan."},{"module":"Day 9 Cumulative Final","group":"d9m1-section-125","question":"What is another name for a Section 125 plan?","options":["Business overhead expense insurance","Disability buy out","A cafeteria plan","Key person disability"],"answer":"A cafeteria plan","topic":"Section 125","explanation":"A Section 125 plan is also called a cafeteria plan."},{"module":"Day 9 Cumulative Final","group":"d9m1-business-continuation","question":"A Business Continuation plan may include all of the following except:","options":["Life insurance","Group insurance","Credit insurance","Disability insurance"],"answer":"Credit insurance","topic":"Business Continuation","explanation":"A business continuation (buy-sell) plan uses life, disability, and group insurance — not credit insurance."},{"module":"Day 9 Cumulative Final","group":"d9m1-cost-sharing-math","question":"An individual major medical plan with a $1,000 individual deductible is going to cost _______ than a comparable plan with a $5,000 individual deductible; and a plan with an 80/20 coinsurance provision will cost ______ than a comparable plan with a 75/25 coinsurance provision.","options":["more/more","less/less","less/more","more/less"],"answer":"more/more","topic":"Cost Sharing Math","explanation":"A lower ($1,000) deductible costs more than a higher one, and 80/20 costs more than 75/25 — so more/more."},{"module":"Day 9 Cumulative Final","group":"d9m1-group-vs-individual","question":"What is the difference between a group medical expense policy and an individual policy?","options":["The group plan requires significantly more out of pocket costs","All group plans are noncontributory","The group plan is significantly less out of pocket costs","All group plans are contributory"],"answer":"The group plan is significantly less out of pocket costs","topic":"Group vs Individual","explanation":"A group plan generally means significantly lower out-of-pocket costs than an individual plan."},{"module":"Day 9 Cumulative Final","group":"d9m1-disability-income","question":"Mr. Jansen falls off a ladder at his boss’ house. Which of the following plans could pay for his injuries?","options":["Key person disability insurance","Business Overhead Expense insurance","Disability buyout plan","Disability income"],"answer":"Disability income","topic":"Disability Income","explanation":"To cover Mr. Jansen\'s own lost income from injury, disability income insurance applies."},{"module":"Day 9 Cumulative Final","group":"d9m1-section-125","question":"Bonnie works for HSON Company, which offers several health insurance options. Bonnie chooses a disability policy and a long-term care policy from the list of options. This is characterized by what type of employee benefit plan?","options":["An overhead policy","Section 125 plan","Ancillary policies","A continuation plan"],"answer":"Section 125 plan","topic":"Section 125","explanation":"Choosing benefits (disability + LTC) from a list of options characterizes a Section 125 (cafeteria) plan."},{"module":"Day 9 Cumulative Final","group":"d9m1-disability-buy-sell","question":"Which of the following plans contains a provision allowing for a lump sum payment of the benefit?","options":["Individual disability income policies","Disability buy-sell agreements","Key person disability insurance","A group disability policy"],"answer":"Disability buy-sell agreements","topic":"Disability Buy-Sell","explanation":"Disability buy-sell agreements can provide a lump-sum benefit to fund the purchase of a disabled owner\'s interest."},{"module":"Day 9 Cumulative Final","group":"d9m1-disability-buy-out","question":"Disability Buy-Out plans feature","options":["Long elimination plans up to two years","Short elimination periods","Short elimination periods and benefits up to 10 years","Long elimination periods and benefits up to 10 years"],"answer":"Long elimination plans up to two years","topic":"Disability Buy-Out","explanation":"Disability buy-out plans feature long elimination periods (up to about two years) to confirm permanent disability."},{"module":"Day 9 Cumulative Final","group":"d9m1-financial-services-commission","question":"Who comprises the Financial Services Commission?","options":["The Governor, CFO, Attorney General, & the Insurance Commissioner","The Governor, CFO, Attorney General, & the Agriculture Commissioner","The Governor, CFO, Insurance Commissioner, & the Agriculture Commissioner","The Governor, CFO, Insurance Commissioner, & the Speaker of the House"],"answer":"The Governor, CFO, Attorney General, & the Agriculture Commissioner","topic":"Financial Services Commission","explanation":"The Financial Services Commission is the Governor, CFO, Attorney General, and Commissioner of Agriculture."},{"module":"Day 9 Cumulative Final","group":"d9m1-insurance-license","question":"What is the purpose of the insurance license?","options":["TO have someone to blame when things go wrong","To help protect the general public by announcing which insurance agents commit poor business practices through public service announcements","TO help protect the general public by requiring a minimum level of insurance knowledge and competence","To help the government track the whereabouts of those conducting insurance activities"],"answer":"TO help protect the general public by requiring a minimum level of insurance knowledge and competence","topic":"Insurance License","explanation":"A license protects the public by requiring a minimum level of insurance knowledge and competence."},{"module":"Day 9 Cumulative Final","group":"d9m1-unfair-discrimination","question":"A company that charges different premiums for people in the same actuarial class could be found guilty of _____.","options":["twisting","unfair discrimination","segregation","unfair trade practices"],"answer":"unfair discrimination","topic":"Unfair Discrimination","explanation":"Charging different premiums within the same actuarial class is unfair discrimination."},{"module":"Day 9 Cumulative Final","group":"d9m1-continuing-education","question":"A licensee is required to complete 24 hours of continuing education if they have been licensed for less than 6 years. How many of those hours are required for ethics and law?","options":["5","3","4","1"],"answer":"5","topic":"Continuing Education","explanation":"Of the 24 CE hours, 5 hours must cover law and ethics (the law & ethics update)."},{"module":"Day 9 Cumulative Final","group":"d9m1-controlled-business","question":"An agent may write controlled business provided she writes at least what percentage of other similar business?","options":["25%","50%","75%","100%"],"answer":"50%","topic":"Controlled Business","explanation":"Controlled business may not exceed other business, so the agent must write at least 50% other (non-controlled) business."},{"module":"Day 9 Cumulative Final","group":"d9m1-defamation","question":"Which of the following is not a condition of defamation?","options":["It may be derogatory.","It is not meant to be maliciously critical.","It can be written (libel).","It can be spoken (slander)."],"answer":"It is not meant to be maliciously critical.","topic":"Defamation","explanation":"NOT a condition of defamation: \'not meant to be maliciously critical\' — defamation IS malicious and injurious."},{"module":"Day 9 Cumulative Final","group":"d9m1-agent-duties","question":"Which statement(s) is/are true? I – Record retention requirements for agents is five years II - No person other than a licensed and appointed agent may accept any commission or other valuable compensation for soliciting and negotiating insurance. III – A fiduciary is a person in a position of special trust and confidence. IV – If a license as an agent has been revoked from soliciting or sale of insurance products to a person over 65 years of age or older, the department may not thereafter grant or issue any insurance license to such individual.","options":["I","I, II, and III","IV","I, II, III, and IV"],"answer":"I, II, and III","topic":"Agent Duties","explanation":"I, II, and III are true (5-year record retention, only licensed/appointed agents may accept commissions, fiduciary = position of trust); IV\'s absolute permanent bar is overstated."},{"module":"Day 9 Cumulative Final","group":"d9m1-licensing","question":"Which statement(s) is/are true? I - Notification to the Department of Insurance is required within 30 days of change of address. II - Notification to the Department of Insurance is required within 30 days of change of company. III - An agent will lose licensure as a result of 1-year non-appointment. IV - An agent will lose licensure as a result of 4 years non-appointment.","options":["I","I, II, and III","IV","I and IV"],"answer":"I and IV","topic":"Licensing","explanation":"I and IV are true: notify the Department within 30 days of an address change, and licensure is lost after 48 months (4 years) without appointment."},{"module":"Day 9 Cumulative Final","group":"d9m1-agency","question":"The term agency refers to which of the following?","options":["Agent","Adjuster","Location","All of the above"],"answer":"Location","topic":"Agency","explanation":"The term \'agency\' refers to the location/business entity through which insurance is transacted."},{"module":"Day 9 Cumulative Final","group":"d9m1-licensing","question":"To be a licensed resident producer in Florida, you must complete all the following tasks EXCEPT _____.","options":["provide a criminal background check","pay a refundable application fee","finish the pre-licensing education requirements","provide any other information required by the state"],"answer":"pay a refundable application fee","topic":"Licensing","explanation":"EXCEPT: the application fee is NON-refundable. A background check, pre-licensing education, and required information are needed."},{"module":"Day 9 Cumulative Final","group":"d9m1-fl-required-provisions","question":"Which of the following is NOT a provision that is required by Florida law for group health insurance policies?","options":["Group health policies must provide coverage for mental and nervous disorders.","A newborn infant is covered from the moment of birth.","Coverage must be provided for a handicapped child who is a family member until he or she reaches the age of 25.","Group health policies must provide coverage for a newborn infant of a covered family member until the infant reaches 18 months of age."],"answer":"Coverage must be provided for a handicapped child who is a family member until he or she reaches the age of 25.","topic":"FL Required Provisions","explanation":"NOT required: the \'handicapped child until age 25\' statement — disabled-dependent coverage continues without that age cutoff."},{"module":"Day 9 Cumulative Final","group":"d9m1-hiv-aids-rules","question":"Which of the following statements is true?","options":["An insurer may not cancel or not renew for diagnosis of HIV/AIDS, but it may cancel or not renew for treatment of HIV/AIDS.","An insurer may cancel or not renew for diagnosis of HIV/AIDS but may not cancel or not renew for treatment of HIV/AIDS.","An insurer may cancel or not renew for diagnosis or treatment of HIV/AIDS.","An insurer may not cancel or not renew for diagnosis or treatment of HIV/AIDS."],"answer":"An insurer may not cancel or not renew for diagnosis or treatment of HIV/AIDS.","topic":"HIV/AIDS Rules","explanation":"TRUE: an insurer may not cancel or non-renew for diagnosis OR treatment of HIV/AIDS."},{"module":"Day 9 Cumulative Final","group":"d9m1-hiv-testing-duties","question":"Which of the following is not correct concerning the insurer\'s obligation to the applicant regarding HIV testing?","options":["The insurer must disclose its intent to test a person for HIV prior to testing for HIV/AIDS.","The insurer must get the person\'s written consent to administer the test.","The insurer must notify the insured of any positive results.","The insurer may inquire whether a person has been tested positive for exposure to the HIV infection."],"answer":"The insurer may inquire whether a person has been tested positive for exposure to the HIV infection.","topic":"HIV Testing Duties","explanation":"NOT correct: an insurer may not simply inquire whether someone previously tested positive for HIV."},{"module":"Day 9 Cumulative Final","group":"d9m1-limitations-exclusions","question":"Which of the following is NOT correct concerning policy limitations and exclusions?","options":["Pre-existing conditions or diseases are acceptable","Alcoholism and drug addiction are acceptable","The insurer can exclude Alzheimer\'s disease","Participation in a felony, riot or insurrection"],"answer":"The insurer can exclude Alzheimer\'s disease","topic":"Limitations & Exclusions","explanation":"NOT correct: insurers may not exclude Alzheimer\'s disease."},{"module":"Day 9 Cumulative Final","group":"d9m1-required-provisions","question":"Which of the following statements regarding the required provisions of a health insurance policy is NOT accurate?","options":["Annual pay policies have a grace period of 31 days.","An entire contract clause indicates that the policy endorsement and attachments constitute the entire contract.","Reinstated policies provide immediate coverage for illnesses.","Claim forms are required to be sent to the insured within 15 days of notice of claim."],"answer":"Reinstated policies provide immediate coverage for illnesses.","topic":"Required Provisions","explanation":"NOT accurate: a reinstated policy covers sickness only after 10 days (accidents are immediate)."},{"module":"Day 9 Cumulative Final","group":"d9m1-group-health-coverage","question":"Which statement about group health insurance policies is CORRECT?","options":["Coverage from an occupational accident cannot be excluded.","Coverage for newborn children can be excluded.","Coverage for VA hospital treatment cannot be excluded.","Coverage for handicapped children may be provided."],"answer":"Coverage for handicapped children may be provided.","topic":"Group Health Coverage","explanation":"CORRECT: coverage for handicapped children may be provided."},{"module":"Day 9 Cumulative Final","group":"d9m1-hiv-consent-form","question":"The HIV/AIDS written consent form must include all of the following information except ___________.","options":["meaning of its results","its purpose","potential uses","sexual orientation"],"answer":"sexual orientation","topic":"HIV Consent Form","explanation":"EXCEPT: the HIV/AIDS written consent form may not include sexual orientation."},{"module":"Day 9 Cumulative Final","group":"d9m1-hiv-testing","question":"Prior to testing for HIV/AIDS all of the following should happen except ___________.","options":["Disclose its intent to test the person for HIV","Must obtain the written informed consent to administer the test","Using sexual orientation to assist in underwriting","If applicant is positive have the results given by a physician or the Dept. of Health"],"answer":"Using sexual orientation to assist in underwriting","topic":"HIV Testing","explanation":"EXCEPT: using sexual orientation in underwriting is prohibited."},{"module":"Day 9 Cumulative Final","group":"d9m1-hiv-aids-rules","question":"Which of the following statements is NOT true?","options":["The agent is responsible for completing the application.","An insurer may cancel or not renew for diagnosis of HIV/AIDS but may not cancel or not renew for treatment of HIV/AIDS.","A long-term are policy can have an elimination period for up to 180 days","An applicant shall be notified of a positive test result of HIV/AIDS by the agent withint 10 days."],"answer":"An insurer may cancel or not renew for diagnosis of HIV/AIDS but may not cancel or not renew for treatment of HIV/AIDS.","topic":"HIV/AIDS Rules","explanation":"NOT true: insurers may not cancel/non-renew for diagnosis OR treatment of HIV/AIDS, so this statement is false."},{"module":"Day 9 Cumulative Final","group":"d9m1-blanket-insurance","question":"Which of the following would a blanket policy NOT cover?","options":["A group of engineers","Individuals on a cruise ship","Individuals in an employer group policy with less than 15 people","An airline covering its passengers"],"answer":"Individuals in an employer group policy with less than 15 people","topic":"Blanket Insurance","explanation":"A blanket policy would not cover an ordinary small employer group; blanket covers transient groups like cruise or airline passengers."},{"module":"Day 9 Cumulative Final","group":"d9m1-hmo-open-enrollment","question":"The law requires that each HMO that offers a group plan within Florida must have an open enrollment period of not less than ________ days during every _______ months.","options":["10 & 1","15 & 24","30 & 18","45 & 6"],"answer":"30 & 18","topic":"HMO Open Enrollment","explanation":"An HMO group plan must have an open enrollment period of at least 30 days every 18 months."},{"module":"Day 9 Cumulative Final","group":"d9m1-health-service-orgs","question":"Which of the following statement about health service organizations is true?","options":["They provide loss of income benefits to policyowners","They provide benefit payments directly to the hospitals and physicians providing service","They reimburse policy owners directly for physicians fees","They reimburse policy owners directly for all medical expenses"],"answer":"They provide benefit payments directly to the hospitals and physicians providing service","topic":"Health Service Orgs","explanation":"Health service organizations pay benefits directly to the hospitals and physicians providing service."},{"module":"Day 9 Cumulative Final","group":"d9m1-hmo-unfair-practices","question":"Choose the term that is NOT considered an unfair trade practice with regard to HMOs.","options":["Defamation","Misrepresentation","Conversion","Twisting"],"answer":"Conversion","topic":"HMO Unfair Practices","explanation":"Conversion is NOT an HMO unfair trade practice; defamation, misrepresentation, and twisting are."},{"module":"Day 9 Cumulative Final","group":"d9m1-copayment","question":"What does the term copayment mean?","options":["The set amount per visit or per service that the subscriber is required to pay","The amount the HMO reimburses to the subscriber if he or she visits a physician outside the service area","The amount the HMO pays the physician for each patient treatment","Another name for the word premium"],"answer":"The set amount per visit or per service that the subscriber is required to pay","topic":"Copayment","explanation":"A copayment is the set amount per visit/service the subscriber must pay."},{"module":"Day 9 Cumulative Final","group":"d9m1-hmo-cap","question":"What is the purpose of the Florida HMO Consumer Assistance Plan?","options":["To helps low-income families pay for HMO coverage","To explain HMO coverage to consumers","To adjudicate subscribers\' contested claims against HMOs","To provide or arrange coverage for subscribers of HMOs that become insolvent"],"answer":"To provide or arrange coverage for subscribers of HMOs that become insolvent","topic":"HMO CAP","explanation":"The HMO Consumer Assistance Plan provides or arranges coverage for subscribers of an insolvent HMO."},{"module":"Day 9 Cumulative Final","group":"d9m1-hmos","question":"Health Maintenance Organizations (HMO)","options":["Are considered the same as a PPO","Can sell insurance to subscribers","Are not allowed to deal with Medicare recipients","Are considered prepaid service systems"],"answer":"Are considered prepaid service systems","topic":"HMOs","explanation":"HMOs are prepaid service systems."},{"module":"Day 9 Cumulative Final","group":"d9m1-hmos","question":"HMOs are known for stressing:","options":["A wide array of choices","Fee-for-service schedules","Unlimited services","Preventive health care and early detection and treatment"],"answer":"Preventive health care and early detection and treatment","topic":"HMOs","explanation":"HMOs stress preventive health care and early detection and treatment."},{"module":"Day 9 Cumulative Final","group":"d9m1-hmos","question":"HMO services are paid:","options":["In advance of any treatment","After treatment is complete","During the treatment","By the HMO and the subscriber"],"answer":"In advance of any treatment","topic":"HMOs","explanation":"HMO services are prepaid — paid in advance of treatment."},{"module":"Day 9 Cumulative Final","group":"d9m1-capitation","question":"What does the term capitation mean?","options":["The HMO\'s premium","The amount the physician pays for each member","The amount of capital the HMO possesses","The value of the HMO capital improvements"],"answer":"The amount the physician pays for each member","topic":"Capitation","explanation":"Capitation is a fixed, per-member payment between the HMO and the physician (the amount tied to each member)."},{"module":"Day 9 Cumulative Final","group":"d9m1-hmo-open-enrollment","question":"Saved The law requires that each HMO that offers a group plan within Florida must have an open enrollment period of not less than ________ days during every 18-month period.","options":["10","15","30","45"],"answer":"30","topic":"HMO Open Enrollment","explanation":"An HMO group plan must have an open enrollment period of at least 30 days every 18-month period."}]')}]);